window.HADITH_CACHE = window.HADITH_CACHE || {};
window.HADITH_CACHE["nasai_0"] = {"1":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا اسْتَيْقَظَ أَحَدُكُمْ مِنْ نَوْمِهِ فَلَا يَغْمِسْ يَدَهُ فِي وَضُوئِهِ حَتَّى يَغْسِلَهَا ثَلَاثًا فَإِنَّ أَحَدَكُمْ لَا يَدْرِي أَيْنَ بَاتَتْ يَدُهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah], Nabi shallallahu 'alaihi wasallam bersabda: \" Apabila salah seorang dari kalian bangun dari tidurnya, jangan mencelupkan tangannya ke tempat wudlunya sehingga dia mencuci tangannya sebanyak tiga kali, karena salah seorang dari kalian tidak tahu di mana tangannya bermalam.\""},"2":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَقُتَيْبَةُ بْنُ سَعِيدٍ عَنْ جَرِيرٍ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ مِنْ اللَّيْلِ يَشُوصُ فَاهُ بِالسِّوَاكِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dan [Qutaibah bin Said] dari [Jarir] dari [Manshur] dari [Abu Wail] dari [Hudzaifah] berkata: \" Rasulullah shallallahu 'alaihi wasallam apabila hendak melaksanakan shalat lail beliau menggosok mulutnya dengan siwak.\""},"3":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدَةَ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ قَالَ أَخْبَرَنَا غَيْلَانُ بْنُ جَرِيرٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَدَخَلْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَسْتَنُّ وَطَرَفُ السِّوَاكِ عَلَى لِسَانِهِ وَهُوَ يَقُولُ عَأْ عَأْ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdah] dia berkata; Telah menceritakan kepada kami [Hammad bin Zaid] berkata; telah mengabarkan kepada kami [Ghalan bin Jarir] dari [Abu Burdah] dari [Abu Musa] dia berkata; \"Saya menemui Rasulullah shallallahu 'alaihi wasallam, sedang beliau sedang bersiwak, dan ujung siwak berada di ujung lidahnya beliau mengucapkan; Aa', Aa'. "},"4":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى وَهُوَ ابْنُ سَعِيدٍ قَالَ حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا حُمَيْدُ بْنُ هِلَالٍ قَالَ حَدَّثَنِي أَبُو بُرْدَةَ عَنْ أَبِي مُوسَى قَالَأَقْبَلْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعِي رَجُلَانِ مِنْ الْأَشْعَرِيِّينَ أَحَدُهُمَا عَنْ يَمِينِي وَالْآخَرُ عَنْ يَسَارِي وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَاكُ فَكِلَاهُمَا سَأَلَ الْعَمَلَ قُلْتُ وَالَّذِي بَعَثَكَ بِالْحَقِّ نَبِيًّا مَا أَطْلَعَانِي عَلَى مَا فِي أَنْفُسِهِمَا وَمَا شَعَرْتُ أَنَّهُمَا يَطْلُبَانِ الْعَمَلَ فَكَأَنِّي أَنْظُرُ إِلَى سِوَاكِهِ تَحْتَ شَفَتِهِ قَلَصَتْ فَقَالَ إِنَّا لَا أَوْ لَنْ نَسْتَعِينَ عَلَى الْعَمَلِ مَنْ أَرَادَهُ وَلَكِنْ اذْهَبْ أَنْتَ فَبَعَثَهُ عَلَى الْيَمَنِ ثُمَّ أَرْدَفَهُ مُعَاذُ بْنُ جَبَلٍ رَضِيَ اللَّهُ عَنْهُمَا","id":"Telah mengabarkan kepada kami [Amru bin Ali] telah menceritakan kepada kami [Yahya -Yaitu Ibnu Sa'id] dia berkata; telah menceritakan kepada kami [Qurrah bin bin Khalid] berkata; telah menceritakan kepada kami [Humaid bin Hilal] berkata; telah menceritakan kepadaku [Abu Burdah] dari [Abu Musa] dia berkata, \"Aku pernah menghadap kepada Rasulullah shallallahu 'alaihi wasallam dan bersamaku dua laki-laki dari bani Asy'ari; satu di sebelah kananku dan yang satu lagi di sebelah kiriku, sedangkan Rasulullah shallallahu 'alaihi wasallam sedang bersiwak. Lalu kedua laki-laki tadi meminta jabatan kepegawaian kepada beliau, maka aku Abu Musa berkata, 'demi Dzat yang mengutus engkau sebagai Nabi pembawa kebenaran, dua orang laki-laki tadi tidak mengungkapkan uneg-unegnya kepadaku dan aku juga tidak sadar kalau keduanya meminta jabatan kepegawaian, kemudian seolah-olah aku melihat siwak beliau yang berada di bawah bibirnya sehingga menyatu dan naik. Lalu beliau bersabda, 'kami tidak -atau tidak akan - meminta pertolongan orang yang menginginkan jabatan kepegawaian, maka pergilah kamu'. Beliau mengutusnya ke Yaman, dan diboncengkan oleh Mu'adz bin Jabal Radliyallahu'anhuma "},"5":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ وَمُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى عَنْ يَزِيدَ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبِي عَتِيقٍ قَالَ حَدَّثَنِي أَبِي قَالَ سَمِعْتُ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ السِّوَاكُ مَطْهَرَةٌ لِلْفَمِ مَرْضَاةٌ لِلرَّبِّ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dan [Muhammad bin Abdul A'la] dari [Yazid] yaitu Ibnu Jura'i dia berkata; telah menyampaikan kepadaku [Abdurrahman bin Abu 'Atiq] dia berkata; [ayahku] telah berkata kepadaku; saya mendengar dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Bersiwak mendatangkan kewangian mulut, dan mendapat ridha Allah.\""},"6":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ وَعِمْرَانُ بْنُ مُوسَى قَالَا حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ الْحَبْحَابِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَكْثَرْتُ عَلَيْكُمْ فِي السِّوَاكِ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dan ['Imran bin Musa] keduanya berkata; telah menceritakan kepada kami [Abdul Warits] berkata; telah menceritakan kepada kami [Syu'aib bin Habhab] dari [Anas bin Malik] dia berkata; bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku sering menganjurkan kalian banyak bersiwak.\""},"7":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَمَرْتُهُمْ بِالسِّوَاكِ عِنْدَ كُلِّ صَلَاةٍ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Abu Zinad] dari [Al A'araj] dari [Abu Hurairah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya aku tidak khawatir memberatkan umatku, aku pasti memerintahkan mereka untuk bersiwak setiap kali shalat.\" "},"8":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ خَشْرَمٍ قَالَ حَدَّثَنَا عِيسَى وَهُوَ ابْنُ يُونُسَ عَنْ مِسْعَرٍ عَنْ الْمِقْدَامِ وَهُوَ ابْنُ شُرَيْحٍ عَنْ أَبِيهِ قَالَ قُلْتُ لِعَائِشَةَبِأَيِّ شَيْءٍ كَانَ يَبْدَأُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ بَيْتَهُ قَالَتْ بِالسِّوَاكِ","id":"Telah mengabarkan kepada kami [Ali bin Khasram] dia berkata; telah menceritakan kepada kami [Isa -yaitu Ibnu Yunus] dari [Mis'ar] dari [Miqdam yaitu Ibnu Syuraih] dari [Ayahnya] dia berkata; \"Aku bertanya kepada Aisyah 'Apa yang pertama kali Rasulullah shallallahu 'alaihi wasallam kerjakan ketika masuk ke dalam rumahnya? ['Aisyah] berkata, 'Bersiwak'.\""},"9":{"ar":"أَخْبَرَنَا الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْفِطْرَةُ خَمْسٌ الِاخْتِتَانُ وَالِاسْتِحْدَادُ وَقَصُّ الشَّارِبِ وَتَقْلِيمُ الْأَظْفَارِ وَنَتْفُ الْإِبْطِ","id":"Telah mengabarkan kepada kami [Al Harits bin Miskin] telah dibacakan kepadanya dan saya mendengarnya dari [Ibnu Wahab] dari [Yunus] dari [Ibnu Syihab] dari [Sa'id bin Musayyab] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Lima perkara yang termasuk fitrah, berkhitan, mencukur bulu kemaluan, memotong kumis, memotong kuku, dan mencabut bulu ketiak.\" "},"10":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ مَعْمَرًا عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمْسٌ مِنْ الْفِطْرَةِ قَصُّ الشَّارِبِ وَنَتْفُ الْإِبْطِ وَتَقْلِيمُ الْأَظْفَارِ وَالِاسْتِحْدَادُ وَالْخِتَانُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; telah menceritakan kepada kami [Al Mu'tamir] berkata; saya mendengar [Ma'mar] dari [Zuhri] dari [Sa'id bin Musayyab] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Lima perkara yang termasuk fitrah, memotong kumis, mencabut bulu ketiak, memotong kuku, mencukur bulu kemaluan, dan berkhitan.\" "},"11":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَمْسٌ مِنْ الْفِطْرَةِ الْخِتَانُ وَحَلْقُ الْعَانَةِ وَنَتْفُ الْإِبْطِ وَتَقْلِيمُ الْأَظْفَارِ وَأَخْذُ الشَّارِبِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazid] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Zuhri] dari [Sa'id bin Musayyab] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Ada lima perkara yang termasuk fitrah yaitu: berkhitan, mencukur bulu kemaluan, mencabut bulu ketiak, memotong kuku, dan memotong kumis.\" "},"12":{"ar":"أَخْبَرَنَا الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ عَنْ حَنْظَلَةَ بْنِ أَبِي سُفْيَانَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْفِطْرَةُ قَصُّ الْأَظْفَارِ وَأَخْذُ الشَّارِبِ وَحَلْقُ الْعَانَةِ","id":"Telah mengabarkan kepada kami [Harits bin Miskin] telah dibacakan kepadanya dan saya mendengar dari [Ibnu Wahb] dari [Handzalah bin Abu Sufyan] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Termasuk fitrah adalah memotong kuku, memotong kumis, dan mencukur bulu kemaluan.\" "},"13":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا عَبِيدَةُ بْنُ حُمَيْدٍ عَنْ يُوسُفَ بْنِ صُهَيْبٍ عَنْ حَبِيبِ بْنِ يَسَارٍ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَمْ يَأْخُذْ شَارِبَهُ فَلَيْسَ مِنَّا","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dia berkata; Telah memberitakan kepada kami ['Ubaidah bin Humaid] dari [Yusuf bin Shuhaib] dari [Habib bin Yasar] dari [Zaid bin Arqam] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa tidak memotong kumisnya, dia tidak termasuk golongan kami.\" "},"14":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا جَعْفَرٌ هُوَ ابْنُ سُلَيْمَانَ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَوَقَّتَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَصِّ الشَّارِبِ وَتَقْلِيمِ الْأَظْفَارِ وَحَلْقِ الْعَانَةِ وَنَتْفِ الْإِبْطِ أَنْ لَا نَتْرُكَ أَكْثَرَ مِنْ أَرْبَعِينَ يَوْمًا وَقَالَ مَرَّةً أُخْرَى أَرْبَعِينَ لَيْلَةً","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Ja'far yaitu Ibnu Sulaiman] dari [Abu 'Imran Al Jauny] dari [Anas bin Malik] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam menentukan waktu bagi kita dalam masalah memotong kumis, memotong kuku, mencukur bulu kemaluan, dan mencabut bulu ketiak, yaitu supaya kami tidak membiarkannya lebih dari empat puluh hari.\" Dalam kesempatan lain beliau bersabda: \"Empat puluh malam.\""},"15":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى هُوَ ابْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَحْفُوا الشَّوَارِبَ وَأَعْفُوا اللِّحَى","id":"Telah mengabarkan kepada kami [Ubaidillah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya yaitu Ibnu Sa'id] dari [Ubaidillah] Telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Pendekkan kumis dan biarkan (panjangkan) jenggot.\""},"16":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا أَبُو جَعْفَرٍ الْخَطْمِيُّ عُمَيْرُ بْنُ يَزِيدَ قَالَ حَدَّثَنِي الْحَارِثُ بْنُ فُضَيْلٍ وَعُمَارَةُ بْنُ خُزَيْمَةَ بْنِ ثَابِتٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي قُرَادٍ قَالَخَرَجْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْخَلَاءِ وَكَانَ إِذَا أَرَادَ الْحَاجَةَ أَبْعَدَ","id":"Telah mengabarkan kepada kami [Amru bin Ali] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Abu Ja'far Al Khathmi Umair bin Yazid] berkata; telah menceritakan kepada kami [Al Harits bin Fudhail] dan ['Umarah bin Huzaimah bin Tsabit] dari [Abdurrahman bin Abu Qurrad] dia berkata; \"Aku pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam ke tempat yang sepi, apabila beliau ingin buang hajat, beliau menjauh.\" "},"17":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا ذَهَبَ الْمَذْهَبَ أَبْعَدَ قَالَ فَذَهَبَ لِحَاجَتِهِ وَهُوَ فِي بَعْضِ أَسْفَارِهِ فَقَالَ ائْتِنِي بِوَضُوءٍ فَأَتَيْتُهُ بِوَضُوءٍ فَتَوَضَّأَ وَمَسَحَ عَلَى الْخُفَّيْنِقَالَ الشَّيْخُ إِسْمَعِيلُ هُوَ ابْنُ جَعْفَرِ بْنِ أَبِي كَثِيرٍ الْقَارِئُ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] Telah memberitakan kepada kami [Ismail] dari [Muhammad bin Amr] dari [Abu Salamah] dari [Al Mughirah bin Syu'bah], apabila Rasulullah shallallahu 'alaihi wasallam pergi ke tempat (WC), beliau menjauh. Dia berkata, \"Pernah Beliau shallallahu 'alaihi wasallam pergi untuk buang hajat saat safar. Lalu beliau berkata, 'Ambilkan air wudlu'. Aku segera mengambilkan air wudlu, beliau segera berwudlu dan membasuh kedua sepatunya (khuf).\" Ini sebagaimana di katakan Syaikh Ismail yaitu Ibnu Ja'far bin Abu Katsir Al Qori "},"18":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عِيسَى بْنُ يُونُسَ قَالَ أَنْبَأَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ حُذَيْفَةَ قَالَكُنْتُ أَمْشِي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْتَهَى إِلَى سُبَاطَةِ قَوْمٍ فَبَالَ قَائِمًا فَتَنَحَّيْتُ عَنْهُ فَدَعَانِي وَكُنْتُ عِنْدَ عَقِبَيْهِ حَتَّى فَرَغَ ثُمَّ تَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Isa bin Yunus] berkata; Telah memberitakan kepada kami [Al A'masy] dari [Syaqiq] dari [Hudzaifah] dia berkata: \"Aku pernah berjalan bersama Rasulullah shallallahu 'alaihi wasallam. Ketika sampai di tempat pembuangan sampah suatu kaum, beliau kencing sambil berdiri, maka aku segera menjauh darinya. Beliau kemudian memanggilku, dan aku di belakangnya hingga beliau selesai. Beliau lalu berwudlu dan mengusap kedua sepatunya (khuf).\""},"19":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ الْخَلَاءَ قَالَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْخُبُثِ وَالْخَبَائِثِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Ismail] dari [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam apabila masuk WC, beliau membaca -doa-, 'Ya Allah, aku berlindung kepada-Mu dari kejahatan setan laki-laki dan setan perempuan.\" "},"20":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ رَافِعِ بْنِ إِسْحَقَ أَنَّهُ سَمِعَ أَبَا أَيُّوبَ الْأَنْصَارِيَّ وَهُوَ بِمِصْرَ يَقُولُوَاللَّهِ مَا أَدْرِي كَيْفَ أَصْنَعُ بِهَذِهِ الْكَرَايِيسِ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا ذَهَبَ أَحَدُكُمْ إِلَى الْغَائِطِ أَوْ الْبَوْلِ فَلَا يَسْتَقْبِلْ الْقِبْلَةَ وَلَا يَسْتَدْبِرْهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dari [Ibnu Qasim] dia berkata; Telah menceritakan kepadaku [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Rafi' bin Ishaq] bahwasanya dia mendengar [Abu Ayyub Al Anshari] (beliau sedang berada di Mesir) dia berkata; \"Demi Allah, aku tidak tahu cara memperlakukan WC-WC ini? padahal Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian ingin buang air besar atau buang air kecil, jangan menghadap kiblat atau membelakanginya.\""},"21":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي أَيُّوبَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَسْتَقْبِلُوا الْقِبْلَةَ وَلَا تَسْتَدْبِرُوهَا لِغَائِطٍ أَوْ بَوْلٍ وَلَكِنْ شَرِّقُوا أَوْ غَرِّبُوا","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Atha bin Yazid] dari [Abu Ayyub Al Anshari] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda, \"Jangan kalian menghadap kiblat dan jangan membelakanginya ketika buang air besar atau buang air kecil, tetapi menghadaplah ke timur atau barat.\""},"22":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا غُنْدَرٌ قَالَ أَنْبَأَنَا مَعْمَرٌ قَالَ أَنْبَأَنَا ابْنُ شِهَابٍ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَى أَحَدُكُمْ الْغَائِطَ فَلَا يَسْتَقْبِلْ الْقِبْلَةَ وَلَكِنْ لِيُشَرِّقْ أَوْ لِيُغَرِّبْ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Ghundar] berkata; Telah memberitakan kepada kami [Ma'mar] berkata; Telah memberitakan kepada kami [Ibnu Syihab] dari [Atha bin Yazid] dari [Abu Ayub Al Anshari] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bila salah seorang dari kalian ingin buang air besar, jangan menghadap kiblat, tetapi menghadaplah ke timur atau barat.\""},"23":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ عَمِّهِ وَاسِعِ بْنِ حَبَّانَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَلَقَدْ ارْتَقَيْتُ عَلَى ظَهْرِ بَيْتِنَا فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى لَبِنَتَيْنِ مُسْتَقْبِلَ بَيْتِ الْمَقْدِسِ لِحَاجَتِهِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari pamannya [wasi' bin Habban] dari [Abdullah bin Umar] dia berkata; \"Aku pernah naik ke atap rumah kami, lalu aku melihat Rasulullah shallallahu 'alaihi wasallam sedang buang hajat di atas dua batu bata dalam keadaan menghadap arah Baitul Maqdis.\""},"24":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ دُرُسْتَ قَالَ أَنْبَأَنَا أَبُو إِسْمَعِيلَ وَهُوَ الْقَنَّادُ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ أَنَّ عَبْدَ اللَّهِ بْنَ أَبِي قَتَادَةَ حَدَّثَهُ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا بَالَ أَحَدُكُمْ فَلَا يَأْخُذْ ذَكَرَهُ بِيَمِينِهِ","id":"Telah mengabarkan kepada kami [Yahya bin Durusta] dia berkata; Telah memberitakan kepada kami [Abu Ismail yaitu Al Qannad] berkata; telah menceritakan kepadaku [Yahya bin Abu katsir] bahwa [Abdullah bin Abu Qatadah] telah menceritakan kepadanya dari [Ayahnya], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian buang air kecil, jangan menyentuh kemaluannya dengan tangan kanannya.\""},"25":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ وَكِيعٍ عَنْ هِشَامٍ عَنْ يَحْيَى هُوَ ابْنُ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ أَحَدُكُمْ الْخَلَاءَ فَلَا يَمَسَّ ذَكَرَهُ بِيَمِينِهِ","id":"Telah mengabarkan kepada kami [Hannad bin As Sariy] dari [Waki'] dari [Hisyam] dari [Yahya yaitu Ibnu Katsir] dari [Abdullah bin Abu Qatadah] dari [Ayahnya] berkata; bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian buang air kecil, jangan menyentuh kemaluannya dengan tangan kanannya.\""},"26":{"ar":"أَخْبَرَنَا مُؤَمَّلُ بْنُ هِشَامٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ قَالَ أَخْبَرَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى سُبَاطَةَ قَوْمٍ فَبَالَ قَائِمًا","id":"Telah mengabarkan kepada kami [Muammal bin Hisyam] dia berkata; Telah memberitakan kepada kami [Ismail] berkata; Telah mengabarkan kepada kami [Syu'bah] dari [Sulaiman] dari [Abu Wa'il] dari [Hudzaifah] \"Rasulullah shallallahu 'alaihi wasallam pernah mendatangi tempat pembuangan sampah suatu kaum, lalu ia buang air kecil dengan berdiri.\""},"27":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ أَنْبَأَنَا مُحَمَّدٌ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ مَنْصُورٍ قَالَ سَمِعْتُ أَبَا وَائِلٍ أَنَّ حُذَيْفَةَ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى سُبَاطَةَ قَوْمٍ فَبَالَ قَائِمًا","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; Telah memberitakan kepada kami [Muhammad bin Ja'far] dia berkata; Telah memberitakan kepada kami [Syu'bah] dari [Manshur] berkata; saya mendengar [Abu Wa'il] bahwasannya [Hudzaifah] telah berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mendatangi tempat pembuangan sampah suatu kaum, lalu ia buang air kecil dengan berdiri.\""},"28":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ عُبَيْدِ اللَّهِ قَالَ أَنْبَأَنَا بَهْزٌ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ سُلَيْمَانَ وَمَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَشَى إِلَى سُبَاطَةِ قَوْمٍ فَبَالَ قَائِمًا قَالَ سُلَيْمَانُ فِي حَدِيثِهِ وَمَسَحَ عَلَى خُفَّيْهِ وَلَمْ يَذْكُرْ مَنْصُورٌ الْمَسْحَ","id":"Telah mengabarkan kepada kami [Sulaiman bin 'Ubaidillah] dia berkata; Telah memberitakan kepada kami [Bahzun] berkata; Telah memberitakan kepada kami [Syu'bah] dari [Sulaiman] dan [Manshur] dari [Abu Wa'il] dari [Hudzaifah] bahwasannya Rasulullah shallallahu 'alaihi wasallam pernah berjalan menuju tempat pembuangan sampah suatu kaum, lalu ia buang air kecil dengan berdiri. Sulaiman berkata dalam hadisnya; \"dan Beliau mengusap kedua khufnya (kedua sepatunya) sedangkan Manshur tidak menyebutkan tentang mengusap khuf sepatu.\""},"29":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا شَرِيكٌ عَنْ الْمِقْدَامِ بْنِ شُرَيْحٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْمَنْ حَدَّثَكُمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَالَ قَائِمًا فَلَا تُصَدِّقُوهُ مَا كَانَ يَبُولُ إِلَّا جَالِسًا","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dia berkata; Telah memberitakan kepada kami [Syarik] dari [Miqdam bin Syuraih] dari [Ayahnya] dari [Aisyah] dia berkata: \"Barangsiapa mengabarkan kepadamu bahwa Rasulullah shallallahu 'alaihi wasallam buang air kecil sambil berdiri, jangan kamu mempercayainya, karena Rasulullah shallallahu 'alaihi wasallam tidak buang air kecil kecuali sambil duduk.\" "},"30":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ عَبْدِ الرَّحْمَنِ ابْنِ حَسَنَةَ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي يَدِهِ كَهَيْئَةِ الدَّرَقَةِ فَوَضَعَهَا ثُمَّ جَلَسَ خَلْفَهَا فَبَالَ إِلَيْهَا فَقَالَ بَعْضُ الْقَوْمِ انْظُرُوا يَبُولُ كَمَا تَبُولُ الْمَرْأَةُ فَسَمِعَهُ فَقَالَ أَوَ مَا عَلِمْتَ مَا أَصَابَ صَاحِبُ بَنِي إِسْرَائِيلَ كَانُوا إِذَا أَصَابَهُمْ شَيْءٌ مِنْ الْبَوْلِ قَرَضُوهُ بِالْمَقَارِيضِ فَنَهَاهُمْ صَاحِبُهُمْ فَعُذِّبَ فِي قَبْرِهِ","id":"Telah mengabarkan kepada kami [Hannad bin As Sariy] dari [Abu Mu'awiyah] dari [Al 'Amasy] dari [Zaid bin Wahab] dari [Abdurrahman bin Hasanah] dia berkata, \" Rasulullah shallallahu 'alaihi wasallam pernah menemui kami, dan di tangan beliau ada sesuatu yang mirip perisai dari kulit. Beliau lalu meletakkannya dan duduk di belakangnya, kemudian buang air kecil ke arah perisai tersebut. Sebagian orang berkomentar, 'Lihatlah, beliau buang air kecil seperti perempuan! ' Ketika Rasulullah shallallahu 'alaihi wasallam mendengar ucapan tersebut, beliau berkata, 'Apakah kalian tidak tahu apa yang menimpa seorang Bani Israil?! Apabila seorang dari mereka terkena air kencing, mereka menggunting kain yang terkena kencing tadi, lalu temannya melarang mereka melakukan demikian, sehingga ia disiksa di kuburnya.\" "},"31":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ وَكِيعٍ عَنْ الْأَعْمَشِ قَالَ سَمِعْتُ مُجَاهِدًا يُحَدِّثُ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى قَبْرَيْنِ فَقَالَ إِنَّهُمَا يُعَذَّبَانِ وَمَا يُعَذَّبَانِ فِي كَبِيرٍ أَمَّا هَذَا فَكَانَ لَا يَسْتَنْزِهُ مِنْ بَوْلِهِ وَأَمَّا هَذَا فَإِنَّهُ كَانَ يَمْشِي بِالنَّمِيمَةِ ثُمَّ دَعَا بِعَسِيبٍ رَطْبٍ فَشَقَّهُ بِاثْنَيْنِ فَغَرَسَ عَلَى هَذَا وَاحِدًا وَعَلَى هَذَا وَاحِدًا ثُمَّ قَالَ لَعَلَّهُ يُخَفَّفُ عَنْهُمَا مَا لَمْ يَيْبَسَاخَالَفَهُ مَنْصُورٌ رَوَاهُ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ وَلَمْ يَذْكُرْ طَاوُسًا","id":"Telah mengabarkan kepada kami [Hannad bin As-Sariy] dari [Waki'] dari [Al A'masy] berkata; \"Saya mendengar [Mujahid] berkata; dari [Thawus] dari [Ibnu Abbas] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah melewati dua kuburan, lalu beliau bersabda: \" Kedua penghuni kubur ini disiksa dan keduanya disiksa bukan karena dosa besar. Yang satu ini, dulu tidak membersihkan air kencingnya, sedangkan yang ini disiksa karena selalu mengadu domba.\" Kemudian beliau meminta sepotong pelepah kurma yang masih basah. Beliau membelahnya menjadi dua dan menancapkannya pada dua kuburan tersebut. Beliau kemudian bersabda: 'Semoga ini bisa meringankan keduanya selagi belum kering. '"},"32":{"ar":"أَخْبَرَنَا أَيَّوبُ بْنُ مُحَمَّدٍ الْوَزَّانُ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَتْنِي حُكَيْمَةُ بِنْتُ أُمَيْمَةَ عَنْ أُمِّهَا أُمَيْمَةَ بِنْتِ رُقَيْقَةَ قَالَتْكَانَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدَحٌ مِنْ عَيْدَانٍ يَبُولُ فِيهِ وَيَضَعُهُ تَحْتَ السَّرِيرِ","id":"Telah mengabarkan kepada kami [Ayyub bin Muhammad Al Wazzan] dia berkata; telah menceritakan kepada kami [Hajjaj] berkata; [Ibnu Juraij] berkata; telah menceritakan kepadaku [Hukaimah binti Umaimah] dari Ibunya [Umaimah binti Ruqaiqah] dia berkata; \" Rasulullah shallallahu 'alaihi wasallam mempunyai bejana dari kayu kurma yang digunakan untuk buang air kecil. Beliau menaruhnya dibawah tempat tidur.\""},"33":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ أَنْبَأَنَا أَزْهَرُ أَنْبَأَنَا ابْنُ عَوْنٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْيَقُولُونَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْصَى إِلَى عَلِيٍّ لَقَدْ دَعَا بِالطَّسْتِ لِيَبُولَ فِيهَا فَانْخَنَثَتْ نَفْسُهُ وَمَا أَشْعُرُ فَإِلَى مَنْ أَوْصَىقَالَ الشَّيْخُ أَزْهَرُ هُوَ ابْنُ سَعْدٍ السَّمَّانُ","id":"Telah mengabarkan kepada kami [Amr bin Ali] dia berkata; telah memberitakan kepada kami [Azhar] telah memberitakan kepada kami [Ibnu 'Aun] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] dia berkata; \" Orang-orang berkata, 'Rasulullah shallallahu 'alaihi wasallam mewasiatkan kepada Ali. Beliau meminta sebuah baskom yang beliau pergunakan untuk buang air kecil, lalu anggota tubuh beliau perlahan-lahan lemah karena mendekati ajal, aku tidak merasakan hal itu, dan kepada siapakah ia berwasiat?\" Amr bin Ali mengatakan; yang dimaksud Syaikh Azhar adalah Ibnu Sa'id bin Saman. "},"34":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ أَنْبَأَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَبُولَنَّ أَحَدُكُمْ فِي جُحْرٍقَالُوا لِقَتَادَةَ وَمَا يُكْرَهُ مِنْ الْبَوْلِ فِي الْجُحْرِ قَالَ يُقَالُ إِنَّهَا مَسَاكِنُ الْجِنِّ","id":"Telah mengabarkan kepada kami ['Ubaidillah bin Sa'id] dia berkata; telah memberitakan kepada kami [Mu'adz bin Hisyam] berkata; [ayahku] telah menceritakan kepadaku dari [Qatadah] dari [Abdullah bin Sarjis] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Jangan sekali-kali salah seorang diantara kalian buang air kecil di lubang.\" Mereka bertanya kepada Qatadah, kenapa dilarang buang air kecil di lubang? dia menjawab; ada berita itu tempat tinggal jin. "},"35":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ الْبَوْلِ فِي الْمَاءِ الرَّاكِدِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al-Laits] dari [Abu Zubair] dari [Jabir] dari Rasulullah shallallahu 'alaihi wasallam, beliau melarang buang air kecil didalam air yang tergenang (tidak mengalir).\""},"36":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا ابْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ الْأَشْعَثِ بْنِ عَبْدِ الْمَلِكِ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَبُولَنَّ أَحَدُكُمْ فِي مُسْتَحَمِّهِ فَإِنَّ عَامَّةَ الْوَسْوَاسِ مِنْهُ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dia berkata; telah memberitakan kepada kami [Ibnu Al Mubarak] dari [Ma'mar] dari [Al Asy'ats bin Abdul Malik] dari [Al Hasan] dari [Abdullah bin Mughaffal] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \" Jangan kalian buang air kecil di tempat pemandian, karena kebanyakan rasa was-was itu berasal darinya.\""},"37":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ وَقَبِيصَةُ قَالَا أَنْبَأَنَا سُفْيَانُ عَنْ الضَّحَّاكِ بْنِ عُثْمَانَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَمَرَّ رَجُلٌ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَبُولُ فَسَلَّمَ عَلَيْهِ فَلَمْ يَرُدَّ عَلَيْهِ السَّلَامَ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Zaid bin Al Hubbab] dan [Qubaishah] keduanya berkata; telah memberitakan kepada kami [Sufyan] dari [Dlahak bin Utsman] dari [Nafi'] dari [Ibnu Umar] dia berkata; \" Seorang laki-laki melewati Rasulullah shallallahu 'alaihi wasallam, dan beliau sedang buang air kecil. Orang itu lalu mengucapkan salam kepada beliau, namun beliau tidak menjawabnya.\" "},"38":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ قَالَ أَنْبَأَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ حُضَيْنٍ أَبِي سَاسَانَ عَنْ الْمُهَاجِرِ بْنِ قُنْفُذٍأَنَّهُ سَلَّمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَبُولُ فَلَمْ يَرُدَّ عَلَيْهِ حَتَّى تَوَضَّأَ فَلَمَّا تَوَضَّأَ رَدَّ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; telah menceritakan kepada kami [Mu'adz bin Mu'adz] berkata; telah memberitakan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Hudlain Abu Saasan] dari [Al Muhajir bin Qunfudz] \" Ia pernah memberi salam kepada Rasulullah shallallahu 'alaihi wasallam ketika ia sedang buang air kecil, dan Rasulullah shallallahu 'alaihi wasallam tidak membalas salamnya. Setelah berwudlu beliau membalas salamnya.\""},"39":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي عُثْمَانَ بْنِ سَنَّةَ الْخُزَاعِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يَسْتَطِيبَ أَحَدُكُمْ بِعَظْمٍ أَوْ رَوْثٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Amr bin As Sarh] dia berkata; telah memberitakan kepada kami [Ibnu Wahab] berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Abu Utsman bin Sanah Al Khuzaa'i] dari [Abdullah bin Mas'ud] bahwa Rasulullah shallallahu 'alaihi wasallam melarang bersuci dengan tulang atau kotoran hewan.\""},"40":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى يَعْنِى ابْنَ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ قَالَ أَخْبَرَنِي الْقَعْقَاعُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا أَنَا لَكُمْ مِثْلُ الْوَالِدِ أُعَلِّمُكُمْ إِذَا ذَهَبَ أَحَدُكُمْ إِلَى الْخَلَاءِ فَلَا يَسْتَقْبِلْ الْقِبْلَةَ وَلَا يَسْتَدْبِرْهَا وَلَا يَسْتَنْجِ بِيَمِينِهِ وَكَانَ يَأْمُرُ بِثَلَاثَةِ أَحْجَارٍ وَنَهَى عَنْ الرَّوْثِ وَالرِّمَّةِ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Yahya yaitu Ibnu Sa'id] dari [Muhammad bin Ajlan] berkata; telah mengabarkan kepadaku [Al Qa'qa'] dari [Abu Shalih] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Aku bagi kalian seperti seorang ayah. Aku mengajari kalian apabila kalian hendak pergi ke WC janganlah menghadap kiblat dan jangan membelakanginya, serta jangan bersuci dengan tangan kanan.\" Beliau juga memerintahkan untuk bersuci dengan tiga batu. Beliau melarang bersuci dengan kotoran hewan dan tulang.\" "},"41":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ سَلْمَانَ قَالَقَالَ لَهُ رَجُلٌ إِنَّ صَاحِبَكُمْ لَيُعَلِّمُكُمْ حَتَّى الْخِرَاءَةَ قَالَ أَجَلْ نَهَانَا أَنْ نَسْتَقْبِلَ الْقِبْلَةَ بِغَائِطٍ أَوْ بَوْلٍ أَوْ نَسْتَنْجِيَ بِأَيْمَانِنَا أَوْ نَكْتَفِيَ بِأَقَلَّ مِنْ ثَلَاثَةِ أَحْجَارٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Abu Mu'awiyah] berkata; telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari [Abdurrahman bin Yazid] dari [Salman] dia berkata, \"Seseorang bertanya kepadaku, 'Apakah temanmu (Rasulullah shallallahu 'alaihi wasallam mengajarimu sampai masalah buang hajat? 'Aku menjawab, 'Ya, beliau shallallahu 'alaihi wasallam melarang kami menghadap kiblat sewaktu buang air besar atau buang air kecil, atau bersuci dengan tangan kanan atau hanya mencukupkan (bersuci) dengan batu kurang dari tiga.\" "},"42":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ عَنْ زُهَيْرٍ عَنْ أَبِي إِسْحَقَ قَالَ لَيْسَ أَبُو عُبَيْدَةَ ذَكَرَهُ وَلَكِنْ عَبْدُ الرَّحْمَنِ بْنُ الْأَسْوَدِ عَنْ أَبِيهِ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ يَقُولُأَتَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْغَائِطَ وَأَمَرَنِي أَنْ آتِيَهُ بِثَلَاثَةِ أَحْجَارٍ فَوَجَدْتُ حَجَرَيْنِ وَالْتَمَسْتُ الثَّالِثَ فَلَمْ أَجِدْهُ فَأَخَذْتُ رَوْثَةً فَأَتَيْتُ بِهِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَ الْحَجَرَيْنِ وَأَلْقَى الرَّوْثَةَ وَقَالَ هَذِهِ رِكْسٌقَالَ أَبُو عَبْد الرَّحْمَنِ الرِّكْسُ طَعَامُ الْجِنِّ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah memberitakan kepada kami [Abu Nu'aim] dari [Zuhair] dari [Abu Ishaq] dia berkata; bukan Abu Ubaidah yang disebutkan tapi [Abdurrahman bin Al Aswad] dari [Ayahnya] bahwasannya dia mendengar [Abdullah] berkata, \" Rasulullah shallallahu 'alaihi wasallam pergi untuk buang air besar, lalu beliau menyuruhku membawa tiga batu. Tetapi aku hanya mendapatkan dua batu, dan aku berusaha mencari yang ketiga, namun aku tidak mendapatkannya. Lalu aku mengambil kotoran hewan yang kering dan aku bawa ke Rasulullah shallallahu 'alaihi wasallam Beliau hanya mengambil dua batu dan membuang kotoran, lalu bersabda, 'Ini adalah riks (najis).\" Abu Abdurrahman berkata; \"Ar riks adalah makanan jin\""},"43":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ سَلَمَةَ بْنِ قَيْسٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا اسْتَجْمَرْتَ فَأَوْتِرْ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Jarir] dari [Manshur] dari [Hilal bin Yasaf] dari [Salamah bin Qais] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda; \" Bila kamu bersuci dengan batu, maka gunakan dengan (jumlah batu) yang ganjil.\" "},"44":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ مُسْلِمِ بْنِ قُرْطٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا ذَهَبَ أَحَدُكُمْ إِلَى الْغَائِطِ فَلْيَذْهَبْ مَعَهُ بِثَلَاثَةِ أَحْجَارٍ فَلْيَسْتَطِبْ بِهَا فَإِنَّهَا تَجْزِي عَنْهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Ayahnya] dari [Muslim bin Qurath] dari [Urwah] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda, \" Bila salah seorang dari kalian pergi ke WC, maka bawalah tiga buah batu dan bersucilah dengannya. Itu telah mencukupi.\""},"45":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا النَّضْرُ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ عَطَاءِ بْنِ أَبِي مَيْمُونَةَ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ الْخَلَاءَ أَحْمِلُ أَنَا وَغُلَامٌ مَعِي نَحْوِي إِدَاوَةً مِنْ مَاءٍ فَيَسْتَنْجِي بِالْمَاءِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [An-Nadlar] berkata; telah memberitakan kepada kami [Syu'bah] dari [Atha' bin Abu Maimunah] dia berkata; \"Saya mendengar dari [Anas bin Malik] dia berkata; \" Bila Rasulullah shallallahu 'alaihi wasallam masuk WC, maka aku dan seorang anak sebayaku membawakan seember air dan beliau beristinja dengan air.\""},"46":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ مُعَاذَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْمُرْنَ أَزْوَاجَكُنَّ أَنْ يَسْتَطِيبُوا بِالْمَاءِ فَإِنِّي أَسْتَحْيِيهِمْ مِنْهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَفْعَلُهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Mu'adzah] dari [Aisyah], dia berkata: \" Perintahkan suami-suami kalian bersuci dengan air, karena aku malu untuk mengatakan kepada mereka bahwa Rasulullah shallallahu 'alaihi wasallam melakukan hal tersebut.\""},"47":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ أَنْبَأَنَا هِشَامٌ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِي قَتَادَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا شَرِبَ أَحَدُكُمْ فَلَا يَتَنَفَّسْ فِي إِنَائِهِ وَإِذَا أَتَى الْخَلَاءَ فَلَا يَمَسَّ ذَكَرَهُ بِيَمِينِهِ وَلَا يَتَمَسَّحْ بِيَمِينِهِ","id":"Telah mengabarkan kepada kami [Ismail bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] berkata; telah memberitakan kepada kami [Hisyam] dari [Yahya] dari [Abdullah bin Abu Qatadah] dari [Abu Qotadah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda, \" Apabila salah seorang dari kalian minum, maka jangan bernafas di dalam tempat air tersebut. Bila kalian pergi ke WC, maka jangan menyentuh kemaluan dengan tangan kanan, serta jangan mengusap dengan tangan kanan.\""},"48":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ عَنْ أَيُّوبَ عَنْ يِحْيَى بْنِ أَبِى كَثِيرٍ عَنْ ابْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يَتَنَفَّسَ فِي الْإِنَاءِ وَأَنْ يَمَسَّ ذَكَرَهُ بِيَمِينِهِ وَأَنْ يَسْتَطِيبَ بِيَمِينِهِ","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin Abdurrahman] dia berkata; telah menceritakan kepada kami [Abdul Wahab] dari [Ayyub] dari [Yahya bin Abu Katsir] dari [Ibnu Abu Qatadah] dari [Ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam melarang (seseorang) bernafas ditempat air minum, menyentuh kemaluan dengan tangan kanannya, dan bersuci dengan tangan kanannya. "},"49":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَشُعَيْبُ بْنُ يُوسُفَ وَاللَّفْظُ لَهُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَهْدِيٍّ عَنْ سُفَيَانَ عَنْ مَنْصُورٍ وَالْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ سَلْمَانَ قَالَقَالَ الْمُشْرِكُونَ إِنَّا لَنَرَى صَاحِبَكُمْ يُعَلِّمُكُمْ الْخِرَاءَةَ قَالَ أَجَلْ نَهَانَا أَنْ يَسْتَنْجِيَ أَحَدُنَا بِيَمِينِهِ وَيَسْتَقْبِلَ الْقِبْلَةَ وَقَالَ لَا يَسْتَنْجِي أَحَدُكُمْ بِدُونِ ثَلَاثَةِ أَحْجَارٍ","id":"Telah mengabarkan kepada kami [Amr bin 'Ali] dan [Syu'aib bin Yusuf] dari [Abdurrahman bin Mahdi] dari [Sufyan] dari [Manshur] dan [Al A'masy] dari [Ibrahim] dari [Abdurrahman bin Yazid] dari [Salman] dia berkata; \"Orang-orang musyrik berkata; \"Kami tahu bahwa temanmu (Rasulullah shallallahu 'alaihi wasallam) mengajarimu cara buang hajat! 'Aku menjawab, Ya, beliau melarang kami bersuci dengan tangan kanan dan menghadap kiblat. Dan Beliau pernah bersabda, \"Jangan kamu bersuci dengan batu kurang dari tiga buah.\""},"50":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ الْمُخَرِّمِيُّ قَالَ حَدَّثَنَا وَكِيعٌ عَنْ شَرِيكٍ عَنْ إِبْرَاهِيمَ بْنِ جَرِيرٍ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَلَمَّا اسْتَنْجَى دَلَكَ يَدَهُ بِالْأَرْضِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Al Mubarak Al Mukharrimi] dia berkata; telah menceritakan kepada kami [Waki'] dari [Syarik] dari [Ibrahim bin Jarir] dari [Abu Zur'ah] dari [Abu Hurairah], dia berkata: \"Rasulullah shallallahu 'alaihi wasallam pernah berwudlu, setelah bersuci dari buang air beliau menggosok tangannya dengan tanah.\" "},"51":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ الصَّبَّاحِ قَالَ حَدَّثَنَا شُعَيْبٌ يَعْنِي ابْنَ حَرْبٍ قَالَ حَدَّثَنَا أَبَانُ بْنُ عَبْدِ اللَّهِ الْبَجَلِيُّ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ جَرِيرٍ عَنْ أَبِيهِ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَى الْخَلَاءَ فَقَضَى الْحَاجَةَ ثُمَّ قَالَ يَا جَرِيرُ هَاتِ طَهُورًا فَأَتَيْتُهُ بِالْمَاءِ فَاسْتَنْجَى بِالْمَاءِ وَقَالَ بِيَدِهِ فَدَلَكَ بِهَا الْأَرْضَقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا أَشْبَهُ بِالصَّوَابِ مِنْ حَدِيثِ شَرِيكٍ وَاللَّهُ سُبْحَانَهُ وَتَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Ahmad bin As-Shabah] dia berkata; telah menceritakan kepada kami [Syu'aib yaitu Ibnu Harb] berkata; telah menceritakan kepada kami [Abban bin Abdullah Al Bajali] berkata; telah menceritakan kepada kami [Ibrahim bin Jarir] dari [Ayahnya] dia berkata; \"Aku pernah bersama Rasulullah shallallahu 'alaihi wasallam, lalu beliau pergi ke WC untuk buang air besar, kemudian beliau memanggilku, 'Wahai Jarir, bawa kemari sesuatu yang bisa dipakai bersuci'. Aku segera membawakan air dan beliau bersuci dengan air tersebut. Setelah itu beliau menggosok tangannya dengan tanah.\" Abu Abdurrahman berkata; \" Kebenaran hadits ini mirip dengan hadits Syarik Wallahu Subhanahu wa Ta'ala A'lam.\" "},"52":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ وَالْحُسَيْنُ بْنُ حُرَيْثٍ عَنْ أَبِي أُسَامَةَ عَنْ الْوَلِيدِ بْنِ كَثِيرٍ عَنْ مُحَمَّدِ بْنِ جَعْفَرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمَاءِ وَمَا يَنُوبُهُ مِنْ الدَّوَابِّ وَالسِّبَاعِ فَقَالَ إِذَا كَانَ الْمَاءُ قُلَّتَيْنِ لَمْ يَحْمِلْ الْخَبَثَ","id":"Telah mengabarkan kepada kami [Hannad bin As-Sariy] dan [Husain bin Huraits] dari [Abu Usamah] dari [Al Walid bin Katsir] dari [Muhammad bin Ja'far] dari [Abdullah bin Abdullah bin Umar] dari [Ayahnya] berkata; Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang air dan (air) yang diminum oleh hewan ternak dan binatang buas berulang kali? Beliau shallallahu 'alaihi wasallam lalu menjawab, \" Bila air itu lebih dari dua qulah maka tidak mengandung najis.\" "},"53":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ أَعْرَابِيًّا بَالَ فِي الْمَسْجِدِ فَقَامَ عَلَيْهِ بَعْضُ الْقَوْمِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعُوهُ لَا تُزْرِمُوهُ فَلَمَّا فَرَغَ دَعَا بِدَلْوٍ فَصَبَّهُ عَلَيْهِقَالَ أَبُو عَبْد الرَّحْمَنِ يَعْنِي لَا تَقْطَعُوا عَلَيْهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Anas bin Malik], ada seorang Badui buang air kecil di masjid. Sebagian orang bangkit untuk menghentikannya. Rasulullah shallallahu 'alaihi wasallam segera mencegahnya dan berkata, \" Biarkan dia, jangan kamu putus hajatnya.\" Setelah dia selesai buang hajatnya, Rasulullah shallallahu 'alaihi wasallam meminta seember air lalu menyiramkannya.\" Abu Abdurrahman berkata; \" Maksudnya jangan kalian cegah dia.\""},"54":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبِيدَةُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَنَسٍ قَالَبَالَ أَعْرَابِيُّ فِي الْمَسْجِدِ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِدَلْوٍ مِنْ مَاءٍ فَصُبَّ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Ubaidah] dari [Yahya bin Sa'id] dari [Anas bin Malik] dia berkata; \"Seorang Badui buang air kecil di masjid, lalu Rasulullah shallallahu 'alaihi wasallam menyuruh untuk mengambil seember air dan disiramkannya.\""},"55":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ يَحْيَى بْنِ سَعِيدٍ قَالَ سَمِعْتُ أَنَسًا يَقُولُجَاءَ أَعْرَابِيٌّ إِلَى الْمَسْجِدِ فَبَالَ فَصَاحَ بِهِ النَّاسُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتْرُكُوهُ فَتَرَكُوهُ حَتَّى بَالَ ثُمَّ أَمَرَ بِدَلْوٍ فَصُبَّ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami [Abdullah] dari [Yahya bin Sa'id] dia berkata; saya mendengar [Anas] berkata; \"Seorang Badui datang ke masjid lalu buang air kecil, maka orang-orang berteriak. Hanya Rasulullah shallallahu 'alaihi wasallam bersabda ' Biarkanlah'. Dia pun dibiarkan hingga selesai hajatnya. Lalu Rasulullah shallallahu 'alaihi wasallam menyuruh untuk dibawakan seember air yang selanjutnya disiramkannya.\""},"56":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ عَنْ عُمَرَ بْنِ عَبْدِ الْوَاحِدِ عَنْ الْأَوْزَاعِيِّ عَنْ مُحَمَّدِ بْنِ الْوَلِيدِ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَامَ أَعْرَابِيٌّ فَبَالَ فِي الْمَسْجِدِ فَتَنَاوَلَهُ النَّاسُ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعُوهُ وَأَهْرِيقُوا عَلَى بَوْلِهِ دَلْوًا مِنْ مَاءٍ فَإِنَّمَا بُعِثْتُمْ مُيَسِّرِينَ وَلَمْ تُبْعَثُوا مُعَسِّرِينَ","id":"Telah mengabarkan kepada kami [Abdurrahman bin Ibrahim] dari [Umar bin Abdul Wahid] dari [Al Auza'i] dari [Muhammad bin Al Walid] dari [Az-Zuhri] dari [Ubaidillah bin Abdullah] dari [Abu Hurairah], dia berkata; \"Seorang Badui datang dan buang air kecil di masjid sehingga orang-orang menghardiknya. Rasulullah shallallahu 'alaihi wasallam lalu bersabda kepada mereka: \" Biarkan. Siramkan seember air pada air kencingnya. Kalian diutus untuk memudahkan, bukan untuk menyulitkan.\""},"57":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عِيسَى بْنُ يُونُسَ قَالَ حَدَّثَنَا عَوْفٌ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَبُولَنَّ أَحَدُكُمْ فِي الْمَاءِ الدَّائِمِ ثُمَّ يَتَوَضَّأُ مِنْهُقَالَ عَوْفٌ وَقَالَ خِلَاسٌ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Isa bin Yunus] berkata; telah menceritakan kepada kami ['Auf] dari [Muhammad] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda; \" Janganlah sekali-kali kalian buang air kecil pada air yang tergenang, lalu berwudlu dari air itu.\" 'Auf dan [Khilas] berkata; dari Abu Hurairah dari Rasulullah shallallahu 'alaihi wasallam sebagaimana hadits tadi. "},"58":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ يَحْيَى بْنِ عَتِيقٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَبُولَنَّ أَحَدُكُمْ فِي الْمَاءِ الدَّائِمِ ثُمَّ يَغْتَسِلُ مِنْهُقَالَ أَبُو عَبْد الرَّحْمَنِ كَانَ يَعْقُوبُ لَا يُحَدِّثُ بِهَذَا الْحَدِيثِ إِلَّا بِدِينَارٍ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Ismail] berkata; dari [Yahya bin 'Atiq] dari [Muhammad bin Sirin] dari [Abu Hurairah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda, ' Jangan kalian buang air kecil pada air yang tergenang, lalu mandi dari air itu.\" Abu Abdurrahman berkata; \"Ya'qub tidak menyampaikan hadits ini kecuali dengan uang satu dinar.\""},"59":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ سَعِيدِ بْنِ سَلَمَةَ أَنَّ الْمُغِيرَةَ بْنَ أَبِي بُرْدَةَ مِنْ بَنِي عَبْدِ الدَّارِ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُسَأَلَ رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّا نَرْكَبُ الْبَحْرَ وَنَحْمِلُ مَعَنَا الْقَلِيلَ مِنْ الْمَاءِ فَإِنْ تَوَضَّأْنَا بِهِ عَطِشْنَا أَفَنَتَوَضَّأُ مِنْ مَاءِ الْبَحْرِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ الطَّهُورُ مَاؤُهُ الْحِلُّ مَيْتَتُهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Shafwan bin Sulaim] dari [Sa'id bin Salamah] bahwa [Al Mughirah bin Abu Burdah] dari Bani Abu Dar telah mengabarkan kepadanya bahwasanya dia telah mendengar [Abu Hurairah] berkata; \"Seseorang bertanya Rasulullah shallallahu 'alaihi wasallam, 'Wahai Rasulullah shallallahu 'alaihi wasallam, kami mengarungi lautan dengan kapal dan kami hanya membawa air (tawar) sedikit. Bila kami berwudlu dengan air tersebut, kami kehausan, apakah kami boleh berwudlu dengan air laut? Rasulullah shallallahu 'alaihi wasallam berkata, ' Laut itu suci airnya, halal bangkainya.\" "},"60":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَفْتَحَ الصَّلَاةَ سَكَتَ هُنَيْهَةً فَقُلْتُ بِأَبِي أَنْتَ وَأُمِّي يَا رَسُولَ اللَّهِ مَا تَقُولُ فِي سُكُوتِكَ بَيْنَ التَّكْبِيرِ وَالْقِرَاءَةِ قَالَ أَقُولُ اللَّهُمَّ بَاعِدْ بَيْنِي وَبَيْنَ خَطَايَايَ كَمَا بَاعَدْتَ بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ اللَّهُمَّ نَقِّنِي مِنْ خَطَايَايَ كَمَا يُنَقَّى الثَّوْبُ الْأَبْيَضُ مِنْ الدَّنَسِ اللَّهُمَّ اغْسِلْنِي مِنْ خَطَايَايَ بِالثَّلْجِ وَالْمَاءِ وَالْبَرَدِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Jarir] dari [Umarah bin Al Qa'qa] dari [Abu Zur'ah bin Amr bin Jarir] dari [Abu Hurairah] dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam memulai shalat, beliau diam beberapa saat. Aku lalu bertanya kepadanya, 'Ayah dan Ibuku sebagai jaminan wahai Rasulullah shallallahu 'alaihi wasallam, apa yang kamu ucapkan tatkala berdiam antara takbir dan bacaan (Al-Fatihah)? 'Beliau shallallahu 'alaihi wasallam menjawab, 'Aku membaca, \" Ya Allah, jauhkan antara aku dan kesalahanku sebagaimana Engkau jauhkan antara timur dan barat. Ya Allah bersihkan (sucikan) dariku kesalahanku sebagaimana Engkau bersihkan (sucikan) baju yang putih dari kotoran. Ya Allah cucilah (bersihkanlah) aku dari kesalahan-kesalahanku dengan salju, air, dan embun.\" "},"61":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ اغْسِلْ خَطَايَايَ بِمَاءِ الثَّلْجِ وَالْبَرَدِ وَنَقِّ قَلْبِي مِنْ الْخَطَايَا كَمَا نَقَّيْتَ الثَّوْبَ الْأَبْيَضَ مِنْ الدَّنَسِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Jarir] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari [Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \" Ya Allah, bersihkanlah kesalahanku dengan air salju (es) dan air embun, dan sucikan (bersihkan) hatiku dari kesalahanku sebagaimana engkau mensucikan (membersihkan) pakaian putih dari kotoran.\""},"62":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ حَبِيبِ بْنِ عُبَيْدٍ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ قَالَ شَهِدْتُ عَوْفَ بْنَ مَالِكٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى مَيِّتٍ فَسَمِعْتُ مِنْ دُعَائِهِ وَهُوَ يَقُولُ اللَّهُمَّ اغْفِرْ لَهُ وَارْحَمْهُ وَعَافِهِ وَاعْفُ عَنْهُ وَأَكْرِمْ نُزُلَهُ وَأَوْسِعْ مُدْخَلَهُ وَاغْسِلْهُ بِالْمَاءِ وَالثَّلْجِ وَالْبَرَدِ وَنَقِّهِ مِنْ الْخَطَايَا كَمَا يُنَقَّى الثَّوْبُ الْأَبْيَضُ مِنْ الدَّنَسِ","id":"Telah mengabarkan kepada kami [Harun bin Abdullah] dia berkata; telah menceritakan kepada kami [Ma'an] berkata; telah menceritakan kepada kami Mu'awiyah bin Shalih dari [Habib bin 'Ubaid] dari [Jubair bin Nufair] berkata; saya mendengar [Auf bin Malik] berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam menshalati jenazah, dan aku mendengar doa beliau, sambil mengucapkan, ' Ya Allah, ampuni dia dan kasih sayangilah dia. Berilah keselamatan, Maafkan dan muliakan tempatnya. Lapangkanlah keadaannya. Basuhlah dengan air, salju, dan air embun. Bersihkanlah dari kesalahannya sebagaimana kain putih yang dibersihkan dari kotoran.\""},"63":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا شَرِبَ الْكَلْبُ فِي إِنَاءِ أَحَدِكُمْ فَلْيَغْسِلْهُ سَبْعَ مَرَّاتٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda; \" Apabila ada anjing yang minum dari bejana salah seorang dari kalian, hendaknya ia mencucinya tujuh kali.\" "},"64":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي زِيَادُ بْنُ سَعْدٍ أَنَّ ثَابِتًا مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ زَيْدٍ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وَلَغَ الْكَلْبُ فِي إِنَاءِ أَحَدِكُمْ فَلْيَغْسِلْهُ سَبْعَ مَرَّاتٍأَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي زِيَادُ بْنُ سَعْدٍ أَنَّهُ أَخْبَرَهُ هِلَالُ بْنُ أَسَامَةَ أَنَّهُ سَمِعَ أَبَا سَلَمَةَ يُخْبِرُ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Hasan] dia berkata; telah menceritakan kepada kami [Hajaj] dia berkata; [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Ziyad bin Sa'ad] dia berkata; [Tsabit] budak Abdurrahman bin Zaid telah mengabarkan kepadanya bahwa dia telah mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Apabila ada seekor anjing yang menjilati bejana salah seorang dari kalian, hendaknya ia mencucinya tujuh kali.\" Telah mengabarkan kepadaku [Ibrahim bin Hasan] dia berkata; telah menceritakan kepada kami [Hajjaj] berkata; [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Ziyad bin Sa'ad] bahwa telah mengabarkan kepadanya [Hilal bin Usamah] bahwa dia mendengar [Abu Salamah] telah mengabarkan dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam mengenai hadits tadi. "},"65":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْأَعْمَشِ عَنْ أَبِي رَزِينٍ وَأَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وَلَغَ الْكَلْبُ فِي إِنَاءِ أَحَدِكُمْ فَلْيُرِقْهُ ثُمَّ لِيَغْسِلْهُ سَبْعَ مَرَّاتٍقَالَ أَبُو عَبْد الرَّحْمَنِ لَا أَعْلَمُ أَحَدًا تَابَعَ عَلِيَّ بْنَ مُسْهِرٍ عَلَى قَوْلِهِ فَلْيُرِقْهُ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dia berkata; Telah memberitakan kepada kami [Ali bin Mushir] dari [Al A'masy] dari [Abu Razin] dan [Abu Shalih] dari [Abu Hurairah] dia berkata, \" Rasulullah shallallahu 'alaihi wasallam bersabda, \" Apabila ada seekor anjing menjilati bejana milik salah seorang dari kalian, hendaknya ia menumpahkan -isinya- kemudian mencucinya tujuh kali.\" Abu Abdurrahman berkata; \"Aku tidak mengetahui seorangpun yang mengikuti Ali bin Mushir dalam ucapannya ' hendaklah ia menumpahkan -isinya-. '"},"66":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ قَالَ حَدَّثَنَا خَالِدٌ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي التَّيَّاحِ قَالَ سَمِعْتُ مُطَرِّفًا عَنْ عَبْدِ اللَّهِ بْنِ الْمُغَفَّلِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِقَتْلِ الْكِلَابِ وَرَخَّصَ فِي كَلْبِ الصَّيْدِ وَالْغَنَمِ وَقَالَ إِذَا وَلَغَ الْكَلْبُ فِي الْإِنَاءِ فَاغْسِلُوهُ سَبْعَ مَرَّاتٍ وَعَفِّرُوهُ الثَّامِنَةَ بِالتُّرَابِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la As-Shan'ani] dia berkata; telah menceritakan kepada kami [Khalid] telah menceritakan kepada kami [Syu'bah] dari [Abu Tayyah] dia berkata; \"Saya mendengar [Mutharrif] dari [Abdullah bin Mughaffal], bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk membunuh anjing dan memberi rukhsah (keringanan) pada anjing yang dipakai untuk berburu serta menjaga kambing. Beliau kemudian bersabda, \"Apabila ada anjing yang menjilat bejana kalian, basuhlah tujuh kali dan kedelapan kalinya dilumuri dengan tanah.\""},"67":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ حُمَيْدَةَ بِنْتِ عُبَيْدِ بْنِ رِفَاعَةَ عَنْ كَبْشَةَ بِنْتِ كَعْبِ بْنِ مَالِكٍ أَنَّ أَبَا قَتَادَةَدَخَلَ عَلَيْهَا ثُمَّ ذَكَرَتْ كَلِمَةً مَعْنَاهَا فَسَكَبْتُ لَهُ وَضُوءًا فَجَاءَتْ هِرَّةٌ فَشَرِبَتْ مِنْهُ فَأَصْغَى لَهَا الْإِنَاءَ حَتَّى شَرِبَتْ قَالَتْ كَبْشَةُ فَرَآنِي أَنْظُرُ إِلَيْهِ فَقَالَ أَتَعْجَبِينَ يَا ابْنَةَ أَخِي فَقُلْتُ نَعَمْ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّهَا لَيْسَتْ بِنَجَسٍ إِنَّمَا هِيَ مِنْ الطَّوَّافِينَ عَلَيْكُمْ وَالطَّوَّافَاتِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Humaidah binti Ubaid bin Rifa'ah] dari [Kabsyah binti Ka'ab bin Malik] bahwa [Abu Qatadah] masuk ke dalam-menemuinya -kemudian menyebutkan suatu kalimat -yang maknanya- aku menuangkan air wudlu kepada beliau, lalu datang seekor kucing yang meminum air wudlu tersebut. Beliau lalu menyodorkan bejana tadi kepada kucing tersebut hingga kucing tersebut meminumnya. Kabsyah berkata, \"Dia melihatku sedang memperhatikannya, maka dia berkata, 'Apakah kamu merasa heran wahai anak perempuan saudaraku? ' Aku berkata, 'Ya'. Dia berkata, 'Rasulullah shallallahu 'alaihi wasallam bersabda, \" Kucing itu tidak najis. Kucing itu termasuk hewan yang ada di sekeliling kalian.\""},"68":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أَنَسٍ قَالَأَتَانَا مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ اللَّهَ وَرَسُولَهُ يَنْهَاكُمْ عَنْ لُحُومِ الْحُمُرِ فَإِنَّهَا رِجْسٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazid] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Ayyub] dari [Muhammad] dari [Anas] dia berkata, \"Salah seorang penyeru Rasulullah shallallahu 'alaihi wasallam datang kepada kami dan memberitahukan (berkata): \" Allah dan Rasul-Nya melarang kalian -memakan- daging keledai, karena ia najis.\""},"69":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ الْمِقْدَامِ بْنِ شُرَيْحٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكُنْتُ أَتَعَرَّقُ الْعَرْقَ فَيَضَعُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاهُ حَيْثُ وَضَعْتُ وَأَنَا حَائِضٌ وَكُنْتُ أَشْرَبُ مِنْ الْإِنَاءِ فَيَضَعُ فَاهُ حَيْثُ وَضَعْتُ وَأَنَا حَائِضٌ","id":"Telah mengabarkan kepada kami [Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Miqdam bin Syuraih] dari [Bapaknya] dari [Aisyah] Radliyallahu'anha, dia berkata; \" Aku pernah menggigit sepotong daging yang bertulang, lalu Rasulullah shallallahu 'alaihi wasallam meletakkan mulutnya ditempat bekas mulutku, padahal aku sedang haid. Aku juga pernah minum dari suatu wadah, kemudian Rasulullah shallallahu 'alaihi wasallam meletakkan mulutnya di tempat bekas mulutku.\" "},"70":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا مَالِكٌ ح وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ الرِّجَالُ وَالنِّسَاءُ يَتَوَضَّئُونَ فِي زَمَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمِيعًا","id":"Telah mengabarkan kepada kami [Harun bin Abdullah] dia berkata; telah menceritakan kepada kami [Ma'an] dia berkata; telah menceritakan kepada kami [Malik] dan [Al Harits bin Miskin] telah dibacakan kepadanya dan saya mendengarnya dari [Ibnu Al Qasim] dia berkata; telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Ibnu Umar], dia berkata, \" Pada zaman Rasulullah shallallahu 'alaihi wasallam laki-laki dan perempuan wudlu bersama-sama.\""},"71":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّهَا أَخْبَرَتْهُأَنَّهَا كَانَتْ تَغْتَسِلُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْإِنَاءِ الْوَاحِدِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Al-Laits] dari [Ibnu Syihab] dari [Urwah] dari [Aisyah], dia memberitahukan bahwa dirinya pernah mandi bersama Rasulullah shallallahu 'alaihi wasallam dalam satu bejana. "},"72":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ جَبْرٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ بِمَكُّوكٍ وَيَغْتَسِلُ بِخَمْسِ مَكَاكِيَّ","id":"Telah mengabarkan kepada kami [Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; telah menceritakan kepadaku [Abdullah bin Abdullah bin Jabr] dia berkata; saya mendengar [Anas bin Malik] berkata; \"Rasulullah shallallahu 'alaihi wasallam berwudlu dengan menggunakan satu makkuk, dan bila mandi maka beliau menggunakan lima makkuk.\" "},"73":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدُ ثُمَّ ذَكَرَ كَلِمَةً مَعْنَاهَا حَدَّثَنَا شُعْبَةُ عَنْ حَبِيبٍ قَالَ سَمِعْتُ عَبَّادَ بْنَ تَمِيمٍ يُحَدِّثُ عَنْ جَدَّتِي وَهِيَ أُمُّ عُمَارَةَ بِنْتُ كَعْبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَأُتِيَ بِمَاءٍ فِي إِنَاءٍ قَدْرَ ثُلُثَيْ الْمُدِّ قَالَ شُعْبَةُ فَأَحْفَظُ أَنَّهُ غَسَلَ ذِرَاعَيْهِ وَجَعَلَ يَدْلُكُهُمَا وَيَمْسَحُ أُذُنَيْهِ بَاطِنَهُمَا وَلَا أَحْفَظُ أَنَّهُ مَسَحَ ظَاهِرَهُمَا","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; telah menceritakan kepada kami [Muhammad] kemudian dia menyebutkan satu kalimat yang maksudnya, telah menceritakan kepada kami [Syu'bah] dari [Habib] dia berkata; saya mendengar ['Abbad bin Tamim] bercerita Nenekku yaitu [Ummu Umarah binti Ka'ab], bahwa Rasulullah shallallahu 'alaihi wasallam hendak berwudlu maka dibawakan air di dalam bejana sekitar dua pertiga mud. Syu'bah berkata; \" Yang aku ingat beliau membasuh kedua lengannya dan menggosok-gosok keduanya, lalu membasuh bagian dalam kedua telinganya dan aku tidak ingat bahwa beliau membasuh bagian luar kedua telinganya. "},"74":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ عَنْ حَمَّادٍ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ حَدَّثَنِي مَالِكٌ ح و أَخْبَرَنَا سُلَيْمَانُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ وَاللَّفْظُ لَهُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ بْنِ وَقَّاصٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الْأَعْمَالُ بِالنِّيَّةِ وَإِنَّمَا لِامْرِئٍ مَا نَوَى فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى اللَّهِ وَإِلَى رَسُولِهِ فَهِجْرَتُهُ إِلَى اللَّهِ وَإِلَى رَسُولِهِ وَمَنْ كَانَتْ هِجْرَتُهُ إِلَى دُنْيَا يُصِيبُهَا أَوْ امْرَأَةٍ يَنْكِحُهَا فَهِجْرَتُهُ إِلَى مَا هَاجَرَ إِلَيْهِ","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin 'Arabi] dari [Hammad] dan [Al Harits bin Miskin] telah dibacakan kepadanya dan saya mendengarnya dari [Ibnu Qasim] telah menceritakan kepadaku [Malik] telah menceritakan kepada kami [Sulaiman bin Manshur] dia berkata; Telah memberitakan kepada kami [Abdullah bin Mubarak] dan lafazhnya dari dia, dari [Yahya bin Sa'id] dari [Muhammad bin Ibrahim] dari [Al Qomah bin Waqqash] dari [Umar bin Khatthab] Radliyallahu'anhu, dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Semua perbuatan tergantung niat, dan (balasan) bagi tiap orang (tergantung) yang diniati, barangsiapa berniat hijrahnya karena Allah dan Rasul-Nya, maka hijrahnya kepada Allah dan Rasul-Nya. Barangsiapa niat hijrahnya karena dunia yang ingin digapai atau karena seorang perempuan yang ingin dinikahi, maka hijrahnya sekedar yang diniatinya.\" "},"75":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَانَتْ صَلَاةُ الْعَصْرِ فَالْتَمَسَ النَّاسُ الْوَضُوءَ فَلَمْ يَجِدُوهُ فَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِوَضُوءٍ فَوَضَعَ يَدَهُ فِي ذَلِكَ الْإِنَاءِ وَأَمَرَ النَّاسَ أَنْ يَتَوَضَّئُوا فَرَأَيْتُ الْمَاءَ يَنْبُعُ مِنْ تَحْتِ أَصَابِعِهِ حَتَّى تَوَضَّئُوا مِنْ عِنْدِ آخِرِهِمْ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas] dia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam -waktu Ashar sudah tiba- dan orang-orang mencari air wudlu, namun belum mendapatkannya. Lalu dibawakan kepada Rasulullah shallallahu 'alaihi wasallam air wudlu, dan Rasulullah shallallahu 'alaihi wasallam meletakkan tangannya kedalam bejana tersebut. Beliau kemudian memerintahkan orang-orang untuk berwudlu. Aku melihat air mengalir dari bawah jari-jari beliau, sehingga mereka berwudlu sampai orang yang terakhir.\""},"76":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَجِدُوا مَاءً فَأُتِيَ بِتَوْرٍ فَأَدْخَلَ يَدَهُ فَلَقَدْ رَأَيْتُ الْمَاءَ يَتَفَجَّرُ مِنْ بَيْنِ أَصَابِعِهِ وَيَقُولُ حَيَّ عَلَى الطَّهُورِ وَالْبَرَكَةِ مِنْ اللَّهِ عَزَّ وَجَلَّقَالَ الْأَعْمَشُ فَحَدَّثَنِي سَالِمُ بْنُ أَبِي الْجَعْدِ قَالَ قُلْتُ لِجَابِرٍ كَمْ كُنْتُمْ يَوْمَئِذٍ قَالَ أَلْفٌ وَخَمْسُ مِائَةٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Abdur Razzak] dia berkata; Telah memberitakan kepada kami [Sufyan] dari [Al A'Masy] dari [Ibrahim] dari [Al Qamah] dari [Abdullah] dia berkata; \"Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam dan mereka tidak mendapatkan air. Lalu dibawakan kepada beliau sebuah bejana kecil. Beliau memasukkan tangannya kedalam bejana tersebut. Setelah itu aku melihat air memancar dari celah-celah jari-jarinya. Beliau kemudian bersabda, 'Mari bersuci dan memperoleh keberkahan dari Allah Azza wa Jalla.\" Al A'Masy berkata; maka telah menceritakan kepadaku [Salim bin Abu Ja'ad] dia berkata; aku bertanya kepada Jabir, \"Berapa orang kalian saat itu?\" [Jabir] menjawab; \"seribu lima ratus orang.\""},"77":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ ثَابِتٍ وَقَتَادَةُ عَنْ أَنَسٍ قَالَطَلَبَ بَعْضُ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَضُوءًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ مَعَ أَحَدٍ مِنْكُمْ مَاءٌ فَوَضَعَ يَدَهُ فِي الْمَاءِ وَيَقُولُ تَوَضَّئُوا بِسْمِ اللَّهِ فَرَأَيْتُ الْمَاءَ يَخْرُجُ مِنْ بَيْنِ أَصَابِعِهِ حَتَّى تَوَضَّئُوا مِنْ عِنْدِ آخِرِهِمْقَالَ ثَابِتٌ قُلْتُ لِأَنَسٍ كَمْ تُرَاهُمْ قَالَ نَحْوًا مِنْ سَبْعِينَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Abdur Razzak] dia berkata; telah menceritakan kepada kami [Ma'mar] dari [Tsabit] dan [Qatadah] dari [Anas], dia berkata, \"Sebagian sahabat Nabi shallallahu 'alaihi wasallam mencari air wudlu, maka Rasulullah shallallahu 'alaihi wasallam bersabda, 'Apakah diantara kalian ada yang membawa air? ' Lalu beliau meletakkan tangannya ke dalam bejana dan berkata, 'Berwudlulah dengan mengucapkan bismillah'. Setelah itu aku melihat air mengalir dari celah-celah jari-jari Rasulullah shallallahu 'alaihi wasallam hingga mereka semua berwudlu sampai orang yang terakhir.\" Tsabit berkata; \"Aku bertanya kepada Anas, 'Berapakah jumlah mereka yang kamu lihat? ' dia menjawab; 'sekitar tujuh puluh orang'.\""},"78":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ وَهْبٍ عَنْ مَالِكٍ وَيُونُسَ وَعَمْرِو بْنِ الْحَارِثِ أَنَّ ابْنَ شِهَابٍ أَخْبَرَهُمْ عَنْ عَبَّادِ بْنِ زِيَادٍ عَنْ عُرْوَةَ بْنِ الْمُغِيرَةِ أَنَّهُ سَمِعَ أَبَاهُ يَقُولُسَكَبْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ تَوَضَّأَ فِي غَزْوَةِ تَبُوكَ فَمَسَحَ عَلَى الْخُفَّيْنِقَالَ أَبُو عَبْد الرَّحْمَنِ لَمْ يَذْكُرْ مَالِكٌ عُرْوَةَ بْنَ الْمُغِيرَةِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud] dan [Al Harits bin Miskin] telah dibacakan kepadanya dan aku mendengar lafazhnya dari dia, dari [Ibnu Wahab] dari [Malik] dan [Yunus] dan [Amr bin Al Harits] bahwasanya [Ibnu Syihab] Telah mengabarkan kepada mereka, dari ['Abbad bin Ziyad] dari ['Urwah bin Al Mughirah] bahwasannya dia mendengar [Bapaknya] berkata; \"Aku pernah menuangkan air untuk Rasulullah shallallahu 'alaihi wasallam ketika beliau wudlu saat perang Tabuk. Saat itu beliau mengusap kedua sepatunya.\" Abu Abdurrahman berkata; Malik tidak menyebutkan Urwah bin Al Mughirah. "},"79":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنَا زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ قَالَأَلَا أُخْبِرُكُمْ بِوُضُوءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَوَضَّأَ مَرَّةً مَرَّةً","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Yahya] dari [Sufyan] dia berkata; telah menceritakan kepada kami [Zaid bin Aslam] dari ['Atha bin Yasar] dari [Ibnu Abbas], dia berkata; \"Maukah kalian aku kabarkan tentang cara wudlu Rasulullah shallallahu 'alaihi wasallam? Beliau shallallahu 'alaihi wasallam berwudlu satu kali-satu kali (untuk tiap anggota wudlu).\""},"80":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ قَالَ أَنْبَأَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي الْمُطَّلِبُ بْنُ عَبْدِ اللَّهِ بْنِ حَنْطَبٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَتَوَضَّأَ ثَلَاثًا ثَلَاثًا يُسْنَدُ ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah memberitakan kepada kami [Abdulllah bin Al Mubarak] dia berkata; Telah memberitakan kepada kami [Al Auza'i] dia berkata; telah menceritakan kepada ku [Al Muthallib bin Abdullah bin Hanthab] bahwa [Abdullah bin Umar], berwudlu tiga kali-tiga kali. Dia menyandarkan hal itu kepada Rasulullah shallallahu 'alaihi wasallam. "},"81":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ الْبَصْرِيُّ عَنْ بِشْرِ بْنِ الْمُفَضَّلِ عَنْ ابْنِ عَوْنٍ عَنْ عَامِرٍ الشَّعْبِيِّ عَنْ عُرْوَةَ بْنِ الْمُغِيرَةِ عَنْ الْمُغِيرَةِ وَعَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ رَجُلٍ حَتَّى رَدَّهُ إِلَى الْمُغِيرَةِ قَالَ ابْنُ عَوْنٍ وَلَا أَحْفَظُ حَدِيثَ ذَا مِنْ حَدِيثِ ذَا أَنَّ الْمُغِيرَةَ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَقَرَعَ ظَهْرِي بِعَصًا كَانَتْ مَعَهُ فَعَدَلَ وَعَدَلْتُ مَعَهُ حَتَّى أَتَى كَذَا وَكَذَا مِنْ الْأَرْضِ فَأَنَاخَ ثُمَّ انْطَلَقَ قَالَ فَذَهَبَ حَتَّى تَوَارَى عَنِّي ثُمَّ جَاءَ فَقَالَ أَمَعَكَ مَاءٌ وَمَعِي سَطِيحَةٌ لِي فَأَتَيْتُهُ بِهَا فَأَفْرَغْتُ عَلَيْهِ فَغَسَلَ يَدَيْهِ وَوَجْهَهُ وَذَهَبَ لِيَغْسِلَ ذِرَاعَيْهِ وَعَلَيْهِ جُبَّةٌ شَامِيَّةٌ ضَيِّقَةُ الْكُمَّيْنِ فَأَخْرَجَ يَدَهُ مِنْ تَحْتِ الْجُبَّةِ فَغَسَلَ وَجْهَهُ وَذِرَاعَيْهِ وَذَكَرَ مِنْ نَاصِيَتِهِ شَيْئًا وَعِمَامَتِهِ شَيْئًا قَالَ ابْنُ عَوْنٍ لَا أَحْفَظُ كَمَا أُرِيدُ ثُمَّ مَسَحَ عَلَى خُفَّيْهِ ثُمَّ قَالَ حَاجَتَكَ قُلْتُ يَا رَسُولَ اللَّهِ لَيْسَتْ لِي حَاجَةٌ فَجِئْنَا وَقَدْ أَمَّ النَّاسَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ وَقَدْ صَلَّى بِهِمْ رَكْعَةً مِنْ صَلَاةِ الصُّبْحِ فَذَهَبْتُ لِأُوذِنَهُ فَنَهَانِي فَصَلَّيْنَا مَا أَدْرَكْنَا وَقَضَيْنَا مَا سُبِقْنَا","id":"Telah mengabarkan kepada kami [Muhammad bin Ibrahim Al Bashri] dari [Bisyir bin Al Mufadhal] dari [Ibnu 'Aun] dari ['Amir As-Sya'bi] dari ['Urwah bin Al Mughirah] dari [Al Mughirah] dan dari [Muhammmad bin Sirin] dari [seorang laki-laki] yang kemudian di sandarkan kepada Al Mughirah, Ibnu 'Aun berkata; 'saya tidak hafal hadits ini dari ini' bahwasannya Al Mughirah, berkata, \"Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu safar (perjalanan). Beliau memukul punggungku dengan tongkat yang ada padanya. Beliau meluruskan posisiku, maka aku pun ikut meluruskan bersamanya hingga sampai pada suatu daerah, beliau singgah, lalu berangkat lagi, (Mughirah berkata) dan beliau pergi hingga tidak nampak olehku. Kemudian beliau datang dan bersabda, 'Apakah kamu punya air? 'Aku memang membawa air dalam tempat yang terbuat dari kulit (sathihah), maka aku datang kepada beliau dengan membawanya, lalu aku tuangkan kepada beliau. Beliaupun segera membasuh kedua tangannya dan wajahnya, dan kedua sikunya. Beliau memakai jubah dari Syam yang sempit kedua tangannya -beliau mengeluarkan tangannya dari bawah jubahnya- lalu membasuh muka dan kedua lengannya. Lalu beliau menyebutkan suatu bagian depan dari kepalanya dan dari surbannya, Ibnu 'Aun berkata; \"Dan saya tidak mengingat apa yang saya inginkan\". kemudian beliau mengusap kedua sepatunya (khuf). Beliau lalu berkata, 'Hajatmu? '. Aku menjawab, 'Wahai Rasulullah shallallahu 'alaihi wasallam, aku tidak ada hajat'. Setelah itu kami datang dan kami dapati Abdurrhaman bin Auf sedang menjadi imam shalat jama'ah bersama orang-orang. Ia sudah mendapat satu raka'at shalat Subuh. Aku segera pergi untuk memberitahukannya, namun beliau mencegahku. Kamipun ikut shalat dari yang kami dapati, kemudian menyempurnakan yang ketinggalan.\""},"82":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ سُفْيَانَ وَهُوَ ابْنُ حَبِيبٍ عَنْ شُعْبَةَ عَنْ النُّعْمَانِ بْنِ سَالِمٍ عَنْ ابْنِ أَوْسِ بْنِ أَبِي أَوْسٍ عَنْ جَدِّهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَوْكَفَ ثَلَاثًا","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dari [Sufyan yaitu Ibnu Habib] dari [Syu'bah] dari [Nu'man bin Salim] dari [Ibnu 'Aus bin Abu Aus] dari [Kakeknya] dia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam membasuh telapak tangan tiga kali.\" "},"83":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ حُمْرَانَ بْنِ أَبَانَ قَالَرَأَيْتُ عُثْمَانَ بْنَ عَفَّانَ رَضِيَ اللَّهُ عَنْهُ تَوَضَّأَ فَأَفْرَغَ عَلَى يَدَيْهِ ثَلَاثًا فَغَسَلَهُمَا ثُمَّ تَمَضْمَضَ وَاسْتَنْشَقَ ثُمَّ غَسَلَ وَجْهَهُ ثَلَاثًا ثُمَّ غَسَلَ يَدَيْهِ الْيُمْنَى إِلَى الْمِرْفَقِ ثَلَاثًا ثُمَّ الْيُسْرَى مِثْلَ ذَلِكَ ثُمَّ مَسَحَ بِرَأْسِهِ ثُمَّ غَسَلَ قَدَمَهُ الْيُمْنَى ثَلَاثًا ثُمَّ الْيُسْرَى مِثْلَ ذَلِكَ ثُمَّ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ نَحْوَ وُضُوئِي ثُمَّ قَالَ مَنْ تَوَضَّأَ نَحْوَ وُضُوئِي هَذَا ثُمَّ صَلَّى رَكْعَتَيْنِ لَا يُحَدِّثُ نَفْسَهُ فِيهِمَا بِشَيْءٍ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah memberitakan kepada kami [Abdullah] dari [Ma'mar] dari [Az-Zuhri] dari [Atha bin Yazid Al Laitsi] dari [Humran bin Abban] dia berkata; \"Aku melihat [Utsman bin Affan] Radliyallahu'anhu berwudlu; dia menuangkan air ke dua tangannya tiga kali, lalu membasuhnya, kemudian berkumur dan memasukkan air ke dalam hidung. Setelah itu ia membasuh mukanya tiga kali, kemudian membasuh tangan kanannya sampai siku sebanyak tiga kali, kemudian tangan kirinya, lalu mengusap kepalanya. Setelah itu membasuh kaki kanannya tiga kali dan kaki kirinya tiga kali. Ketika selesai, beliau berkata, 'Aku melihat Rasulullah shallallahu 'alaihi wasallam berwudlu seperti wudluku tadi. Rasulullah shallallahu 'alaihi wasallam bersabda, \"Barangsiapa berwudlu seperti wudluku ini, kemudian shalat dua raka'at -tanpa berbicara terhadap dirinya diantara keduanya- Allah mengampuni dosa-dosanya yang lalu.\""},"84":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ الْمُغِيرَةِ قَالَ حَدَّثَنَا عُثْمَانُ هُوَ ابْنُ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ الْحِمْصِيُّ عَنْ شُعَيْبٍ هُوَ ابْنُ أبِي حَمْزَةَ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عَطَاءُ بْنُ يَزِيدَ عَنْ حُمْرَانَأَنَّهُ رَأَى عُثْمَانَ دَعَا بِوَضُوءٍ فَأَفْرَغَ عَلَى يَدَيْهِ مِنْ إِنَائِهِ فَغَسَلَهَا ثَلَاثَ مَرَّاتٍ ثُمَّ أَدْخَلَ يَمِينَهُ فِي الْوَضُوءِ فَتَمَضْمَضَ وَاسْتَنْشَقَ ثُمَّ غَسَلَ وَجْهَهُ ثَلَاثًا وَيَدَيْهِ إِلَى الْمِرْفَقَيْنِ ثَلَاثَ مَرَّاتٍ ثُمَّ مَسَحَ بِرَأْسِهِ ثُمَّ غَسَلَ كُلَّ رِجْلٍ مِنْ رِجْلَيْهِ ثَلَاثَ مَرَّاتٍ ثُمَّ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ وُضُوئِي هَذَا ثُمَّ قَالَ مَنْ تَوَضَّأَ مِثْلَ وُضُوئِي هَذَا ثُمَّ قَامَ فَصَلَّى رَكْعَتَيْنِ لَا يُحَدِّثُ فِيهِمَا نَفْسَهُ بِشَيْءٍ غَفَرَ اللَّهُ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Ahmad bin Muhammad bin Al Mughirah] dia berkata; telah menceritakan kepada kami [Utsman yaitu Ibnu Sa'id bin Katsir bin Dinar Al Hamshi] dari [Syu'aib yaitu Ibnu Abu Hamzah] dari [Az-Zuhri] telah mengabarkan kepadaku ['Atha bin Yazid] dari [Humran], bahwa dia melihat [Utsman bin Affan] meminta air wudlu. Lalu dituangkanlah kepada kedua tangannya dari bejananya, maka beliau membasuh kedua tangannya tiga kali, kemudian dia memasukkan tangan kanannya kedalam air wudlu. Setelah itu berkumur dan memasukkan air ke hidung, membasuh mukanya tiga kali, membasuh kedua tangannya sampai ke siku-sikunya tiga kali, mengusap kepalanya, membasuh kakinya tiga kali, kemudian berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam berwudlu seperti wudluku ini, kemudian shalat dua raka'at -tanpa berbicara terhadap dirinya diantara keduanya- maka Allah akan mengampuni dosa-dosanya yang telah lalu.\" "},"85":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا أَبُو الزِّنَادِ ح و حَدَّثَنَا الْحُسَيْنُ بْنُ عِيسَى عَنْ مَعْنٍ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَوَضَّأَ أَحَدُكُمْ فَلْيَجْعَلْ فِي أَنْفِهِ مَاءً ثُمَّ لِيَسْتَنْثِرْ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dia berkata; telah menceritakan kepada kami [Abu Zinad] dan telah menceritakan kepada kami [Al Husain bin Isa] dari [Ma'an] dari [Malik] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda, \" Apabila salah seorang dari kalian berwudlu, hendaknya menghisap air ke dalam hidung, lalu mengeluarkannya (kembali).\""},"86":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ عَنْ إِسْمَعِيلَ بْنِ كَثِيرٍ ح وَأَنْبَأَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي هَاشِمٍ عَنْ عَاصِمِ بْنِ لَقِيطِ بْنِ صَبْرَةَ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَخْبِرْنِي عَنْ الْوُضُوءِ قَالَ أَسْبِغْ الْوُضُوءَ وَبَالِغْ فِي الِاسْتِنْشَاقِ إِلَّا أَنْ تَكُونَ صَائِمًا","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya bin Sulaim] dari [Ismail bin Katsir] dan Telah memberitakan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Waki'] dari [Sufyan] dari [Abu Hasyim] dari [Ashim bin Laqith bin Shabirah] dari [Bapaknya] dia berkata, \"Aku berkata kepada Rasulullah shallallahu 'alaihi wasallam, 'Wahai Rasulullah shallallahu 'alaihi wasallam, kabarkan kepadaku tentang wudlu'. Beliau shallallahu 'alaihi wasallam menjawab, ' Sempurnakanlah wudlu dan sungguh-sungguhlah dalam menghisap air ke dalam hidung, kecuali saat puasa.\" "},"87":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ ح و حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَوَضَّأَ فَلْيَسْتَنْثِرْ وَمَنْ اسْتَجْمَرَ فَلْيُوتِرْ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dan telah menceritakan kepada kami [Ishaq bin Manshur] dia berkata; telah menceritakan kepada kami [Abdurrahman] dari [Malik] dari [Ibnu Syihab] dari [Abu Idris Al Khaulani] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barangsiapa berwudlu, hendaklah ia memasukkan ke dalam hidung dan mengeluarkannya. Barangsiapa bersuci dengan batu, hendaklah melakukannya dengan jumlah ganjil. "},"88":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ سَلَمَةَ بْنِ قَيْسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَوَضَّأْتَ فَاسْتَنْثِرْ وَإِذَا اسْتَجْمَرْتَ فَأَوْتِرْ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Hammad] dari [Manshur] dari [Hilal bin Yasaf] dari [Salamah bin Qais], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda, \" Apabila kamu berwudlu, tolong masukkan air ke hidung, lalu keluarkanlah. Bila kamu bersuci dengan batu, gunakan dengan jumlah ganjil.\""},"89":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ زُنْبُورٍ الْمَكِّيُّ قَالَ حَدَّثَنَا ابْنُ أَبِي حَازِمٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ أَنَّ مُحَمَّدَ بْنَ إِبْرَاهِيمَ حَدَّثَهُ عَنْ عِيسَى بْنِ طَلْحَةَ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا اسْتَيْقَظَ أَحَدُكُمْ مِنْ مَنَامِهِ فَتَوَضَّأَ فَلْيَسْتَنْثِرْ ثَلَاثَ مَرَّاتٍ فَإِنَّ الشَّيْطَانَ يَبِيتُ عَلَى خَيْشُومِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Zunbur Al Makki] dia berkata; telah menceritakan kepada kami [Ibnu Abu Hazim] dari [Yazid bin Abdullah] bahwasanya [Muhammad bin Ibrahim] bercerita, dari [Isa bin Thalhah] dari [Abu Hurairah], dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \" Apabila salah seorang dari kalian bangun dari tidurnya, lalu berwudlu, hendaklah ia menghirup air ke hidung lalu mengeluarkannya kembali sebanyak tiga kali, karena setan tinggal (bermalam) dalam batang hidungnya.\""},"90":{"ar":"أَخْبَرَنَا مُوسَى بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ عَنْ زَائِدَةَ قَالَ حَدَّثَنَا خَالِدُ بْنُ عَلْقَمَةَ عَنْ عَبْدِ خَيْرٍ عَنْ عَلِيٍّأَنَّهُ دَعَا بِوَضُوءٍ فَتَمَضْمَضَ وَاسْتَنْشَقَ وَنَثَرَ بِيَدِهِ الْيُسْرَى فَفَعَلَ هَذَا ثَلَاثًا ثُمَّ قَالَ هَذَا طُهُورُ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Musa bin Abdurrahman] dia berkata; telah menceritakan kepada kami [Husain bin Ali] dari [Zaidah] dia berkata; telah menceritakan kepada kami [Khalid bin 'Alqamah] dari [Abdu Khair] dari [Ali], bahwa ia pernah meminta air wudlu. Dia lalu berkumur dan menghirup air ke dalam hidung kemudian mengeluarkannya dengan tangan kirinya; dia melakukannya tiga kali, kemudian berkata, \"Beginilah cara bersuci Rasulullah shallallahu 'alaihi wasallam.\""},"91":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ خَالِدِ بْنِ عَلْقَمَةَ عَنْ عَبْدِ خَيْرٍ قَالَأَتَيْنَا عَلِيَّ بْنَ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ وَقَدْ صَلَّى فَدَعَا بِطَهُورٍ فَقُلْنَا مَا يَصْنَعُ بِهِ وَقَدْ صَلَّى مَا يُرِيدُ إِلَّا لِيُعَلِّمَنَا فَأُتِيَ بِإِنَاءٍ فِيهِ مَاءٌ وَطَسْتٍ فَأَفْرَغَ مِنْ الْإِنَاءِ عَلَى يَدَيْهِ فَغَسَلَهَا ثَلَاثًا ثُمَّ تَمَضْمَضَ وَاسْتَنْشَقَ ثَلَاثًا مِنْ الْكَفِّ الَّذِي يَأْخُذُ بِهِ الْمَاءَ ثُمَّ غَسَلَ وَجْهَهُ ثَلَاثًا وَغَسَلَ يَدَهُ الْيُمْنَى ثَلَاثًا وَيَدَهُ الشِّمَالَ ثَلَاثًا وَمَسَحَ بِرَأْسِهِ مَرَّةً وَاحِدَةً ثُمَّ غَسَلَ رِجْلَهُ الْيُمْنَى ثَلَاثًا وَرِجْلَهُ الشِّمَالَ ثَلَاثًا ثُمَّ قَالَ مَنْ سَرَّهُ أَنْ يَعْلَمَ وُضُوءَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهُوَ هَذَا","id":"Telah mengabarkan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu 'Awanah] dari [Khalid bin Alqamah] dari [Abdu Khair], dia berkata, \"Kami datang kepada [Ali bin Abu Thalib] Radliyallahu'anhu. Dia sudah shalat, tetapi dia meminta air wudlu, maka kami katakan, 'Apa yang dia lakukan dengan air ini, padahal dia telah shalat? ' Ternyata dia tidak menginginkan yang demikian kecuali untuk mengajari kami! Maka dibawakanlah sebuah bejana dan gayung berisi air, lalu ia menuangkan air ke tangannya, lalu membasuhnya tiga kali, berkumur dan menghisap air kedalam hidung tiga kali dari telapak tangan yang beliau pakai untuk mengambil air, membasuh wajahnya tiga kali, membasuh tangan kanannya tiga kali, membasuh tangan kirinya tiga kali, dan mengusap kepalanya sekali. Kemudian membasuh kaki kanannya tiga kali, dan membasuh kaki kirinya tiga kali. Setelah selesai Ali berkata, 'Barangsiapa senang ingin mengetahui wudlunya Rasulullah shallallahu 'alaihi wasallam, inilah wudlu beliau shallallahu 'alaihi wasallam.\""},"92":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ وَهُوَ ابْنُ الْمُبَارَكِ عَنْ شُعْبَةَ عَنْ مَالِكِ بْنِ عُرْفُطَةَ عَنْ عَبْدِ خَيْرٍ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُأَنَّهُ أُتِيَ بِكُرْسِيٍّ فَقَعَدَ عَلَيْهِ ثُمَّ دَعَا بِتَوْرٍ فِيهِ مَاءٌ فَكَفَأَ عَلَى يَدَيْهِ ثَلَاثًا ثُمَّ مَضْمَضَ وَاسْتَنْشَقَ بِكَفٍّ وَاحِدٍ ثَلَاثَ مَرَّاتٍ وَغَسَلَ وَجْهَهُ ثَلَاثًا وَغَسَلَ ذِرَاعَيْهِ ثَلَاثًا ثَلَاثًا وَأَخَذَ مِنْ الْمَاءِ فَمَسَحَ بِرَأْسِهِ وَأَشَارَ شُعْبَةُ مَرَّةً مِنْ نَاصِيَتِهِ إِلَى مُؤَخَّرِ رَأْسِهِ ثُمَّ قَالَ لَا أَدْرِي أَرَدَّهُمَا أَمْ لَا وَغَسَلَ رِجْلَيْهِ ثَلَاثًا ثَلَاثًا ثُمَّ قَالَ مَنْ سَرَّهُ أَنْ يَنْظُرَ إِلَى طُهُورِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَذَا طُهُورُهُو قَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا خَطَأٌ وَالصَّوَابُ خَالِدُ بْنُ عَلْقَمَةَ لَيْسَ مَالِكَ بْنَ عُرْفُطَةَ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah memberitakan kepada kami [Abdullah yaitu Ibnu Mubarak] dari [Syu'bah] dari Malik bin 'Urfuthah dari [Abdu Khair] dari [Ali Radliyallahu'anhu], bahwa ia dibawakan sebuah kursi, ia segera duduk di kursi tersebut. Kemudian ia meminta bejana kecil berisi air, ia tuangkan ke telapak tangannya tiga kali kemudian berkumur tiga kali dan menghisapnya ke dalam hidung dengan satu telapak tangan sebanyak tiga kali. Lalu membasuh wajahnya tiga kali, membasuh kedua lengannya tiga-tiga kali, kemudian mengambil dan mengusap kepalanya- Syu'bah - (perawi hadits ini) menunjukkan bahwa Rasulullah shallallahu 'alaihi wasallam mengusap kepalanya sekali dari ujung ubun-ubun sampai tengkuknya, ia (Syu'bah) berkata, 'Aku tidak tahu apakah beliau mengembalikan kedua tangannya atau tidak (dari tengkuk sampai ubun-ubun)?\"-dan beliau membasuh kedua kakinya masing-masing tiga kali. Setelah itu ia berkata, \"Barangsiapa senang melihat cara Rasulullah shallallahu 'alaihi wasallam bersuci, inilah cara beliau shallallahu 'alaihi wasallam bersuci.\" Dan Abu Abdurrahman berkata; \"Jalur periwayatan di atas ada yang salah, yang benar adalah [Khalid bin Alqamah] bukan Malik bin 'Urfuthah. "},"93":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَحُمَيْدُ بْنُ مَسْعَدَةَ عَنْ يَزِيدَ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنِي شُعْبَةُ عَنْ مَالِكِ بْنِ عُرْفُطَةَ عَنْ عَبْدِ خَيْرٍ قَالَشَهِدْتُ عَلِيًّا دَعَا بِكُرْسِيٍّ فَقَعَدَ عَلَيْهِ ثُمَّ دَعَا بِمَاءٍ فِي تَوْرٍ فَغَسَلَ يَدَيْهِ ثَلَاثًا ثُمَّ مَضْمَضَ وَاسْتَنْشَقَ بِكَفٍّ وَاحِدٍ ثَلَاثًا ثُمَّ غَسَلَ وَجْهَهُ ثَلَاثًا وَيَدَيْهِ ثَلَاثًا ثَلَاثًا ثُمَّ غَمَسَ يَدَهُ فِي الْإِنَاءِ فَمَسَحَ بِرَأْسِهِ ثُمَّ غَسَلَ رِجْلَيْهِ ثَلَاثًا ثَلَاثًا ثُمَّ قَالَ مَنْ سَرَّهُ أَنْ يَنْظُرَ إِلَى وُضُوءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَذَا وُضُوءُهُ","id":"Telah mengabarkan kepada kami [Amru bin Ali] dan [Humaid bin Mas'adah] dari [Yazid yaitu Ibnu Zura'i] dia berkata; telah menceritakan kepadaku [Syu'bah] dari [Malik bin 'Urfuthah] dari [Abdi Khair], dia berkata, \"Aku melihat [Ali] meminta kursi, dan didudukinya. Kemudian ia meminta air dalam bejana kecil. Ia lalu membasuh kedua tangannya, berkumur tiga kali dan menghisap air ke dalam hidung dengan satu telapak tangan sebanyak tiga kali, membasuh wajahnya tiga kali, membasuh kedua tangannya tiga kali-tiga kali, kemudian mencelupkan tangannya ke dalam bejana dan mengusap kepalanya sekali. Beliau juga membasuh kedua kakinya masing-masing tiga kali. Setelah itu beliau berkata, 'Barangsiapa senang melihat cara Rasulullah shallallahu 'alaihi wasallam berwudlu, inilah cara beliau shallallahu 'alaihi wasallam berwudlu.\" "},"94":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ الْمِقْسَمِيُّ قَالَ أَنْبَأَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ حَدَّثَنِي شَيْبَةُ أَنَّ مُحَمَّدَ بْنَ عَلِيٍّ أَخْبَرَهُ قَالَ أَخْبَرَنِي أَبِي عَلِيٌّ أَنَّ الْحُسَيْنَ بْنَ عَلِيٍّ قَالَدَعَانِي أَبِي عَلِيٌّ بِوَضُوءٍ فَقَرَّبْتُهُ لَهُ فَبَدَأَ فَغَسَلَ كَفَّيْهِ ثَلَاثَ مَرَّاتٍ قَبْلَ أَنْ يُدْخِلَهُمَا فِي وَضُوئِهِ ثُمَّ مَضْمَضَ ثَلَاثًا وَاسْتَنْثَرَ ثَلَاثًا ثُمَّ غَسَلَ وَجْهَهُ ثَلَاثَ مَرَّاتٍ ثُمَّ غَسَلَ يَدَهُ الْيُمْنَى إِلَى الْمِرْفَقِ ثَلَاثًا ثُمَّ الْيُسْرَى كَذَلِكَ ثُمَّ مَسَحَ ب��رَأْسِهِ مَسْحَةً وَاحِدَةً ثُمَّ غَسَلَ رِجْلَهُ الْيُمْنَى إِلَى الْكَعْبَيْنِ ثَلَاثًا ثُمَّ الْيُسْرَى كَذَلِكَ ثُمَّ قَامَ قَائِمًا فَقَالَ نَاوِلْنِي فَنَاوَلْتُهُ الْإِنَاءَ الَّذِي فِيهِ فَضْلُ وَضُوئِهِ فَشَرِبَ مِنْ فَضْلِ وَضُوئِهِ قَائِمًا فَعَجِبْتُ فَلَمَّا رَآنِي قَالَ لَا تَعْجَبْ فَإِنِّي رَأَيْتُ أَبَاكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ مِثْلَ مَا رَأَيْتَنِي صَنَعْتُ يَقُولُ لِوُضُوئِهِ هَذَا وَشُرْبِ فَضْلِ وَضُوئِهِ قَائِمًا","id":"Telah mengabarkan kepada kami [Ibrahim bin Hasan Al Miqsami] dia berkata; Telah memberitakan kepada kami [Hajjaj] dia berkata; [Ibnu Juraij] berkata; telah menceritakan kepadaku [Syaibah] bahwa [Muhammad bin Ali] Telah mengabarkan kepadanya dia berkata; Telah mengabarkan kepadaku bapakku ([Ali]) bahwa [Husain bin Ali], berkata, \" Bapakku ([Ali]) memintaku air wudlu, maka aku bawakan kepadanya. Lalu ia mulai membasuh kedua telapak tangannya tiga kali-sebelum memulai wudlunya-, berkumur tiga kali dan menghirup air ke hidung lalu mengeluarkannya, kemudian membasuh wajahnya tiga kali, membasuh tangan kanannya sampai siku-siku tiga kali, membasuh tangan kirinya tiga kali, mengusap kepalanya satu kali usapan, lalu membasuh kaki kanannya sampai mata kaki tiga kali dan kaki kirinya tiga kali. Setelah itu ia berdiri dan berkata, 'Terima ini'. Aku segera menerima bejana yang masih ada sisa wudlunya, dan ia meminum air dari sisa wudlunya sambil berdiri. Akupun heran! Setelah melihatku terheran-heran, ia berkata, 'Jangan heran! Aku pernah melihat kakekmu (Rasulullah shallallahu 'alaihi wasallam melakukan apa yang kamu lihat dari perbuatanku ini.\" Ali bin Abu Thalib mengatakan tentang wudlunya dan minum air sisa wudlunya sambil berdiri. "},"95":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي حَيَّةَ وَهُوَ ابْنُ قَيْسٍ قَالَرَأَيْتُ عَلِيًّا رَضِيَ اللَّهُ عَنْهُ تَوَضَّأَ فَغَسَلَ كَفَّيْهِ حَتَّى أَنْقَاهُمَا ثُمَّ تَمَضْمَضَ ثَلَاثًا وَاسْتَنْشَقَ ثَلَاثًا وَغَسَلَ وَجْهَهُ ثَلَاثًا وَغَسَلَ ذِرَاعَيْهِ ثَلَاثًا ثَلَاثًا ثُمَّ مَسَحَ بِرَأْسِهِ ثُمَّ غَسَلَ قَدَمَيْهِ إِلَى الْكَعْبَيْنِ ثُمَّ قَامَ فَأَخَذَ فَضْلَ طَهُورِهِ فَشَرِبَ وَهُوَ قَائِمٌ ثُمَّ قَالَ أَحْبَبْتُ أَنْ أُرِيَكُمْ كَيْفَ طُهُورُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Ishaq] dari [Abu Hayyah yaitu Ibnu Qais] dia berkata; \"Aku melihat [Ali] Radliyallahu'anhu berwudlu; ia membasuh kedua telapak tangannya hingga beliau mencucinya, kemudian berkumur tiga kali dan memasukkan air kedalam hidungnya juga tiga kali, kemudian membasuh mukanya tiga kali serta membasuh kedua lengannya tiga kali-tiga kali, lalu mengusap kepalanya, selanjutnya beliau membasuh kedua telapak kakinya sampai kedua mata kakinya. Setelah itu berdiri dengan mengambil sisa wudlunya, dan meminumnya sambil berdiri. dia lalu berkata, 'Aku senang memperlihatkan cara wudlunya Rasulullah shallallahu 'alaihi wasallam kepada kalian.\" "},"96":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ عَمْرِو بْنِ يَحْيَى الْمَازِنِيِّ عَنْ أَبِيهِأَنَّهُ قَالَ لِعَبْدِ اللَّهِ بْنِ زَيْدِ بْنِ عَاصِمٍ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ جَدُّ عَمْرِو بْنِ يَحْيَى هَلْ تَسْتَطِيعُ أَنْ تُرِيَنِي كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ قَالَ عَبْدُ اللَّهِ بْنُ زَيْدٍ نَعَمْ فَدَعَا بِوَضُوءٍ فَأَفْرَغَ عَلَى يَدَيْهِ فَغَسَلَ يَدَيْهِ مَرَّتَيْنِ مَرَّتَيْنِ ثُمَّ تَمَضْمَضَ وَاسْتَنْشَقَ ثَلَاثًا ثُمَّ غَسَلَ وَجْهَهُ ثَلَاثًا ثُمَّ غَسَلَ يَدَيْهِ مَرَّتَيْنِ مَرَّتَيْنِ إِلَى الْمِرْفَقَيْنِ ثُمَّ مَسَحَ رَأْسَهُ بِيَدَيْهِ فَأَقْبَلَ بِهِمَا وَأَدْبَرَ بَدَأَ بِمُقَدَّمِ رَأْسِهِ ثُمَّ ذَهَبَ بِهِمَا إِلَى قَفَاهُ ثُمَّ رَدَّهُمَا حَتَّى رَجَعَ إِلَى الْمَكَانِ الَّذِي بَدَأَ مِنْهُ ثُمَّ غَسَلَ رِجْلَيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] telah di bacakan kepadanya dan saya mendengar lafazhnya dari dia, dari [Ibnu Qasim] dia berkata; telah menceritakan kepadaku [Malik] dari ['Amru bin Yahya Al Mazini] dari [Bapaknya] bahwa dia berkata kepada [Abdullah bin Zaid bin 'Ashim] - sahabat Rasulullah shallallahu 'alaihi wasallam, dan kakeknya Amru bin Yahya-, \"Bisakah engkau memperlihatkan kepadaku cara Rasulullah shallallahu 'alaihi wasallam berwudlu?\" Abdullah bin Zaid berkata, \"Ya.\" Lalu ia meminta air wudlu, kemudian menuangkan air kedua tangannya dan membasuhnya dua kali-dua kali. Kemudian berkumur dan memasukkan air ke dalam hidungnya tiga kali, membasuh mukanya tiga kali, membasuh kedua tangannya dua kali sampai kedua sikunya, mengusap kepalanya dengan kedua tangannya. Ia jalankan kedua tangannya ke depan lalu ke belakang, ia mulai dari ujung kepalanya lalu ditarik ke belakang sampai tengkuknya, lantas mengembalikannya ke tempat semula, kemudian membasuh kedua kakinya.\""},"97":{"ar":"أَخْبَرَنَا عُتْبَةُ بْنُ عَبْدِ اللَّهِ عَنْ مَالِكٍ هُوَ ابْنُ أَنَسٍ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ أَنَّهُ قَالَ لِعَبْدِ اللَّهِ بْنِ زَيْدِ بْنِ عَاصِمٍ وَهُوَ جَدُّ عَمْرِو بْنِ يَحْيَىهَلْ تَسْتَطِيعُ أَنْ تُرِيَنِي كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ قَالَ عَبْدُ اللَّهِ بْنُ زَيْدٍ نَعَمْ فَدَعَا بِوَضُوءٍ فَأَفْرَغَ عَلَى يَدِهِ الْيُمْنَى فَغَسَلَ يَدَيْهِ مَرَّتَيْنِ ثُمَّ مَضْمَضَ وَاسْتَنْشَقَ ثَلَاثًا ثُمَّ غَسَلَ وَجْهَهُ ثَلَاثًا ثُمَّ غَسَلَ يَدَيْهِ مَرَّتَيْنِ مَرَّتَيْنِ إِلَى الْمِرْفَقَيْنِ ثُمَّ مَسَحَ رَأْسَهُ بِيَدَيْهِ فَأَقْبَلَ بِهِمَا وَأَدْبَرَ بَدَأَ بِمُقَدَّمِ رَأْسِهِ ثُمَّ ذَهَبَ بِهِمَا إِلَى قَفَاهُ ثُمَّ رَدَّهُمَا حَتَّى رَجَعَ إِلَى الْمَكَانِ الَّذِي بَدَأَ مِنْهُ ثُمَّ غَسَلَ رِجْلَيْهِ","id":"Telah mengabarkan kepada kami ['Utbah bin Abdullah] dari [Malik yaitu Ibnu Anas] dari [Amr bin Yahya] dari [Bapaknya], bahwa dia pernah berkata kepada [Abdullah bin Zaid bin Ashim] -kakek Amru bin Yahya-, \"Bisakah memperlihatkan kepadaku cara Rasulullah shallallahu 'alaihi wasallam berwudlu?\" Abdullah bin Zaid berkata, \"Ya.\" Lantas ia meminta air wudlu. Ia menuangkannya ke kedua tangannya dan membasuhnya dua kali, kemudian berkumur dan memasukkan air kedalam hidungnya tiga kali. Lalu membasuh mukanya tiga kali, membasuh kedua tangannya dua kali sampai kedua sikunya, mengusap kepalanya ke belakang, ia mulai dari ujung kepalanya lalu ditarik ke belakang sampai ke tengkuknya, lantas mengembalikannya ke tempat semula. Setelah itu membasuh kedua kakinya.\" "},"98":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ الَّذِي أُرِيَ النِّدَاءَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَغَسَلَ وَجْهَهُ ثَلَاثًا وَيَدَيْهِ مَرَّتَيْنِ وَغَسَلَ رِجْلَيْهِ مَرَّتَيْنِ وَمَسَحَ بِرَأْسِهِ مَرَّتَيْنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Amr bin Yahya] dari [Bapaknya] dari [Abdullah bin Zaid] dia berkata; \"Saya melihat Rasulullah shallallahu 'alaihi wasallam berwudlu, maka beliau membasuh wajahnya tiga kali, kedua tangannya dua kali, kedua kakinya dua kali dan mengusap kepalanya dua kali.\""},"99":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ جُعَيْدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ أَخْبَرَنِي عَبْدُ الْمَلِكِ بْنُ مَرْوَانَ بْنِ الْحَارِثِ بْنِ أَبِي ذُنَابٍ قَالَ أَخْبَرَنِي أَبُو عَبْدِ اللَّهِ سَالِمٌ سَبَلَانُ قَالَوَكَانَتْ عَائِشَةُ تَسْتَعْجِبُ بِأَمَانَتِهِ وَتَسْتَأْجِرُهُ فَأَرَتْنِي كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ فَتَمَضْمَضَتْ وَاسْتَنْثَرَتْ ثَلَاثًا وَغَسَلَتْ وَجْهَهَا ثَلَاثًا ثُمَّ غَسَلَتْ يَدَهَا الْيُمْنَى ثَلَاثًا وَالْيُسْرَى ثَلَاثًا وَوَضَعَتْ يَدَهَا فِي مُقَدَّمِ رَأْسِهَا ثُمَّ مَسَحَتْ رَأْسَهَا مَسْحَةً وَاحِدَةً إِلَى مُؤَخِّرِهِ ثُمَّ أَمَرَّتْ يَدَهَا بِأُذُنَيْهَا ثُمَّ مَرَّتْ عَلَى الْخَدَّيْنِقَالَ سَالِمٌ كُنْتُ آتِيهَا مُكَاتَبًا مَا تَخْتَفِي مِنِّي فَتَجْلِسُ بَيْنَ يَدَيَّ وَتَتَحَدَّثُ مَعِي حَتَّى جِئْتُهَا ذَاتَ يَوْمٍ فَقُلْتُ ادْعِي لِي بِالْبَرَكَةِ يَا أُمَّ الْمُؤْمِنِينَ قَالَتْ وَمَا ذَاكَ قُلْتُ أَعْتَقَنِي اللَّهُ قَالَتْ بَارَكَ اللَّهُ لَكَ وَأَرْخَتْ الْحِجَابَ دُونِي فَلَمْ أَرَهَا بَعْدَ ذَلِكَ الْيَوْمِ","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits] dia berkata; telah menceritakan kepada kami [Fadhlu bin Musa] dari [Ju'aid bin Abdurrahman] dia berkata; Telah mengabarkan kepadaku [Abdul Malik bin Marwan bin Al Harits bin Abu Dzunab] dia berkata; Telah mengabarkan kepadaku [Abu Abdullah Salim Sabalan] dia berkata; \" [Aisyah] sangat kagum dengan sifat amanahnya dan ia menyewanya. Lalu Aisyah memperlihatkan kepadaku cara Rasulullah shallallahu 'alaihi wasallam berwudlu; dia berkumur dan menghirup air ke hidung dan mengeluarkannya kembali tiga kali, membasuh mukanya tiga kali, membasuh tangan kanannya tiga kali dan tangan kirinya tiga kali, lalu meletakkan tangannya di bagian depan kepalanya dan mengusapkannya dengan sekali usapan sampai ke belakang. Kemudian ia menjalankan (mengusapkan) tangannya di kedua telinga dan kedua pipinya.\" Salim berkata; \"Aku pernah datang kepada 'Aisyah dalam keadaan masih mukatab (budak yang dijanjikan untuk dimerdekakan dengan pembayaran secara diangsur). Hingga tidak ada yang tertutup dariku. Ia duduk di depanku dan berbincang-bincang denganku. Pada suatu hari aku berkata, 'wahai ummul mukminin, do'akan aku dengan keberkahan! ' 'Aisyah berkata; ada apa ini? ' aku menjawab, 'Allah memerdekakan diriku'. Ia mendo'akanku dan berkata; 'semoga Allah memberkahimu'. Ia segera menutupkan hijab di hadapanku dan setelah itu aku tidak pernah melihatnya lagi.\""},"100":{"ar":"أَخْبَرَنَا الْهَيْثَمُ بْنُ أَيُّوبَ الطَّالَقَانِيُّ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَغَسَلَ يَدَيْهِ ثُمَّ تَمَضْمَضَ وَاسْتَنْشَقَ مِنْ غَرْفَةٍ وَاحِدَةٍ وَغَسَلَ وَجْهَهُ وَغَسَلَ يَدَيْهِ مَرَّةً مَرَّةً وَمَسَحَ بِرَأْسِهِ وَأُذُنَيْهِ مَرَّةًقَالَ عَبْدُ الْعَزِيزِ وَأَخْبَرَنِي مَنْ سَمِعَ ابْنَ عَجْلَانَ يَقُولُ فِي ذَلِكَ وَغَسَلَ رِجْلَيْهِ","id":"Telah mengabarkan kepada kami [Al Haitsam bin Ayyub At Thalaqani] dia berkata; telah menceritakan kepada kami [Abdul 'Aziz bin Muhammad] dia berkata; telah menceritakan kepada kami [Zaid bin Aslam] dari [Atha bin Yasar] dari [Ibnu 'Abbas], dia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam berwudlu. Beliau membasuh kedua tangannya, kemudian berkumur-kumur dan memasukkan air ke hidung dari satu cidukan (mengambil air dari telapak tangan) dan membasuh muka serta kedua tangannya sekali-sekali. Kemudian mengusap kepalanya dan kedua telinganya satu kali.\" [Abdul 'Aziz] berkata; [orang] yang mendengar dari [Ibnu 'Ajlan] mengabarkan kepadaku, beliau dalam hadits ini dia berkata; 'Beliau membasuh kedua kakinya'.\""},"101":{"ar":"أَخْبَرَنَا مُجَاهِدُ بْنُ مُوسَى قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ قَالَ حَدَّثَنَا ابْنُ عَجْلَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ قَالَتَوَضَّأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَغَرَفَ غَرْفَةً فَمَضْمَضَ وَاسْتَنْشَقَ ثُمَّ غَرَفَ غَرْفَةً فَغَسَلَ وَجْهَهُ ثُمَّ غَرَفَ غَرْفَةً فَغَسَلَ يَدَهُ الْيُمْنَى ثُمَّ غَرَفَ غَرْفَةً فَغَسَلَ يَدَهُ الْيُسْرَى ثُمَّ مَسَحَ بِرَأْسِهِ وَأُذُنَيْهِ بَاطِنِهِمَا بِالسَّبَّاحَتَيْنِ وَظَاهِرِهِمَا بِإِبْهَامَيْهِ ثُمَّ غَرَفَ غَرْفَةً فَغَسَلَ رِجْلَهُ الْيُمْنَى ثُمَّ غَرَفَ غَرْفَةً فَغَسَلَ رِجْلَهُ الْيُسْرَى","id":"Telah mengabarkan kepada kami [Mujahid bin Musa] dia berkata; telah menceritakan kepada kami [Abdullah bin Idris] berkata; telah menceritakan kepada kami [Ibnu 'Ajlan] dari [Zaid bin 'Aslam] dari ['Atha bin Yasar] dari [Ibnu Abbas] berkata: \" Rasulullah shallallahu 'alaihi wasallam berwudlu, beliau menyiduk satu ciduk air untuk berkumur, dan memasukkan air ke hidungnya, kemudian menyiduk lagi satu ciduk air untuk membasuh wajahnya, kemudian menyiduk lagi satu ciduk untuk membasuh tangan kanan. Kemudian menyiduk lagi untuk membasuh tangan kiri, kemudian mengusap kepalanya beserta kedua telinganya, bagian dalam telinga dengan kedua jari telunjuknya dan bagian luar telinga dengan kedua ibu jari. Lalu beliau menyiduk lagi untuk membasuh kaki kanan dan menyiduk lagi untuk membasuh kaki kiri.\" "},"102":{"ar":"أَخْبَرَنَا قُتَيْبَةُ وَعُتْبَةُ بْنُ عَبْدِ اللَّهِ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ الصُّنَابِحِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَوَضَّأَ الْعَبْدُ الْمُؤْمِنُ فَتَمَضْمَضَ خَرَجَتْ الْخَطَايَا مِنْ فِيهِ فَإِذَا اسْتَنْثَرَ خَرَجَتْ الْخَطَايَا مِنْ أَنْفِهِ فَإِذَا غَسَلَ وَجْهَهُ خَرَجْتِ الْخَطَايَا مِنْ وَجْهِهِ حَتَّى تَخْرُجَ مِنْ تَحْتِ أَشْفَارِ عَيْنَيْهِ فَإِذَا غَسَلَ يَدَيْهِ خَرَجَتْ الْخَطَايَا مِنْ يَدَيْهِ حَتَّى تَخْرُجَ مِنْ تَحْتِ أَظْفَارِ يَدَيْهِ فَإِذَا مَسَحَ بِرَأْسِهِ خَرَجَتْ الْخَطَايَا مِنْ رَأْسِهِ حَتَّى تَخْرُجَ مِنْ أُذُنَيْهِ فَإِذَا غَسَلَ رِجْلَيْهِ خَرَجَتْ الْخَطَايَا مِنْ رِجْلَيْهِ حَتَّى تَخْرُجَ مِنْ تَحْتِ أَظْفَارِ رِجْلَيْهِ ثُمَّ كَانَ مَشْيُهُ إِلَى الْمَسْجِدِ وَصَلَاتُهُ نَافِلَةً لَهُ قَالَ قُتَيْبَةُ عَنْ الصُّنَابِحِيِّ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ","id":"Telah mengabarkan kepada kami [Qutaibah] dan [Uthbah bin Abdullah] dari [Malik] dari [Zaid bin Aslam] dari [Atha' bin Yasar] dari [Abdullah As Shunabihi], bahwasannya Rasulullah shallallahu 'alaihi wasallam bersabda: \" Apabila seorang hamba yang beriman berwudlu lalu ia berkumur-kumur, maka keluarlah kesalahan mulutnya (maksudnya kesalahan yang diperbuat oleh mulutnya). Bila dia menghirup air ke dalam hidung lalu mengeluarkannya, maka keluarlah kesalahan dari hidungnya. Bila membasuh muka, keluarlah kesalahan dari mukanya hingga keluar dari kedua kelopak matanya. Jika ia membasuh kedua tangannya, maka keluarlah kesalahannya dari kedua tangannya hingga keluar dari bawah kuku-kuku kedua tangannya. Apabila mengusap kepalanya, maka keluarlah kesalahannya dari kepalanya hingga keluar dari kedua telinganya, dan apabila membasuh kedua kakinya, maka keluarlah kesalahan dari kedua kakinya hingga dari bawah kedua kuku-kuku kedua kakinya. Kemudian berjalannya ke masjid menjadi ibadah sunnah baginya.\" Qutaibah berkata; dari As-Sunabihi; Demikian Rasulullah shallallahu 'alaihi wasallam mengatakan. "},"103":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ ح وَأَنْبَأَنَا الْحُسَيْنُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ عَنْ بِلَالٍ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ عَلَى الْخُفَّيْنِ وَالْخِمَارِ","id":"Telah mengabarkan kepada kami [Husain bin Manshur] dia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dia berkata, telah menceritakan kepada kami [Al 'Amasy]. Dalam jalur yang lain disebutkan; dan telah mengabarkan kepada kami [Al Husain bin Manshur] dia berkata, telah menceritakan kepada kami [Abdullah bin Numair] dia berkata, telah menceritakan kepada kami [Al 'Amasy] dari [Hakam] dari [Abdurrahman bin Abu Laila] dari [Ka'ab bin 'Ujrah] dari [Bilal] dia berkata: \" Aku melihat Rasulullah shallallahu 'alaihi wasallam mengusap kedua sepatunya (khuf) dan Surbannya.\""},"104":{"ar":"و أَخْبَرَنَا الْحُسَيْنُ بْنُ عَبْدِ الرَّحْمَنِ الْجَرْجَرَائِيُّ عَنْ طَلْقِ بْنِ غَنَّامٍ قَالَ حَدَّثَنَا زَائِدَةُ وَحَفْصُ بْنُ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ بْنِ عَازِبٍ عَنْ بِلَالٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ عَلَى الْخُفَّيْنِ","id":"Telah mengabarkan kepada kami [Al Husain bin Abdurrahman Al Jarjaraa'i] dari [Thalaq bin Ghanam] dia berkata; telah menceritakan kepada kami [Zaidah] dan [Hafs bin Ghiyats] dari [Al 'Amasy] dari [Al Hakam] dari [Abdurrahman bin Abu Laila] dari [Barra' bin 'Azib], dari [Bilal] dia berkata: \"Saya melihat Rasulullah shallallahu 'alaihi wasallam mengusap kedua khufnya (sepatunya).\" "},"105":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ وَكِيعٍ عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ بِلَالٍ قَالَرَأَيْتُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ عَلَى الْخِمَارِ وَالْخُفَّيْنِ","id":"Telah mengabarkan kepada kami [Hannad bin As Sariyyi], dari [Waki'] dari [Syu'bah] dari [Al Hakam] dari [Abdurrahman bin Abu Laila] dari [Bilal] dia berkata: \" Saya melihat Rasulullah shallallahu 'alaihi wasallam mengusap surban dan kedua khufnya (sepatunya).\""},"106":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُلَيْمَانُ التَّيْمِيُّ قَالَ حَدَّثَنَا بَكْرُ بْنُ عَبْدِ اللَّهِ الْمُزَنِيُّ عَنْ الْحَسَنِ عَنْ ابْنِ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ الْمُغِيرَةِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ فَمَسَحَ نَاصِيَتَهُ وَعِمَامَتَهُ وَعَلَى الْخُفَّيْنِقَالَ بَكْرٌ وَقَدْ سَمِعْتُهُ مِنِ ابْنِ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ أَبِيهِ","id":"Telah mengabarkan kepada kami [Amru bin Ali] dia berkata; telah menceritakan kepadaku [Yahya bin Said] berkata; telah menceritakan kepada kami [Sulaiman At Taimiy] berkata; telah menceritakan kepada kami [Bakar bin Abdullah Al Muzzani] dari [Al Hasan] dari [Ibnu Al Mughirah bin Syu'bah] dari [Al Mughirah], Rasulullah shallallahu 'alaihi wasallam berwudlu, lalu beliau mengusap ubun-ubunnya, surbannya dan kedua sepatunya. Bakar berkata; \"Saya telah mendengarnya dari Ibnu Al Mughirah, dari Syu'bah, dari (Bapaknya). "},"107":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَحُمَيْدُ بْنُ مَسْعَدَةَ عَنْ يَزِيدَ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنَا حُمَيْدٌ قَالَ حَدَّثَنَا بَكْرُ بْنُ عَبْدِ اللَّهِ الْمُزَنِيُّ عَنْ حَمْزَةَ بْنِ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ أَبِيهِ قَالَتَخَلَّفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَخَلَّفْتُ مَعَهُ فَلَمَّا قَضَى حَاجَتَهُ قَالَ أَمَعَكَ مَاءٌ فَأَتَيْتُهُ بِمِطْهَرَةٍ فَغَسَلَ يَدَيْهِ وَغَسَلَ وَجْهَهُ ثُمَّ ذَهَبَ يَحْسُرُ عَنْ ذِرَاعَيْهِ فَضَاقَ كُمُّ الْجُبَّةِ فَأَلْقَاهُ عَلَى مَنْكِبَيْهِ فَغَسَلَ ذِرَاعَيْهِ وَمَسَحَ بِنَاصِيَتِهِ وَعَلَى الْعِمَامَةِ وَعَلَى خُفَّيْهِ","id":"Telah mengabarkan kepada kami [Amru bin Ali] dan [Humaid bin Mas'adah] dari [Yazid yaitu Ibnu zurai'] dia berkata; telah menceritakan kepada kami [Humaid] berkata; telah menceritakan kepada kami [Bakar bin Abdullah Al Muzani] dari [Hamzah Al Mughirah bin Syu'bah] dari [Bapaknya] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah tertinggal (shalat berjama'ah) dan aku juga tertinggal bersama beliau. Setelah selesai dari hajatnya beliau berkata, 'Apakah kamu membawa air? ' lalu aku membawakan air untuk bersuci, maka beliau pun membasuh kedua tangannya dan membasuh mukanya. Kemudian beliau ingin membuka kedua lengan bajunya. Namun karena lengan bajunya terlalu sempit maka beliau menyingsingkannya di atas kedua pundaknya. Lalu beliau membasuh kedua lengannya dan mengusap bagian depan kepalanya serta surbannya, juga kedua sepatunya (khuf).\" "},"108":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ أَخْبَرَنَا يُونُسُ بْنُ عُبَيْدٍ عَنْ ابْنِ سِيرِينَ قَالَ أَخْبَرَنِي عَمْرُو بْنُ وَهْبٍ الثَّقَفِيُّ قَالَ سَمِعْتُ الْمُغِيرَةَ بْنَ شُعْبَةَ قَالَخَصْلَتَانِ لَا أَسْأَلُ عَنْهُمَا أَحَدًا بَعْدَ مَا شَهِدْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُنَّا مَعَهُ فِي سَفَرٍ فَبَرَزَ لِحَاجَتِهِ ثُمَّ جَاءَ فَتَوَضَّأَ وَمَسَحَ بِنَاصِيَتِهِ وَجَانِبَيْ عِمَامَتِهِ وَمَسَحَ عَلَى خُفَّيْهِ قَالَ وَصَلَاةُ الْإِمَامِ خَلْفَ الرَّجُلِ مِنْ رَعِيَّتِهِ فَشَهِدْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ فِي سَفَرٍ فَحَضَرَتْ الصَّلَاةُ فَاحْتَبَسَ عَلَيْهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَقَامُوا الصَّلَاةَ وَقَدَّمُوا ابْنَ عَوْفٍ فَصَلَّى بِهِمْ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى خَلْفَ ابْنِ عَوْفٍ مَا بَقِيَ مِنْ الصَّلَاةِ فَلَمَّا سَلَّمَ ابْنُ عَوْفٍ قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَضَى مَا سُبِقَ بِهِ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Husyaim] dia berkata; telah mengabarkan kepada kami [Yunus bin 'Ubaid] dari [Ibnu Sirin] berkata; telah mengabarkan kepadaku [Amru bin Wahab Ats Tsaqofi] berkata; \"Saya mendengar [Al Mughirah bin Syu'bah] berkata: \"Ada dua perkara yang tidak pernah aku tanyakan kepada siapapun setelah aku melihatnya dari Rasulullah shallallahu 'alaihi wasallam.\" Ia melanjutkan bicaranya: \"Kami pernah bersama beliau dalam suatu safar (bepergian). Beliau pergi untuk buang hajatnya kemudian datang dan beliau berwudlu dan mengusap bagian depan kepalanya (ubun-ubun) serta kedua sisi surbannya, juga mengusap kedua sepatunya.\" Lalu Mughirah berkata, \"Shalat seorang pemimpin di belakang seseorang dari rakyatnya.\" Mughirah berkata; \"Maka aku menyaksikan langsung dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau dalam safar, lalu datanglah waktu shalat, namun Rasulullah shallallahu 'alaihi wasallam terlambat datang kepada mereka, lalu mereka melakukan iqamah dan menyuruh Ibnu 'Auf maju (menjadi Imam). Maka ia pun shalat bersama para sahabat, lalu datanglah Rasulullah shallallahu 'alaihi wasallam dan ikut shalat di belakang Ibnu 'Auf. Setelah Ibnu 'Auf salam (selesai), beliau shallallahu 'alaihi wasallam berdiri untuk menyempurnakan sisa raka'at yang ketinggalan.\""},"109":{"ar":"أَخْبَرَنَا قُتَيْبَةَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ شُعْبَةَ ح وَأَنْبَأَنَا مُؤَمَّلُ بْنُ هِشَامٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ شُعْبَةَ عَنْ مُحَمَّدِ بْنِ زِيَادٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيْلٌ لِلْعَقِبِ مِنْ النَّارِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dari [Syu'bah], dan telah memberitakan kepada kami [Muammal bin Hisyam] dia berkata; telah menceritakan kepada kami [Ismail] dari [Syu'bah] dari [Muhammad bin Ziyad] dari [Abu Hurairah] berkata; Abul Qasim shallallahu 'alaihi wasallam telah bersabda: \" Celakalah tumit-tumit yang tak tersentuh air wudlu dari api neraka.\""},"110":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ ح وَأَنْبَأَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ وَاللَّفْظُ لَهُ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ أَبِي يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَوْمًا يَتَوَضَّئُونَ فَرَأَى أَعْقَابَهُمْ تَلُوحُ فَقَالَ وَيْلٌ لِلْأَعْقَابِ مِنْ النَّارِ أَسْبِغُوا الْوُضُوءَ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] dia berkata; telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Sufyan]. Dalam jalur yang lain disebutkan; dan telah memberitakan kepada kami [Amru bin Ali] dia berkata; telah menceritakan kepada kami [Abdurrahman] berkata; telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Hilal bin Yasaf] dari [Abu Yahya] dari [Abdullah bin Amru] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam melihat suatu kaum sedang berwudlu dan beliau melihat tumit-tumit mereka belum kena air, lalu beliau bersabda: \" Celakalah tumit-tumit yang tak tersentuh air wudlu dari api neraka. Sempurnakanlah wudlu kalian.\" "},"111":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي الْأَشْعَثُ قَالَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا وَذَكَرَتْأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُحِبُّ التَّيَامُنَ مَا اسْتَطَاعَ فِي طُهُورِهِ وَنَعْلِهِ وَتَرَجُّلِهِقَالَ شُعْبَةُ ثُمَّ سَمِعْتُ الْأَشْعَثَ بِوَاسِطٍ يَقُولُ يَحِبُّ التَّيَامُنَ فَذَكَرَ شَأْنَهُ كُلَّهُ ثُمَّ سَمِعْتُهُ بِالْكُوفَةِ يَقُولُ يُحِبُّ التَّيَامُنَ مَا اسْتَطَاعَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul 'Ala] dia berkata; telah menceritakan kepada kami [Kholid] berkata; telah menceritakan kepada kami [Syu'bah], dia berkata; telah mengabarkan kepada kami [Al Asy'ast] dia berkata; saya mendengar [Ayahku] berkata; dari [Masruq] dari [Aisyah Radliyallahu'anha] berkata: \"Rasulullah shallallahu 'alaihi wasallam mencintai tayamum (mendahulukan yang sebelah kanan) semampunya dalam bersuci, memakai sandal, serta menyisir rambutnya.\" Syu'bah berkata; Kemudian saya mendengar di kota Wasit Al Asy'ats berkata; \"Beliau mencintai tayamum.\" Lalu dia menyebutkan semua hal tersebut. Kemudian saya mendengar di Kufah dia berkata; \"Beliau mencintai tayamum semampunya.\""},"112":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي أَبُو جَعْفَرٍ الْمَدَنِيُّ قَالَ سَمِعْتُ ابْنَ عُثْمَانَ بْنِ حُنَيْفٍ يَعْنِي عُمَارَةَ قَالَ حَدَّثَنِي الْقَيْسِيُّأَنَّهُ كَانَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَأُتِيَ بِمَاءٍ فَقَالَ عَلَى يَدَيْهِ مِنْ الْإِنَاءِ فَغَسَلَهُمَا مَرَّةً وَغَسَلَ وَجْهَهُ وَذِرَاعَيْهِ مَرَّةً مَرَّةً وَغَسَلَ رِجْلَيْهِ بِيَمِينِهِ كِلْتَاهُمَا","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; telah menceritakan kepada kami [Muhammad] berkata; telah menceritakan kepada kami [Syu'bah] berkata; telah mengabarkan kepadaku [Abu Ja'far al Madani] berkata; saya mendengar [Ibnu Usman bin Hanif yaitu 'Umarah] berkata; telah menceritakan [Al Qoisiyy]; Pernah ia bersama Rasulullah shallallahu 'alaihi wasallam dalam sebuah perjalanan, (kata Alqaisi); lalu diberikan kepada Beliau air dalam bejana, Beliau mencuci kedua tangannya satu kali, membasuh muka dan kedua lengannya masing-masing satu kali, dan mencuci kedua kakinya dengan tangan kanannya. "},"113":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنِي يَحْيَى بْنُ سُلَيْمٍ عَنْ إِسْمَعِيلَ بْنِ كَثِيرٍ وَكَانَ يُكْنَى أَبَا هَاشِمٍ ح وَأَنْبَأَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي هَاشِمٍ عَنْ عَاصِمِ بْنِ لَقِيطٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأْتَ فَأَسْبِغْ الْوُضُوءَ وَخَلِّلْ بَيْنَ الْأَصَابِعِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Yahya bin Sulaim] dari [Ismail bin Katsir] yang biasa dipanggil dengan Abu Hasyim. Dalam jalur periwayatan yang lain disebutkan; dan telah menceritakan kepada kami [Muhammad bin Rafi'] berkata; telah menceritakan kepada kami [Yahya bin Adam] berkata; telah menceritakan kepada kami [Sufyan], dari [Abu Hasyim] dari ['Ashim bin Laqith] dari [Ayahnya] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Apabila kamu wudlu, sempurnakan wudlumu dan bersihkan celah-celah jari-jemari.\""},"114":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ آدَمَ عَنْ ابْنِ أَبِي زَائِدَةَ قَالَ حَدَّثَنِي أَبِي وَغَيْرُهُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي حَيَّةَ الْوَادِعِيِّ قَالَرَأَيْتُ عَلِيًّا تَوَضَّأَ فَغَسَلَ كَفَّيْهِ ثَلَاثًا وَتَمَضْمَضَ وَاسْتَنْشَقَ ثَلَاثًا وَغَسَلَ وَجْهَهُ ثَلَاثًا وَذِرَاعَيْهِ ثَلَاثًا ثَلَاثًا وَمَسَحَ بِرَأْسِهِ وَغَسَلَ رِجْلَيْهِ ثَلَاثًا ثَلَاثًا ثُمَّ قَالَ هَذَا وُضُوءُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Adam], dari [Ibnu Abu Zaidah] berkata; telah menceritakan kepada kami [ayahku] dan yang lainnya, dari [Abu Ishaq] dari [Abu Hayyah Al Waadli'i] berkata; \" Saya melihat [Ali] berwudlu, dia mencuci kedua telapak tangannya tiga kali, berkumur-kumur dan memasukkan air ke hidung tiga kali, membasuh muka tiga kali, membasuh kedua lengan tiga kali-tiga kali, mengusap kepalanya, dan membasuh kedua kakinya tiga kali-tiga kali.\" Kemudian dia berkata: \"Ini adalah Wudlunya Rasulullah shallallahu 'alaihi wasallam.\" "},"115":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ أَنَّ عَطَاءَ بْنَ يَزِيدَ اللَّيْثِيَّ أَخْبَرَهُ أَنَّ حُمْرَانَ مَوْلَى عُثْمَانَ أَخْبَرَهُأَنَّ عُثْمَانَ دَعَا بِوَضُوءٍ فَتَوَضَّأَ فَغَسَلَ كَفَّيْهِ ثَلَاثَ مَرَّاتٍ ثُمَّ مَضْمَضَ وَاسْتَنْشَقَ ثُمَّ غَسَلَ وَجْهَهُ ثَلَاثَ مَرَّاتٍ ثُمَّ غَسَلَ يَدَهُ الْيُمْنَى إِلَى الْمِرْفَقِ ثَلَاثَ مَرَّاتٍ ثُمَّ غَسَلَ يَدَهُ الْيُسْرَى مِثْلَ ذَلِكَ ثُمَّ مَسَحَ بِرَأْسِهِ ثُمَّ غَسَلَ رِجْلَهُ الْيُمْنَى إِلَى الْكَعْبَيْنِ ثَلَاثَ مَرَّاتٍ ثُمَّ غَسَلَ رِجْلَهُ الْيُسْرَى مِثْلَ ذَلِكَ ثُمَّ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ نَحْوَ وُضُوئِي هَذَا ثُمَّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَوَضَّأَ نَحْوَ وُضُوئِي هَذَا ثُمَّ قَامَ فَرَكَعَ رَكْعَتَيْنِ لَا يُحَدِّثُ فِيهِمَا نَفْسَهُ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amr bin As Sarh] dan [Al Harits bin Miskin] yang dibacakan kepadanya dan saya mendengar lafazhnya dari dia, dari [Ibnu Wahab] dari [Yunus] dari [Ibnu Syihab], bahwasannya ['Atha bin Yazid Al Laitsi] telah mengabarkan kepadanya, sesungguhnya [Humran] -budak Usman- telah mengabarkan kepadanya, bahwa [Usman] meminta air Wudlu dan dipakai untuk berwudlu. Dia mencuci kedua telapak tangannya tiga kali, berkumur, dan memasukkan air ke hidung, membasuh mukanya tiga kali, membasuh tangan kanannya sampai siku tiga kali, membasuh tangan kiri seperti itu juga, mengusap kepalanya, kemudian membasuh kaki kanan sampai mata kaki tiga kali, dan membasuh kaki kiri seperti itu juga. Kemudian dia berkata: \"Aku melihat Rasulullah shallallahu 'alaihi wasallam berwudlu seperti wudluku ini.\" Dia menambahkan bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berwudlu seperti wudluku ini, kemudian shalat dua raka'at -sedang ia dalam dua raka'at itu tidak mengajak hati bicara selain konsentrasi shalat-maka akan diampuni dosa-dosanya yang lalu.\""},"116":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ عُبَيْدِ اللَّهِ وَمَالِكٍ وَابْنِ جُرَيْجٍ عَنْ الْمَقْبُرِيِّ عَنْ عُبَيْدِ بْنِ جُرَيْجٍ قَالَقُلْتُ لِابْنِ عُمَرَ رَأَيْتُكَ تَلْبَسُ هَذِهِ النِّعَالَ السِّبْتِيَّةَ وَتَتَوَضَّأُ فِيهَا قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلْبَسُهَا وَيَتَوَضَّأُ فِيهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Alla] dia berkata; telah menceritakan kepada kami [Ibnu Idris], dari ['Ubaidillah] dan [Malik] dan [Ibnu Juraij] dari [Al Maqburi], dari ['Ubaid bin Juraij] dia berkata; \"Aku pernah berkata kepada [Ibnu Umar], Aku melihatmu berwudlu dengan mengenakan sandal sibtiyyah (sandal yang terbuat dari kulit) ini? Ia menjawab, \" Aku melihat Rasulullah shallallahu 'alaihi wasallam berwudlu dengan mengenakannya.\" "},"117":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَفْصٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِأَنَّهُ تَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِ فَقِيلَ لَهُ أَتَمْسَحُ فَقَالَ قَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُوَكَانَ أَصْحَابُ عَبْدِ اللَّهِ يُعْجِبُهُمْ قَوْلُ جَرِيرٍ وَكَانَ إِسْلَامُ جَرِيرٍ قَبْلَ مَوْتِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَسِيرٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Hafsh] dari [Al A'Masy] dari [Ibrahim] dari [Hammam] dari [Jarir bin Abdullah], bahwa dia pernah berwudlu dan mengusap kedua sepatunya. Lalu dia ditanya, \"Apakah kamu mengusapnya?\" dia menjawab, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam mengusapnya.\" Para sahabat Abdullah merasa kagum dengan perkataan Jarir ini, karena Jarir masuk Islam beberapa saat sebelum wafatnya Rasulullah shallallahu 'alaihi wasallam. "},"118":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا حَرْبُ بْنُ شَدَّادٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ أُمَيَّةَ الضَّمْرِيِّ عَنْ أَبِيهِأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ وَمَسَحَ عَلَى الْخُفَّيْنِ","id":"Telah mengabarkan kepada kami [Al 'Abbas bin Abdul 'Azhim] dia berkata; telah menceritakan kepada kami [Abdurrahman] berkata; telah menceritakan kepada kami [Harb bin Syaddad] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Ja'far bin Amru bin Umayyah Adl-Dlamri], dari [ayahnya], bahwa dia pernah melihat Rasulullah shallallahu 'alaihi wasallam berwudlu dan mengusap kedua sepatunya (Khuf). "},"119":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ دُحَيْمٌ وَسُلَيْمَانُ بْنُ دَاوُدَ وَاللَّفْظُ لَهُ عَنْ ابْنِ نَافِعٍ عَنْ دَاوُدَ بْنِ قَيْسٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أُسَامَةَ بْنِ زَيْدٍ قَالَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِلَالٌ الْأَسْوَاقَ فَذَهَبَ لِحَاجَتِهِ ثُمَّ خَرَجَ قَالَ أُسَامَةُ فَسَأَلْتُ بِلَالًا مَا صَنَعَ فَقَالَ بِلَالٌ ذَهَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحَاجَتِهِ ثُمَّ تَوَضَّأَ فَغَسَلَ وَجْهَهُ وَيَدَيْهِ وَمَسَحَ بِرَأْسِهِ وَمَسَحَ عَلَى الْخُفَّيْنِ ثُمَّ صَلَّى","id":"Telah mengabarkan kepada kami [Abdurrahman bin Ibrahim Duhaim] dan [Sulaiman bin Daud], sedangkan lafazhnya dari dia, dari [Ibnu Nafi'] dari [Daud bin Qais] dari [Zaid bin Aslam], dari [Atha' bin Yasar] dari [Usamah bin Zaid] dia berkata: \" Rasulullah shallallahu 'alaihi wasallam dan Bilal masuk ke daerah Aswaf, lalu beliau pergi untuk buang hajat, kemudian keluar.\" Usamah berkata: \"Aku bertanya kepada Bilal, 'Apa yang beliau perbuat? ' [Bilal] menjawab; 'Rasulullah shallallahu 'alaihi wasallam pergi untuk buang hajat, kemudian berwudlu. Beliau membasuh muka dan kedua tangannya, lalu mengusap kepalanya serta kedua sepatunya, kemudian shalat.\""},"120":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ أَبِي النَّضْرِ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ مَسَحَ عَلَى الْخُفَّيْنِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud] dan [Harist bin Miskin], dari [Ibnu Wahab], dari ['Amru bin Al Harits] dari [Abu An Nadlri], dari [Abu Salamah bin Abdur Rahman] dari [Abdullah bin 'Umar], dari [Sa'ad bin Abi Waqqash], dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau shallallahu 'alaihi wasallam mengusap kedua sepatunya. "},"121":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا إِسْمَعِيلُ وَهُوَ ابْنُ جَعْفَرٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ أَبِي النَّضْرِ عَنْ أَبِي سَلَمَةَ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْحِ عَلَى الْخُفَّيْنِ أَنَّهُ لَا بَأْسَ بِهِ","id":"Telah mengabarkan kepada kami, [Qutaibah] dia berkata; telah menceritakan kepada kami [Ismail] -yaitu Ibnu Ja'far- dari [Musa bin 'Uqbah] dari [Abu An Nadlri], dari [Abu Salamah] dari [Sa'ad bin Abi Waqqash], dari Rasulullah shallallahu 'alaihi wasallam, - tentang mengusap kedua sepatu-hal itu tidak apa-apa. "},"122":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ خَشْرَمٍ قَالَ حَدَّثَنَا عِيسَى عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحَاجَتِهِ فَلَمَّا رَجَعَ تَلَقَّيْتُهُ بِإِدَاوَةٍ فَصَبَبْتُ عَلَيْهِ فَغَسَلَ يَدَيْهِ ثُمَّ غَسَلَ وَجْهَهُ ثُمَّ ذَهَبَ لِيَغْسِلَ ذِرَاعَيْهِ فَضَاقَتْ بِهِ الْجُبَّةُ فَأَخْرَجَهُمَا مِنْ أَسْفَلِ الْجُبَّةِ فَغَسَلَهُمَا وَمَسَحَ عَلَى خُفَّيْهِ ثُمَّ صَلَّى بِنَا","id":"Telah mengabarkan kepada kami [Ali bin Khasyram] dia berkata; telah menceritakan kepada kami [Isa] dari [Al A'masy] dari [Muslim] dari [Masruq] dari [Mughirah bin Syu'bah], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam keluar untuk buang hajat, dan setelah kembali aku menjumpai beliau, dan aku sedang membawa ember, maka aku menuangkan air tersebut untuk beliau. Beliau lalu membasuh kedua tangannya, membasuh mukanya, kemudian membasuh kedua lengannya namun selempangnya terlalu sempit, maka beliau keluarkan lengannya dari bawah selempang, lantas beliau basuh keduanya, dan mengusap kedua sepatunya, setelah itu beliau mengerjakan shalat bersama kami.\" "},"123":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَحْيَى عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ عُرْوَةَ بْنِ الْمُغِيرَةِ عَنْ أَبِيهِ الْمُغِيرَةِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ خَرَجَ لِحَاجَتِهِ فَاتَّبَعَهُ الْمُغِيرَةُ بِإِدَاوَةٍ فِيهَا مَاءٌ فَصَبَّ عَلَيْهِ حَتَّى فَرَغَ مِنْ حَاجَتِهِ فَتَوَضَّأَ وَمَسَحَ عَلَى الْخُفَّيْنِ","id":"Telah mengabarkan kepada kami, [Qutaibah bin Said] dia berkata; telah menceritakan kepada kami [Al Laits bin Sa'ad] dari [Yahya] dari [Sa'ad bin Ibrahim], dari [Nafi' bin Jubair] dari ['Urwah bin Mughirah] dari [Mughirah bin Syu'bah], dari Rasulullah shallallahu 'alaihi wasallam. bahwa beliau shallallahu 'alaihi wasallam pernah keluar untuk buang hajat, maka Mughirah bin Syu'bah mengikutinya dengan membawa seember air. Lalu dia menuangkannya kepada beliau shallallahu 'alaihi wasallam hingga beliau selesai dari hajatnya. Kemudian beliau berwudlu dan mengusap kedua khufnya (sepatunya). "},"124":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ إِسْمَعِيلَ بْنَ مُحَمَّدِ بْنِ سَعْدٍ قَالَ سَمِعْتُ حَمْزَةَ بْنَ الْمُغِيرَةِ بْنِ شُعْبَةَ يُحَدِّثُ عَنْ أَبِيهِ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَقَالَ تَخَلَّفْ يَا مُغِيرَةُ وَامْضُوا أَيُّهَا النَّاسُ فَتَخَلَّفْتُ وَمَعِي إِدَاوَةٌ مِنْ مَاءٍ وَمَضَى النَّاسُ فَذَهَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحَاجَتِهِ فَلَمَّا رَجَعَ ذَهَبْتُ أَصُبُّ عَلَيْهِ وَعَلَيْهِ جُبَّةٌ رُومِيَّةٌ ضَيِّقَةُ الْكُمَّيْنِ فَأَرَادَ أَنْ يُخْرِجَ يَدَهُ مِنْهَا فَضَاقَتْ عَلَيْهِ فَأَخْرَجَ يَدَهُ مِنْ تَحْتِ الْجُبَّةِ فَغَسَلَ وَجْهَهُ وَيَدَيْهِ وَمَسَحَ بِرَأْسِهِ وَمَسَحَ عَلَى خُفَّيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] berkata; telah menceritakan kepada kami [Sufyan] berkata; saya mendengar [Ismail bin Muhammad bin Sa'ad] berkata; saya mendengar [Hamzah bin Al Mughirah bin Syu'bah] bercerita dari [ayahnya] berkata; \"Aku pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan. Beliau shallallahu 'alaihi wasallam bersabda: \"Wahai Mughirah, belakangan saja! Dan kalian wahai manusia teruslah berjalan.\" Aku pun memperlambat diri dan aku membawa seember air, sedang sahabat lain tetap berlalu. Kemudian Rasulullah shallallahu 'alaihi wasallam pergi buang hajat. Setelah beliau selesai, aku pergi menuangkan air untuk beliau, sedangkan beliau memakai jubah buatan Romawi yang sempit lengan bajunya, sehingga beliau tidak bisa mengeluarkan tangannya dari dalam lengan bajunya, maka beliau mengeluarkannya dari jubahnya. Beliau membasuh wajah dan kedua tangannya, mengusap kepalanya, dan mengusap kedua khufnya (sepatunya). "},"125":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وَكِيعٌ أَنْبَأَنَا سُفْيَانُ عَنْ أَبِي قَيْسٍ عَنْ هُذَيْلِ بْنِ شُرَحْبِيلَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ عَلَى الْجَوْرَبَيْنِ وَالنَّعْلَيْنِقَالَ أَبُو عَبْد الرَّحْمَنِ مَا نَعْلَمُ أَحَدًا تَابَعَ أَبَا قَيْسٍ عَلَى هَذِهِ الرِّوَايَةِ وَالصَّحِيحُ عَنْ الْمُغِيرَةِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ عَلَى الْخُفَّيْنِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Sufyan] dari [Abu Qais] dari [Hudzail bin Syurahbil] dari [Mughirah bin Syu'bah], bahwa Rasulullah shallallahu 'alaihi wasallam mengusap kedua kaos kakinya dan kedua sandalnya. Abdurrahman berkata; \"kami tidak mengetahui seorangpun yang mengikuti Abu Qais mengenai riwayat ini, dan yang benar adalah dari Al Mughirah bahwasannya Rasulullah shallallahu 'alaihi wasallam mengusap kedua khufnya (sepatunya). "},"126":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ صَفْوَانَ بْنِ عَسَّالٍ قَالَرَخَّصَ لَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كُنَّا مُسَافِرِينَ أَنْ لَا نَنْزِعَ خِفَافَنَا ثَلَاثَةَ أَيَّامٍ وَلَيَالِيَهُنَّ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata, telah menceritakan kepada kami [Sufyan] dari ['Ashim] dari [Zirr] dari [Shafwan bin Assal], dia berkata; \" Rasulullah shallallahu 'alaihi wasallam memberi keringanan kepada kami bila dalam perjalanan, untuk tidak melepas khuf (sepatu-sepatu) kami selama tiga hari tiga malam.\""},"127":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ الرُّهَاوِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا سُفْيَانُ الثَّوْرِيُّ وَمَالِكُ بْنُ مِغْوَلٍ وَزُهَيْرٌ وَأَبُو بَكْرِ بْنُ عَيَّاشٍ وَسُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَاصِمٍ عَنْ زِرٍّ قَالَسَأَلْتُ صَفْوَانَ بْنَ عَسَّالٍ عَنْ الْمَسْحِ عَلَى الْخُفَّيْنِ فَقَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنَا إِذَا كُنَّا مُسَافِرِينَ أَنْ نَمْسَحَ عَلَى خِفَافِنَا وَلَا نَنْزِعَهَا ثَلَاثَةَ أَيَّامٍ مِنْ غَائِطٍ وَبَوْلٍ وَنَوْمٍ إِلَّا مِنْ جَنَابَةٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman Ar Ruhawi] dia berkata; telah menceritakan kepada kami [Yahya bin Adam] berkata; telah menceritakan kepada kami [Sufyan bin Ats Tsauri], [Malik bin Mighwal], [Zuhair], dan [Abu Bakar bin 'Ayyasy] juga [Sufyan bin 'Uyainah] dari ['Ashim], dari [Zirr], dia berkata; \"Aku bertanya kepada [Shafwan bin Assal] tentang mengusap kedua sepatu, ia menjawab: \" Bila kami dalam perjalanan, maka Rasulullah shallallahu 'alaihi wasallam memerintahkan kami mengusap sepatu kami, dan tidak melepasnya selama tiga hari karena buang air besar atau buang air kecil, atau tidur, kecuali karena junub.\""},"128":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا الثَّوْرِيُّ عَنْ عَمْرِو بْنِ قَيْسٍ الْمُلَائِيِّ عَنْ الْحَكَمِ بْنِ عُتَيْبَةَ عَنْ الْقَاسِمِ بْنِ مُخَيْمِرَةَ عَنْ شُرَيْحِ بْنِ هَانِئٍ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْمُسَافِرِ ثَلَاثَةَ أَيَّامٍ وَلَيَالِيَهُنَّ وَيَوْمًا وَلَيْلَةً لِلْمُقِيمِ يَعْنِي فِي الْمَسْحِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Abdu Razaq] dia berkata; telah memberitakan kepada kami [Ats Tsauri] dari [Amru bin Qais Al Mulaa'i] dari [Al Hakam bin 'Utaibah] dari [Al Qaasim bin Mukhaimi Radliyallahu'anha] dari [Syuraih bin Hani'] dari [Ali] Radliyallahu'anhu dia berkata: \" Rasulullah shallallahu 'alaihi wasallam menentukan tiga hari tiga malam bagi musafir dan satu hari satu malam bagi yang bermukim (menetap) -yakni dalam hal mengusap sepatu-. "},"129":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ الْحَكَمِ عَنْ الْقَاسِمِ بْنِ مُخَيْمِرَةَ عَنْ شُرَيْحِ بْنِ هَانِئٍ قَالَسَأَلْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا عَنْ الْمَسْحِ عَلَى الْخُفَّيْنِ فَقَالَتْ ائْتِ عَلِيًّا فَإِنَّهُ أَعْلَمُ بِذَلِكَ مِنِّي فَأَتَيْتُ عَلِيًّا فَسَأَلْتُهُ عَنْ الْمَسْحِ فَقَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنَا أَنْ يَمْسَحَ الْمُقِيمُ يَوْمًا وَلَيْلَةً وَالْمُسَافِرُ ثَلَاثًا","id":"Telah mengabarkan kepada kami [Hannad bin As Sariyyi] dari [Abu Mu'awiyah] dari [Al A'masy] dari [Al Hakam] dari [Al Qasim bin Mukhaimi Radliyallahu'anha] dari [Syuraih bin Hani'], dia berkata; \"Aku bertanya kepada Aisyah Radliyallahu'anha tentang mengusap kedua sepatu? lalu dia menjawab, \" Datanglah kepada Ali, karena dia lebih tahu tentang hal tersebut daripada aku\". Lalu aku datang kepada [Ali] untuk menanyakan hal itu. Ia menjawab, \"Dulu Rasulullah shallallahu 'alaihi wasallam memerintahkan kami agar orang yang bermukim mengusap sepatunya selama sehari semalam dan bagi yang musafir selama tiga hari tiga malam.\""},"130":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ قَالَ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ مَيْسَرَةَ قَالَ سَمِعْتُ النَّزَّالَ بْنَ سَبْرَةَ قَالَرَأَيْتُ عَلِيًّا رَضِيَ اللَّهُ عَنْهُ صَلَّى الظُّهْرَ ثُمَّ قَعَدَ لِحَوَائِجِ النَّاسِ فَلَمَّا حَضَرَتْ الْعَصْرُ أُتِيَ بِتَوْرٍ مِنْ مَاءٍ فَأَخَذَ مِنْهُ كَفًّا فَمَسَحَ بِهِ وَجْهَهُ وَذِرَاعَيْهِ وَرَأْسَهُ وَرِجْلَيْهِ ثُمَّ أَخَذَ فَضْلَهُ فَشَرِبَ قَائِمًا وَقَالَ إِنَّ نَاسًا يَكْرَهُونَ هَذَا وَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُهُ وَهَذَا وُضُوءُ مَنْ لَمْ يُحْدِثْ","id":"Telah mengabarkan kepada kami ['Amru bin Yazid] dia berkata; telah menceritakan kepada kami [Bahzu bin Asad] berkata; telah menceritakan kepada kami [Syu'bah] dari [Abdul Malik bin Maisa Radliyallahu'anha] berkata; \"Saya mendengar [An Nazzal bin Sabrah] berkata: \"Aku melihat [Ali] Radliyallahu'anhu shalat dzuhur. Kemudian dia duduk untuk keperluan orang lain. Tatkala datang waktu Ashar, dibawakanlah kepadanya seember air, maka beliau mengambilnya dengan telapak tangannya dan mengusap wajahnya, kedua lengannya, kepalanya, dan kedua kakinya. Lalu beliau mengambil sisanya dan meminumnya sambil berdiri. Setelah itu dia berkata, \"Manusia tidak suka seperti ini! padahal aku melihat Rasulullah shallallahu 'alaihi wasallam melakukannya, dan inilah cara berwudlu bagi orang yang belum batal.\""},"131":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ عَامِرٍ عَنْ أَنَسٍأَنَّهُ ذَكَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِإِنَاءٍ صَغِيرٍ فَتَوَضَّأَ قُلْتُ أَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ لِكُلِّ صَلَاةٍ قَالَ نَعَمْ قَالَ فَأَنْتُمْ قَالَ كُنَّا نُصَلِّي الصَّلَوَاتِ مَا لَمْ نُحْدِثْ قَالَ وَقَدْ كُنَّا نُصَلِّي الصَّلَوَاتِ بِوُضُوءٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] telah menceritakan kepada kami [Syu'bah] dari [Amru bin 'Amir] dari [Anas] dia mengatakan bahwa Rasulullah shallallahu 'alaihi wasallam pernah dibawakan bejana kecil untuk berwudlu. Aku bertanya, \"Apakah Rasulullah shallallahu 'alaihi wasallam berwudlu pada setiap shalat?\" Ia menjawab, \" Ya\". Dia bertanya, \"Kalau kalian?\" Dia menjawab, \"Kami melakukan beberapa shalat selagi belum batal.\" Dia berkata, \"Dulu kami juga selalu melakukan beberapa shalat dengan satu wudlu.\""},"132":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيَّوبَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مِنْ الْخَلَاءِ فَقُرِّبَ إِلَيْهِ طَعَامٌ فَقَالُوا أَلَا نَأْتِيكَ بِوَضُوءٍ فَقَالَ إِنَّمَا أُمِرْتُ بِالْوُضُوءِ إِذَا قُمْتُ إِلَى الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub] dia berkata; telah menceritakan kepada kami [Ibnu 'Ulayyah] berkata; telah menceritakan kepada kami [Ayyub] dari [Ibnu Abu Mulaikah] dari [Ibnu Abbas], bahwa Rasulullah shallallahu 'alaihi wasallam keluar dari WC lalu dihidangkanlah makanan kepadanya. Kemudian orang-orang berkata; \"Maukah kami bawakan air wudlu untuk Anda?\" Beliau shallallahu 'alaihi wasallam menjawab: \" Aku hanya di perintahkan untuk berwudlu bila hendak menegakkan shalat.\""},"133":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنَا عَلْقَمَةُ بْنُ مَرْثَدٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ لِكُلِّ صَلَاةٍ فَلَمَّا كَانَ يَوْمُ الْفَتْحِ صَلَّى الصَّلَوَاتِ بِوُضُوءٍ وَاحِدٍ فَقَالَ لَهُ عُمَرُ فَعَلْتَ شَيْئًا لَمْ تَكُنْ تَفْعَلُهُ قَالَ عَمْدًا فَعَلْتُهُ يَا عُمَرُ","id":"Telah mengabarkan kepada kami ['Ubaidillah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya] dari [Sufyan] berkata; telah menceritakan kepada kami ['Alqmah bin Marsad] dari [Ibnu Buraidah], dari [ayahnya] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam selalu berwudlu bila hendak shalat, tetapi setelah peristiwa penaklukan kota Makkah beliau mengerjakan beberapa shalat dengan satu kali wudlu. Lalu Umar bertanya, \"Engkau melakukan sesuatu yang tidak biasa engkau lakukan sebelumnya?\" Beliau menjawab, \"Aku sengaja melakukannya wahai Umar!\""},"134":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ عَنْ شُعْبَةَ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ الْحَكَمِ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا تَوَضَّأَ أَخَذَ حَفْنَةً مِنْ مَاءٍ فَقَالَ بِهَا هَكَذَا وَوَصَفَ شُعْبَةُ نَضَحَ بِهِ فَرْجَهُفَذَكَرْتُهُ لِإِبْرَاهِيمَ فَأَعْجَبَهُ قَالَ الشَّيْخُ ابْنُ السُّنِّيِّ الْحَكَمُ هُوَ ابْنُ سُفْيَانَ الثَّقَفِيُّ رَضِيَ اللَّهُ عَنْهُ","id":"Telah mengabarkan kepada kami [Ismail bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid bin Al Harits] dari [Syu'bah] dari [Manshur] dari [Mujahid] dari [Al Hakam] dari [Ayahnya], apabila Rasulullah shallallahu 'alaihi wasallam berwudlu maka beliau mengambil air sepenuh kedua telapak tangan, lalu Syu'bah (perawi) mengatakan bahwa beliau memercikkan air ke kemaluannya. Kemudian hal itu di sampaikan kepada Ibrahim dan dia mengaguminya. Syaikh Ibnu Sunni Al Hakam berkata; \"Dia adalah Ibnu Sufyan Ats Tsaqofi Radliyallahu'anhu "},"135":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ مُحَمَّدٍ الدُّورِيُّ قَالَ حَدَّثَنَا الْأَحْوَصُ بْنُ جَوَّابٍ حَدَّثَنَا عَمَّارُ بْنُ رُزَيْقٍ عَنْ مَنْصُورٍ ح وَأَنْبَأَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا قَاسِمٌ وَهُوَ ابْنُ يَزِيدَ الْجَرْمِيُّ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا مَنْصُورٌ عَنْ مُجَاهِدٍ عَنْ الْحَكَمِ بْنِ سُفْيَانَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ وَنَضَحَ فَرْجَهُ قَالَ أَحْمَدُ فَنَضَحَ فَرْجَهُ","id":"Telah mengabarkan kepada kami [Al Abbas bin Muhammad Ad Duuri] dia berkata; telah menceritakan kepada kami [Al Ahwash bin Jawwab] telah menceritakan kepada kami [Ammar bin Ruzaiq] dari [Manshur]. Dalam jalur periwayatan yang lain disebutkan; dan telah memberitakan kepada kami [Ahmad bin Harb] berkata; telah menceritakan kepada kami [Qasim yaitu Ibnu Yazid Al Jarmi] berkata; telah menceritakan kepada kami [Sufyan] dia berkata; telah menceritakan kepada kami [Manshur] dari [Mujahid] dari [Al Hakam bin Sufyan] dia berkata: \"Aku melihat Rasulullah shallallahu 'alaihi wasallam berwudlu dan memercikkan air ke kemaluannya.\" Ahmad berkata dengan redaksi: \"Maka beliau memercikkan air ke kemaluannya\". "},"136":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ سُلَيْمَانُ بْنُ سَيْفٍ قَالَ حَدَّثَنَا أَبُو عَتَّابٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي حَيَّةَ قَالَرَأَيْتُ عَلِيًّا رَضِيَ اللَّهُ عَنْهُ تَوَضَّأَ ثَلَاثًا ثَلَاثًا ثُمَّ قَامَ فَشَرِبَ فَضْلَ وَضُوئِهِ وَقَالَ صَنَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا صَنَعْتُ","id":"Telah mengabarkan kepada kami [Abu Daud Sulaiman bin Saif] dia berkata; telah menceritakan kepada kami [Abu 'Attab] berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Abu Hayyah], dia berkata: \"Aku Melihat [Ali] Radliyallahu'anhu berwudlu tiga kali-tiga kali, kemudian berdiri dan meminum air sisa wudlunya, dan berkata; \"Rasulullah shallallahu 'alaihi wasallam melakukan, seperti yang ku lakukan sekarang.\""},"137":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ عَنْ سُفْيَانَ قَالَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ عَونِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ قَالَشَهِدْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْبَطْحَاءِ وَأَخْرَجَ بِلَالٌ فَضْلَ وَضُوئِهِ فَابْتَدَرَهُ النَّاسُ فَنِلْتُ مِنْهُ شَيْئًا وَرَكَزْتُ لَهُ الْعَنَزَةَ فَصَلَّى بِالنَّاسِ وَالْحُمُرُ وَالْكِلَابُ وَالْمَرْأَةُ يَمُرُّونَ بَيْنَ يَدَيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dari [Sufyan] berkata; telah menceritakan kepada kami [Malik bin Mighwal] dari ['Aun bin Abu Juhaifah], dari [ayahnya] dia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam di Bathha, lalu Bilal mengeluarkan air sisa wudlu Rasulullah shallallahu 'alaihi wasallam, maka orang-orang berebutan dan aku mendapatkannya sedikit. Kemudian aku menancapkan tombak kecil untuk Rasulullah shallallahu 'alaihi wasallam. Lalu beliau shalat bersama orang-orang, sedangkan banyak anjing, keledai dan perempuan yang lewat di depan tombak tadi.\""},"138":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ عَنْ سُفْيَانَ قَالَ سَمِعْتُ ابْنَ الْمُنْكَدِرِ يَقُولُ سَمِعْتُ جَابِرًا يَقُولُمَرِضْتُ فَأَتَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ يَعُودَانِي فَوَجَدَانِي قَدْ أُغْمِيَ عَلَيَّ فَتَوَضَّأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَبَّ عَلَيَّ وَضُوءَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dari [Sufyan] dia berkata; \"Saya mendengar [Ibnu Al Munkadir] berkata; \"Aku mendengar [Jabir] berkata; ' Aku sakit'. Kemudian Rasulullah shallallahu 'alaihi wasallam dan Abu Bakar datang menjengukku dan keduanya mendapati diriku pingsan, maka beliau berwudlu dan air sisa wudlunya disiramkan kepadaku.\""},"139":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقْبَلُ اللَّهُ صَلَاةً بِغَيْرِ طُهُورٍ وَلَا صَدَقَةً مِنْ غُلُولٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abu 'Awwanah] dari [Qatadah] dari [Abu Al Malih] dari [ayahnya] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Allah tidak menerima shalat tanpa bersuci, juga sedekah dari harta rampasan perang yang diambil secara sembunyi-sembunyi sebelum dibagikan.\""},"140":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا يَعْلَى قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مُوسَى بْنِ أَبِي عَائِشَةَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَجَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْأَلُهُ عَنْ الْوُضُوءِ فَأَرَاهُ الْوُضُوءَ ثَلَاثًا ثَلَاثًا ثُمَّ قَالَ هَكَذَا الْوُضُوءُ فَمَنْ زَادَ عَلَى هَذَا فَقَدْ أَسَاءَ وَتَعَدَّى وَظَلَمَ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] dia berkata; telah menceritakan kepada kami [Ya'la] berkata; telah menceritakan kepada kami [Sufyan] dari [Musa bin Abu Aisyah] dari [Amru bin Syu'aib] dari [ayahnya] dari [kakeknya] berkata; \"Seorang Badui datang kepada Rasulullah shallallahu 'alaihi wasallam untuk bertanya perihal wudlu. Lalu Rasulullah shallallahu 'alaihi wasallam memperlihatkan kepadanya cara berwudlu yang semuanya tiga kali - tiga kali. Kemudian Beliau bersabda, 'Beginilah cara berwudlu'.\"Barang siapa menambah lebih dari ini, dia berbuat kejelekan dan berlebihan, serta berbuat dzalim'.\""},"141":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ حَدَّثَنَا أَبُو جَهْضَمٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عُبَيْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَكُنَّا جُلُوسًا إِلَى عَبْدِ اللَّهِ بْنِ عَبَّاسٍ فَقَالَ وَاللَّهِ مَا خَصَّنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَيْءٍ دُونَ النَّاسِ إِلَّا بِثَلَاثَةِ أَشْيَاءَ فَإِنَّهُ أَمَرَنَا أَنْ نُسْبِغَ الْوُضُوءَ وَلَا نَأْكُلَ الصَّدَقَةَ وَلَا نُنْزِيَ الْحُمُرَ عَلَى الْخَيْلِ","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin 'Arabi] dia berkata; telah menceritakan kepada kami [Hammad] dia berkata; telah menceritakan kepada kami [Abu Jahdlam] dia berkata; telah menceritakan kepadaku [Abdullah bin Ubaidillah bin Abbas], dia berkata, \" Kami pernah duduk bersama [Abdullah bin Abbas], lalu ia berkata, 'Rasulullah shallallahu 'alaihi wasallam tidak mengkhususkan sesuatupun bagi kita ahlul bait kecuali dalam tiga hal, yaitu: Rasulullah shallallahu 'alaihi wasallam memerintahkan kita untuk menyempurnakan wudlu, tidak makan sedekah, dan tidak mengawinkan keledai dengan kuda.\""},"142":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ أَبِي يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوقَالَ قَال رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْبِغُوا الْوُضُوءَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Hilal bin Yasaf] dari [Abu Yahya] dari [Abdullah bin Amru], dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: ' Sempurnakanlah wudlu'.\""},"143":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أُخْبِرُكُمْ بِمَا يَمْحُو اللَّهُ بِهِ الْخَطَايَا وَيَرْفَعُ بِهِ الدَّرَجَاتِ إِسْبَاغُ الْوُضُوءِ عَلَى الْمَكَارِهِ وَكَثْرَةُ الْخُطَا إِلَى الْمَسَاجِدِ وَانْتِظَارُ الصَّلَاةِ بَعْدَ الصَّلَاةِ فَذَلِكُمْ الرِّبَاطُ فَذَلِكُمْ الرِّبَاطُ فَذَلِكُمْ الرِّبَاطُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Al 'Alla bin Abdurrahman] dari [Bapaknya] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Maukah kalian ku kabarkan tentang hal-hal yang membuat Allah menghapus kesalahan serta mengangkat derajat kalian? Yaitu menyempurnakan Wudlu meskipun dalam kondisi saat engkau tidak suka (karena cuaca dingin atau kemalasan), banyak langkah ke mesjid, menunggu shalat setelah shalat, dan diketahui itulah Ribath, itulah Ribath, itulah Ribath.\""},"144":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ سُفْيَانَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَاصِمِ بْنِ سُفْيَانَ الثَّقَفِيِّأَنَّهُمْ غَزَوْا غَزْوَةَ السُّلَاسِلِ فَفَاتَهُمْ الْغَزْوُ فَرَابَطُوا ثُمَّ رَجَعُوا إِلَى مُعَاوِيَةَ وَعِنْدَهُ أَبُو أَيُّوبَ وَعُقْبَةُ بْنُ عَامِرٍ فَقَالَ عَاصِمٌ يَا أَبَا أَيُّوبَ فَاتَنَا الْغَزْوُ الْعَامَ وَقَدْ أُخْبِرْنَا أَنَّهُ مَنْ صَلَّى فِي الْمَسَاجِدِ الْأَرْبَعَةِ غُفِرَ لَهُ ذَنْبُهُ فَقَالَ يَا ابْنَ أَخِي أَدُلُّكَ عَلَى أَيْسَرَ مِنْ ذَلِكَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ تَوَضَّأَ كَمَا أُمِرَ وَصَلَّى كَمَا أُمِرَ غُفِرَ لَهُ مَا قَدَّمَ مِنْ عَمَلٍأَكَذَلِكَ يَا عُقْبَةُ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Allaits] dari [Abu Zubair] dari [Sufyan bin Abdurrahman] dari [Ashim bin Sufyan Ats-Tsaqafi], bahwa mereka ikut perang Sulasil namun perang telah usai, sehingga mereka berjaga-jaga. Kemudian mereka kembali ke Mu'awiyyah, dan di sisinya ada Abu Ayyub dan Uqbah bin Amir Lalu Ashim berkata, \"Wahai [Abu Ayyub]! Kami ketinggalan perang tahun ini! Padahal Rasulullah shallallahu 'alaihi wasallam memberitahukan orang yang shalat di masjid yang empat dosa-dosanya akan diampuni? Ia berkata, 'Wahai keponakanku, maukah ku tunjukkan hal yang lebih mudah dari itu? Aku mendengar Rasulullah bersabda, \" Barangsiapa berwudlu sebagaimana diperintahkan, maka dosa-dosanya yang lalu diampuni.\" Bukankah begitu wahai [Uqbah]? ' Dia menjawab, 'ya', \""},"145":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ جَامِعِ بْنِ شَدَّادٍ قَالَ سَمِعْتُ حُمْرَانَ بْنَ أَبَانَ أَخْبَرَ أَبَا بُرْدَةَ فِي الْمَسْجِدِ أَنَّهُ سَمِعَ عُثْمَانَ يُحَدِّثُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَتَمَّ الْوُضُوءَ كَمَا أَمَرَهُ اللَّهُ عَزَّ وَجَلَّ فَالصَّلَوَاتُ الْخَمْسُ كَفَّارَاتٌ لِمَا بَيْنَهُنَّ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] telah menceritakan kepada kami [Khalid] dari [Syu'bah] dari [Jami' bin Syadad] berkata; saya telah mendengar [Humran bin Aban]. Telah mengabarkan Abu Burdah di masjid, bahwasannya dia mendengar [Usman] bercerita, dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \" Barangsiapa menyempurnakan wudlu sebagaimana yang diperintahkan Allah, shalat lima waktu baginya merupakan penghapus dosa diantara lima waktu tersebut.\" "},"146":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ حُمْرَانَ مَوْلَى عُثْمَانَ أَنَّ عُثْمَانَ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ امْرِئٍ يَتَوَضَّأُ فَيُحْسِنُ وُضُوءَهُ ثُمَّ يُصَلِّي الصَّلَاةَ إِلَّا غُفِرَ لَهُ مَا بَيْنَهُ وَبَيْنَ الصَّلَاةِ الْأُخْرَى حَتَّى يُصَلِّيَهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Humran] -Budak Usman-, bahwa [Usman] Radliyallahu'anhu berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: ' Tidaklah seseorang berwudlu lalu memperbaiki wudlunya kemudian shalat, melainkan diampuni dosa yang ada diantara shalat tersebut dengan shalat lainnya sehingga dia melakukan shalat tersebut'.\""},"147":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ قَالَ حَدَّثَنَا اللَّيْثُ هُوَ ابْنُ سَعْدٍ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ قَالَ أَخْبَرَنِي أَبُو يَحْيَى سُلَيْمُ بْنُ عَامِرٍ وَضَمْرَةُ بْنُ حَبِيبٍ وَأَبُو طَلْحَةَ نُعَيْمُ بْنُ زِيَادٍ قَالُوا سَمِعْنَا أَبَا أُمَامَةَ الْبَاهِلِيَّ يَقُولُ سَمِعْتُ عَمْرَو بْنَ عَبَسَةَ يَقُولُقُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ الْوُضُوءُ قَالَ أَمَّا الْوُضُوءُ فَإِنَّكَ إِذَا تَوَضَّأْتَ فَغَسَلْتَ كَفَّيْكَ فَأَنْقَيْتَهُمَا خَرَجَتْ خَطَايَاكَ مِنْ بَيْنِ أَظْفَارِكَ وَأَنَامِلِكَ فَإِذَا مَضْمَضْتَ وَاسْتَنْشَقْتَ مَنْخِرَيْكَ وَغَسَلْتَ وَجْهَكَ وَيَدَيْكَ إِلَى الْمِرْفَقَيْنِ وَمَسَحْتَ رَأْسَكَ وَغَسَلْتَ رِجْلَيْكَ إِلَى الْكَعْبَيْنِ اغْتَسَلْتَ مِنْ عَامَّةِ خَطَايَاكَ فَإِنْ أَنْتَ وَضَعْتَ وَجْهَكَ لِلَّهِ عَزَّ وَجَلَّ خَرَجْتَ مِنْ خَطَايَاكَ كَيَوْمَ وَلَدَتْكَ أُمُّكَقَالَ أَبُو أُمَامَةَ فَقُلْتُ يَا عَمْرَو بْنَ عَبَسَةَ انْظُرْ مَا تَقُولُ أَكُلُّ هَذَا يُعْطَى فِي مَجْلِسٍ وَاحِدٍ فَقَالَ أَمَا وَاللَّهِ لَقَدْ كَبِرَتْ سِنِّي وَدَنَا أَجَلِي وَمَا بِي مِنْ فَقْرٍ فَأَكْذِبَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَقَدْ سَمِعَتْهُ أُذُنَايَ وَوَعَاهُ قَلْبِي مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Amru bin Manshur] dia berkata; telah menceritakan kepada kami [Adam bin Abu Iyas] berkata; telah menceritakan kepada kami [Al laits yaitu Ibnu Sa'id] dia berkata; telah menceritakan kepada kami [Mu'awiyah bin Shalih] dia berkata; Telah mengabarkan kepadaku [Abu Yahya Sulaim bin Amir] dan [Dhamrah bin Habib] dan [Abu Thalhah Nu'aim bin Ziyad] mereka telah berkata; kami telah mendengar dari [Abu Umamah Al Bahili] dia berkata, \" Aku mendengar [Amru bin Abasah] berkata, Aku pernah bertanya, \" Wahai Rasulullah shallallahu 'alaihi wasallam bagaimana cara berwudlu?\" Beliau menjawab, \"Adapun wudlu, apabila kamu melakukan wudlu dan membasuh kedua telapak tanganmu lalu kamu mensucikan keduanya, maka keluarlah kesalahan-kesalahan dari celah-celah kuku-kukumu dan ujung jari-jarimu. Bila kamu berkumur dan memasukkan air ke dalam hidung. Serta membasuh mukamu dan kedua tanganmu sampai ke siku-siku dan mengusap kepalamu, dan membasuh kedua tanganmu sampai ke siku-siku dan mengusap kepalamu, kemudian membasuh kedua sampai ke kedua mata kaki, maka kamu membersihkan kesalahanmu. Jika kamu meletakkan mukamu ke hadapan Allah Azza wa Jalla, maka kamu keluar dari kesalahanmu seperti kamu baru dilahirkan ibumu.\"Abu Umamah berkata: \"Aku berkata, 'wahai Amru bin Abasah! Lihat yang kamu katakan, apakah ini diberikan dalam satu majlis? 'dia menjawab, 'demi Allah, umurku sudah tua dan ajal semakin dekat, apa gunanya aku berdusta atas nama Rasulullah shallallahu 'alaihi wasallam. Sungguh, kedua telingaku mendengar dari Rasulullah shallallahu 'alaihi wasallam dan hatiku masih sangat sadar bahwa itu dari Rasulullah shallallahu 'alaihi wasallam '.\""},"148":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَلِيِّ بْنِ حَرْبٍ الْمَرْوَزِيُّ قَالَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ رَبِيعَةَ بْنِ يَزِيدَ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ وَأَبِي عُثْمَانَ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ عَنْ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ قَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ فُتِّحَتْ لَهُ ثَمَانِيَةُ أَبْوَابِ الْجَنَّةِ يَدْخُلُ مِنْ أَيِّهَا شَاءَ","id":"Telah mengabarkan kepada kami [Muhammad bin Ali bin Harb Al Marwazi] dia berkata; telah menceritakan kepada kami [Zaid bin Hubab] dia berkata; telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari [Rabi'ah bin Yazid] dari [Abu Idris Al Khaulani] dan [Abu Utsman] dari ['Uqbah bin Amir Al Juhani] dari [Umar bin Khattab] Radliyallahu'anhu, dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barangsiapa berwudlu kemudian memperbaiki wudlunya lalu berdo'a, 'Aku bersaksi bahwa tiada Dzat yang berhak disembah selain Allah dan aku bersaksi bahwa Muhammad adalah hamba dan utusan-Nya, dibukakan baginya delapan pintu surga, dan dia masuk lewat pintu manapun yang engkau kehendaki.\""},"149":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ خَلَفٍ وَهُوَ ابْنُ خَلِيفَةَ عَنْ أَبِي مَالِكٍ الْأَشْجَعِيِّ عَنْ أَبِي حَازِمٍ قَالَكُنْتُ خَلْفَ أَبِي هُرَيْرَةَ وَهُوَ يَتَوَضَّأُ لِلصَّلَاةِ وَكَانَ يَغْسِلُ يَدَيْهِ حَتَّى يَبْلُغَ إِبْطَيْهِ فَقُلْتُ يَا أَبَا هُرَيْرَةَ مَا هَذَا الْوُضُوءُ فَقَالَ لِي يَا بَنِي فَرُّوخَ أَنْتُمْ هَاهُنَا لَوْ عَلِمْتُ أَنَّكُمْ هَاهُنَا مَا تَوَضَّأْتُ هَذَا الْوُضُوءَ سَمِعْتُ خَلِيلِي صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَبْلُغُ حِلْيَةُ الْمُؤْمِنِ حَيْثُ يَبْلُغُ الْوُضُوءُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Khalaf yaitu Ibnu Khalifah] dari [Abu Malik Al Asyja'i] dari [Abu Hazim], dia berkata, \"Aku di belakang [Abu Hurairah], saat dia sedang berwudlu untuk shalat. Ia membasuh kedua tangannya sampai ketiaknya. Aku bertanya kepadanya, 'Wahai Abu Hurairah! Wudlu apa ini? ' Ia menjawab, 'Wahai Bani Farrukh, kalian di sini? Andai aku tahu kalian di sini, aku tidak akan Wudlu seperti ini. Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: ' Hiasan wudlu seorang mukmin akan sampai ke tempat badan yang terkena aliran air wudlu', \""},"150":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى الْمَقْبُرَةِ فَقَالَ السَّلَامُ عَلَيْكُمْ دَارَ قَوْمٍ مُؤْمِنِينَ وَإِنَّا إِنْ شَاءَ اللَّهُ بِكُمْ لَاحِقُونَ وَدِدْتُ أَنِّي قَدْ رَأَيْتُ إِخْوَانَنَا قَالُوا يَا رَسُولَ اللَّهِ أَلَسْنَا إِخْوَانَكَ قَالَ بَلْ أَنْتُمْ أَصْحَابِي وَإِخْوَانِي الَّذِينَ لَمْ يَأْتُوا بَعْدُ وَأَنَا فَرَطُهُمْ عَلَى الْحَوْضِ قَالُوا يَا رَسُولَ اللَّهِ كَيْفَ تَعْرِفُ مَنْ يَأْتِي بَعْدَكَ مِنْ أُمَّتِكَ قَالَ أَرَأَيْتَ لَوْ كَانَ لِرَجُلٍ خَيْلٌ غُرٌّ مُحَجَّلَةٌ فِي خَيْلٍ بُهْمٍ دُهْمٍ أَلَا يَعْرِفُ خَيْلَهُ قَالُوا بَلَى قَالَ فَإِنَّهُمْ يَأْتُونَ يَوْمَ الْقِيَامَةِ غُرًّا مُحَجَّلِينَ مِنْ الْوُضُوءِ وَأَنَا فَرَطُهُمْ عَلَى الْحَوْضِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Al 'Alla bin Abdurrahman] dari [Bapaknya] dari [Abu Hurairah Radliyallahu'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam keluar dari pekuburan, lantas beliau mengucapkan, \" Assalamu'alaikum wahai penghuni negeri kaum mukmin. Kami insya Allah akan menyusul kalian. Aku ingin melihat saudara-saudaraku!\" mereka berkata, \"Wahai Rasulullah, Bukankah kita semua ini bersaudara?\" beliau menjawab, \"Ya, kalian adalah sahabat dan saudaraku dan tidak akan datang lagi setelah ini. Aku akan mendahului kalian menuju Haudl.\" Mereka berkata, Wahai Rasulullah shallallahu 'alaihi wasallam! bagaimana engkau tahu orang-orang setelah engkau dari umatmu?\" beliau bersabda: \"Apakah kamu tahu kalau seseorang mempunyai seekor kuda yang ada putih-putihnya di ujung kepalanya yang berada di antara kuda-kuda yang hitam pekat? Bukankah ia akan mengenali kuda-kudanya?\" mereka berkata, \"Ya, tentu.\" Beliau meneruskan sabdanya: \"Mereka akan datang pada hari kiamat dengan wajah bersinar di wajahnya dari bekas wudlu, dan aku tidak mendahului mereka masuk ke dalam telaga (Haudl).\""},"151":{"ar":"أَخْبَرَنَا مُوسَى بْنُ عَبْدِ الرَّحْمَنِ الْمَسْرُوقِيُّ قَالَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ قَالَ حَدَّثَنَا رَبِيعَةُ بْنُ يَزِيدَ الدِّمَشْقِيُّ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ وَأَبِي عُثْمَانَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ الْحَضْرَمِيِّ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ صَلَّى رَكْعَتَيْنِ يُقْبِلُ عَلَيْهِمَا بِقَلْبِهِ وَوَجْهِهِ وَجَبَتْ لَهُ الْجَنَّةُ","id":"Telah mengabarkan kepada kami [Musa bin Abdurrahman Al Masruqi] dia berkata; telah menceritakan kepada kami [Zaid bin Al Hubab] dia berkata; telah menceritakan kepada kami [Mu'awiyah bin Shalih] dia berkata; telah menceritakan kepada kami [Rabi'ah bin Yazid Ad-Dimasqy] dari [Abu Idris Al Khaulani] dan [Abu Usman] dari [Jubair bin Nufair Al Hadhrami] dari [Uqbah bin Amir Al juhaini], dia mengatakan bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barangsiapa berwudlu dan memperbaiki wudlunya kemudian shalat dua raka'at, menghadap kepadanya dengan hati dan wajahnya, wajib baginya surga.\""},"152":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَيَّاشٍ عَنْ أَبِي حَصِينٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ قَالَ قَالَ عَلِيٌّكُنْتُ رَجُلًا مَذَّاءً وَكَانَتْ ابْنَةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَحْتِي فَاسْتَحْيَيْتُ أَنْ أَسْأَلَهُ فَقُلْتُ لِرَجُلٍ جَالِسٍ إِلَى جَنْبِي سَلْهُ فَسَأَلَهُ فَقَالَ فِيهِ الْوُضُوءُ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Abu Bakr bin 'Ayyasy] dari [Abu Hashin] dari [Abu Abdurrahman] dia berkata; [Ali] berkata, \"Aku laki-laki yang gampang keluar Madzi-nya, dan anak perempuan Nabi shallallahu 'alaihi wasallam adalah istriku, maka aku malu bertanya kepada beliau. Lalu aku bertanya kepada orang yang berada di sampingku, 'Tanyakanlah hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam\" lantas diapun bertanya kepada Rasulullah shallallahu 'alaihi wasallam, dan beliau berkata: ' Harus wudlu'.\""},"153":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَخْبَرَنَا جَرِيرٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَقُلْتُ لِلْمِقْدَادِ إِذَا بَنَى الرَّجُلُ بِأَهْلِهِ فَأَمْذَى وَلَمْ يُجَامِعْ فَسَلْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَإِنِّي أَسْتَحِي أَنْ أَسْأَلَهُ عَنْ ذَلِكَ وَابْنَتُهُ تَحْتِي فَسَأَلَهُ فَقَالَ يَغْسِلُ مَذَاكِيرَهُ وَيَتَوَضَّأُ وُضُوءَهُ لِلصَّلَاةِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah mengabarkan kepada kami [Jarir] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Ali] Radliyallahu'anhu, dia berkata; \"Aku berkata kepada Miqdad, \"Bila seseorang mendatangi istrinya lalu keluar madzinya dan belum bersetubuh, tolong tanyakanlah hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam. Aku malu untuk bertanya kepada beliau tentang hal tersebut, karena anak perempuannya adalah istriku\". Kemudian dia bertanya dan Rasulullah shallallahu 'alaihi wasallam bersabda; \"Hendaklah ia mencuci kemaluannya dan berwudlu sebagaimana wudlu untuk shalat'.\""},"154":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ عَطَاءٍ عَنْ عَائِشِ بْنِ أَنَسٍ أَنَّ عَلِيًا قَالَكُنْتُ رَجُلًا مَذَّاءً فَأَمَرْتُ عَمَّارَ بْنَ يَاسِرٍ يَسْأَلُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَجْلِ ابْنَتِهِ عِنْدِي فَقَالَ يَكْفِي مِنْ ذَلِكَ الْوُضُوءُ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Amru] dari ['Atha] dari ['Aisy bin Anas] bahwasannya [Ali] berkata; \"Aku laki-laki yang gampang keluar Madzi-nya, maka aku menyuruh 'Ammar bin Yasir bertanya kepada Rasulullah shallallahu 'alaihi wasallam karena anak perempuannya adalah istriku. Lalu beliau shallallahu 'alaihi wasallam bersabda: \" Cukup dari yang demikian itu dengan berwudlu.\" "},"155":{"ar":"أَخْبَرَنَا عُثْمَانُ بْنُ عَبْدِ اللَّهِ قَالَ أَنْبَأَنَا أُمَيَّةُ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ أَنَّ رَوْحَ بْنَ الْقَاسِمِ حَدَّثَهُ عَنْ ابْنِ أَبِي نُجَيْحٍ عَنْ عَطَاءٍ عَنْ إِيَاسِ بْنِ خَلِيفَةَ عَنْ رَافِعِ بْنِ خَدِيجٍأَنَّ عَلِيًّا أَمَرَ عَمَّارًا أَنْ يَسْأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمَذْيِ فَقَالَ يَغْسِلُ مَذَاكِيرَهُ وَيَتَوَضَّأُ","id":"Telah mengabarkan kepada kami [Usman bin Abdullah] dia berkata, telah memberitakan kepada kami [Umayyah] dia berkata, telah menceritakan kepada kami [Yazid bin Zuro'i] bahwa [Rauh bin Al Qosim] telah menceritakannya dari [Ibnu Abu Nujaih] dari ['Atho] dari [Iyas bin Khalifah] dari [Rafi' bin Khadij] bahwa Ali pernah menyuruh Amar untuk menanyakan tentang Madzi kepada Rasulullah shallallahu 'alaihi wasallam, beliau menjawab: \"Hendaknya ia mencuci kemaluannya lalu berwudlu'.\""},"156":{"ar":"أَخْبَرَنَا عُتْبَةُ بْنُ عَبْدِ اللَّهِ الْمَرْوَزِيُّ عَنْ مَالِكٍ وَهُوَ ابْنُ أَنَسٍ عَنْ أَبِي النَّضْرِ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ الْمِقْدَادِ بْنِ الْأَسْوَدِأَنَّ عَلِيًّا أَمَرَهُ أَنْ يَسْأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرَّجُلِ إِذَا دَنَا مِنْ أَهْلِهِ فَخَرَجَ مِنْهُ الْمَذْيُ مَاذَا عَلَيْهِ فَإِنَّ عِنْدِي ابْنَتَهُ وَأَنَا أَسْتَحِي أَنْ أَسْأَلَهُ فَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَقَالَ إِذَا وَجَدَ أَحَدُكُمْ ذَلِكَ فَلْيَنْضَحْ فَرْجَهُ وَيَتَوَضَّأْ وُضُوءَهُ لِلصَّلَاةِ","id":"Telah mengabarkan kepada kami ['Utbah bin Abdullah Al Marwazi] dari [Malik yaitu Ibnu Anas] dari [Abu Nadhr] dari [Sulaiman bin Yasar] dari [Miqad bin Al Aswad], bahwa Ali memerintahkannya untuk bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang orang yang ingin mendekati istrinya, tetapi keluarlah air madzi, apakah yang harus ia perbuat? Anak perempuan nabi adalah istriku, sehingga aku malu menanyakan hal tersebut, dan beliau menjawab, \" Bila salah seorang dari kalian mendapatkan seperti itu, hendaklah ia memercikkan kemaluannya dengan air, lalu berwudlu sebagai mana wudlu shalat.\""},"157":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعَلَى قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ قَالَ أَخْبَرَنِي سُلَيْمَانُ قَالَ سَمِعْتُ مُنْذِرًا عَنْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ عَلِيٍّ قَالَاسْتَحْيَيْتُ أَنْ أَسْأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْ��ِ وَسَلَّمَ عَنْ الْمَذْيِ مِنْ أَجْلِ فَاطِمَةَ فَأَمَرْتُ الْمِقْدَادَ بْنَ الْأَسْوَدِ فَسَأَلَهُ فَقَالَ فِيهِ الْوُضُوءُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] dia berkata; Telah mengabarkan kepadaku [Sulaiman] dia berkata; Saya mendengar [Mundzir] dari [Muhammad bin Ali] dari [Ali] dia berkata; \"Aku malu bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang madzi karena Fatimah, jadi aku menyuruh Miqdad bin Al Aswad untuk bertanya. Lalu dia bertanya, dan Rasulullah shallallahu 'alaihi wasallam menjawab: Mengenai hal itu, maka ia harus wudlu.\""},"158":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ أَنَّهُ سَمِعَ زِرَّ بْنَ حُبَيْشٍ يُحَدِّثُ قَالَأَتَيْتُ رَجُلًا يُدْعَى صَفْوَانَ بْنَ عَسَّالٍ فَقَعَدْتُ عَلَى بَابِهِ فَخَرَجَ فَقَالَ مَا شَأْنُكَ قُلْتُ أَطْلُبُ الْعِلْمَ قَالَ إِنَّ الْمَلَائِكَةَ تَضَعُ أَجْنِحَتَهَا لِطَالِبِ الْعِلْمِ رِضًا بِمَا يَطْلُبُ فَقَالَ عَنْ أَيِّ شَيْءٍ تَسْأَلُ قُلْتُ عَنْ الْخُفَّيْنِ قَالَ كُنَّا إِذَا كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ أَمَرَنَا أَنْ لَا نَنْزِعَهُ ثَلَاثًا إِلَّا مِنْ جَنَابَةٍ وَلَكِنْ مِنْ غَائِطٍ وَبَوْلٍ وَنَوْمٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] telah menceritakan kepada kami [Syu'bah] dari ['Ashim] bahwasannya dia mendengar [Zirr bin Hubaisy] berkata; \"Aku datang kepada seseorang yang biasa dipanggil [Shafwan bin Assal], dan aku duduk di depan pintunya. Kemudian dia keluar dan berkata, 'Ada apa denganmu? ' Aku menjawab, 'Aku ingin menuntut ilmu'. Ia berkata, para malaikat meletakkan sayap-sayapnya kepada para pemburu ilmu, sebagai tanda keridhaan terhadap mereka'. Lalu dia berkata, ' kamu mau tanya masalah apa? ' Aku berkata, 'tentang dua sepatu khuf.' Dia menjawab, 'Dulu jika kami dalam perjalanan bersama Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk tidak melepasnya selama tiga hari, kecuali karena junub. Akan tetapi (boleh tidak lepas) karena buang air besar atau buang air kecil atau tertidur'.\""},"159":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَإِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَا حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ عَنْ زِرٍّ قَالَقَالَ صَفْوَانُ بْنُ عَسَّالٍ كُنَّا إِذَا كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ أَمَرَنَا أَنْ لَا نَنْزِعَهُ ثَلَاثًا إِلَّا مِنْ جَنَابَةٍ وَلَكِنْ مِنْ غَائِطٍ وَبَوْلٍ وَنَوْمٍ","id":"Telah mengabarkan kepada kami [Amru bin Ali] dan [Ismail bin Mas'ud] keduanya berkata; telah menceritakan kepada kami [Yazid bin Zura'i] berkata; telah menceritakan kepada kami [Syu'bah] dari ['Ashim] dari [Zirr] berkata; [Shafwan bin Assal] berkata, \"kami dulu bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, dan beliau memerintahkan kami untuk tidak melepas sepatu (khuf) selama tiga hari kecuali karena junub. Akan tetapi boleh kalau karena buang air besar dan buang air kecil, atau dari tidur.\""},"160":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ ح و أَخْبَرَنِي مُحَمَّدُ بْنُ مَنْصُورٍ عَنْ سُفْيَانَ قَالَ حَدَّثَنَا الزُّهْرِيُّ قَالَ أَخْبَرَنِي سَعِيدٌ يَعْنِي ابْنَ الْمُسَيَّبِ وَعَبَّادُ بْنُ تَمِيمٍ عَنْ عَمِّهِ وَهُوَ عَبْدُ اللَّهِ بْنُ زَيْدٍ قَالَشُكِيَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّجُلُ يَجِدُ الشَّيْءَ فِي الصَّلَاةِ قَالَ لَا يَنْصَرِفْ حَتَّى يَجِدَ رِيحًا أَوْ يَسْمَعَ صَوْتًا","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Sufyan] dari [Az-Zuhri]. Dari jalur periwayatan yang lain juga disebutkan; dan Telah mengabarkan kepadaku [Muhammad bin Manshur] dari [Sufyan] berkata; telah menceritakan kepada kami [Az-Zuhri] berkata; Telah mengabarkan kepada ku [Sa'id yaitu Ibnu Musayyab] dan ['Abbad bin Tamim] dari pamannya yaitu [Abdullah bin Zaid] dia berkata; \"Diadukan kepada Rasulullah shallallahu 'alaihi wasallam tentang seorang laki-laki yang mendapati sesuatu ketika sedang shalat?\" Beliau bersabda: \" Janganlah keluar (dari shalat) hingga ia mencium bau atau mendengar suara (kentut).\""},"161":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ وَحُمَيْدُ بْنُ مَسْعَدَةَ قَالَا حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا اسْتَيْقَظَ أَحَدُكُمْ مِنْ مَنَامِهِ فَلَا يُدْخِلْ يَدَهُ فِي الْإِنَاءِ حَتَّى يُفْرِغَ عَلَيْهَا ثَلَاثَ مَرَّاتٍ فَإِنَّهُ لَا يَدْرِي أَيْنَ بَاتَتْ يَدُهُ","id":"Telah mengabarkan kepada kami [Ismail bin Mas'ud] dan [Humaid bin Mas'adah] keduanya berkata; telah menceritakan kepada kami [Yazid bin Zura'i] berkata; telah menceritakan kepada kami [Ma'mar] dari [Az-Zuhri] dari [Abu Salamah] dari [Abu Hurairah] Radliyallahu'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda; \" Apabila salah seorang dari kalian bangun dari tidurnya, janganlah memasukkan tangannya ke bejana air sehingga dia menuangkan ke tangannya sebanyak tiga kali, karena dia tidak tahu dimana tangannya berada (pada waktu dia tidur).\""},"162":{"ar":"أَخْبَرَنَا بِشْرُ بْنُ هِلَالٍ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَيُّوبَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا نَعَسَ الرَّجُلُ وَهُوَ فِي الصَّلَاةِ فَلْيَنْصَرِفْ لَعَلَّهُ يَدْعُو عَلَى نَفْسِهِ وَهُوَ لَا يَدْرِي","id":"Telah mengabarkan kepada kami [Bisyir bin Hilal] dia berkata; telah menceritakan kepada kami [Abdul Warits] dari [Ayyub] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah Radliyallahu'anha] dia berkata; Bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Apabila seseorang mengantuk dalam shalatnya hendaklah ia menghentikan, karena mungkin dia berdo'a untuk kecelakaan (kebinasaan) bagi dirinya sendiri sedang dia tidak menyadarinya!\""},"163":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مَعْنٌ أَنْبَأَنَا مَالِكٌ ح وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ أَنْبَأَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ أَنَّهُ سَمِعَ عُرْوَةَ بْنَ الزُّبَيْرِ يَقُولُ دَخَلْتُ عَلَى مَرْوَانَ بْنِ الْحَكَمِ فَذَكَرْنَا مَا يَكُونُ مِنْهُ الْوُضُوءُ فَقَالَ مَرْوَانُ مِنْ مَسِّ الذَّكَرِ الْوُضُوءُ فَقَالَ عُرْوَةُ مَا عَلِمْتُ ذَلِكَ فَقَالَ مَرْوَانُ أَخْبَرَتْنِي بُسْرَةُ بِنْتُ صَفْوَانَأَنَّهَا سَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا مَسَّ أَحَدُكُمْ ذَكَرَهُ فَلْيَتَوَضَّأْ","id":"Telah mengabarkan kepada kami [Harun bin Abdullah] telah menceritakan kepada kami [Ma'an] Telah memberitakan kepada kami [Malik] dan [Al Harits bin Miskin] telah dibacakan kepadanya dan saya mendengarnya dari [Ibnu Qasim] berkata; Telah memberitakan kepada kami [Malik] dari [Abdullah bin Abu Bakr bin Muhammad bin Amr bin Hazim] bahwasannya dia mendengar [Urwah bin zubair] berkata; \"Aku menemui Marwan bin Hakam, lalu kami menyebutkan hal yang mengharuskan untuk berwudlu. Lalu Marwan berkata, menyentuh kemaluan\". Urwah berkata, \"Aku tidak tahu hal tersebut. Lalu [Marwan] berkata lagi, Telah mengabarkan kepadaku ' [Busrah binti Shafwan] bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda, \" Apabila salah seorang dari kalian menyentuh kemaluannya, hendaklah ia berwudlu.\""},"164":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ الْمُغِيرَةِ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ سَعِيدٍ عَنْ شُعَيْبٍ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ أَبِي بَكْرِ بْنِ عَمْرِو بْنِ حَزْمٍ أَنَّهُ سَمِعَ عُرْوَةَ بْنَ الزُّبَيْرِ يَقُولُ ذَكَرَ مَرْوَانُ فِي إِمَارَتِهِ عَلَى الْمَدِينَةِ أَنَّهُ يُتَوَضَّأُ مِنْ مَسِّ الذَّكَرِ إِذَا أَفْضَى إِلَيْهِ الرَّجُلُ بِيَدِهِ فَأَنْكَرْتُ ذَلِكَ وَقُلْتُ لَا وُضُوءَ عَلَى مَنْ مَسَّهُ فَقَالَ مَرْوَانُ أَخْبَرَتْنِي بُسْرَةُ بِنْتُ صَفْوَانَأَنَّهَا سَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ مَا يُتَوَضَّأُ مِنْهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيُتَوَضَّأُ مِنْ مَسِّ الذَّكَرِقَالَ عُرْوَةُ فَلَمْ أَزَلْ أُمَارِي مَرْوَانَ حَتَّى دَعَا رَجُلًا مِنْ حَرَسِهِ فَأَرْسَلَهُ إِلَى بُسْرَةَ فَسَأَلَهَا عَمَّا حَدَّثَتْ مَرْوَانَ فَأَرْسَلَتْ إِلَيْهِ بُسْرَةُ بِمِثْلِ الَّذِي حَدَّثَنِي عَنْهَا مَرْوَانُ","id":"Telah mengabarkan kepada kami [Ahmad bin Muhammad bin Al Mughirah] dia berkata; telah menceritakan kepada kami [Usman bin Sa'id] dari [Syu'aib] dari [Az-Zuhri] dia berkata; Telah mengabarkan kepadaku [Abdullah bin Abu Bakr bin Amr bin Hazim] bahwasannya dia mendengar [Urwah bin Zubair] berkata; \"Marwan menyebutkan pada masa pemerintahannya di Madinah, bahwa hendaklah berwudlu karena memegang kemaluan dengan tangannya. Aku mengingkarinya dan aku mengatakan, 'tidak ada wudlu bagi yang menyentuhnya! ' lalu [Marwan] berkata, ['Busrah bin Shafwan] mengabarkan kepadaku bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda, \" Hendaklah berwudlu karena menyentuh kemaluan.\" Urwah berkata, \"Tapi aku masih saja mendebat Marwan hingga dia memanggil seorang pengawalnya. dia mengutus kepada Busrah untuk menanyakan tentang hal yang dia kabarkan kepada Marwan, Kemudian Busrah mengabarkan seperti apa yang telah di kabarkan oleh Marwan kepadaku.\""},"165":{"ar":"أَخْبَرَنَا هَنَّادٌ عَنْ مُلَازِمٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَدْرٍ عَنْ قَيْسِ بْنِ طَلْقِ بْنِ عَلِيٍّ عَنْ أَبِيهِ قَالَخَرَجْنَا وَفْدًا حَتَّى قَدِمْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَايَعْنَاهُ وَصَلَّيْنَا مَعَهُ فَلَمَّا قَضَى الصَّلَاةَ جَاءَ رَجُلٌ كَأَنَّهُ بَدَوِيٌّ فَقَالَ يَا رَسُولَ اللَّهِ مَا تَرَى فِي رَجُلٍ مَسَّ ذَكَرَهُ فِي الصَّلَاةِ قَالَ وَهَلْ هُوَ إِلَّا مُضْغَةٌ مِنْكَ أَوْ بَضْعَةٌ مِنْكَ","id":"Telah mengabarkan kepada kami [Hannad] dari [Mulazim] dia berkata; telah menceritakan kepada kami [Abdullah bin Badr] dari [Qais bin Thalq bin Ali] dari [Bapaknya] dia berkata; \"Kami keluar (dari daerah kami) hingga kami sampai kepada Rasulullah shallallahu 'alaihi wasallam. Lalu kami berbaiat kepadanya dan shalat bersamanya. Setelah selesai shalat datanglah seseorang yang kelihatannya seorang badui, dia berkata, 'Wahai Rasulullah shallallahu 'alaihi wasallam, Apa pendapat engkau tentang orang yang menyentuh kemaluannya ketika shalat? ' Rasulullah shallallahu 'alaihi wasallam menjawab, ' Bukankah itu hanya bagian dari dagingmu? '"},"166":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ عَنْ شُعَيْبٍ عَنْ اللَّيْثِ قَالَ أَنْبَأَنَا ابْنُ الْهَادِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ قَالَتْإِنْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُصَلِّي وَإِنِّي لَمُعْتَرِضَةٌ بَيْنَ يَدَيْهِ اعْتِرَاضَ الْجَنَازَةِ حَتَّى إِذَا أَرَادَ أَنْ يُوتِرَ مَسَّنِي بِرِجْلِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Al Hakam] dari [Syu'aib] dari [Laits] dia berkata; Telah memberitakan kepada kami [Ibnu Had] dari [Abdurrahman bin Qasim] dari [Al Qasim] dari [Aisyah] dia berkata; \" Jika Rasulullah shallallahu 'alaihi wasallam shalat dan aku berbaring di depannya laksana mayat, apabila beliau ingin melakukan shalat witir, beliau menyentuhku dengan kakinya.\""},"167":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ سَمِعْتُ الْقَاسِمَ بْنَ مُحَمَّدٍ يُحَدِّثُ عَنْ عَائِشَةَ قَالَتْلَقَدْ رَأَيْتُمُونِي مُعْتَرِضَةً بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فَإِذَا أَرَادَ أَنْ يَسْجُدَ غَمَزَ رِجْلِي فَضَمَمْتُهَا إِلَيَّ ثُمَّ يَسْجُدُ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] berkata; Saya mendengar [Al Qasim bin Muhammad] berkata; dari [Aisyah] dia berkata; \" Kalian telah mengetahui bahwa aku berbaring di depan Rasulullah shallallahu 'alaihi wasallam padahal Rasulullah shallallahu 'alaihi wasallam sedang shalat. Apabila beliau hendak sujud, maka beliau meraba kakiku, lalu aku menarik kakiku, kemudian beliau sujud.\""},"168":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ أَبِي النَّضْرِ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَنَامُ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرِجْلَايَ فِي قِبْلَتِهِ فَإِذَا سَجَدَ غَمَزَنِي فَقَبَضْتُ رِجْلَيَّ فَإِذَا قَامَ بَسَطْتُهُمَا وَالْبُيُوتُ يَوْمِئِذٍ لَيْسَ فِيهَا مَصَابِيحُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abu Nadhr] dari [Abu Salamah] dari [Aisyah] dia berkata; \" Aku pernah tidur di depan Rasulullah shallallahu 'alaihi wasallam dan kedua kakiku berada di kiblatnya. Apabila sujud beliau menyentuh kakiku dan apabila beliau berdiri aku membentangkan lagi kedua kakiku, lalu aku menarik kedua kakiku, dan saat itu di dalamnya tidak ada lampunya.\""},"169":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ وَنُصَيْرُ بْنُ الْفَرَجِ وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْفَقَدْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَجَعَلْتُ أَطْلُبُهُ بِيَدِي فَوَقَعَتْ يَدِي عَلَى قَدَمَيْهِ وَهُمَا مَنْصُوبَتَانِ وَهُوَ سَاجِدٌ يَقُولُ أَعُوذُ بِرِضَاكَ مِنْ سَخَطِكَ وَبِمُعَافَاتِكَ مِنْ عُقُوبَتِكَ وَأَعُوذُ بِكَ مِنْكَ لَا أُحْصِي ثَنَاءً عَلَيْكَ أَنْتَ كَمَا أَثْنَيْتَ عَلَى نَفْسِكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Al Mubarak] dan [Nushair bin Al Faraj] dan lafazh ini darinya, keduanya berkata; telah menceritakan kepada kami [Abu Usamah] dari [Ubaidullah bin Umar] dari [Muhammad bin Yahya bin Habbad] dari [Al A'raj] dari [Abu Hurairah] dari [Aisyah] dia berkata; \"Pada suatu malam aku kehilangan Rasulullah shallallahu 'alaihi wasallam dan aku mencari-carinya dengan kedua tanganku. Lalu kedua tanganku menyentuh kedua kakinya yang berdiri tegak, sedangkan beliau sedang dalam keadaan sujud. Beliau mengucapkan (do'a), ' aku berlindung dengan ridha-Mu dari murka-Mu dan berlindung dengan sikap pemaaf-Mu dari siksa-Mu, dan berlindung dengan-Mu dari Engkau. Aku tidak bisa menghitung pujian kepada Engkau sebagaimana Engkau memuji diri-Mu sendiri'.\""},"170":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ سُفْيَانَ قَالَ أَخْبَرَنِي أَبُو رَوْقٍ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُقَبِّلُ بَعْضَ أَزْوَاجِهِ ثُمَّ يُصَلِّي وَلَا يَتَوَضَّأُقَالَ أَبُو عَبْد الرَّحْمَنِ لَيْسَ فِي هَذَا الْبَابِ حَدِيثٌ أَحْسَنُ مِنْ هَذَا الْحَدِيثِ وَإِنْ كَانَ مُرْسَلًا وَقَدْ رَوَى هَذَا الْحَدِيثَ الْأَعْمَشُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَ يَحْيَى الْقَطَّانُ حَدِيثُ حَبِيبٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ هَذَا وَحَدِيثُ حَبِيبٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ تُصَلِّ وَإِنْ قَطَرَ الدَّمُ عَلَى الْحَصِيرِ لَا شَيْءَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dari [Yahya bin Sa'id] dari [Sufyan] dia berkata; Telah mengabarkan kepadaku [Abu Rauq] dari [Ibrahim At-Taimi] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam pernah mencium sebagian istrinya, kemudian shalat tanpa berwudlu lagi. Abu Abdurrahman berkata; tidak ada dalam bab ini sebuah hadits yang lebih baik dari hadist ini, walaupun hadits ini Mursal. Hadits ini telah diriwayatkan oleh [Al A'masy] dari [Habib bin Abu Tsabit] dari [Urwah] dari [Aisyah]. Yahya Al Qathan berkata; \"Ini adalah hadits Habib, dari Urwah dari Aisyah. "},"171":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا إِسْمَعِيلُ وَعَبْدُ الرَّزَّاقِ قَالَا حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ قَارِظٍ عَنْ أَبِي هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَوَضَّئُوا مِمَّا مَسَّتْ النَّارُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Ismail] dan [Abdurrazzak] keduanya berkata; telah menceritakan kepada kami [Ma'mar] dari [Az-Zuhri] dari [Umar bin Abdul Aziz] dari [Ibrahim bin Abdullah bin Qarizh] dari [Abu Hurairah] dia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: ' Berwudlulah kalian karena memakan sesuatu yang disentuh (dimasak dengan) api'.\" "},"172":{"ar":"أَخْبَرَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ قَالَ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ حَرْبٍ قَالَ حَدَّثَنِي الزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ أَنَّ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ قَارِظٍ أَخْبَرَهُ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَوَضَّئُوا مِمَّا مَسَّتْ النَّارُ","id":"Telah mengabarkan kepada kami [Hisyam bin Abdul Malik] dia berkata; telah menceritakan kepada kami [Muhammad yaitu Ibnu Harb] berkata; telah menceritakan kepadaku [Az-Zubaidi] dari [Az-Zuhri] sesungguhnya [Umar bin Abdul Aziz] Telah mengabarkan kepadanya bahwasannya [Abdullah bin Qarizh] Telah mengabarkan kepadanya bahwa [Abu Hurairah] berkata; 'Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda': \" Berwudlulah kalian dari -makanan sesuatu - yang disentuh (dimasak dengan) api'.\""},"173":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ بَكْرٍ وَهُوَ ابْنُ مُضَرَ قَالَ حَدَّثَنِي أَبِي عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ بَكْرِ بْنِ سَوَادَةَ عَنْ مُحَمَّدِ بْنِ مُسْلِمٍ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ عَبْدِ اللَّهِ بْنِ إِبْرَاهِيمَ بْنِ قَارِظٍ قَالَرَأَيْتُ أَبَا هُرَيْرَةَ يَتَوَضَّأُ عَلَى ظَهْرِ الْمَسْجِدِ فَقَالَ أَكَلْتُ أَثْوَارَ أَقِطٍ فَتَوَضَّأْتُ مِنْهَا إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُ بِالْوُضُوءِ مِمَّا مَسَّتْ النَّارُ","id":"Telah mengabarkan kepada kami [Ar-Rabi' bin Sulaiman] dia berkata; telah menceritakan kepada kami [Ishaq bin Bakr yaitu Ibnu Mudlar] dia berkata; telah menceritakan kepadaku [Bapakku] dari [Ja'far bin Rabi'ah] dari [Bakr bin Sawadah] dari [Muhammad bin Muslim] dari [Umar bin Abdul 'Aziz] dari [Abdullah bin Ibrahim bin Qarizh] dia berkata; \"Aku melihat [Abu Hurairah] berwudlu di belakang masjid, lalu dia berkata, 'Aku memakan sepotong daging sapi lalu berwudlu karenanya, aku mendengar Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk berwudlu karena (memakan sesuatu yang dimasak) dengan api'.\""},"174":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ قَالَ حَدَّثَنَا أَبِي عَنْ حُسَيْنٍ الْمُعَلِّمِ قَالَ حَدَّثَنِي يَحْيَىَ بْنُ أَبِي كَثِيرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَمْرٍو الْأَوْزَاعِيِّ أَنَّهُ سَمِعَ الْمُطَّلِبَ بْنَ عَبْدِ اللَّهِ بْنِ حَنْطَبٍ يَقُولُقَالَ ابْنُ عَبَّاسٍ أَتَوَضَّأُ مِنْ طَعَامٍ أَجِدُهُ فِي كِتَابِ اللَّهِ حَلَالًا لِأَنَّ النَّارَ مَسَّتْهُ فَجَمَعَ أَبُو هُرَيْرَةَ حَصًى فَقَالَ أَشْهَدُ عَدَدَ هَذَا الْحَصَى أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَوَضَّئُوا مِمَّا مَسَّتْ النَّارُ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub] dia berkata; telah menceritakan kepada kami [Abdu Shamad bin Abdul Warits] berkata; telah menceritakan kepada kami [Bapakku] dari [Husain Al Mu'allim] berkata; telah menceritakan kepadaku [Yahya bin Abu Katsir] dari [Abdurrahman bin Amr Al Auza'i] bahwasannya dia mendengar [Al Muthallib bin Abdullah bin Hanthab] berkata; Ibnu Abbas berkata: \"Apakah aku harus wudlu karena (makan) makanan halal yang aku dapati di dalam Al-Qur'an karena di sentuh (dimasak dengan) api?\" lalu [Abu Hurairah] mengambil kerikil dan berkata, \"Aku bersaksi sebanyak kerikil-kerikil ini, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Berwudlulah kalian karena memakan makanan yang dimasak dengan api'.\""},"175":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ يَحْيَى بْنِ جَعْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرٍو عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَوَضَّئُوا مِمَّا مَسَّتْ النَّارُ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] berkata; telah menceritakan kepada kami [Ibnu Abu Adi] dari [Syu'bah] dari [Amr bin Dinar] dari [Yahya bin Ja'dah] dari [Abdullah bin Umar] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Berwudlulah kalian karena memakan sesuatu yang di sentuh (dimasak dengan) api.\""},"176":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا أَنْبَأَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ يَحْيَى بْنِ جَعْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ مُحَمَّدٌ الْقَارِيُّ عَنْ أَبِي أَيُّوبَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّئُوا مِمَّا غَيَّرَتْ النَّارُ","id":"Telah mengabarkan kepada kami [Amr bin Ali] dan [Muhammad bin Basyar] keduanya berkata; Telah memberitakan kepada kami [Ibnu Abu Adi] dari [Syu'bah] dari [Amr bin Dinar] dari [Yahya bin Ja'dah] dari [Abdullah bin 'Amru]. [Muhammad Al Qari] berkata; dari [Abu Ayyub] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Berwudlulah karena (memakan) sesuatu yang di rubah (dimasak, diolah dengan) api.\""},"177":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ وَهَارُونُ بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا حَرَمِيٌّ وَهُوَ ابْنُ عُمَارَةَ بْنِ أَبِي حَفْصَةَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ سَمِعْتُ يَحْيَى بْنَ جَعْدَةَ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو الْقَارِيِّ عَنْ أَبِي طَلْحَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَوَضَّئُوا مِمَّا غَيَّرَتْ النَّارُ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] dan [Harun bin Abdullah] keduanya berkata; telah menceritakan kepada kami [Harami yaitu Ibnu 'Umarah bin Abu Hafshah] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Amr bin Dinar] berkata; \"Saya telah mendengar [Yahya bin Ja'dah] berkata; dari [Abdullah bin Amr Al Qari] dari [Abu Thalhah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Berwudlulah kalian karena (memakan) sesuatu yang di rubah (dimasak, diolah dengan) api.\""},"178":{"ar":"أَخْبَرَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا الزُّبَيْدِيُّ قَالَ أَخْبَرَنِي الزُّهْرِيُّ أَنَّ عَبْدَ الْمَلِكِ بْنَ أَبِي بَكْرٍ أَخْبَرَهُ أَنَّ خَارِجَةَ بْنَ زَيْدِ بْنِ ثَابِتٍ أَخْبَرَهُ أَنَّ زَيْدَ بْنَ ثَابِتٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَوَضَّئُوا مِمَّا مَسَّتْ النَّارُ","id":"Telah mengabarkan kepada kami [Hisyam bin Abdul Malik] dia berkata; telah menceritakan kepada kami [Muhammad] berkata; telah menceritakan kepada kami [Az-Zubaidi] berkata; Telah mengabarkan kepadaku [Az-Zuhri] bahwasanya [Abdul Malik bin Abu Bakar] Telah mengabarkan kepadanya bahwa [Kharijah bin Zaid bin Tsabit] Telah mengabarkan kepadanya, Bahwa [Zaid bin Tsabit] berkata: \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \" Berwudlulah karena (memakan) sesuatu yang disentuh (dimasak, dipanggang dengan) api'.\""},"179":{"ar":"أَخْبَرَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ قَالَ حَدَّثَنَا ابْنُ حَرْبٍ قَالَ حَدَّثَنَا الزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ أَنَّ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ أَخْبَرَهُ عَنْ أَبِي سُفْيَانَ بْنِ سَعِيدِ بْنِ الْأَخْ��َسِ بْنِ شَرِيقٍ أَنَّهُ أَخْبَرَهُأَنَّهُ دَخَلَ عَلَى أُمِّ حَبِيبَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ خَالَتُهُ فَسَقَتْهُ سَوِيقًا ثُمَّ قَالَتْ لَهُ تَوَضَّأْ يَا ابْنَ أُخْتِي فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَوَضَّئُوا مِمَّا مَسَّتْ النَّارُ","id":"Telah mengabarkan kepada kami [Hisyam bin Abdul Malik] dia berkata; telah menceritakan kepada kami [Ibnu Harb] berkata; telah menceritakan kepada kami [Az-Zubaidi] dari [Az-Zuhri] bahwasannya [Abu Salamah bin Abdurrahman] Telah mengabarkan kepadaku dari [Abu Sufyan bin Sa'id bin Al-Akhnas bin Syariq], bahwa dia menemui [Ummu Habibah] -istri Rasulullah shallallahu 'alaihi wasallam dan dia adalah bibi dari ibunya- lalu memberi sawik (makanan dari tepung gandum), kemudian berkata kepadanya, \"Berwudlulah wahai keponakanku, karena Rasulullah shallallahu 'alaihi wasallam bersabda: ' Berwudlulah dari sesuatu yang terpanggang oleh api'.\""},"180":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ بْنِ دَاوُدَ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ بَكْرِ بْنِ مُضَرَ قَالَ حَدَّثَنِي بَكْرُ بْنُ مُضَرَ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ بَكْرِ بْنِ سَوَادَةَ عَنْ مُحَمَّدِ بْنِ مُسْلِمِ بْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي سُفْيَانَ بْنِ سَعِيدِ بْنِ الْأَخْنَسِ أَنَّ أُمَّ حَبِيبَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ لَهُوَشَرِبَ سَوِيقًا يَا ابْنَ أُخْتِي تَوَضَّأْ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَوَضَّئُوا مِمَّا مَسَّتْ النَّارُ","id":"Telah mengabarkan kepada kami [Ar-Rabi' bin Sulaiman bin Daud] dia berkata; telah menceritakan kepada kami [Ishaq bin Bakr bin Mudlar] berkata; telah menceritakan kepadaku [Bakr bin Mudlar] dari [Ja'far bin Rabi'ah] dari [Bakr bin Sawadah] dari [Muhammad bin Muslim bin Syihab] dari [Abu Salamah bin Abdurrahman] dari [Abu Sufyan bin Sa'id bin Al Akhnas bin Syariq], bahwa [Ummu Habibah] -istri Rasulullah shallallahu 'alaihi wasallam -berkata kepadanya, -dan Abu Sufyan baru saja makan sawik (makanan dari tepung gandum) -: \"Wahai keponakanku! Berwudlulah, karena aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \" Berwudlulah karena memakan sesuatu yang disentuh oleh (dimasak dengan) api'.\""},"181":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ عَلِيِّ بْنِ الْحُسَيْنِ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكَلَ كَتِفًا فَجَاءَهُ بِلَالٌ فَخَرَجَ إِلَى الصَّلَاةِ وَلَمْ يَمَسَّ مَاءً","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Yahya] dari [Ja'far bin Muhammad] dari [Bapaknya] dari [Ali bin Husain] dari [Zainab bin Ummu Salamah] dari [Ummu Salamah] bahwa Rasulullah shallallahu 'alaihi wasallam pernah makan daging bagian paha, lalu datang Bilal, kemudian beliau keluar untuk shalat dan beliau tidak berwudlu lagi. "},"182":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ مُحَمَّدِ بْنِ يُوسُفَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ قَالَدَخَلْتُ عَلَى أُمِّ سَلَمَةَ فَحَدَّثَتْنِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصْبِحُ جُنُبًا مِنْ غَيْرِ احْتِلَامٍ ثُمَّ يَصُومُ وَحَدَّثَنَا مَعَ هَذَا الْحَدِيثِ أَنَّهَا حَدَّثَتْهُ أَنَّهَا قَرَّبَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَنْبًا مَشْوِيًّا فَأَكَلَ مِنْهُ ثُمَّ قَامَ إِلَى الصَّلَاةِ وَلَمْ يَتَوَضَّأْ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] berkata; telah menceritakan kepada kami [Ibnu Juraij] dari [Muhammad bin Yusuf] dari [Sulaiman bin Yasar] dia berkata; \"Aku pernah menemui [Ummu Salamah] lalu beliau menceritakan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam pernah bangun subuh dalam keadaan junub bukan karena mimpi. Beliau lalu berpuasa -selain Sulaiman bin Yasar menceritai kami hadits ini, namun Ummu Salamah memberitahukan kepadanya- bahwa dia menghidangkan kepada beliau shallallahu 'alaihi wasallam daging bagian pundak (paha) yang di bakar. Beliau memakannya, lalu beliau shalat tanpa berwudlu lagi.\""},"183":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ يُوسُفَ عَنْ ابْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ قَالَشَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكَلَ خُبْزًا وَلَحْمًا ثُمَّ قَامَ إِلَى الصَّلَاةِ وَلَمْ يَتَوَضَّأْ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] berkata; telah menceritakan kepada kami [Ibnu Juraij] berkata; telah menceritakan kepadaku [Muhammad bin Yusuf] dari [Ibnu Yasar] dari [Ibnu Abbas] dia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam memakan roti dan daging, kemudian melaksanakan shalat tanpa berwudlu lagi.\""},"184":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ قَالَ حَدَّثَنَا شُعَيْبٌ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَكَانَ آخِرَ الْأَمْرَيْنِ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَرْكُ الْوُضُوءِ مِمَّا مَسَّتْ النَّارُ","id":"Telah mengabarkan kepada kami [Amr bin Manshur] dia berkata; telah menceritakan kepada kami [Ali bin 'Ayyas] berkata; telah menceritakan kepada kami [Syu'aib] dari [Muhammad bin Munkadir] berkata; \"Saya mendengar [Jabir bin Abdullah] berkata; \"Salah satu dari dua hal yang ditinggalkan oleh Rasulullah shallallahu 'alaihi wasallam adalah tidak berwudlu karena memakan sesuatu yang disentuh oleh (dimasak dengan) api.\""},"185":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ مَوْلَى بَنِي حَارِثَةَ أَنَّ سُوَيْدَ بْنَ النُّعْمَانِ أَخْبَرَهُأَنَّهُ خَرَجَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ خَيْبَرَ حَتَّى إِذَا كَانُوا بِالصَّهْبَاءِ وَهِيَ مِنْ أَدْنَى خَيْبَرَ صَلَّى الْعَصْرَ ثُمَّ دَعَا بِالْأَزْوَادِ فَلَمْ يُؤْتَ إِلَّا بِالسَّوِيقِ فَأَمَرَ بِهِ فَثُرِّيَ فَأَكَلَ وَأَكَلْنَا ثُمَّ قَامَ إِلَى الْمَغْرِبِ فَتَمَضْمَضَ وَتَمَضْمَضْنَا ثُمَّ صَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] telah dibacakan kepadanya dan saya mendengarnya lafazh ini darinya, dari [Ibnu Al Qasim] dia berkata; telah menceritakan kepadaku [Malik] dari [Yahya bin Sa'id] dari [Busyair bin Yasar] -budak Bani Haritsah- bahwa [Suwaid bin Nu'man] telah mengabarkan kepadanya, bahwa ia pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam pada tahun perang khaibar ke daerah Shahban' - daerah di Khaibar yang paling rendah - lalu beliau mengerjakan shalat Ashar. Kemudian beliau minta dibawakan perbekalan, maka tidak ada yang bisa dibawa kecuali sawiq. Lalu beliau menyuruh untuk melunakkannya, beliau segera berdiri untuk melaksanakan shalat maghrib, lalu beliau berkumur dan kamipun ikut berkumur, kemudian beliau shalat tanpa berwudlu. "},"186":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَرِبَ لَبَنًا ثُمَّ دَعَا بِمَاءٍ فَتَمَضْمَضَ ثُمَّ قَالَ إِنَّ لَهُ دَسَمًا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al -Laits] dari [Uqail] dari [Zuhri] dari [Ubaidillah bin Abdullah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam meminum susu kemudian meminta air untuk berkumur. Lalu beliau bersabda, \"Susu itu mengandung lemak.\" "},"187":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَغَرِّ وَهوَ ابْنُ الصَّبَّاحِ عَنْ خَلِيفَةَ بْنِ حُصَيْنٍ عَنْ قَيْسِ بْنِ عَاصِمٍأَنَّهُ أَسْلَمَ فَأَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَغْتَسِلَ بِمَاءٍ وَسِدْرٍ","id":"Telah mengabarkan kepada kami [Amr bin Ali] telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Al Aghar yaitu Ibnu Shabah] dari [Khalifah bin Hushain] dari [Qais bin 'Ashim] bahwa dia masuk Islam, maka Rasulullah shallallahu 'alaihi wasallam menyuruhnya mandi dengan air dan sidr (Daun Bidara). "},"188":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُإِنَّ ثُمَامَةَ بْنَ أُثَالٍ الْحَنَفِيَّ انْطَلَقَ إِلَى نَجْلٍ قَرِيبٍ مِنْ الْمَسْجِدِ فَاغْتَسَلَ ثُمَّ دَخَلَ الْمَسْجِدَ فَقَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ يَا مُحَمَّدُ وَاللَّهِ مَا كَانَ عَلَى الْأَرْضِ وَجْهٌ أَبْغَضَ إِلَيَّ مِنْ وَجْهِكَ فَقَدْ أَصْبَحَ وَجْهُكَ أَحَبَّ الْوُجُوهِ كُلِّهَا إِلَيَّ وَإِنَّ خَيْلَكَ أَخَذَتْنِي وَأَنَا أُرِيدُ الْعُمْرَةَ فَمَاذَا تَرَى فَبَشَّرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمَرَهُ أَنْ يَعْتَمِرَ مُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al-Laits] dari [Sa'id bin Abu Sa'id] bahwa beliau mendengar [Abu Hurairah] berkata; \" Tsumamah bin Utsal Al Hanafi pergi ke tempat air mengalir dekat masjid untuk mandi, kemudian masuk ke dalam masjid dan berkata \" Aku bersaksi bahwa tiada tuhan yang diibadahi selain Allah, tidak ada sekutu baginya dan aku bersaksi bahwa Muhammad adalah hamba dan utusan-Nya. Wahai Muhammad! Demi Allah di muka bumi ini, dulu tidak ada wajah yang paling aku benci melainkan wajahmu, dan sekarang wajahmu menjadi wajah yang paling aku cintai. Kudamu akan membawaku dan aku ingin umrah. Bagaimana pendapatmu?\" Rasulullah shallallahu 'alaihi wasallam memberikan kabar gembira kepadanya dan menyuruhnya umrah.\"-Demikian cerita ini secara ringkas- "},"189":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ مُحَمَّدٍ قَالَ حَدَّثَنِي شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَ سَمِعْتُ نَاجِيَةَ بْنَ كَعْبٍ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُأَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ أَبَا طَالِبٍ مَاتَ فَقَالَ اذْهَبْ فَوَارِهِ قَالَ إِنَّهُ مَاتَ مُشْرِكًا قَالَ اذْهَبْ فَوَارِهِ فَلَمَّا وَارَيْتُهُ رَجَعْتُ إِلَيْهِ فَقَالَ لِي اغْتَسِلْ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dari [Muhammad] dia berkata; telah menceritakan kepadaku [Syu'bah] dari [Abu Ishaq] berkata; saya mendengar [Najiah bin Ka'ab] dari [Ali] Radliyallahu'anhu bahwa dia datang kepada Rasulullah shallallahu 'alaihi wasallam untuk mengabarkan bahwa Abu Thalib meninggal dunia! Beliau bersabda, \" Pergilah ke sana dan kuburlah\" Ali berkata; dia mati dalam keadaan musyrik. Rasul bersabda; \"pergilah ke sana dan kuburlah\" Ali berkata, \"Setelah selesai menguburnya aku pulang, lalu beliau shallallahu 'alaihi wasallam bersabda kepadaku; 'Mandilah. '\""},"190":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ الْحَسَنَ يُحَدِّثُ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا جَلَسَ بَيْنَ شُعَبِهَا الْأَرْبَعِ ثُمَّ اجْتَهَدَ فَقَدْ وَجَبَ الْغُسْلُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] berkata; \"saya mendengar [Hasan] berkata; dari [Abu Rafi'] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Apabila telah duduk di antara dua tangan dan dua kaki (bersetubuh), kemudian bersungguh-sungguh, telah wajib mandi baginya.\""},"191":{"ar":"أَخْبَرَنَا إ��بْرَاهِيمُ بْنُ يَعْقُوبَ بْنِ إِسْحَقَ الْجَوْزَجَانِيُّ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ قَالَ حَدَّثَنَا أَشْعَثُ بْنُ عَبْدِ الْمَلِكِ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَعَدَ بَيْنَ شُعَبِهَا الْأَرْبَعِ ثُمَّ اجْتَهَدَ فَقَدْ وَجَبَ الْغُسْلُقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا خَطَأٌ وَالصَّوَابُ أَشْعَثُ عَنْ الْحَسَنِ عَنْ أَبِي هُرَيْرَةَ وَقَدْ رَوَى الْحَدِيثَ عَنْ شُعْبَةَ النَّضْرُ بْنُ شُمَيْلٍ وَغَيْرُهُ كَمَا رَوَاهُ خَالِدٌ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub bin Ishaq Al Jauzajani] dia berkata; Telah menceritakan kepada kami [Abdullah bin Yusuf] dia berkata; Telah menceritakan kepada kami [Isa bin Yunus] dia berkata; Telah menceritakan kepada kami [Asy'ats bin Abdul Malik] dari [Ibnu Sirin] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Apabila telah duduk di antara dua tangan dan dua kaki kemudian bersungguh-sungguh, telah wajib mandi baginya.\" Abu Abdurrahman berkata; Yang ini salah, yang benar adalah, Asy'ats dari Al Hasan dari Abu Hurairah. Telah meriwayatkan hadis ini, An-Nadlr bin Syumail, Khalid, dan yang lainnya dari Syu'bah. "},"192":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَعَلِيُّ بْنُ حُجْرٍ وَاللَّفْظُ لِقُتَيْبَةَ قَالَ حَدَّثَنَا عَبِيدَةُ بْنُ حُمَيْدٍ عَنْ الرُّكَيْنِ بْنِ الرَّبِيعِ عَنْ حُصَيْنِ بْنِ قَبِيصَةَ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ رَجُلًا مَذَّاءً فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَيْتَ الْمَذْيَ فَاغْسِلْ ذَكَرَكَ وَتَوَضَّأْ وُضُوءَكَ لِلصَّلَاةِ وَإِذَا فَضَخْتَ الْمَاءَ فَاغْتَسِلْ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dan [Ali bin Hujr] lafazh ini dari Qutaibah dia berkata; Telah menceritakan kepada kami [Abidah bin Humaid] dari [Rukain bin Rabi'] dari [Husain bin Qabishah] dari [Ali] Radliyallahu'anhu berkata; \"Aku laki-laki yang sering mengeluarkan madzi. Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \" Apabila kamu melihat madzi, maka cucilah kemaluanmu dan berwudlulah seperti wudlu untuk shalat. Jika kamu mengeluarkan air mani, mandilah.\""},"193":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ عَنْ زَائِدَةَ ح و أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لَهُ أَنْبَأَنَا أَبُو الْوَلِيدِ حَدَّثَنَا زَائِدَةُ عَنْ الرُّكَيْنِ بْنِ الرَّبِيعِ بْنِ عَمِيلَةَ الْفَزَارِيِّ عَنْ حُصَيْنِ بْنِ قَبِيصَةَ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ رَجُلًا مَذَّاءً فَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِذَا رَأَيْتَ الْمَذْيَ فَتَوَضَّأْ وَاغْسِلْ ذَكَرَكَ وَإِذَا رَأَيْتَ فَضْخَ الْمَاءِ فَاغْتَسِلْ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] dia berkata; Telah memberitakan kepada kami [Abdurrahman] dari [Zaidah], dan Telah mengabarkan kepada kami [Ishaq bin Ibrahim] lafazh ini darinya, Telah mengabarkan kepada kami [Abu Walid] Telah menceritakan kepada kami [Zaidah] dari [Rukain bin Rabi' bin 'Amilah Al Fajariy] dari [Husain bin Qabishah] dari [Ali] Radliyallahu'anhu dia berkata; \"Aku laki-laki yang sering mengeluarkan madzi, maka aku bertanya Rasulullah shallallahu 'alaihi wasallam, lalu beliau bersabda kepadaku: \" Apabila kamu melihat madzi, berwudlulah seperti wudlu untuk shalat, kemudian cuci kemaluanmu. Jika kamu melihat keluarnya air mani, mandilah.\""},"194":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدَةُ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ أُمَّ سُلَيْمٍ سَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمَرْأَةِ تَرَى فِي مَنَامِهَا مَا يَرَى الرَّجُلُ قَالَ إِذَا أَنْزَلَتْ الْمَاءَ فَلْتَغْتَسِلْ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah menceritakan kepada kami ['Abdah] dia berkata; Telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas], bahwa Ummu Sulaim bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang perempuan yang bermimpi seperti mimpinya laki-laki? Maka beliau menjawab, \" Apabila ia mengeluarkan mani. Maka hendaklah mandi.\""},"195":{"ar":"أَخْبَرَنَا كَثِيرُ بْنُ عُبَيْدٍ عَنْ مُحَمَّدِ بْنِ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ أَنَّ عَائِشَةَ أَخْبَرَتْهُأَنَّ أُمَّ سُلَيْمٍ كَلَّمَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَائِشَةُ جَالِسَةٌ فَقَالَتْ لَهُ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ لَا يَسْتَحْيِي مِنْ الْحَقِّ أَرَأَيْتَ الْمَرْأَةَ تَرَى فِي النَّوْمِ مَا يَرَى الرَّجُلُ أَفَتَغْتَسِلُ مِنْ ذَلِكَ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ قَالَتْ عَائِشَةُ فَقُلْتُ لَهَا أُفٍّ لَكِ أَوَ تَرَى الْمَرْأَةُ ذَلِكَ فَالْتَفَتَ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ تَرِبَتْ يَمِينُكِ فَمِنْ أَيْنَ يَكُونُ الشَّبَهُ","id":"Telah mengabarkan kepada kami [Katsir bin 'Ubaid] dari [Muhammad bin Harb] dari [Az-Zubaidi] dari [Az-Zuhri] dari [Urwah] bahwa [Aisyah] mengabarkan kepadanya, sesungguhnya Ummu Sulaim berbincang-bincang dengan Rasulullah shallallahu 'alaihi wasallam dan aku sedang duduk, kemudian Ummu Sulaim berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, Allah tidak malu sedikitpun dari kebenaran, jadi apa pendapat engkau bila ada perempuan yang bermimpi seperti mimpinya laki-laki? Apakah dia harus mandi?\" Rasulullah shallallahu 'alaihi wasallam menjawab, \" Ya.\" Aisyah berkata; \"Aku bertanya kepada Ummu Sulaim. 'Ah, apakah perempuan juga bermimpi demikian! ' Lalu Rasulullah shallallahu 'alaihi wasallam menengok kepadaku dan berkata, \"Ah, kamu ini bagaimana, lalu dari manakah anak bisa mirip orang tuanya itu?\""},"196":{"ar":"أَخْبَرَنَا شُعَيْبُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَأَنَّ امْرَأَةً قَالَتْ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ لَا يَسْتَحْيِي مِنْ الْحَقِّ هَلْ عَلَى الْمَرْأَةِ غُسْلٌ إِذَا هِيَ احْتَلَمَتْ قَالَ نَعَمْ إِذَا رَأَتْ الْمَاءَ فَضَحِكَتْ أُمُّ سَلَمَةَ فَقَالَتْ أَتَحْتَلِمُ الْمَرْأَةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَفِيمَ يُشْبِهُهَا الْوَلَدُ","id":"Telah mengabarkan kepada kami [Syu'aib bin Yusuf] dia berkata; Telah menceritakan kepada kami [Yahya] dari [Hisyam] dia berkata; Telah mengabarkan kepadaku [Bapakku] dari [Zainab bin Salamah] dari [Ummu Salamah] bahwa seorang perempuan berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, Allah tidak Malu sedikitpun dari kebenaran, apakah seorang perempuan wajib mandi apabila ia bermimpi?\" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \" Ya, jika dia melihat mani. Maka Ummu Salamah tertawa dan bertanya; Apakah wanita bermimpi basah juga? Beliau shallallahu 'alaihi wasallam menjawab: \"Kalau tidak, lalu dari mana anak itu dapat menyerupainya (mirip dengannya)?\""},"197":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ شُعْبَةَ قَالَ سَمِعْتُ عَطَاءً الْخُرَاسَانِيَّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ خَوْلَةَ بِنْتِ حَكِيمٍ قَالَتْسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمَرْأَةِ تَحْتَلِمُ فِي مَنَامِهَا فَقَالَ إِذَا رَأَتْ الْمَاءَ فَلْتَغْتَسِلْ","id":"Telah mengabarkan kepada kami [Yusuf bin Sa'id] dia berkata; Telah menceritakan kepada kami [Hajaj] dari [Syu'bah] dia berkata; Saya mendengar [Atha' Al Khurasani] dari [Sa'id bin Musayyab] dari [Khaulah bin Hakim] dia berkata; \"Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang perempuan yang bermimpi? Lalu beliau bersabda: \" Apabila ia melihat air (Mani), maka hendaklah ia mandi'.\""},"198":{"ar":"أَخْبَرَنَا عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ عَنْ سُفْيَانَ عَنْ عَمْرٍو عَنْ عَبْدِ الرَّحْمَنِ بْنِ السَّائِبِ عَنْ عَبْدِ الرَّحْمَنِ ابْنِ سُعَادٍ عَنْ أَبِي أَيُّوبَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَاءُ مِنْ الْمَاءِ","id":"Telah mengabarkan kepada kami [Abdul Jabar bin Al 'Alla] dari [Sufyan] dari [Amr] dari [Abdurrahman bin As-Saib] dari [Abdurrahman bin Su'ad] dari [Abu Ayyub] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \" Air (Mandi Junub) itu adalah karena (keluarnya Mani) \""},"199":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدَةُ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاءُ الرَّجُلِ غَلِيظٌ أَبْيَضُ وَمَاءُ الْمَرْأَةِ رَقِيقٌ أَصْفَرُ فَأَيُّهُمَا سَبَقَ كَانَ الشَّبَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Abdah] dia berkata; Telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Mani laki-laki itu kental dan berwarna putih, sedangkan mani perempuan itu encer dan berwarna kuning. Maka diantara keduanya yang lebih kuat itulah yang mirip atau menyerupai (dengan anaknya).\""},"200":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَبْدِ اللَّهِ الْعَدَوِيُّ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنِي هِشَامُ بْنُ عُرْوَةَ عَنْ عُرْوَةَ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍ مِنْ بَنِي أَسَدِ قُرَيْشٍأَنَّهَا أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ أَنَّهَا تُسْتَحَاضُ فَزَعَمَتْ أَنَّهُ قَالَ لَهَا إِنَّمَا ذَلِكَ عِرْقٌ فَإِذَا أَقْبَلَتْ الْحَيْضَةُ فَدَعِي الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَاغْسِلِي عَنْكِ الدَّمَ ثُمَّ صَلَّى","id":"Telah mengabarkan kepada kami ['Imran bin Yazid] dia berkata; telah menceritakan kepada kami [Ismail bin Abdullah Al 'Adawi] berkata; telah menceritakan kepada kami [Al Auza'i] berkata; telah menceritakan kepada kami [Yahya bin Sa'id] berkata; telah menceritakan kepadaku [Hisyam bin Urwah] dari [Urwah] dari [Fatimah binti Qais] -dari Bani Asad Qiraisy- bahwa dia pernah datang kepada Rasulullah shallallahu 'alaihi wasallam dan mengatakan bahwa dirinya sedang istihadhah (mengeluarkan darah penyakit). Ia menyangka bahwa Rasulullah shallallahu 'alaihi wasallam telah bersabda kepadanya: \" Itu darah penyakit. Apabila datang haid maka tinggalkan shalat, dan apabila telah selesai maka mandilah dan kerjakanlah shalat.\""},"201":{"ar":"أَخْبَرَنَا هِشَامُ بْنُ عَمَّارٍ قَالَ حَدَّثَنَا سَهْلُ بْنُ هَاشِمٍ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَقْبَلَتْ الْحَيْضَةُ فَاتْرُكِي الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَاغْتَسِلِي","id":"Telah mengabarkan kepada kami [Hisyam bin 'Ammar] dia berkata; Telah menceritakan kepada kami [Sahal bin Hasyim] berkata; Telah menceritakan kepada kami [Al Auza'i] dari [Zuhri] dari ['Urwah] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Apabila datang haid maka tinggalkanlah shalat, dan apabila telah berhenti maka mandilah.\""},"202":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنَا الزُّهْرِيُّ عَنْ عُرْوَةَ وَعَمْرَةَ عَنْ عَائِشَةَ قَالَتْاسْتُحِيضَتْ أُمُّ حَبِيبَةَ بِنْتُ جَحْشٍ سَبْعَ سِنِينَ فَاشْتَكَتْ ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذِهِ لَيْسَتْ بِالْحَيْضَةِ وَلَكِنْ هَذَا عِرْقٌ فَاغْتَسِلِي ثُمَّ صَلِّي","id":"Telah mengabarkan kepada kami ['Imran bin Yazid] dia berkata; Telah menceritakan kepada kami [Ismail bin Abdullah] berkata; Telah menceritakan kepada kami [Al Auza'i] berkata; Telah menceritakan kepada kami [Az-Zuhri] dari ['Urwah] dan ['Amrah] dari [Aisyah] dia berkata; \"Ummu Habibah binti Jahsyi mengalami istihadhah selama tujuh tahun maka ia mengadu kepada Rasulullah shallallahu 'alaihi wasallam tentang hal tersebut. Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \" Ini bukan haid, tetapi darah penyakit. Maka mandilah kemudian shalatlah.\""},"203":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ بْنِ دَاوُدَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ حَدَّثَنَا الْهَيْثَمُ بْنُ حُمَيْدٍ قَالَ أَخْبَرَنِي النُّعْمَانُ وَالْأَوْزَاعِيُّ وَأَبُو مُعَيْدٍ وَهُوَ حَفْصُ بْنُ غَيْلَانَ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ وَعَمْرَةُ بْنْتُ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ قَالَتْاسْتُحِيضَتْ أُمُّ حَبِيبَةَ بِنْتُ جَحْشٍ امْرَأَةُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَهِيَ أُخْتُ زَيْنَبَ بِنْتِ جَحْشٍ فَاسْتَفْتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذِهِ لَيْسَتْ بِالْحَيْضَةِ وَلَكِنْ هَذَا عِرْقٌ فَإِذَا أَدْبَرَتْ الْحَيْضَةُ فَاغْتَسِلِي وَصَلِّي وَإِذَا أَقْبَلَتْ فَاتْرُكِي لَهَا الصَّلَاةَ قَالَتْ عَائِشَةُ فَكَانَتْ تَغْتَسِلُ لِكُلِّ صَلَاةٍ وَتُصَلِّي وَكَانَتْ تَغْتَسِلُ أَحْيَانًا فِي مِرْكَنٍ فِي حُجْرَةِ أُخْتِهَا زَيْنَبَ وَهِيَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَنَّ حُمْرَةَ الدَّمِ لَتَعْلُو الْمَاءَ وَتَخْرُجُ فَتُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا يَمْنَعُهَا ذَلِكَ مِنْ الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman bin Daud] dia berkata; Telah menceritakan kepada kami [Abdullah bin Yusuf] berkata; Telah menceritakan kepada kami [Al Haitsam bin Humaid] telah mengabarkan kepadaku [An-Nu'man] dan [Al Auzai] dan [Abu Mu'aid yaitu Hafs bin Ghailan] dari [Az-Zuhri] berkata; Telah mengabarkan kepadaku ['Urwan bin Zubair] dan [Amrah binti Abdurrahman] dari [Aisyah] dia berkata: \" Ummu Habibah binti Jahsy -istri Abdurrahman bin Auf, saudari Zainab binti Jahsy- mengalami istihadah, maka ia meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam tentang hal tersebut. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya, \" Ini bukan haid, tetapi darah penyakit. Apabila selesai haid maka mandi dan kerjakanlah shalat, dan jika datang haid maka tinggalkanlah shalat.\" Aisyah berkata, Dia (Ummu Habibah) selalu mandi untuk setiap shalat, lalu dia shalat. Kadang dia mandi di tempat mencuci pakaian di dalam kamar saudaranya (Zainab), dan dia tinggal bersama Rasulullah shallallahu 'alaihi wasallam, hingga merahnya darah mengalahkan air. Dia keluar untuk shalat bersama Rasulullah shallallahu 'alaihi wasallam, dan beliau shallallahu 'alaihi wasallam tidak mencegahnya untuk melaksanakan shalat karena hal itu.\""},"204":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ وَعَمْرَةَ عَنْ عَائِشَةَأَنَّ أُمَّ حَبِيبَةَ خَتَنَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَحْتَ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ اسْتُحِيضَتْ سَبْعَ سِنِينَ اسْتَفْتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذَلِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذِهِ لَيْسَتْ بِالْحَيْضَةِ وَلَكِنْ هَذَا عِرْقٌ فَاغْتَسِلِي وَصَلِّي","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; Telah menceritakan kepada kami [Ibnu Wahab] dari [Amr bin Al Harits] dari [Ibnu Syihab] dari ['Urwah] dan [Amrah] dari [Aisyah] bahwa Ummu Habibah -saudari istri Rasulullah shallallahu 'alaihi wasallam dari istri Abdurrahman bin Auf- mengalami istihadhah selama tujuh tahun, maka dia meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau bersabda kepadanya: \" Ini bukan darah haid, tetapi darah penyakit. Maka mandi dan shalatlah.\""},"205":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْاسْتَفْتَتْ أُمُّ حَبِيبَةَ بِنْتُ جَحْشٍ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي أُسْتَحَاضُ فَقَالَ إِنَّمَا ذَلِكَ عِرْقٌ فَاغْتَسِلِي وَصَلِّي فَكَانَتْ تَغْتَسِلُ لِكُلِّ صَلَاةٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] dia berkata; \"Ummu Habibah binti Jahsy meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam, \"Wahai Rasulullah shallallahu 'alaihi wasallam! Aku mengalami istihadhah?\" Beliau bersabda: \" Itu darah penyakit, maka mandi dan shalatlah\" Lalu Ummu Habibah selalu mandi jika akan shalat. "},"206":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ أُمَّ حَبِيبَةَ سَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدَّمِ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا رَأَيْتُ مِرْكَنَهَا مَلْآنَ دَمًا فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْكُثِي قَدْرَ مَا كَانَتْ تَحْبِسُكِ حَيْضَتُكِ ثُمَّ اغْتَسِلِيأَخْبَرَنَا قُتَيْبَةُ مَرَّةً أُخْرَى وَلَمْ يَذْكُرْ جَعْفَرًا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Ja'far bin Rabi'ah] dari ['Irak bin Malik] dari ['Urwah] dari [Aisyah] bahwa Ummu Habibah bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang darah? Aisyah Radliyallahu'anha berkata; \"Aku melihat tempatnya mencuci pakaian penuh dengan darah. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \" Tetapkanlah sesuai masa/waktu haid yang biasa kamu alami kemudian mandilah.\" Dan telah mengabarkan kepada kami lagi Qutaibah tanpa menyebutkan Ja'far. "},"207":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ أُمِّ سَلَمَةَتَعْنِي أَنَّ امْرَأَةً كَانَتْ تُهَرَاقُ الدَّمَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَفْتَتْ لَهَا أُمُّ سَلَمَةَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِتَنْظُرْ عَدَدَ اللَّيَالِي وَالْأَيَّامِ الَّتِي كَانَتْ تَحِيضُ مِنْ الشَّهْرِ قَبْلَ أَنْ يُصِيبَهَا الَّذِي أَصَابَهَا فَلْتَتْرُكْ الصَّلَاةَ قَدْرَ ذَلِكَ مِنْ الشَّهْرِ فَإِذَا خَلَّفَتْ ذَلِكَ فَلْتَغْتَسِلْ ثُمَّ لِتَسْتَثْفِرْ ثُمَّ لِتُصَلِّي","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Nafi'] dari [Sulaiman bin Yasar] dari [Ummu Salamah] -ia bermaksud- ada seseorang perempuan yang mengalami pendarahan pada zaman Rasulullah shallallahu 'alaihi wasallam, lalu dia (Ummu Salamah) memintakan fatwa kepada Rasulullah shallallahu 'alaihi wasallam? Beliau bersabda, \" Hendaklah kamu menghitung malam dan hari (jadwal) yang biasa kamu haid setiap bulannya. Selama kamu masih berada di hari kebiasaan kamu haid pada setiap bulannya maka tinggalkanlah seukuran malam/hari tersebut dalam setiap bulannya. Bila hal itu selesai maka mandilah, kemudian letakkan kain pada tempat haid, dan kerjakan shalat.\" "},"208":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ بْنِ دَاوُدَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ بَكْرٍ قَالَ حَدَّثَنِي أَبِي عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَأَنَّ أُمَّ حَبِيبَةَ بِنْتَ جَحْشٍ الَّتِي كَانَتْ تَحْتَ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَأَنَّهَا اسْتُحِيضَتْ لَا تَطْهُرْ فَذُكِرَ شَأْنُهَا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهَا لَيْسَتْ بِالْحَيْضَةِ وَلَكِنَّهَا رَكْضَةٌ مِنْ الرَّحِمِ فَلْتَنْظُرْ قَدْرَ قَرْئِهَا الَّتِي كَانَتْ تَحِيضُ لَهَا فَلْتَتْرُكْ الصَّلَاةَ ثُمَّ تَنْظُرْ مَا بَعْدَ ذَلِكَ فَلْتَغْتَسِلْ عِنْدَ كُلِّ صَلَاةٍ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman bin Daud bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Ishaq bin Bakr] berkata; Telah menceritakan kepadaku [Ayahku] dari [Yazid bin Abdullah] dari [Abu Bakar bin Muhammad] dari [Amrah] dari [Aisyah] bahwa Ummu Habibah binti Jahsy -istri Abdurrahman bin Auf- mengalami istihadhah dan tidak suci, maka dia mengadukan keadaannya kepada Rasulullah shallallahu 'alaihi wasallam. Beliau shallallahu 'alaihi wasallam lalu bersabda kepadanya, \" Ini bukan haid, tetapi hentakan dari rahim. Jadi mandilah dan kerjakanlah shalat. Lalu lihat kebiasaan masa haid, kemudian tinggalkan shalat, dan lihat apa yang terjadi setelah itu. Kemudian mandilah pada setiap akan mengerjakan shalat.\" "},"209":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عَمْرَةَ عَنْ عَائِشَةَأَنَّ أُمَّ حَبِيبَةَ بِنْتَ جَحْشٍ كَانَتْ تُسْتَحَاضُ سَبْعَ سِنِينَ فَسَأَلَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَيْسَتْ بِالْحَيْضَةِ إِنَّمَا هُوَ عِرْقٌ فَأَمَرَهَا أَنْ تَتْرُكَ الصَّلَاةَ قَدْرَ أَقْرَائِهَا وَحَيْضَتِهَا وَتَغْتَسِلَ وَتُصَلِّيَ فَكَانَتْ تَغْتَسِلُ عِنْدَ كُلِّ صَلَاةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Az-Zuhri] dari ['Amrah] dari [Aisyah] bahwa Ummu Habibah binti Jahsy mengalami istihadhah (mengeluarkan darah penyakit) selama tujuh tahun, maka ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang hal tersebut. Beliau lalu berkata, \" Itu bukan haid, tetapi darah penyakit.\" Lalu beliau memerintahkannya untuk meninggalkan shalat menurut waktu kebiasaan haidnya, lalu mandi serta tetap shalat, dan harus mandi pada setiap shalat.\" "},"210":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ عَنْ الْمُنْذِرِ بْنِ الْمُغِيرَةِ عَنْ عُرْوَةَأَنَّ فَاطِمَةَ بِنْتَ أَبِي حُبَيْشٍ حَدَّثَتْ أَنَّهَا أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَكَتْ إِلَيْهِ الدَّمَ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا ذَلِكَ عِرْقٌ فَانْظُرِي إِذَا أَتَاكِ قُرْؤُكِ فَلَا تُصَلِّ فَإِذَا مَرَّ قُرْؤُكِ فَتَطَهَّرِي ثُمَّ صَلِّي مَا بَيْنَ الْقُرْءِ إِلَى الْقُرْءِ هَذَا الدَّلِيلُ عَلَى أَنَّ الْأَقْرَاءَ حَيْضٌقَالَ أَبُو عَبْد الرَّحْمَنِ وَقَدْ رَوَى هَذَا الْحَدِيثَ هِشَامُ بْنُ عُرْوَةَ عَنْ عُرْوَةَ وَلَمْ يَذْكُرْ فِيهِ مَا ذَكَرَ الْمُنْذِرُ","id":"Telah mengabarkan kepada kami [Isa bin Hammad] dia berkata; Telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Bukair bin Abdullah] dari [Al Mundziri bin Al Mughirah] dari ['Urwah] bahwa [Fatimah binti Hubaisy] menceritakan dirinya pernah datang kepada Rasulullah shallallahu 'alaihi wasallam untuk mengadukan pendarahannya. Rasulullah shallallahu 'alaihi wasallam lalu bersabda kepadanya: \" Itu darah penyakit. Perhatikan waktu kebiasaan haidmu, jika datang maka jangan shalat dan jika Telah berlalu maka bersuci dan shalatlah antara waktu haid yang satu ke waktu haid yang lain.\" Ini adalah dalil bahwa Haidh itu memiliki waktu-waktu tertentu. Abu Abdurrahman berkata; dan telah meriwayatkan pula terhadap hadits ini Hisyam bin 'Urwah dari 'Urwah tetapi dia tidak menyebutkan sebagaimana yang telah disebutkan oleh Al Mundzir. "},"211":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَخْبَرَنَا عَبْدَةُ وَوَكِيعٌ وَأَبُو مُعَاوِيَةَ قَالُوا حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْجَاءَتْ فَاطِمَةُ بِنْتُ أَبِي حُبَيْشٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنِّي امْرَأَةٌ أُسْتَحَاضُ فَلَا أَطْهُرُ أَفَأَدَعُ الصَّلَاةَ قَالَ لَا إِنَّمَا ذَلِكَ عِرْقٌ وَلَيْسَ بِالْحَيْضَةِ فَإِذَا أَقْبَلَتْ الْحَيْضَةُ فَدَعِي الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَاغْسِلِي عَنْكِ الدَّمَ وَصَلِّي","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah mengabarkan kepada kami [Abdah], [Waki'] dan [Abu Mu'awiyah] mereka berkata; telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] dia berkata: \"Fatimah binti Abu Hubaisy datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Aku perempuan yang sedang mengalami istihadhah, dan aku tidak bersuci. Apakah aku harus meninggalkan shalat?\" Beliau bersabda, \" Tidak, itu darah penyakit, bukan haid. Bila datang haid, tinggalkanlah shalat, dan jika sudah selesai haid maka cucilah darah itu darimu dan shalatlah.\" "},"212":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ امْرَأَةً مُسْتَحَاضَةً عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِيلَ لَهَا أَنَّهُ عِرْقٌ عَانِدٌ فَأُمِرَتْ أَنْ تُؤَخِّرَ الظُّهْرَ وَتُعَجِّلَ الْعَصْرَ وَتَغْتَسِلَ لَهُمَا غُسْلًا وَاحِدًا وَتُؤَخِّرَ الْمَغْرِبَ وَتُعَجِّلَ الْعِشَاءَ وَتَغْتَسِلَ لَهُمَا غُسْلًا وَاحِدًا وَتَغْتَسِلَ لِصَلَاةِ الصُّبْحِ غُسْلًا وَاحِدًا","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; Telah menceritakan kepada kami [Muhammad], [Syu'bah] berkata; dari [Abdurrahman bin Qasim] dari [Ayahnya] dari [Aisyah] Radliyallahu'anha, bahwa ada seorang perempuan yang sedang istihadhah pada zaman Rasulullah shallallahu 'alaihi wasallam, maka dikatakan kepadanya bahwa itu adalah darah penyakit yang tidak wajar. Ia lalu diperintahkan mengakhirkan shalat zhuhur dan memajukan shalat Ashar, serta mandi satu kali untuk dua shalat tersebut. Juga mengakhirkan shalat Maghrib dan memajukan shalat Isya' serta mandi satu kali untuk dua shalat, kemudian mandi satu kali untuk shalat Subuh.\""},"213":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِفِي حَدِيثِ أَسْمَاءَ بِنْتِ عُمَيْسٍ حِينَ نُفِسَتْ بِذِي الْحُلَيْفَةِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَبِي بَكْرٍ مُرْهَا أَنْ تَغْتَسِلَ وَتُهِلَّ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dia berkata; Telah menceritakan kepada kami [Jarir] dari [Yahya bin Sa'id] dari [Ja'far bin Muhammad] dari [Ayahnya] dari [Jabir bin Abdullah] didalam haditsnya. Asma' binti Umais ketika ia sedang nifas di Dzul Hulaifah, Rasulullah shallallahu 'alaihi wasallam berkata kepada Abu Bakar: \" Suruh ia mandi lalu berihram (dan mengucap talbiyah).\" "},"214":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ مُحَمَّدٍ وَهُوَ ابْنُ عَمْرِو بْنِ عَلْقَمَةَ بْنِ وَقَّاصٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ فَاطِمَةَ بِنْتِ أَبِي حُبَيْشٍأَنَّهَا كَانَتْ تُسْتَحَاضُ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ دَمُ الْحَيْضِ فَإِنَّهُ دَمٌ أَسْوَدُ يُعْرَفُ فَأَمْسِكِي عَنْ الصَّلَاةِ فَإِذَا كَانَ الْآخَرُ فَتَوَضَّئِي فَإِنَّمَا هُوَ عِرْقٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] Telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Muhammad yaitu Ibnu Amr bin 'Alqamah bin Waqqash] dari [Ibnu Syihab] dari [Urwan bin Zubair] dari [Fatimah binti Abu Hubaisy] bahwa dia mengalami istihadhah, maka Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \" Apabila darah itu adalah darah haid, maka darahnya berwarna hitam yang sudah dikenal, maka tinggalkanlah shalat. Jika bukan demikian maka berwudlulah, karena itu hanya darah penyakit.\""},"215":{"ar":"قَالَ أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ هَذَا مِنْ كِتَابِهِ أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ مِنْ حِفْظِهِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ فَاطِمَةَ بِنْتَ أَبِي حُبَيْشٍ كَانَتْ تُسْتَحَاضُ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ دَمَ الْحَيْضِ دَمٌ أَسْوَدُ يُعْرَفُ فَإِذَا كَانَ ذَلِكَ فَأَمْسِكِي عَنْ الصَّلَاةِ وَإِذَا كَانَ الْآخَرُ فَتَوَضَّئِي وَصَلِّيقَالَ أَبُو عَبْد الرَّحْمَنِ قَدْ رَوَى هَذَا الْحَدِيثَ غَيْرُ وَاحِدٍ لَمْ يَذْكُرْ أَحَدٌ مِنْهُمْ مَا ذَكَرَهُ ابْنُ أَبِي عَدِيٍّ وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] Telah menceritakan kepada kami [Ibnu Abu 'Adi] -ini dari bukunya- Telah mengabarkan kepada kami Muhammad bin Al Mutsanna Telah menceritakan kepada kami Ibnu Abu 'Adi -dari Hafalannya- dia berkata; Telah menceritakan kepada kami [Muhammad bin Amr] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] bahwa Fatimah binti Hubaisy mengalami istihadhah, sehingga Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya, \" Bila darah itu adalah darah haid, darahnya hitam dan sudah dikenal, maka tinggalkanlah shalat. Jika selain itu, berwudlulah dan kerjakanlah shalat.\" Abu Abdurrahman berkata; \"Telah banyak yang meriwayatkan hadits ini, dan mereka tidak menyebutkan sebagaimana yang telah disebutkan oleh Ibnu Abu 'Adi, Wallahu Ta'ala A'lam. "},"216":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ قَالَ حَدَّثَنَا حَمَّادٌ وَهُوَ ابْنُ زَيْدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْاسْتُحِيضَتْ فَاطِمَةُ بِنْتُ أَبِي حُبَيْشٍ فَسَأَلَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي أُسْتَحَاضُ فَلَا أَطْهُرُ أَفَأَدَعُ الصَّلَاةَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا ذَلِكَ عِرْقٌ وَلَيْسَتْ بِالْحَيْضَةِ فَإِذَا أَقْبَلَتْ الْحَيْضَةُ فَدَعِي الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَاغْسِلِي عَنْكِ أَثَرَ الدَّمِ وَتَوَضَّئِي فَإِنَّمَا ذَلِكَ عِرْقٌ وَلَيْسَتْ بِالْحَيْضَةِ قِيلَ لَهُ فَالْغُسْلُ قَالَ ذَلِكَ لَا يَشُكُّ فِيهِ أَحَدٌقَالَ أَبُو عَبْد الرَّحْمَنِ لَا أَعْلَمُ أَحَدًا ذَكَرَ فِي هَذَا الْحَدِيثِ وَتَوَضَّئِي غَيْرَ حَمَّادِ بْنِ زَيْدٍ وَقَدْ رَوَى غَيْرُ وَاحِدٍ عَنْ هِشَامٍ وَلَمْ يَذْكُرْ فِيهِ وَتَوَضَّئِي","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin 'Araby] dia berkata; telah menceritakan kepada kami [Hammad Yaitu Ibnu Zaid] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] Radliyallhu'anha bahwa Fatimah binti Hubaisy mengalami istihadhah, maka ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \" Wahai Rasulullah shallallahu 'alaihi wasallam! Aku sedang istihadhah, maka aku tidak bersuci. Apakah aku harus meninggalkan shalat?\" Rasulullah shallallahu 'alaihi wasallam berkata, \" Itu darah penyakit, bukan haid. Bila sedang haid maka tinggalkanlah shalat, dan jika sudah selesai dari haid maka cucilah bekas darah darimu dan berwudlulah, karena itu hanya darah penyakit, bukan haid.\" Beliau ditanya, \"Bagaimana dengan mandi?, maka beliau menjawab, \"Tidak seorangpun meragukan hal itu.\" Abu Abdurrahman berkata; \"saya tidak mengetahui seorangpun yang menyebutkan dalam hadits ini lafadz 'wa tawadha'i' (dan berwudlulah) selain Hammad bin Yazid, padahal telah banyak yang meriwayatkan hadits ini dari Hisyam, tapi mereka tidak menyebutkan di dalamnya lafadz 'Wa tawadha'i'. "},"217":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَتْ فَاطِمَةُ بِنْتُ أَبِي حُبَيْشٍ يَا رَسُولَ اللَّهِ لَا أَطْهُرُ أَفَأَدَعُ الصَّلَاةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا ذَلِكَ عِرْقٌ وَلَيْسَتْ بِالْحَيْضَةِ فَإِذَا أَقْبَلَتْ الْحَيْضَةُ فَدَعِي الصَّلَاةَ فَإِذَا ذَهَبَ قَدْرُهَا فَاغْسِلِي عَنْكِ الدَّمَ وَصَلِّي","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Hisyam bin 'Urwah] dari [Ayahnya], dari [Aisyah Radliyallahu'nha] dia berkata; \"Fatimah binti Abu Hubaisy berkata, 'Wahai Rasulullah shallallahu 'alaihi wasallam, aku tidak suci. Apakah aku harus meninggalkan shalat?\" Beliau shallallahu 'alaihi wasallam menjawab, \" Itu hanya darah penyakit, bukan darah haid. Bila datang waktu haid maka tinggalkanlah shalat, dan jika telah selesai waktu kebiasaan haid, maka cucilah (bersihkanlah) tempat darah itu dan shalatlah.\" "},"218":{"ar":"أَخْبَرَنَا أَبُو الْأَشْعَثِ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ سَمِعْتُ هِشَامَ بْنَ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ بِنْتَ أَبِي حُبَيْشٍ قَالَتْ يَا رَسُولَ اللَّهِ إِنِّي لَا أَطْهُرُ أَفَأَتْرُكُ الصَّلَاةَ قَالَ لَا إِنَّمَا هُوَ عِرْقٌ قَالَ خَالِدٌ فِيمَا قَرَأْتُ عَلَيْهِ وَلَيْسَتْ بِالْحَيْضَةِ فَإِذَا أَقْبَلَتْ الْحَيْضَةُ فَدَعِي الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَاغْسِلِي عَنْكِ الدَّمَ وَصَلِّي","id":"Telah mengabarkan kepada kami [Abu Al Asy'ats] dia berkata; telah menceritakan kepada kami [Khalid bin Al Harits] berkata; \"Saya mendengar dari [Hisyam bin 'Urwah] dari [Ayahnya], dari [Aisyah] Radliyallahu'anha bahwa Fatimah binti Abu Hubaisy berkata: \"Wahai Rasulullah shallallahu 'alaihi wasallam, aku tidak suci, jadi apakah aku harus meninggalkan shalat?\" Beliau shallallahu 'alaihi wasallam menjawab, \" Tidak, itu hanya darah penyakit, -Khalid berkomentar setelah ku ungkapkan kepadanya perihal `arq, \"`arq bukan darah haid. Jadi bila datang waktu haid maka tinggalkanlah shalat dan jika telah selesai waktu kebiasaan haid maka cucilah (tempat) keluarnya darah itu dan shalatlah.\" "},"219":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ بُكَيْرٍ أَنَّ أَبَا السَّائِبِ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَغْتَسِلْ أَحَدُكُمْ فِي الْمَاءِ الدَّائِمِ وَهُوَ جُنُبٌ","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud] dan [Harits bin Miskin] telah dibacakan kepadanya dan saya mendengar lafazhnya dari dia, dari [Ibnu Wahab] dari [Amr bin Al Harits] dari [Bukair] berkata; [Abu Saib] telah mengabarkan kepadanya bahwasannya dia telah mendengar [Abu Hurairah] berkata; telah bersabda Rasulullah shallallahu 'alaihi wasallam \"Janganlah salah seorang dari kalian mandi junub dalam air yang tergenang.\" "},"220":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ الْمُقْرِي عَنْ سُفْيَانَ عَنْ أَبِي الزِّنَادِ عَنْ مُوسَى بْنِ أَبِي عُثْمَانَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَبُولَنَّ أَحَدُكُمْ فِي الْمَاءِ الرَّاكِدِ ثُمَّ يَغْتَسِلُ مِنْهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazid Al Muqri] dari [Sufyan] dari [Abu Zinad] dari [Musa bin Abu Utsman] dari [Ayahnya] dari [Abu Hurairah] dia berkata; bahwa Rasulullah shallallahu 'alaihi wasallam bersabda, \" Janganlah salah seorang dari kalian buang air kecil dalam air yang diam (tergenang), kemudian mandi di situ.\" "},"221":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ هِشَامٍ قَالَ حَدَّثَنَا مَخْلَدٌ عَنْ سُفْيَانَ عَنْ أَبِي الْعَلَاءِ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ غُضَيْفِ بْنِ الْحَارِثِأَنَّهُ سَأَلَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَيُّ اللَّيْلِ كَانَ يَغْتَسِلُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ رُبَّمَا اغْتَسَلَ أَوَّلَ اللَّيْلِ وَرُبَّمَا اغْتَسَلَ آخِرَهُ قُلْتُ الْحَمْدُ لِلَّهِ الَّذِي جَعَلَ فِي الْأَمْرِ سَعَةً","id":"Telah mengabarkan kepada kami [Amr bin Hisyam] dia berkata; telah menceritakan kepada kami [Makhlad] dari [Sufyan] dari [Abu Al 'Allaa'i] dari ['Ubaidah bin Nusay] dari [Ghudhaif bin Al Harits] bahwa dia pernah bertanya kepada Aisyah Radliyallhu'anha, \"Kapan Rasulullah shallallahu 'alaihi wasallam mandi di malam hari?\" [Aisyah] menjawab, \" Beliau kadang mandi pada permulaan malam, namun kadang pula pada akhir malam.\" Aku berkata, \"Segala puji bagi Allah yang telah menjadikan kelonggaran dalam masalah ini.\""},"222":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ بُرْدٍ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ غُضَيْفِ بْنِ الْحَارِثِ قَالَدَخَلْتُ عَلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَسَأَلْتُهَا قُلْتُ أَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْتَسِلُ مِنْ أَوَّلِ اللَّيْلِ أَوْ مِنْ آخِرِهِ قَالَتْ كُلَّ ذَلِكَ رُبَّمَا اغْتَسَلَ مِنْ أَوَّلِهِ وَرُبَّمَا اغْتَسَلَ مِنْ آخِرِهِ قُلْتُ الْحَمْدُ لِلَّهِ الَّذِي جَعَلَ فِي الْأَمْرِ سَعَةً","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin 'Araby] dia berkata; telah menceritakan kepada kami [Hammad] dari [Burd] dari ['Ubadah bin Nusay] dari [Ghudaif bin Al Harits] dia berkata: \"Aku masuk menemui Aisyah Radliyallahu'anha, lalu aku bertanya kepadanya, 'Rasulullah shallallahu 'alaihi wasallam mandi pada permulaan malam atau pada akhir malam? ' [Aisyah] menjawab, 'Pada setiap waktu itu. Kadang ia mandi pada permulaan malam dan kadang pada akhir malam.\" Aku berkata, 'Segala puji bagi Allah yang telah menjadikan kelonggaran dalam masalah ini.\""},"223":{"ar":"أَخْبَرَنَا مُجَاهِدُ بْنُ مُوسَى قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنِي يَحْيَى بْنُ الْوَلِيدِ قَالَ حَدَّثَنِي مُحِلُّ بْنُ خَلِيفَةَ قَالَ حَدَّثَنِي أَبُو السَّمْحِ قَالَكُنْتُ أَخْدُمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ إِذَا أَرَادَ أَنْ يَغْتَسِلَ قَالَ وَلِّنِي قَفَاكَ فَأُوَلِّيهِ قَفَايَ فَأَسْتُرُهُ بِهِ","id":"Telah mengabarkan kepada kami [Mujahid bin Musa] dia berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] berkata; telah menceritakan kepadaku [Yahya bin Al Walid] dia berkata; telah menceritakan kepadaku [Muhil bin Khalifah] berkata; telah menceritakan kepadaku [Abu As-Samh] berkata; \"Aku pernah melayani Rasulullah shallallahu 'alaihi wasallam. Jika beliau hendak mandi, maka beliau berkata, 'Palingkan mukamu dariku'. Maka akupun memalingkan mukaku darinya dan menutupi beliau.\""},"224":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ عَنْ مَالِكٍ عَنْ سَالِمٍ عَنْ أَبِي مُرَّةَ مَوْلَى عَقِيلِ بْنِ أَبِي طَالِبٍ عَنْ أُمِّ هَانِئٍ رَضِيَ اللَّهُ عَنْهَاأَنَّهَا ذَهَبَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ فَوَجَدَتْهُ يَغْتَسِلُ وَفَاطِمَةُ تَسْتُرُهُ بِثَوْبٍ فَسَلَّمَتْ فَقَالَ مَنْ هَذَا قُلْتُ أُمُّ هَانِئٍ فَلَمَّا فَرَغَ مِنْ غُسْلِهِ قَامَ فَصَلَّى ثَمَانِيَ رَكَعَاتٍ فِي ثَوْبٍ مُلْتَحِفًا بِهِ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dari [Abdurrahman] dari [Malik] dari [Salim] dari [Abu Murrah] -budak Aqil bin Abu Thalib- dari [Ummu Hani Radliyallhu'anha] bahwa dia pernah pergi kepada Rasulullah shallallahu 'alaihi wasallam pada hari penaklukkan kota Makkah dan aku mendapati beliau sedang mandi, sedangkan Fatimah menutupinya dengan kain, lantas dia memberi salam. Rasulullah shallallahu 'alaihi wasallam lalu berkata, \"Siapa?\" Aku katakana, \"Ummu Hani.\" Setelah selesai mandi beliau bangkit lalu shalat delapan raka'at dengan kain yang diselimutkan di badannya.\" "},"225":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ مُوسَى الْجُهَنِيِّ قَالَأُتِيَ مُجَاهِدٌ بِقَدَحٍ حَزَرْتُهُ ثَمَانِيَةَ أَرْطَالٍ فَقَالَ حَدَّثَتْنِي عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَغْتَسِلُ بِمِثْلِ هَذَا","id":"Telah mengabarkan kepada kami [Muhammad bin Ubaid] dia berkata; telah menceritakan kepada kami [Yahya bin Zakaria bin Abu Zaidah] dari [Musa Al Juhani] dia berkata; bahwa [Mujahid] dibawakan ember -aku perkirakan (kapasitasnya) delapan rithl-, maka ia mengatakan bahwa [Aisyah Radliyallahu'anha] pernah menceritakan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam mandi dengan air yang seperti ini. "},"226":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بَكْرِ بْنِ حَفْصٍ سَمِعْتُ أَبَا سَلَمَةَ يَقُولُدَخَلْتُ عَلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا وَأَخُوهَا مِنْ الرَّضَاعَةِ فَسَأَلَهَا عَنْ غُسْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَتْ بِإِنَاءٍ فِيهِ مَاءٌ قَدْرَ صَاعٍ فَسَتَرَتْ سِتْرًا فَاغْتَسَلَتْ فَأَفْرَغَتْ عَلَى رَأْسِهَا ثَلَاثًا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul 'Ala] berkata; telah menceritakan kepada kami [Khalid] berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Bakr bin Hafsh] aku mendengar [Abu Salamah] berkata; \"Saya menemui [Aisyah] Radliyallahu'anha dan aku adalah saudara Aisyah sepersusuan. Lalu ia bertanya kepadanya tentang mandinya Rasulullah shallallahu 'alaihi wasallam? Maka ia meminta dibawakan bejana berisi air seukuran satu sha', lalu ia menutup diri dan mandi, dan beliau mandi menyiramkan ke kepalanya tiga kali.\""},"227":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْتَسِلُ فِي الْقَدَحِ وَهُوَ الْفَرَقُ وَكُنْتُ أَغْتَسِلُ أَنَا وَهُوَ فِي إِنَاءٍ وَاحِدٍ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] dia berkata: \"Rasulullah shallallahu 'alaihi wasallam dahulu mandi di ember -al faraq- dan aku mandi beliau dalam satu bejana.\""},"228":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ جَبْرٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ بِمَكُّوكٍ وَيَغْتَسِلُ بِخَمْسَةِ مَكَاكِيَّ","id":"Telah mengabarkan kepada kami [Suwaid bin Nushr] dia berkata; telah memberitakan kepada kami [Abdullah] berkata; telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Jubair] berkata; \"Saya mendengar [Anas bin Malik] berkata; \"Rasulullah shallallahu 'alaihi wasallam berwudlu dengan satu makkuk, dan bila mandi maka beliau menggunakan lima makkuk.\""},"229":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي جَعْفَرٍ قَالَتَمَارَيْنَا فِي الْغُسْلِ عِنْدَ جَابِرِ بْنِ عَبْدِ اللَّهِ فَقَالَ جَابِرٌ يَكْفِي مِنْ الْغُسْلِ مِنْ الْجَنَابَةِ صَاعٌ مِنْ مَاءٍ قُلْنَا مَا يَكْفِي صَاعٌ وَلَا صَاعَانِ قَالَ جَابِرٌ قَدْ كَانَ يَكْفِي مَنْ كَانَ خَيْرًا مِنْكُمْ وَأَكْثَرَ شَعْرًا","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Ishaq] dari [Abu Ja'far] berkata; \"Kami berdebat dalam masalah mandi dengan Jabir bin Abdullah, dia berkata; ' Dalam mandi junub cukup satu sha? ' Kami katakan bahwa tidak cukup hanya dengan satu atau dua sha. [Jabir] berkata, \"Satu sha' telah mencukupi bagi orang yang lebih baik dan lebih tebal rambutnya (Rasulullah shallallahu 'alaihi wasallam daripada kalian.\""},"230":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ ح وَأَنْبَأَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ وَابْنُ جُرَيْجٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكُنْتُ أَغْتَسِلُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ وَهُوَ قَدْرُ الْفَرَقِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah menceritakan kepada kami [Abdullah] dari [Ma'mar] dari [Az-Zuhri]. Dalam jalur periwayatan yang lain disebutkan; Dan telah memberitakan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Abdur Razak] berkata; Telah memberitakan kepada kami [Ma'mar] dan [Ibnu Juraij] dari [Az-Zuhri] dari ['Urwah] dari [Aisyah] Radliyallahu'anha, dia berkata; \" Aku pernah mandi bersama Rasulullah shallallahu 'alaihi wasallam dari satu bejana, dan bejana itu seukuran satu faraq.\" "},"231":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ هِشَامِ بْنِ عُرْوَةَ ح وَأَنْبَأَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَغْتَسِلُ وَأَنَا مِنْ إِنَاءٍ وَاحِدٍ نَغْتَرِفُ مِنْهُ جَمِيعًا","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah memberitakan kepada kami [Abdullah] dari [Hisyam bin 'Urwah] dan Telah memberitakan kepada kami [Qutaibah] dari [Malik] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah] Radliyallahu'anha dia berkata; \" Rasulullah shallallahu 'alaihi wasallam mandi bersamaku dari satu bejana. Kami menyiduk air dari bejana tersebut bersama-sama.\""},"232":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ الْقَاسِمِ قَالَ سَمِعْتُ الْقَاسِمَ يُحَدِّثُ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَغْتَسِلُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ مِنْ الْجَنَابَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; telah menceritakan kepadaku [Abdurrahman bin Al Qasim] dia berkata; saya mendengar [Al Qasim] diceritakan dari [Aisyah] dia berkata, \" Aku dan Rasulullah shallallahu 'alaihi wasallam mandi junub bersama dari satu bejana.\""},"233":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبِيدَةُ بْنُ حُمَيْدٍ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَقَدْ رَأَيْتُنِي أُنَازِعُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْإِنَاءَ أَغْتَسِلُ أَنَا وَهُوَ مِنْهُ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami ['Abidah bin Humaid] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] Radliyallahu'anha dia berkata, \" Seingatku aku pernah berebut bejana air bersama Rasulullah shallallahu 'alaihi wasallam. Aku dan beliau shallallahu 'alaihi wasallam mandi dari bejana tersebut.\""},"234":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي مَنْصُورٌ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكُنْتُ أَغْتَسِلُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ","id":"Telah mengabarkan kepada kami [Amr bin Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Sufyan] berkata; telah menceritakan kepadaku [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] Radliyallhu'anha dia berkata, \" Aku pernah mandi bersama Rasulullah shallallahu 'alaihi wasallam dari satu bejana.\""},"235":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ عَمْرٍو عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍ قَالَ أَخْبَرَتْنِي خَالَتِي مَيْمُونَةُأَنَّهَا كَانَتْ تَغْتَسِلُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ","id":"Telah mengabarkan kepada kami [Yahya bin Musa] dari [Sufyan] dari [Amr] dari [Jabir bin Zaid] dari [Ibnu Abbas] dia berkata; \"Bibiku - [Maimunah] - memberitahukan bahwa dia pernah mandi bersama Rasulullah shallallahu 'alaihi wasallam dari satu bejana.\""},"236":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ سَعِيدِ بْنِ يَزِيدَ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ هُرْمُزَ الْأَعْرَجَ يَقُولُ حَدَّثَنِي نَاعِمٌ مَوْلَى أُمِّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ أُمَّ سَلَمَةَ سُئِلَتْ أَتَغْتَسِلُ الْمَرْأَةُ مَعَ الرَّجُلِ قَالَتْ نَعَمْ إِذَا كَانَتْ كَيِّسَةً رَأَيْتُنِي وَرَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَغْتَسِلُ مِنْ مِرْكَنٍ وَاحِدٍ نُفِيضُ عَلَى أَيْدِينَا حَتَّى نُنْقِيَهُمَا ثُمَّ نُفِيضَ عَلَيْهَا الْمَاءَ قَالَ الْأَعْرَجُ لَا تَذْكُرُ فَرْجًا وَلَا تَبَالَهُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah menceritakan kepada kami [Abdullah] dari [Said bin Yazid] dia berkata; Saya mendengar [Abdurrahman bin Hurmuz Al A'raj] berkata; telah menceritakan kepadaku [Na'im] -budak Ummu Salamah Radliyallahu'anha bahwa [Ummu Salamah] pernah ditanya, \"Apakah perempuan boleh mandi bersama suaminya? Ia menjawab, \"Ya, jika perempuannya berakal dan cepat paham. Aku dan Rasulullah shallallahu 'alaihi wasallam pernah mandi bersama dari satu wadah. Kami mengguyur air ke tangan-tangan kami hingga kami membersihkannya, kemudian kami siramkan air kepada dua tangan kami.\" "},"237":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ دَاوُدَ الْأَوْدِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَلَقِيتُ رَجُلًا صَحِبَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا صَحِبَهُ أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ أَرْبَعَ سِنِينَ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَمْتَشِطَ أَحَدُنَا كُلَّ يَوْمٍ أَوْ يَبُولَ فِي مُغْتَسَلِهِ أَوْ يَغْتَسِلَ الرَّجُلُ بِفَضْلِ الْمَرْأَةِ وَالْمَرْأَةُ بِفَضْلِ الرَّجُلِ وَلْيَغْتَرِفَا جَمِيعًا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Daud Al Audi] dari [Humaid bin Abdurrahman], dia berkata; \"Aku berjumpa dengan [seseorang] yang bersahabat dengan Rasulullah shallallahu 'alaihi wasallam selama empat tahun, sebagaimana halnya Abu Hurairah Radliyallahu'anhu yang berkawan dengan nabi shallallahu 'alaihi wasallam selama itu pula, dia berkata; ' Rasulullah shallallahu 'alaihi wasallam melarang salah seorang dari kita menyisir rambut tiap hari atau buang air kecil pada tempat mandinya, atau seseorang mandi dengan air sisa mandi istrinya atau sebaliknya, namun ciduklah air itu bersama-sama.\" "},"238":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ عَنْ مُحَمَّدٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ ح و أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ عَاصِمٍ عَنْ مُعَاذَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكُنْتُ أَغْتَسِلُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءِ وَاحِدٍ يُبَادِرُنِي وَأُبَادِرُهُ حَتَّى يَقُولَ دَعِي لِي وَأَقُولُ أَنَا دَعْ لِي قَالَ سُوَيْدٌ يُبَادِرُنِي وَأُبَادِرُهُ فَأَقُولُ دَعْ لِي دَعْ لِي","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dari [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Ashim] dan Telah mengabarkan kepada kami [Suwaid bin Nashr] Telah memberitakan kepada kami [Abdullah] dari ['Ashim] dari [Mu'adzah] dari [Aisyah] Radliyallahu'anha dia berkata; \" Aku pernah mandi bersama Rasulullah shallallahu 'alaihi wasallam dari satu bejana. Beliau mendahuluiku dan aku pun mendahului beliau, hingga beliau berkata, 'Tinggalkan untukku'. Aku juga berkata, 'Tinggalkan untukku'. beliau mendahuluiku dan aku mendahului beliau, lalu aku katakan, 'Tinggalkan untukku, tinggalkan untukku.\""},"239":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ نَافِعٍ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أُمِّ هَانِئٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اغْتَسَلَ هُوَ وَمَيْمُونَةُ مِنْ إِنَاءٍ وَاحِدٍ فِي قَصْعَةٍ فِيهَا أَثَرُ الْعَجِينِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; telah menceritakan kepada kami [Abdurrahman] berkata; telah menceritakan kepada kami [Ibrahim bin Nafi'] dari [Ibnu Abu Nujaih] dari [Mujahid] dari [Ummu Hani'] bahwa Rasulullah shallallahu 'alaihi wasallam mandi bersama Maimunah dari satu bejana yang ada sisa adonan.\""},"240":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ مَنْصُورٍ عَنْ سُفْيَانَ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ عَبْدِ اللَّهِ بْنِ رَافِعٍ عَنْ أُمِّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي امْرَأَةٌ أَشُدُّ ضَفْرَ رَأْسِي أَفَأَنْقُضُهَا عِنْدَ غَسْلِهَا مِنْ الْجَنَابَةِ قَالَ إِنَّمَا يَكْفِيكِ أَنْ تَحْثِي عَلَى رَأْسِكِ ثَلَاثَ حَثَيَاتٍ مِنْ مَاءٍ ثُمَّ تُفِيضِينَ عَلَى جَسَدِكِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Manshur] dari [Sufyan] dari [Ayyub bin Musa] dari [Sa'id bin Abu Sa'id] dari [Abdullah bin Rafi'] dari [Ummu Salamah] Radliyallahu'anha -salah satu istri Rasulullah shallallahu 'alaihi wasallam- dia berkata, \"Aku pernah bertanya kepada beliau, 'Wahai Rasulullah shallallahu 'alaihi wasallam! Aku mengikat (rambut) kepalaku, apakah aku harus menguraikannya saat mandi junub? ' Beliau shallallahu 'alaihi wasallam menjawab, ' Cukup dengan menyiramkan air ke kepalamu tiga kali, kemudian siramkan ke badanmu.\""},"241":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا أَشْهَبُ عَنْ مَالِكٍ أَنَّ ابْنَ شِهَابٍ وَهِشَامَ بْنَ عُرْوَةَ حَدَّثَاهُ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ حَجَّةِ الْوَدَاعِ فَأَهْلَلْتُ بِالْعُمْرَةِ فَقَدِمْتُ مَكَّةَ وَأَنَا حَائِضٌ فَلَمْ أَطُفْ بِالْبَيْتِ وَلَا بَيْنَ الصَّفَا وَالْمَرْوَةِ فَشَكَوْتُ ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ انْقُضِي رَأْسَكِ وَامْتَشِطِي وَأَهِلِّي بِالْحَجِّ وَدَعِي الْعُمْرَةَ فَفَعَلْتُ فَلَمَّا قَضَيْنَا الْحَجَّ أَرْسَلَنِي مَعَ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ إِلَى التَّنْعِيمِ فَاعْتَمَرْتُ فَقَالَ هَذِهِ مَكَانُ عُمْرَتِكِقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا حَدِيثٌ غَرِيبٌ مِنْ حَدِيثِ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ لَمْ يَرْوِهِ أَحَدٌ إِلَّا أَشْهَبُ","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la] dia berkata; telah menceritakan kepada kami [Asyhab] dari [Malik] bahwa [Ibnu Syihab] dan [Hisyam bin Urwah] keduanya berkata kepadanya; dari [Urwah] dari [Aisyah] Radliyallahu'anha, dia berkata; \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam pada tahun haji wada'. Aku berihram untuk umrah, lalu datang ke Makkah padahal aku sedang haid, maka aku tidak thawaf di Ka'bah dan tidak sa'i antara Shafa dan Marwah. Kemudian aku mengadu kepada Rasulullah shallallahu 'alaihi wasallam, dan beliau pun bersabda, ' Lepaskan kepangan rambut kepalamu, lalu sisirlah. Kemudian berihram untuk haji dan tinggalkan umrah'. Akupun melakukannya, dan setelah selesai haji beliau mengutusku dan Abdurrahman bin Abu Bakar (saudaraku) ke Tan'im, lalu aku berihram. Beliau kemudian berkata kepadaku, 'Ini tempat umrahmu.\" Abu Abdurrahman berkata; \"Ini Hadits gharib (asing), hadits Malik dari Hisyam bin Urwah tidak seorangpun yang meriwayatkannya kecuali Asyhab. "},"242":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا حُسَيْنٌ عَنْ زَائِدَةَ قَالَ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَتْنِي عَائِشَةُ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا اغْتَسَلَ مِنْ الْجَنَابَةِ وُضِعَ لَهُ الْإِنَاءُ فَيَصُبُّ عَلَى يَدَيْهِ قَبْلَ أَنْ يُدْخِلَهُمَا الْإِنَاءَ حَتَّى إِذَا غَسَلَ يَدَيْهِ أَدْخَلَ يَدَهُ الْيُمْنَى فِي الْإِنَاءِ ثُمَّ صَبَّ بِالْيُمْنَى وَغَسَلَ فَرْجَهُ بِالْيُسْرَى حَتَّى إِذَا فَرَغَ صَبَّ بِالْيُمْنَى عَلَى الْيُسْرَى فَغَسَلَهُمَا ثُمَّ تَمَضْمَضَ وَاسْتَنْشَقَ ثَلَاثًا ثُمَّ يَصُبُّ عَلَى رَأْسِهِ مِلْءَ كَفَّيْهِ ثَلَاثَ مَرَّاتٍ ثُمَّ يُفِيضُ عَلَى جَسَدِهِ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Husain] dari [Zaidah] berkata; telah menceritakan kepada kami [Atha' bin Saib] berkata; telah menceritakan kepadaku [Abu Salamah bin Abdurrahman] berkata; telah menceritakan kepadaku [Aisyah] Radliyallahu'anha bahwa jika Rasulullah shallallahu 'alaihi wasallam mandi junub, maka diletakkannya bejana air lalu beliau menyiram kedua tangannya sebelum memasukkannya ke dalam bejana. Bila beliau sudah mencuci kedua tangannya, maka beliau memasukkan tangan kanannya kedalam bejana dan menyiramkan dengan tangan kanannya dan mencuci kemaluannya dengan tangan kirinya. Setelah selesai, maka beliau menyiramkan dengan tangan kanannya ke tangan kirinya, lalu mencuci keduanya, kemudian berkumur dan memasukkan air ke hidung tiga kali, menyiramkan air sepenuh telapak tangannya ke kepalanya tiga kali, dan menyiram seluruh badannya.\" "},"243":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِي سَلَمَةَ قَالَسَأَلْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا عَنْ غُسْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْجَنَابَةِ فَقَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُفْرِغُ عَلَى يَدَيْهِ ثَلَاثًا ثُمَّ يَغْسِلُ فَرْجَهُ ثُمَّ يَغْسِلُ يَدَيْهِ ثُمَّ يُمَضْمِضُ وَيَسْتَنْشِقُ ثُمَّ يُفْرِغُ عَلَى رَأْسِهِ ثَلَاثًا ثُمَّ يُفِيضُ عَلَى سَائِرِ جَسَدِهِ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Yazid] berkata; telah menceritakan kepada kami [Syu'bah] dari [Atha' bin Sa'ib] dari [Abu Salamah] berkata; \"Aku bertanya kepada Aisyah Radliyallahu'anha tentang mandi junub Rasulullah shallallahu 'alaihi wasallam? [Aisyah] lalu menjawab, \" Beliau shallallahu 'alaihi wasallam menyiramkan air ke kedua tangannya tiga kali, kemudian mencuci kemaluannya, lalu mencuci kedua tangannya, berkumur, memasukkan air ke hidung, menyiramkan air ke kepalanya tiga kali, kemudian menyiramkan air ke seluruh tubuhnya.\""},"244":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ أَنْبَأَنَا النَّضْرُ قَالَ أَنْبَأَنَا شُعْبَةُ قَالَ أَنْبَأَنَا عَطَاءُ بْنُ السَّائِبِ قَالَ سَمِعْتُ أَبَا سَلَمَةَأَنَّهُ دَخَلَ عَلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَسَأَلَهَا عَنْ غُسْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْجَنَابَةِ فَقَالَتْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُؤْتَى بِالْإِنَاءِ فَيَصُبُّ عَلَى يَدَيْهِ ثَلَاثًا فَيَغْسِلُهُمَا ثُمَّ يَصُبُّ بِيَمِينِهِ عَلَى شِمَالِهِ فَيَغْسِلُ مَا عَلَى فَخِذَيْهِ ثُمَّ يَغْسِلُ يَدَيْهِ وَيَتَمَضْمَضُ وَيَسْتَنْشِقُ وَيَصُبُّ عَلَى رَأْسِهِ ثَلَاثًا ثُمَّ يُفِيضُ عَلَى سَائِرِ جَسَدِهِ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] Telah memberitakan kepada kami [An-Nadhr] dia berkata; Telah memberitakan kepada kami [Syu'bah] berkata; Telah memberitakan kepada kami ['Atha bin Saib] berkata; \"Saya mendengar [Abu Salamah] dia pernah datang kepada Aisyah dan bertanya tentang mandi junub Rasulullah shallallahu 'alaihi wasallam? [Aisyah] lalu menjawab, \"Beliau shallallahu 'alaihi wasallam dibawakan bejana; beliau menyiramkan air ke kedua tangannya tiga kali, kemudian mencuci kedua tangannya, kemudian menyiramkan dengan tangan kanannya ke tangan kirinya, lantas mencuci apa yang ada di kedua pahanya, kemudian mencuci kedua tangannya dan berkumur serta memasukkan air ke hidung, kemudian menyiramkan air ke kepalanya tiga kali, lalu menyiramkan air ke seluruh tubuhnya.\""},"245":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عُمَرُ بْنُ عُبَيْدٍ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ قَالَوَصَفَتْ عَائِشَةُ غُسْلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْجَنَابَةِ قَالَتْ كَانَ يَغْسِلُ يَدَيْهِ ثَلَاثًا ثُمَّ يُفِيضُ بِيَدِهِ الْيُمْنَى عَلَى الْيُسْرَى فَيَغْسِلُ فَرْجَهُ وَمَا أَصَابَهُ قَالَ عُمَرُ وَلَا أَعْلَمُهُ إِلَّا قَالَ يُفِيضُ بِيَدِهِ الْيُمْنَى عَلَى الْيُسْرَى ثَلَاثَ مَرَّاتٍ ثُمَّ يَتَمَضْمَضُ ثَلَاثًا وَيَسْتَنْشِقُ ثَلَاثًا وَيَغْسِلُ وَجْهَهُ ثَلَاثًا ثُمَّ يُفِيضُ عَلَى رَأْسِهِ ثَلَاثًا ثُمَّ يَصُبُّ عَلَيْهِ الْمَاءَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Umar bin 'Ubaid] dari [Atha bin Saib] dari [Abu Salamah bin Abdurrahman] dia berkata; \" [Aisyah] menyifati (menerangkan) cara mandi Rasulullah shallallahu 'alaihi wasallam, dia berkata, 'Beliau mencuci kedua tangannya tiga kali, kemudian menyiramkan dengan tangan kanannya ke tangan kirinya, lantas mencuci kemaluannya dan yang mengenainya Umar berkata; \"Yang saya ketahui beliau menyiramkan dengan tangan kanannya ke tangan kirinya tiga kali-kemudian berkumur tiga kali serta memasukkan air ke hidung tiga kali, membasuh mukanya tiga kali, kemudian beliau menyiramkan air ke kepalanya tiga kali lalu menyiram seluruh tubuhnya. "},"246":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا اغْتَسَلَ مِنْ الْجَنَابَةِ بَدَأَ فَغَسَلَ يَدَيْهِ ثُمَّ تَوَضَّأَ كَمَا يَتَوَضَّأُ لِلصَّلَاةِ ثُمَّ يُدْخِلُ أَصَابِعَهُ الْمَاءَ فَيُخَلِّلُ بِهَا أُصُولَ شَعْرِهِ ثُمَّ يَصُبُّ عَلَى رَأْسِهِ ثَلَاثَ غُرَفٍ ثُمَّ يُفِيضُ الْمَاءَ عَلَى جَسَدِهِ كُلِّهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Hisyam bin Urwah] dari [Bapaknya] Dari [Aisyah] Radliyallahu'anha, apabila Rasulullah shallallahu 'alaihi wasallam mandi junub, maka beliau mulai dengan mencuci kedua tangannya, kemudian berwudlu seperti untuk shalat, kemudian memasukkan jari-jarinya kedalam air lalu membersihkan celah-celah pangkal rambutnya dengan jari-jarinya, lantas menyiramkan air ke kepalanya dengan cidukan tiga kali, kemudian menyiramkan air ke seluruh tubuhnya. "},"247":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ أَنْبَأَنَا يَحْيَى قَالَ أَنْبَأَنَا هِشَامُ بْنُ عُرْوَةَ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَتْنِي عَائِشَةُ رَضِيَ اللَّهُ عَنْهَاعَنْ غُسْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْجَنَابَةِ أَنَّهُ كَانَ يَغْسِلُ يَدَيْهِ وَيَتَوَضَّأُ وَيُخَلِّلُ رَأْسَهُ حَتَّى يَصِلَ إِلَى شَعْرِهِ ثُمَّ يُفْرِغُ عَلَى سَائِرِ جَسَدِهِ","id":"Telah mengabarkan kepada kami [Amr bin Ali] dia berkata; Telah memberitakan kepada kami [Yahya] dia berkata; Telah memberitakan kepada kami [Hisyam bin Urwah] dia berkata; telah mengabarkan kepadaku [Bapakku] dia berkata; telah menceritakan kepadaku [Aisyah] Radliyallahu'anha tentang mandi junub Rasulullah shallallahu 'alaihi wasallam, 'Beliau mencuci tangannya lalu berwudlu dan menyela-nyela kepalanya hingga rambutnya, kemudian menyiramkan air ke seluruh badannya.\""},"248":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُشَرِّبُ رَأْسَهُ ثُمَّ يَحْثِي عَلَيْهِ ثَلَاثًا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazid] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah] Radliyallahu'anha bahwa Rasulullah shallallahu 'alaihi wasallam mengairi kepalanya kemudian menyiramnya tiga kali.\" "},"249":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ سُلَيْمَانَ بْنِ صُرَدٍ عَنْ جُبَيْرِ بْنِ مُطْعِمٍ قَالَتَمَارَوْا فِي الْغُسْلِ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بَعْضُ الْقَوْمِ إِنِّي لَأَغْسِلُ كَذَا وَكَذَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا أَنَا فَأُفِيضُ عَلَى رَأْسِي ثَلَاثَ أَكُفٍّ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Abu Ahwash] dari [Abu Ishaq] dari [Sulaiman bin Shurd] dari [Jubair bin Muth'im] berkata; \"Orang-orang berdebat di hadapan Rasulullah shallallahu 'alaihi wasallam dalam masalah mandi; sebagian berkata, 'Aku menyiramkannya seperti ini. ' Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \" Aku menyiram kepalaku dengan tiga (cidukan) telapak tangan.\" "},"250":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ وَهُوَ ابْنُ صَفِيَّةَ عَنْ أُمِّهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ امْرَأَةً سَأَلْتِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ غُسْلِهَا مِنْ الْمَحِيضِ فَأَخْبَرَهَا كَيْفَ تَغْتَسِلُ ثُمَّ قَالَ خُذِي فِرْصَةً مِنْ مَسْكٍ فَتَطَهَّرِي بِهَا قَالَتْ وَكَيْفَ أَتَطَهَّرُ بِهَا فَاسْتَتَرَ كَذَا ثُمَّ قَالَ سُبْحَانَ اللَّهِ تَطَهَّرِي بِهَا قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا فَجَذَبْتُ الْمَرْأَةَ وَقُلْتُ تَتَّبِعِينَ بِهَا أَثَرَ الدَّمِ","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin Abdurrahman] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Manshur yaitu Ibnu Shafiyyah] dari [Ibunya] dari [Aisyah] Radliyallhu'anha bahwa ada seorang perempuan bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang mandi seorang perempuan dari haidnya? Maka Rasulullah shallallahu 'alaihi wasallam mengajarkan cara mandi dari haid. Kemudian beliau bersabda: \" Ambil sepotong kapas (yang sudah diberi) minyak wangi misik dan bersucilah dengannya.\" Lalu dia bertanya, \"Bagaimana aku bersuci dengannya\" Beliaupun segera bersembunyi dan bersabda, \"Subhaanallah! Bersucilah dengannya.\" Aisyah Radliyallahu'anha berkata; Maka aku menariknya dan kukatakan kepadanya; 'kamu usap-usap dengan kapas itu sisa-sisa darahnya. '"},"251":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا أَبِي أَنْبَأَنَا الْحَسَنُ وَهُوَ ابْنُ صَالِحٍ عَنْ أَبِي إِسْحَقَ ح و حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَتَوَضَّأُ بَعْدَ الْغُسْلِ","id":"Telah mengabarkan kepada kami [Ahmad bin Utsman bin Hakim] dia berkata; Telah menceritakan kepada kami [Bapakku] Telah memberitakan kepada kami [Al Hasan yaitu Ibnu Shalih] dari [Abu Ishaq], dan telah menceritakan kepada kami [Amr bin Ali] dia berkata; Telah menceritakan kepada kami [Abdurrahman] berkata; Telah menceritakan kepada kami [Syarik] dari [Abu Ishaq] dari [Al Aswad] dari [Aisyah] Radliyallahu'anha dia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak berwudlu lagi setelah mandi wajib.\""},"252":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا عِيسَى عَنْ الْأَعْمَشِ عَنْ سَالِمٍ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَ حَدَّثَتْنِي خَالَتِي مَيْمُونَةُ قَالَتْأَدْنَيْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غُسْلَهُ مِنْ الْجَنَابَةِ فَغَسَلَ كَفَّيْهِ مَرَّتَيْنِ أَوْ ثَلَاثًا ثُمَّ أَدْخَلَ بِيَمِينِهِ فِي الْإِنَاءِ فَأَفْرَغَ بِهَا عَلَى فَرْجِهِ ثُمَّ غَسَلَهُ بِشِمَالِهِ ثُمَّ ضَرَبَ بِشِمَالِهِ الْأَرْضَ فَدَلَكَهَا دَلْكًا شَدِيدًا ثُمَّ تَوَضَّأَ وُضُوءَهُ لِلصَّلَاةِ ثُمَّ أَفْرَغَ عَلَى رَأْسِهِ ثَلَاثَ حَثَيَاتٍ مِلْءَ كَفِّهِ ثُمَّ غَسَلَ سَائِرَ جَسَدِهِ ثُمَّ تَنَحَّى عَنْ مَقَامِهِ فَغَسَلَ رِجْلَيْهِ قَالَتْ ثُمَّ أَتَيْتُهُ بِالْمِنْدِيلِ فَرَدَّهُ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dia berkata; Telah memberitakan kepada kami [Isa] dari [Al A'masy] dari [Salim] dari [Kuraib] dari [Ibnu Abbas] dia berkata; Telah menceritakan kepadaku sepupuku - [Maimunah] - dia berkata; ' Aku mendekat kepada Rasulullah shallallahu 'alaihi wasallam saat beliau mandi junub; beliau mencuci kedua telapak tangannya dua kali atau tiga kali, kemudian memasukkan tangannya kedalam bejana, lalu menuangkan air ke kemaluannya dan mencuci dengan tangan kirinya, lalu memukulkan tangan kirinya ke tanah dan menggosok-gosoknya dengan kuat, kemudian beliau berwudlu sebagaimana wudlu untuk shalat. Selanjutnya beliau menyiramkan air sepenuh telapak tangan ke kepalanya sebanyak tiga kali, dan membasuh seluruh badannya. Kemudian berpindah dari tempat mandinya, lalu membasuh kakinya.\" Dia berkata, \"Aku membawakan handuk, namun beliau menolaknya.\""},"253":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ أَيُّوبَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ الْأَعْمَشِ عَنْ سَالِمٍ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اغْتَسَلَ فَأُتِيَ بِمِنْدِيلٍ فَلَمْ يَمَسَّهُ وَجَعَلَ يَقُولُ بِالْمَاءِ هَكَذَا","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya bin Ayyub bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Abdullah bin Idris] dari [Al A'masy] dari [Salim] dari [Kuraib] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam mandi, kemudian di bawakan handuk untuknya. Namun beliau tidak mengelap (badan) nya dengan handuk tersebut. Beliau katakan 'cukuplah air di badan ini dilap dengan tangan'. "},"254":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ سُفْيَانَ بْنِ حَبِيبٍ عَنْ شُعْبَةَ ح و حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى وَعَبْدُ الرَّحْمَنِ عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ عَمْرٌو كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَنْ يَأْكُلَ أَوْ يَنَامَ وَهُوَ جُنُبٌ تَوَضَّأَ زَادَ عَمْرٌو فِي حَدِيثِهِ وُضُوءَهُ لِلصَّلَاةِ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dari [Sufyan bin Habib] dari [Syu'bah], dan telah menceritakan kepada kami [Amr bin Ali] dia berkata; Telah menceritakan kepada kami [Yahya] dan [Abdurrahman] dari [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] Radliyallahu'anha, dia berkata, \"Nabi shallallahu 'alaihi wasallam -pada lafazh lain Rasulullah shallallahu 'alaihi wasallam - bila ingin makan atau tidur ketika sedang junub, maka beliau berwudlu. Amr menambahkan, \"seperti wudlu untuk shalat.\""},"255":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُبَيْدِ بْنِ مُحَمَّدٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَرَادَ أَنْ يَنَامَ وَهُوَ جُنُبٌ تَوَضَّأَ وَإِذَا أَرَادَ أَنْ يَأْكُلَ غَسَلَ يَدَيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ubaid bin Muhammad] dia berkata; Telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Yunus] dari [Az-Zuhri] dari [Abu Salamah] dari [Aisyah Radliyallahu'anha], bahwa apabila Rasulullah shallallahu 'alaihi wasallam hendak tidur sedangkan beliau dalam keadaan junub, maka beliau berwudlu, dan bila hendak makan beliau hanya mencuci keduanya tangannya. "},"256":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَنْ يَنَامَ وَهُوَ جُنُبٌ تَوَضَّأَ وَإِذَا أَرَادَ أَنْ يَأْكُلَ أَوْ يَشْرَبَ قَالَتْ غَسَلَ يَدَيْهِ ثُمَّ يَأْكُلُ أَوْ يَشْرَبُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah memberitakan kepada kami [Abdullah] dari [Yunus] dari [Az-Zuhri] dari [Abu Salamah] dari [Aisyah Radliyallahu'anha], dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam ingin tidur dan beliau sedang junub, maka beliau berwudlu, dan bila ingin makan atau minum (Aisyah) berkata, \"Beliau mencuci kedua tangannya, kemudian makan atau minum.\""},"257":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَرَادَ أَنْ يَنَامَ وَهُوَ جُنُبٌ تَوَضَّأَ وُضُوءَهُ لِلصَّلَاةِ قَبْلَ أَنْ يَنَامَ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; Telah menceritakan kepada kami [Al-Laits] dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman] dari [Aisyah] Radliyallahu'anha, dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam ingin tidur padahal beliau sedang junub, maka beliau berwudlu seperti wudlu untuk shalat sebelum tidur.\""},"258":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ عُمَرَ قَالَ يَا رَسُولَ اللَّهِ أَيَنَامُ أَحَدُنَا وَهُوَ جُنُبٌ قَالَ إِذَا تَوَضَّأَ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] dia berkata; Telah menceritakan kepada kami [Yahya] dari [Ubaidullah] dia berkata; Telah mengabarkan kepadaku [Nafi'] dari [Abdullah bin Umar] bahwa Umar pernah bertanya, \"Wahai Rasulullah shallallahu 'alaihi wasallam! Apakah salah seorang dari kami boleh tidur bila sedang junub?\" Beliau menjawab, \"Jika ia telah wudlu.\""},"259":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَذَكَرَ عُمَرُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ تُصِيبُهُ الْجَنَابَةُ مِنْ اللَّيْلِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأْ وَاغْسِلْ ذَكَرَكَ ثُمَّ نَمْ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abdullah bin Dinar] dari [Ibnu Umar] dia berkata; \"Umar berkata kepada Rasulullah shallallahu 'alaihi wasallam bahwa dirinya pada suatu malam pernah mengalami junub? Lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya, ' Berwudlu dan cucilah kemaluannya, kemudian tidurlah.\""},"260":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ قَالَ أَنْبَأَنَا شُعْبَةُ ح وَأَنْبَأَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ وَاللَّفْظُ لَهُ عَنْ عَلِيِّ بْنِ مُدْرِكٍ عَنْ أَبِي زُرْعَةَ عَنْ عَبْدِ اللَّهِ بْنِ نُجَيٍّ عَنْ أَبِيهِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَدْخُلُ الْمَلَائِكَةُ بَيْتًا فِيهِ صُورَةٌ وَلَا كَلْبٌ وَلَا جُنُبٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Hisyam bin Abdul Malik] dia berkata; Telah memberitakan kepada kami [Syu'bah], dan Telah memberitakan kepada kami [Ubaidullah bin Sa'id] dia berkata; Telah menceritakan kepada kami [Yahya] dari [Syu'bah] dan lafazh ini darinya, dari [Ali bin Mudrik] dari [Abu Zur'ah] dari [Abdullah bin Nujay] dari [Bapaknya] dari [Ali] Radliyallahu'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \" Malaikat tidak akan masuk ke dalam rumah yang di dalamnya ada gambar, anjing dan orang yang sedang junub.\""},"261":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَرَادَ أَحَدُكُمْ أَنْ يَعُودَ تَوَضَّأَ","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits] dia berkata; Telah menceritakan kepada kami [Sufyan] dari ['Ashim] dari [Abu Al Mutawakkil] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \" Apabila salah seorang dari kalian hendak mengulangi (bersetubuh), berwudlulah.\""},"262":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَيَعْقُوبُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لِإِسْحَقَ قَالَا حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَافَ عَلَى نِسَائِهِ فِي لَيْلَةٍ بِغُسْلٍ وَاحِدٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dan [Ya'qub bin Ibrahim] lafazh ini dari Ishaq, keduanya berkata; Telah menceritakan kepada kami [Ismail bin Ibrahim] dari [Humaid At- Thawil] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam menggilir istri-istrinya dalam satu malam dengan satu kali mandi. "},"263":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَطُوفُ عَلَى نِسَائِهِ فِي غُسْلٍ وَاحِدٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Ubaid] dia berkata; Telah menceritakan kepada kami [Abdullah bin Mubarak] dia berkata; Telah memberitakan kepada kami [Ma'mar] dari [Qatadah] dari [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam menggilir istrinya dengan satu kali mandi. "},"264":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ شُعْبَةَ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ سَلَمَةَ قَالَأَتَيْتُ عَلِيًّا أَنَا وَرَجُلَانِ فَقَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجُ مِنْ الْخَلَاءِ فَيَقْرَأُ الْقُرْآنَ وَيَأْكُلُ مَعَنَا اللَّحْمَ وَلَمْ يَكُنْ يَحْجُبُهُ عَنْ الْقُرْآنِ شَيْءٌ لَيْسَ الْجَنَابَةَ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dia berkata; Telah memberitakan kepada kami [Ismail bin Ibrahim] dari [Syu'bah] dari [Amr bin Murrah] dari [Abdullah bin Salamah] dia berkata; \"Aku dan dua orang laki-laki mendatangi Ali, maka kemudian [Ali] berkata; Rasulullah shallallahu 'alaihi wasallam keluar dari kamar mandi WC, kemudian beliau membaca Al Qur'an, dan makan daging bersama kami, tidak ada yang menghalangi beliau dari membaca Al Qur'an, selain junub. "},"265":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ أَبُو يُوسُفَ الصَّيْدَلَانِيُّ الرِّقِّيُّ قَالَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ سَلَمَةَ عَنْ عَلِيٍّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ الْقُرْآنَ عَلَى كُلِّ حَالٍ لَيْسَ الْجَنَابَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad Abu Yusuf As-Shailadani Ar-Riqqi] berkata; Telah menceritakan kepada kami [Isa bin Yunus] berkata; Telah menceritakan kepada kami [Al- A'masy] dari [Amr bin Murrah] dari [Abdullah bin Salamah] dari [Ali] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam selalu membaca Al-Qur'an di setiap saat, kecuali ketika junub.\""},"266":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ الشَّيْبَانِيِّ عَنْ أَبِي بُرْدَةَ عَنْ حُذَيْفَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا لَقِيَ الرَّجُلَ مِنْ أَصْحَابِهِ مَاسَحَهُ وَدَعَا لَهُ قَالَ فَرَأَيْتُهُ يَوْمًا بُكْرَةً فَحِدْتُ عَنْهُ ثُمَّ أَتَيْتُهُ حِينَ ارْتَفَعَ النَّهَارُ فَقَالَ إِنِّي رَأَيْتُكَ فَحِدْتَ عَنِّي فَقُلْتُ إِنِّي كُنْتُ جُنُبًا فَخَشِيتُ أَنْ تَمَسَّنِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمُسْلِمَ لَا يَنْجُسُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Jarir] dari [As-Syaibani] dari [Abu Burdah] dari [Hudzaifah] berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam bertemu dengan sahabatnya, maka beliau bersalaman dan mendoakannya. Kemudian Hudzaifah berkata, \"Pada suatu hari aku bertemu dengan beliau shallallahu 'alaihi wasallam, maka aku segera menghindar darinya. Kemudian aku mendatanginya saat matahari telah tinggi, dan beliau shallallahu 'alaihi wasallam berkata kepadaku, 'Aku melihatmu terburu-buru menghindar dariku? ' Aku berkata, \"Aku sedang junub. Aku khawatir engkau menyentuhku! ' Beliau lalu bersabda: ' Orang muslim itu tidak najis.\""},"267":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ أَخْبَرَنَا يَحْيَى قَالَ حَدَّثَنَا مِسْعَرٌ قَالَ حَدَّثَنِي وَاصِلٌ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقِيَهُ وَهُوَ جُنُبٌ فَأَهْوَى إِلَيَّ فَقُلْتُ إِنِّي جُنُبٌ فَقَالَ إِنَّ الْمُسْلِمَ لَا يَنْجُسُ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; Telah mengabarkan kepada kami [Yahya] berkata; Telah menceritakan kepada kami [Mis'ar] berkata; Telah menceritakan kepadaku [Washil] dari [Abu Wa'il] dari [Hudzaifah] bahwa Nabi shallallahu 'alaihi wasallam berjumpa dengannya, sedangkan dia dalam keadaan junub. Hudzaifah berkata, \"Beliau mendekat kepadaku dengan cepat, maka aku katakan bahwa aku sedang junub. Beliau shallallahu 'alaihi wasallam lalu bersabda; \" Orang muslim tidak najis\". "},"268":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا بِشْرٌ وَهُوَ ابْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ بَكْرٍ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقِيَهُ فِي طَرِيقٍ مِنْ طُرُقِ الْمَدِينَةِ وَهُوَ جُنُبٌ فَانْسَلَّ عَنْهُ فَاغْتَسَلَ فَفَقَدَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا جَاءَ قَالَ أَيْنَ كُنْتَ يَا أَبَا هُرَيْرَةَ قَالَ يَا رَسُولَ اللَّهِ إِنَّكَ لَقِيتَنِي وَأَنَا جُنُبٌ فَكَرِهْتُ أَنْ أُجَالِسَكَ حَتَّى أَغْتَسِلَ فَقَالَ سُبْحَانَ اللَّهِ إِنَّ الْمُؤْمِنَ لَا يَنْجُسُ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dia berkata; Telah menceritakan kepada kami [Bisyr yaitu Ibnu Al Mufadlal] dia berkata; Telah menceritakan kepada kami [Humaid] dari [Bakr] dari [Abu Rafi'] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam berjumpa dengannya di sebuah jalan di Madinah, sedangkan dia (Abu Hurairah) dalam keadaan junub. Dia pun segera mengelak dari Rasulullah shallallahu 'alaihi wasallam dan segera mandi. Rasulullah shallallahu 'alaihi wasallam mencari-carinya dan setelah Abu Hurairah datang beliau segera bertanya kepadanya, \"Dimana kamu tadi wahai Abu Hurairah?\" Abu Hurairah menjawab, \"Wahai Rasulullah shallallahu 'alaihi wasallam, engkau menjumpaiku sedangkan aku dalam keadaan junub. Aku tidak suka duduk bersama engkau hingga aku mandi!\" Beliau bersabda: \" Maha suci Allah. Orang mukmin itu tidak najis.\""},"269":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ يَزِيدَ بْنَ كَيْسَانَ قَالَ حَدَّثَنِي أَبُو حَازِمٍ قَالَ قَالَ أَبُو هُرَيْرَةَبَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ إِذْ قَالَ يَا عَائِشَةُ نَاوِلِينِي الثَّوْبَ فَقَالَتْ إِنِّي لَا أُصَلِّي قَالَ إِنَّهُ لَيْسَ فِي يَدِكِ فَنَاوَلَتْهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Yazid bin Kaisan] dia berkata; Telah menceritakan kepadaku [Abu Hazim] dia berkata; [Abu Hurairah] berkata; \" Tatkala Rasulullah shallallahu 'alaihi wasallam di masjid, tiba-tiba beliau bersabda, 'Wahai Aisyah, ambilkan baju. ' Aisyah menjawab, 'Aku tidak shalat (sedang tidak suci). ' Beliau bersabda, \"Haid tidak di tanganmu.\" Lalu diapun mengambilkannya.\""},"270":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ عَبِيدَةَ عَنْ الْأَعْمَشِ ح و أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ ثَابِتِ بْنِ عُبَيْدٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاوِلِينِي الْخُمْرَةَ مِنْ الْمَسْجِدِ قَالَتْ إِنِّي حَائِضٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَتْ حَيْضَتُكِ فِي يَدِكِأَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Qutaibah bin Said] dari [Abidah] dari [Al A'masy], dan Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Tsabit bin Ubaid] dari [Al Qasim bin Muhammad] dari [Aisyah] Radliyallahu'anha, dia mengatakan bahwa Rasulullah shallallahu 'alaihi wasallam bersabda, \"Ambilkan tikar kecil dari masjid.\" Aisyah berkata, \"Aku sedang haid.\" Rasulullah shallallahu 'alaihi wasallam bersabda, \"Haidmu tidak di tanganmu.\" Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dengan sanad seperti ini juga. "},"271":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ عَنْ سُفْيَانَ عَنْ مَنْبُوذٍ عَنْ أُمِّهِ أَنَّ مَيْمُونَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضَعُ رَأْسَهُ فِي حَجْرِ إِحْدَانَا فَيَتْلُو الْقُرْآنَ وَهِيَ حَائِضٌ وَتَقُومُ إِحْدَانَا بِالْخُمْرَةِ إِلَى الْمَسْجِدِ فَتَبْسُطُهَا وَهِيَ حَائِضٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dari [Sufyan] dari [Manbudz] dari [Ibunya] bahwa [Maimunah] berkata; \" Rasulullah shallallahu 'alaihi wasallam meletakkan kepalanya di kamar salah satu dari kami (istri-istri Nabi shallallahu 'alaihi wasallam dan beliau membaca Al-Qur'an, dan Maimunah sedang haid. Salah satu dari kami (istri-istri Nabi shallallahu 'alaihi wasallam bangkit membawa tikar ke masjid, lalu menggelarnya, padahal dia sedang haid.\" "},"272":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَلِيُّ بْنُ حُجْرٍ وَاللَّفْظُ لَهُ أَنْبَأَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ أُمِّهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَأْسُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجْرِ إِحْدَانَا وَهِيَ حَائِضٌ وَهُوَ يَتْلُو الْقُرْآنَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dan [Ali bin Hujr] Lafazh ini darinya, telah memberitakan kepada kami [Sufyan] dari [Manshur] dari [Ibunya] dari [Aisyah] Radliyallahu'anha, dia berkata, \" Kepala Rasulullah shallallahu 'alaihi wasallam berada di kamar salah satu dari kami yang sedang haid, dan beliau membaca Al-Qur'an.\""},"273":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي مَنْصُورٌ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُومِئُ إِلَيَّ رَأْسَهُ وَهُوَ مُعْتَكِفٌ فَأَغْسِلُهُ وَأَنَا حَائِضٌ","id":"Telah mengabarkan kepada kami [Amr bin Ali] dia berkata; Telah menceritakan kepada kami [Yahya] berkata; Telah menceritakan kepada kami [Sufyan] berkata; Telah menceritakan kepadaku [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] Radliyallahu'anha, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah melongokkan (menjulurkan) kepalanya kepadaku padahal beliau sedang i'tikaf, maka aku membasuhnya, padahal aku sedang haid.\" "},"274":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ وَذَكَرَ آخَرُ عَنْ أَبِي الْأَسْوَدِ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخْرِجُ إِلَيَّ رَأْسَهُ مِنْ الْمَسْجِدِ وَهُوَ مُجَاوِرٌ فَأَغْسِلُهُ وَأَنَا حَائِضٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; Telah menceritakan kepada kami [Ibnu Wahab] dari [Amr bin Al Harits], dan yang lainnya menyebutkan dari [Abu Al Aswad] dari [Urwah] dari [Aisyah] Radliyallahu'anha, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengeluarkan kepalanya kepadaku dari dalam masjid, karena masjidnya bersebelahan, maka aku membasuhnya padahal aku sedang haid. "},"275":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكُنْتُ أُرَجِّلُ رَأْسَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا حَائِضٌأَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ ح وَأَنْبَأَنَا عَلِيُّ بْنُ شُعَيْبٍ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا مَالِكٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا مِثْلَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah] Radliyallahu'anha, dia berkata, \" Aku pernah menyisir rambut Rasulullah shallallahu 'alaihi wasallam, padahal aku sedang haid.\" Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik], dan Telah memberitakan kepada kami [Ali bin Syu'aib] dia berkata; telah menceritakan kepada kami [Ma'an] berkata; telah menceritakan kepada kami [Malik] dari [Az-Zuhri] dari [Urwah] dari [Aisyah] Radliyallahu'anha seperti itu juga. "},"276":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ الْمِقْدَامِ بْنِ شُرَيْحِ بْنِ هَانِئٍ عَنْ أَبِيهِ عَنْ شُرَيْحٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا سَأَلْتُهَاهَلْ تَأْكُلُ الْمَرْأَةُ مَعَ زَوْجِهَا وَهِيَ طَامِثٌ قَالَتْ نَعَمْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُونِي فَآكُلُ مَعَهُ وَأَنَا عَارِكٌ وَكَانَ يَأْخُذُ الْعَرْقَ فَيُقْسِمُ عَلَيَّ فِيهِ فَأَعْتَرِقُ مِنْهُ ثُمَّ أَضَعُهُ فَيَأْخُذُهُ فَيَعْتَرِقُ مِنْهُ وَيَضَعُ فَمَهُ حَيْثُ وَضَعْتُ فَمِي مِنْ الْعَرْقِ وَيَدْعُو بِالشَّرَابِ فَيُقْسِمُ عَلَيَّ فِيهِ قَبْلَ أَنْ يَشْرَبَ مِنْهُ فَآخُذُهُ فَأَشْرَبُ مِنْهُ ثُمَّ أَضَعُهُ فَيَأْخُذُهُ فَيَشْرَبُ مِنْهُ وَيَضَعُ فَمَهُ حَيْثُ وَضَعْتُ فَمِي مِنْ الْقَدَحِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Yazid yaitu Ibnu Miqdam bin Syuraih bin Hani'] dari [Bapaknya] dari [Syuraih] dari [Aisyah] Radliyallahu'anha aku (perawi) bertanya kepadanya, \"Apakah perempuan boleh makan bersama dengan suaminya jika dia sedang datang haid?\" Dia (Aisyah) berkata, \"Ya, boleh. Rasulullah shallallahu 'alaihi wasallam pernah memanggilku, lalu aku makan bersama beliau, padahal aku sedang haid. Beliau shallallahu 'alaihi wasallam mengambil daging dan membaginya kepadaku. Lantas aku segera memakannya, dan aku menaruhnya. Lalu Rasulullah shallallahu 'alaihi wasallam mengambilnya dan memakannya. Beliau meletakkan mulutnya di daging tempat aku meletakkan mulutku tadi. Lalu beliau meminta air minum dan membaginya kepadaku sebelum beliau meminumnya. Lalu beliau mengambil dan meminumnya, kemudian meletakkannya. Kemudian beliau mengambil dan meminumnya, dan beliau meletakkan mulutnya di tempat aku meletakkan mulutku pada gelas tadi, \""},"277":{"ar":"أَخْبَرَنَا أَيُّوبُ بْنُ مُحَمَّدٍ الْوَزَّانُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ الْأَعْمَشِ عَنْ الْمِقْدَامِ بْنِ شُرَيْحٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضَعُ فَاهُ عَلَى الْمَوْضِعِ الَّذِي أَشْرَبُ مِنْهُ فَيَشْرَبُ مِنْ فَضْلِ سُؤْرِي وَأَنَا حَائِضٌ","id":"Telah mengabarkan kepada kami [Ayyub bin Muhammad Al Wazzan] dia berkata; Telah menceritakan kepada kami [Abdullah bin Ja'far] dia berkata; Telah menceritakan kepada kami [Ubaidullah bin Amr] dari [Al A'masy] dari [Al Miqdam bin Syuraih] dari [Bapaknya] dari [Aisyah] Radliyallahu'anha dia berkata, \"Rasulullah shallallahu 'alaihi wasallam meletakkan mulutnya di tempat aku meletakkan mulutku ketika aku meminumnya, dan beliau juga meminum sisa minumku, padahal aku sedang haid.\" "},"278":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مِسْعَرٍ عَنْ الْمِقْدَامِ بْنِ شُرَيْحٍ عَنْ أَبِيهِ قَالَ سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا تَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنَاوِلُنِي الْإِنَاءَ فَأَشْرَبُ مِنْهُ وَأَنَا حَائِضٌ ثُمَّ أُعْطِيهِ فَيَتَحَرَّى مَوْضِعَ فَمِي فَيَضَعُهُ عَلَى فِيهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Mis'ar] dari [Al Miqdam bi Syuraih] dari [Bapaknya] dia berkata; Saya mendengar [Aisyah] Radliyallahu'anha berkata; \" Rasulullah shallallahu 'alaihi wasallam memberikan gelas kepadaku, lalu aku minum darinya, padahal aku sedang haid. Kemudian aku berikan kepadanya, maka beliau mencari bekas tempat mulutku lalu meletakkan mulutnya di situ.\""},"279":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا مِسْعَرٌ وَسُفْيَانُ عَنْ الْمِقْدَامِ بْنِ شُرَيْحٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكُنْتُ أَشْرَبُ وَأَنَا حَائِضٌ وَأُنَاوِلُهُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَضَعُ فَاهُ عَلَى مَوْضِعِ فِيَّ فَيَشْرَبُ وَأَتَعَرَّقُ الْعَرْقَ وَأَنَا حَائِضٌ وَأُنَاوِلُهُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَضَعُ فَاهُ عَلَى مَوْضِعِ فِيَّ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] dia berkata; Telah menceritakan kepada kami [Waki'] dia berkata; Telah menceritakan kepada kami [Mis'ar] dan [Sufyan] dari [Al Miqdam bin Syuraih] dari [Bapaknya] dari [Aisyah] Radliyallahu'anha, dia berkata, \" Aku pernah minum dalam keadaan haid lalu -sisa minum- aku berikan kepada Nabi shallallahu 'alaihi wasallam, maka beliau meletakkan mulutnya di tempat mulutku, lalu beliau minum. Aku juga pernah menggigit daging dalam keadaan haid, lalu -sisa daging- aku berikan kepada Nabi shallallahu 'alaihi wasallam, maka beliau meletakkan mulutnya di tempat mulutku tadi.\" "},"280":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا هِشَامٌ ح وَأَنْبَأَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَا حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ وَاللَّفْظُ لَهُ قَالَ حَدَّثَنِي أَبِي عَنْ يَحْيَى قَالَ حَدَّثَنَا أَبُو سَلَمَةَ أَنَّ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ حَدَّثَتْهُ أَنَّ أُمَّ سَلَمَةَ حَدَّثَتْهَا قَالَتْبَيْنَمَا أَنَا مُضْطَجِعَةٌ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْخَمِيلَةِ إِذْ حِضْتُ فَانْسَلَلْتُ فَأَخَذْتُ ثِيَابَ حَيْضَتِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَفِسْتِ قُلْتُ نَعَمْ فَدَعَانِي فَاضْطَجَعْتُ مَعَهُ فِي الْخَمِيلَةِ","id":"Telah mengabarkan kepada kami [Ismail bin Mas'ud] dia berkata; Telah menceritakan kepada kami [Khalid] berkata; Telah menceritakan kepada kami [Hisyam] dan Telah memberitakan kepada kami [Ubaidullah bin Sa'id] dan [Ishaq bin Ibrahim] keduanya berkata; Telah menceritakan kepada kami [Mu'adz bin Hisyam] lafazh ini darinya, dia berkata; Telah menceritakan kepadaku [Bapakku] dari [Yahya] dia berkata; Telah menceritakan kepada kami [Abu Salamah] bahwa [Zainab binti Abu Salamah] berkata kepadanya, sesungguhnya [Ummu Salamah] berkata; \" Ketika aku sedang berbaring (tidur) bersama Rasulullah shallallahu 'alaihi wasallam didalam selimut, tiba-tiba aku haid, maka aku keluar perlahan-lahan, kemudian mengambil pakaian (yang biasa dipakai) haid. Rasulullah shallallahu 'alaihi wasallam bertanya, \"Apakah kamu sedang haid?\" Aku menjawab, 'Ya'. Beliau lalu memanggilku, kami berbaring (tidur) bersama dalam satu selimut.\""},"281":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ جَابِرِ بْنِ صُبْحٍ قَالَ سَمِعْتُ خِلَاسًا يُحَدِّثُ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبِيتُ فِي الشِّعَارِ الْوَاحِدِ وَأَنَا طَامِثٌ أَوْ حَائِضٌ فَإِنْ أَصَابَهُ مِنِّي شَيْءٌ غَسَلَ مَكَانَهُ وَلَمْ يَعْدُهُ وَصَلَّى فِيهِ ثُمَّ يَعُودُ فَإِنْ أَصَابَهُ مِنِّي شَيْءٌ فَعَلَ مِثْلَ ذَلِكَ وَلَمْ يَعْدُهُ وَصَلَّى فِيهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Jabir bin Shubhi] dia berkata; Saya mendengar [Khilas] berkata; dari [Aisyah] dia berkata; \" Aku pernah tidur bersama Rasulullah shallallahu 'alaihi wasallam dalam satu selimut, padahal aku sedang haid. Jika beliau terkena sesuatu dariku, maka beliau membasuh tempat yang terkena tadi dan tidak melebihinya, kemudian beliau shalat dengan selimut tadi, lalu beliau kembali lagi. Jika beliau terkena sesuatu dariku maka dia melakukan seperti yang tadi tidak melebihinya, lalu shalat dengan kondisi seperti itu.\" "},"282":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُ إِحْدَانَا إِذَا كَانَتْ حَائِضًا أَنْ تَشُدَّ إِزَارَهَا ثُمَّ يُبَاشِرُهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Ishaq] dari [Amr bin Syurahbil] dari [Aisyah] dia berkata; bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan salah satu dari kami yang sedang haid untuk mengikat kainnya, kemudian beliau mempergaulinya (selain hubungan intim, jimak). "},"283":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكَانَتْ إِحْدَانَا إِذَا حَاضَتْ أَمَرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَتَّزِرَ ثُمَّ يُبَاشِرُهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] dia berkata; \" Apabila salah satu dari kami sedang haid, maka Rasulullah shallallahu 'alaihi wasallam memerintahkannya untuk memakai kain, kemudian beliau mempergaulinya (selain hubungan intim, jimak).\""},"284":{"ar":"أَخْبَرَنَا الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ عَنْ يُونُسَ وَاللَّيْثِ عَنْ ابْنِ شِهَابٍ عَنْ حَبِيبٍ مَوْلَى عُرْوَةَ عَنْ بُدَيَّةَ وَكَانَ اللَّيْثُ يَقُولُ نَدَبَةَ مَوْلَاةُ مَيْمُونَةَ عَنْ مَيْمُونَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُبَاشِرُ الْمَرْأَةُ مِنْ نِسَائِهِ وَهِيَ حَائِضٌ إِذَا كَانَ عَلَيْهَا إِزَارٌ يَبْلُغُ أَنْصَافَ الْفَخِذَيْنِ وَالرُّكُبَتَيْنِ فِي حَدِيثِ اللَّيْثِ مُحْتَجِزَةً بِهِ","id":"Telah mengabarkan kepada kami [Al Harits bin Miskin] telah dibacakan kepadanya dan saya mendengarnya dari [Ibnu Wahab] dari [Yunus] dan [Al Laits] dari [Ibnu Syihab] dari [Habib] -budak Urwah- dari [Budayah] -dan menurut Al Laits ia adalah budak Maimunah yang fasih- dari [Maimunah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam mempergauli salah satu istrinya yang sedang haid apabila memakai kain yang sampai ke tengah kedua pahanya dan kedua lututnya. Di dalam hadits Al-Laits (dikatakan) sebagai penghalangnya.\""},"285":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِثٍ عَنْ أَنَسٍقَالَ كَانَتْ الْيَهُودُ إِذَا حَاضَتْ الْمَرْأَةُ مِنْهُمْ لَمْ يُؤَاكِلُوهُنَّ وَلَمْ يُشَارِبُوهُنَّ وَلَمْ يُجَامِعُوهُنَّ فِي الْبُيُوتِ فَسَأَلُوا نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ قُلْ هُوَ أَذًى }الْآيَةَ فَأَمَرَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُؤَاكِلُوهُنَّ وَيُشَارِبُوهُنَّ وَيُجَامِعُوهُنَّ فِي الْبُيُوتِ وَأَنْ يَصْنَعُوا بِهِنَّ كُلَّ شَيْءٍ مَا خَلَا الْجِمَاعَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Sulaiman bin Harb] dia berkata; Telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] dia berkata; Bahwa orang Yahudi apabila ada istri mereka sedang haid, maka mereka tidak mengajak makan bersama, tidak mempergaulinya, dan tidak berkumpul bersamanya di rumah. Mereka bertanya kepada Nabi Allah shallallahu 'alaihi wasallam tentang hal itu? Lalu Allah Azza wa Jalla menurunkan ayat \" Mereka bertanya kepadamu tentang haid. Katakanlah, (Hai Muhammad) bahwa itu adalah penyakit… (Qs. Al-Baqarah (2): 222) lalu Rasulullah shallallahu 'alaihi wasallam memerintahkan mereka untuk ikut makan bersama, mempergaulinya, berkumpul dengan mereka di rumah, dan untuk berbuat apa saja selain bersetubuh. "},"286":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ عَبْدِ الْحَمِيدِ عَنْ مُقْسَمٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الرَّجُلِ يَأْتِي امْرَأَتَهُ وَهِيَ حَائِضٌ يَتَصَدَّقُ بِدِينَارٍ أَوْ بِنِصْفِ دِينَارٍ","id":"Telah mengabarkan kepada kami [Amr bin Ali] dia berkata; Telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Al Hakam] dari [Abdul Hamid] dari [Muqsim] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda tentang seorang laki-laki yang menggauli istrinya dalam keadaan haid, \"Bersedekah dengan satu Dinar atau setengah Dinar.\""},"287":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نُرَى إِلَّا الْحَجَّ فَلَمَّا كَانَ بِسَرِفَ حِضْتُ فَدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أَبْكِي فَقَالَ مَا لَكِ أَنَفِسْتِ فَقُلْتُ نَعَمْ قَالَ هَذَا أَمَرٌ كَتَبَهُ اللَّهُ عَزَّ وَجَلَّ عَلَى بَنَاتِ آدَمَ فَاقْضِي مَا يَقْضِي الْحَاجُّ غَيْرَ أَنَّ لَا تَطُوفِي بِالْبَيْتِ وَضَحَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نِسَائِهِ بِالْبَقَرِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Sufyan] dari [Abdurrahman bin Al Qasim] dari [Bapaknya] dari [Aisyah] dia berkata; \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam yang kami tidak kelihatannya kecuali untuk haji. Setelah di Sarif, aku mendapat haid. Kemudian Rasulullah shallallahu 'alaihi wasallam masuk -menemuiku- dan aku menangis. Beliau lalu bertanya, 'Ada apa denganmu? Apakah kamu sedang haid? ' Aku menjawab, 'Ya. ' Beliau berkata ' Ini suatu perkara yang telah Allah Azza wa Jalla tetapkan bagi kaum wanita, jadi kerjakanlah apa yang dikerjakan oleh orang yang haji, selain thawaf di Ka'bah'. Kemudian Rasulullah shallallahu 'alaihi wasallam berkurban sapi untuk para istrinya.\""},"288":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَيَعْقُوبُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لَهُ قَالُوا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا جَعْفَرُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنِي أَبِي قَالَأَتَيْنَا جَابِرَ بْنَ عَبْدِ اللَّهِ فَسَأَلْنَاهُ عَنْ حَجَّةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَدَّثَنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ لِخَمْسٍ بَقِينَ مِنْ ذِي الْقَعْدَةِ وَخَرَجْنَا مَعَهُ حَتَّى إِذَا أَتَى ذَا الْحُلَيْفَةِ وَلَدَتْ أَسْمَاءُ بِنْتُ عُمَيْسٍ مُحَمَّدَ بْنَ أَبِي بَكْرٍ فَأَرْسَلَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ أَصْنَعُ قَالَ اغْتَسِلِي وَاسْتَثْفِرِي ثُمَّ أَهِلِّي","id":"Telah mengabarkan kepada kami [Amr bin Ali] dan [Muhammad bin Al Mutsanna] dan [Ya'qub bin Ibrahim] lafazh ini darinya, mereka berkata; Telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; Telah menceritakan kepada kami [Ja'far bin Muhammad] dia berkata; Telah menceritakan kepadaku [Bapakku] dia berkata; \"Kami datang kepada [Jabir bin Abdullah] dan menanyakan tentang hajinya Nabi shallallahu 'alaihi wasallam? Dia lalu menceritakan kepada kami bahwa Rasulullah shallallahu 'alaihi wasallam keluar pada tanggal dua puluh lima Dzul Qa'dah, \"Kami keluar bersama beliau hingga Dzul Hulaifah dan di situ Asma bin Umais melahirkan Muhammad bin Abu Bakar. Lalu ia mengirim seseorang kepada Rasulullah shallallahu 'alaihi wasallam untuk bertanya, 'Apa yang harus kuperbuat? ' Rasulullah shallallahu 'alaihi wasallam berkata, ' Mandilah dan letakkan kain di tempat keluarnya darah, kemudian ihramlah.\""},"289":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ قَالَ حَدَّثَنِي أَبُو الْمِقْدَامِ ثَابِتٌ الْحَدَّادُ عَنْ عَدِيِّ بْنِ دِينَارٍ قَالَسَمِعْتُ أُمَّ قَيْسٍ بِنْتَ مِحْصَنٍ أَنَّهَا سَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ دَمِ الْحَيْضِ يُصِيبُ الثَّوْبَ قَالَ حُكِّيهِ بِضِلَعٍ وَاغْسِلِيهِ بِمَاءٍ وَسِدْرٍ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] dia berkata; Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] dia berkata; Telah menceritakan kepadaku [Abu Miqdam Tsabit Al Haddad] dari [Adi bin Dinar] dia berkata; Saya mendengar [Ummu Qais binti Mihshan] bahwa dia pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang darah yang mengenai baju? Beliau shallallahu 'alaihi wasallam menjawab, \" Kerok dengan tulang, lalu cuci dengan air dan sidr (daun bidara).\""},"290":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ عَنْ حَمَّادِ بْنِ زَيْدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ فَاطِمَةَ بِنْتِ الْمُنْذِرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ وَكَانَتْ تَكُونُ فِي حَجْرِهَاأَنَّ امْرَأَةً اسْتَفْتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ دَمِ الْحَيْضِ يُصِيبُ الثَّوْبَ فَقَالَ حُتِّيهِ ثُمَّ اقْرُصِيهِ بِالْمَاءِ ثُمَّ انْضَحِيهِ وَصَلِّي فِيهِ","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin Arabi] dari [Hammad bin Zaid] dari [Hisyam bin Urwah] dari [Fathimah binti Al Mundzir] dari [Asma' binti Abu Bakr] -dia ada di kamarnya- bahwa seorang perempuan meminta fatwa Rasulullah shallallahu 'alaihi wasallam tentang darah haid yang menodai baju? Beliau lalu berkata, ' Gosok dan keroklah dengan kuku, kemudian percikilah dengan air, lalu shalatlah dengan kain tersebut.\""},"291":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سُوَيْدِ بْنِ قَيْسٍ عَنْ مُعَاوِيَةَ بْنِ حُدَيْجٍ عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَأَنَّهُ سَأَلَ أُمَّ حَبِيبَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي الثَّوْبِ الَّذِي كَانَ يُجَامِعُ فِيهِ قَالَتْ نَعَمْ إِذَا لَمْ يَرَ فِيهِ أَذًى","id":"Telah mengabarkan kepada kami [Isa bin Hammad] dia berkata; Telah menceritakan kepada kami [Al-Laits] dari [Yazid bin Abu Habib] dari [Suwaid bin Qais] dari [Mu'awiyah bin Hudaij] dari [Mu'awiyah bin Abu Sufyan] bahwa ia pernah bertanya kepada [Ummu Habibah] -istri Nabi shallallahu 'alaihi wasallam- \"Apakah Rasulullah shallallahu 'alaihi wasallam shalat dengan mengenakan pakaian yang dipakai untuk bersetubuh?\" Ia menjawab, \"Ya, jika beliau tidak melihat kotoran (mani) pada baju tersebut.\""},"292":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ عَمْرِو بْنِ مَيْمُونٍ الْجَزَرِيِّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَغْسِلُ الْجَنَابَةَ مِنْ ثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَخْرُجُ إِلَى الصَّلَاةِ وَإِنَّ بُقَعَ الْمَاءِ لَفِي ثَوْبِهِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah memberitakan kepada kami [Abdullah] dari [Amr bin Maimun Al Jazari] dari [Sulaiman bin Yasar] dari [Aisyah] dia berkata, \" Aku mencuci bekas junub (mani) dari baju Rasulullah shallallahu 'alaihi wasallam, lalu beliau keluar untuk shalat dan baju tersebut masih ada bekas air mani.\""},"293":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَبِي هَاشِمٍ عَنْ أَبِي مِجْلَزٍ عَنْ الْحَارِثِ بْنِ نَوْفَلٍ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَفْرُكُ الْجَنَابَةَ وَقَالَتْ مَرَّةً أُخْرَى الْمَنِيَّ مِنْ ثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Hammad] dari [Abu Hasyim] dari [Abu Mijlaz] dari [Al Harits bin Naufal] dari [Aisyah] dia berkata; ' Aku pernah mengerok bekas junub -pada kesempatan lain dia berkata, \"menggosok mani\"- dari baju Rasulullah shallallahu 'alaihi wasallam.\""},"294":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ قَالَ حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ الْحَكَمُ أَخْبَرَنِي عَنْ إِبْرَاهِيمَ عَنْ هَمَّامِ بْنِ الْحَارِثِ أَنَّ عَائِشَةَ قَالَتْلَقَدْ رَأَيْتُنِي وَمَا أَزِيدُ عَلَى أَنْ أَفْرُكَهُ مِنْ ثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Amr bin Yazid] dia berkata; Telah menceritakan kepada kami [Bahaz] dia berkata; Telah menceritakan kepada kami [Syu'bah] berkata; Telah mengabarkan kepadaku [Al Hakam] dari [Ibrahim] dari [Hammam bin Al Harits] bahwa [Aisyah] berkata; \" Sepengetahuanku, tidak lebih aku hanya menggosok mani dari baju Rasulullah shallallahu 'alaihi wasallam.\""},"295":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ أَنْبَأَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامٍ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَفْرُكُهُ مِنْ ثَوْبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Husain bin Huraits] Telah memberitakan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari [Hammam] dari [Aisyah] dia berkata; \" Aku pernah menggosoknya (mani) dari baju Rasulullah shallallahu 'alaihi wasallam.\" "},"296":{"ar":"أَخْبَرَنَا شُعَيْبُ بْنُ يُوسُفَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامٍ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَرَاهُ فِي ثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَحُكُّهُ","id":"Telah mengabarkan kepada kami [Syu'aib bin Yusuf] dari [Yahya bin Sa'id] dari [Al A'masy] dari [Ibrahim] dari [Hammam] dari [Aisyah] dia berkata; \" Aku melihat mani pada baju Rasulullah shallallahu 'alaihi wasallam, lalu aku menggosoknya.\""},"297":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ أَبِي مَعْشَرٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْلَقَدْ رَأَيْتُنِي أَفْرُكُ الْجَنَابَةَ مِنْ ثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Hammad bin Zaid] dari [Hisyam bin Hasan] dari [Abu Ma'syar] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] dia berkata; \" Seingatku aku pernah menggosok mani dari baju Rasulullah shallallahu 'alaihi wasallam.\""},"298":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ كَامِلٍ الْمَرْوَزِيُّ قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْلَقَدْ رَأَيْتُنِي أَجِدُهُ فِي ثَوْبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَحُتُّهُ عَنْهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Kamil Al Marwazi] Telah menceritakan kepada kami [Husyaim] dari [Mughirah] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] dia berkata; \" Seingatku aku dapati mani pada baju Rasulullah shallallahu 'alaihi wasallam, maka aku menggosoknya.\""},"299":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أُمِّ قَيْسٍ بِنْتِ مِحْصَنٍأَنَّهَا أَتَتْ بِابْنٍ لَهَا صَغِيرٍ لَمْ يَأْكُلْ الطَّعَامَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَجْلَسَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجْرِهِ فَبَالَ عَلَى ثَوْبِهِ فَدَعَا بِمَاءٍ فَنَضَحَهُ وَلَمْ يَغْسِلْهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah bin 'Utbah] dari [Ummu Qais binti Mihshan] bahwa dia pernah datang kepada Rasulullah shallallahu 'alaihi wasallam bersama anak laki-lakinya yang masih kecil dan belum makan makanan. Rasulullah shallallahu 'alaihi wasallam lalu mendudukkan anak laki-laki tersebut di pangkuannya, lalu anak kecil tersebut kencing, maka Nabi shallallahu 'alaihi wasallam minta air, lalu memercikannya dengan air tersebut, dan tidak mencucinya."},"300":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِصَبِيٍّ فَبَالَ عَلَيْهِ فَدَعَا بِمَاءٍ فَأَتْبَعَهُ إِيَّاهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah] dia berkata; \"Didatangkan seorang anak kecil kepada Rasulullah shallallahu 'alaihi wasallam, kemudian anak kecil tersebut kencing, maka beliau shallallahu 'alaihi wasallam meminta air lalu memercikinya.\""},"301":{"ar":"أَخْبَرَنَا مُجَاهِدُ بْنُ مُوسَى قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ الْوَلِيدِ قَالَ حَدَّثَنِي مُحِلُّ بْنُ خَلِيفَةَ قَالَ حَدَّثَنِي أَبُو السَّمْحِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُغْسَلُ مِنْ بَوْلِ الْجَارِيَةِ وَيُرَشُّ مِنْ بَوْلِ الْغُلَامِ","id":"Telah mengabarkan kepada kami [Mujahid bin Musa] dia berkata; Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dia berkata; Telah menceritakan kepada kami [Yahya bin Al Walid] dia berkata; Telah menceritakan kepadaku [Muhil bin Khalifah] dia berkata; Telah menceritakan kepadaku [Abu Samah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Air kencing bayi perempuan dicuci, sedangkan air kencing bayi laki-laki cukup disiram.\""},"302":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا سَعِيدٌ قَالَ حَدَّثَنَا قَتَادَةُ أَنَّ أَنَسَ بْنَ مَالِكٍ حَدَّثَهُمْأَنَّ أُنَاسًا أَوْ رِجَالًا مِنْ عُكْلٍ قَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَكَلَّمُوا بِالْإِسْلَامِ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّا أَهْلُ ضَرْعٍ وَلَمْ نَكُنْ أَهْلَ رِيفٍ وَاسْتَوْخَمُوا الْمَدِينَةَ فَأَمَرَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَوْدٍ وَرَاعٍ وَأَمَرَهُمْ أَنْ يَخْرُجُوا فِيهَا فَيَشْرَبُوا مِنْ أَلْبَانِهَا وَأَبْوَالِهَا فَلَمَّا صَحُّوا وَكَانُوا بِنَاحِيَةِ الْحَرَّةِ كَفَرُوا بَعْدَ إِسْلَامِهِمْ وَقَتَلُوا رَاعِيَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتَاقُوا الذَّوْدَ فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثَ الطَّلَبَ فِي آثَارِهِمْ فَأُتِيَ بِهِمْ فَسَمَرُوا أَعْيُنَهُمْ وَقَطَعُوا أَيْدِيَهُمْ وَأَرْجُلَهُمْ ثُمَّ تُرِكُوا فِي الْحَرَّةِ عَلَى حَالِهِمْ حَتَّى مَاتُوا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; Telah menceritakan kepada kami [Yazid bin Zura'i] dia berkata; Telah menceritakan kepada kami [Sa'id] dia berkata; Telah menceritakan kepada kami [Qatadah], bahwa [Anas bin Malik] berkata kepada mereka; Sekelompok orang lelaki dari kabilah 'Ukl datang kepada Rasulullah shallallahu 'alaihi wasallam, mereka menyatakan masuk Islam. Mereka berkata, \"Wahai Rasulullah shallallahu 'alaihi wasallam, kami orang yang hidup dari hasil ternak, bukan dari hasil pertanian.\" Lalu mereka tidak betah tinggal di Madinah -karena penyakit perut yang mereka derita-- maka Rasulullah shallallahu 'alaihi wasallam mengirim mereka beberapa unta dan pengembalanya. Kemudian beliau menyuruh mereka keluar dari Madinah. Mereka minum susu hasil dari perahan unta tersebut dan minum air kencingnya. Tatkala mereka sudah sehat dan berada di perbatasan Madinah, mereka keluar dari Islam (kufur) dan kembali menjadi kafir, kemudian membunuh penggembala unta Nabi shallallahu 'alaihi wasallam, dan menggiring untanya. Berita tersebut sampai kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau menyuruh untuk mencari jejak mereka, dan akhirnya mereka dapat dibawa kepada Rasulullah shallallahu 'alaihi wasallam. Mereka dihukum dengan mata mereka ditusuk dengan paku, tangan dan kaki mereka dipotong, lalu mereka dibiarkan dalam keadaan seperti itu di Harrat hingga mereka mati. "},"303":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ وَهْبٍ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ أَبِي عَبْدِ الرَّحِيمِ قَالَ حَدَّثَنِي زَيْدُ بْنُ أَبِي أُنَيْسَةَ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَدِمَ أَعْرَابٌ مِنْ عُرَيْنَةَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْلَمُوا فَاجْتَوَوْا الْمَدِينَةَ حَتَّى اصْفَرَّتْ أَلْوَانُهُمْ وَعَظُمَتْ بُطُونُهُمْ فَبَعَثَ بِهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى لِقَاحٍ لَهُ وَأَمَرَهُمْ أَنْ يَشْرَبُوا مِنْ أَلْبَانِهَا وَأَبْوَالِهَا حَتَّى صَحُّوا فَقَتَلُوا رَاعِيَهَا وَاسْتَاقُوا الْإِبِلَ فَبَعَثَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طَلَبِهِمْ فَأُتِيَ بِهِمْ فَقَطَعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَرَ أَعْيُنَهُمْقَالَ أَمِيرُ الْمُؤْمِنِينَ عَبْدُ الْمَلِكِ لِأَنَسٍ وَهُوَ يُحَدِّثُهُ هَذَا الْحَدِيثَ بِكُفْرٍ أَمْ بِذَنْبٍ قَالَ بِكُفْرٍ قَالَ أَبُو عَبْد الرَّحْمَنِ لَا نَعْلَمُ أَحَدًا قَالَ عَنْ يَحْيَى عَنْ أَنَسٍ فِي هَذَا الْحَدِيثِ غَيْرَ طَلْحَةَ وَالصَّوَابُ عِنْدِي وَاللَّهُ تَعَالَى أَعْلَمُ يَحْيَى عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ مُرْسَلٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Wahab] Telah menceritakan kepada kami [Muhammad bin Salamah] dari [Abu Abdurrahim] dia berkata; Telah menceritakan kepadaku [Zaid bin Abu Unaisah] dari [Thalhah bin Musharrif] dari [Yahya bin Sa'id] dari [Anas bin Malik] dia berkata; \"Sekelompok Arab Badui dari suku Urainah datang kepada Nabi shallallahu 'alaihi wasallam, mereka masuk Islam dan tidak suka tinggal di Madinah -karena wabah demam yang menjangkitnya- hingga menguninglah warna mereka dan perut mereka membesar. Kemudian Rasulullah shallallahu 'alaihi wasallam mengirimkan seekor unta perahannya kepada mereka, dan menyuruh mereka minum susu dan air kencingnya sampai mereka sehat. -Namun- kemudian mereka membunuh penggembala unta tersebut dan menggiring unta tersebut. Rasulullah shallallahu 'alaihi wasallam lalu mengirim orang untuk mencarinya, dan mereka dapat diseret kepada beliau. Kemudian beliau memotong tangan dan kaki mereka serta menusuk mata mereka dengan paku.\" Amir Mukminin Abdul Malik bertanya kepada Anas; Apakah karena kesalahan mereka atau karena kekufuran? Anas menjawab; karena kekufuran. Abu Abdurrahman berkata; kami tidak mengetahui seorangpun mengenai hadits ini yang mengatakan dari Yahya dari Anas kecuali Thalhah. Menurut saya yang benar adalah -Wallahu A'lam- dari Yahya dari Sa'id bin Al Musayyab dengan bentuk mursal. "},"304":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ مَخْلَدٍ قَالَ حَدَّثَنَا عَلِيٌّ وَهُوَ ابْنُ صَالِحٍ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ فِي بَيْتِ الْمَالِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عِنْدَ الْبَيْتِ وَمَلَأٌ مِنْ قُرَيْشٍ جُلُوسٌ وَقَدْ نَحَرُوا جَزُورًا فَقَالَ بَعْضُهُمْ أَيُّكُمْ يَأْخُذُ هَذَا الْفَرْثَ بِدَمِهِ ثُمَّ يُمْهِلُهُ حَتَّى يَضَعَ وَجْهَهُ سَاجِدًا فَيَضَعُهُ يَعْنِي عَلَى ظَهْرِهِ قَالَ عَبْدُ اللَّهِ فَانْبَعَثَ أَشْقَاهَا فَأَخَذَ الْفَرْثَ فَذَهَبَ بِهِ ثُمَّ أَمْهَلَهُ فَلَمَّا خَرَّ سَاجِدًا وَضَعَهُ عَلَى ظَهْرِهِ فَأُخْبِرَتْ فَاطِمَةُ بِنْتُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ جَارِيَةٌ فَجَاءَتْ تَسْعَى فَأَخَذَتْهُ مِنْ ظَهْرِهِ فَلَمَّا فَرَغَ مِنْ صَلَاتِهِ قَالَ اللَّهُمَّ عَلَيْكَ بِقُرَيْشٍ ثَلَاثَ مَرَّاتٍ اللَّهُمَّ عَلَيْكَ بِأَبِي جَهْلِ بْنِ هِشَامٍ وَشَيْبَةَ بْنِ رَبِيعَةَ وَعُتْبَةَ بْنِ رَبِيعَةَ وَعُقْبَةَ بْنِ أَبِي مَعِيطٍ حَتَّى عَدَّ سَبْعَةً مِنْ قُرَيْشٍقَالَ عَبْدُ اللَّهِ فَوَالَّذِي أَنْزَلَ عَلَيْهِ الْكِتَابَ لَقَدْ رَأَيْتُهُمْ صَرْعَى يَوْمَ بَدْرٍ فِي قَلِيبٍ وَاحِدٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Utsman bin Hakim] dia berkata; Telah menceritakan kepada kami [Khalid yaitu Ibnu Makhlad] dia berkata; Telah menceritakan kepada kami [Ali yaitu Ibnu Shalih] dari [Abu Ishaq] dari [Amr bin Maimun] dia berkata; Telah menceritakan kepada kami [Abdullah] -di Baitul Mal- dia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat di Baitullah, sedangkan pembesar-pembesar Quraisy sedang duduk-duduk, dan mereka menyembelih seekor kambing. ' Salah satu dari mereka mengajukan usul, \"Siapa diantara kalian yang berani mengambil kotorannya dengan darahnya, kemudian berjalan pelan-pelan hingga Muhammad sujud lalu meletakkannya di punggungnya?\" Abdullah berkata, \"Lalu bangkitlah orang yang paling jahat di antara mereka untuk mengambil kotoran hewan tersebut dan membawanya dengan pelan-pelan. Saat Rasulullah shallallahu 'alaihi wasallam sujud, dia meletakkannya di atas punggung beliau. Fatimah binti Rasulullah shallallahu 'alaihi wasallam diberitahu hal tersebut -saat itu dia masih remaja- maka dia langsung berusaha mengambil kotoran tersebut dari punggung beliau. Tatkala selesai dari shalatnya, beliau bersabda, 'Ya Allah, orang-orang Quraisy ini kupasrahkan kepada-Mu -beliau mengulanginya sebanyak tiga kali- kupasrahkan kepadamu Abu Jahal, Syaibah bin Rabi'ah, Uqbah bin Abu Mu'ith sampai -perawi- menghitung tujuh orang dari orang Quraisy.\" Abdullah berkata; \"Demi yang menurunkan Al Kitab kepadanya, kamu lihat mereka terbunuh pada perang Badar dalam satu sumur.\""},"305":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ حُمَيْدٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ طَرَفَ رِدَائِهِ فَبَصَقَ فِيهِ فَرَدَّ بَعْضَهُ عَلَى بَعْضٍ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dia berkata; Telah menceritakan kepada kami [Ismail] dari [Humaid] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengambil ujung selendangnya lalu meludah padanya, kemudian melipat sebagian pada sebagian yang lain. "},"306":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ عَنْ مُحَمَّدٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ الْقَاسِمَ بْنَ مِهْرَانَ يُحَدِّثُ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا صَلَّى أَحَدُكُمْ فَلَا يَبْزُقْ بَيْنَ يَدَيْهِ وَلَا عَنْ يَمِينِهِ وَلَكِنْ عَنْ يَسَارِهِ أَوْ تَحْتَ قَدَمِهِ وَإِلَّا فَبَزَقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا فِي ثَوْبِهِ وَدَلَكَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dari [Muhammad] dia berkata; Telah menceritakan kepada kami [Syu'bah] dia berkata; Saya mendengar [Al Qasim bin Mihran] berkata; dari [Abu Rafi'] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Jika salah seorang dari kalian shalat, maka jangan meludah di depan dan di samping kanannya, tetapi meludahlah di sebelah kirinya atau di bawah telapak kakinya. Jika tidak, maka Rasulullah shallallahu 'alaihi wasallam meludah seperti ini di bajunya, lalu menggosoknya. "},"307":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ أَسْفَارِهِ حَتَّى إِذَا كُنَّا بِالْبَيْدَاءِ أَوْ ذَاتِ الْجَيْشِ انْقَطَعَ عِقْدٌ لِي فَأَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْتِمَاسِهِ وَأَقَامَ النَّاسُ مَعَهُ وَلَيْسُوا عَلَى مَاءٍ وَلَيْسَ مَعَهُمْ مَاءٌ فَأَتَى النَّاسُ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَقَالُوا أَلَا تَرَى مَا صَنَعَتْ عَائِشَةُ أَقَامَتْ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِالنَّاسِ وَلَيْسُوا عَلَى مَاءٍ وَلَيْسَ مَعَهُمْ مَاءٌ فَجَاءَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاضِعٌ رَأْسَهُ عَلَى فَخِذِي قَدْ نَامَ فَقَالَ حَبَسْتِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسَ وَلَيْسُوا عَلَى مَاءٍ وَلَيْسَ مَعَهُمْ مَاءٌ قَالَتْ عَائِشَةُ فَعَاتَبَنِي أَبُو بَكْرٍ وَقَالَ مَا شَاءَ اللَّهُ أَنْ يَقُولَ وَجَعَلَ يَطْعُنُ بِيَدِهِ فِي خَاصِرَتِي فَمَا مَنَعَنِي مِنْ التَّحَرُّكِ إِلَّا مَكَانُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى فَخِذِي فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَصْبَحَ عَلَى غَيْرِ مَاءٍ فَأَنْزَلَ اللَّهُ عَزَّ وَج��لَّ آيَةَ التَّيَمُّمِ فَقَالَ أُسَيْدُ بْنُ حُضَيْرٍ مَا هِيَ بِأَوَّلِ بَرَكَتِكُمْ يَا آلَ أَبِي بَكْرٍ قَالَتْ فَبَعَثْنَا الْبَعِيرَ الَّذِي كُنْتُ عَلَيْهِ فَوَجَدْنَا الْعِقْدَ تَحْتَهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abdurrahman bin Al Qasim] dari [Bapaknya] dari [Aisyah] Radliyallahu'anha dia berkata; \"Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam sebagian perjalanannya, dan saat kami sampai di Al Baida -atau di Dzatuljaisy-- kalungku hilang, maka Rasulullah shallallahu 'alaihi wasallam berhenti untuk mencarinya dan para sahabat juga ikut bersamanya. Mereka tidak mempunyai air dan juga Rasulullah shallallahu 'alaihi wasallam. Para sahabat datang kepada Abu Bakar Radliyallhu'anhu dan berkata, 'Apakah kamu tidak melihat apa yang diperbuat Aisyah?! Ia menghentikan (menahan) Rasulullah shallallahu 'alaihi wasallam dan para sahabat, padahal mereka tidak pada tempat yang ada airnya dan mereka juga tidak mempunyai air'. Abu Bakar Radliyallahu'anhu lalu datang (kepadaku) dan Rasulullah shallallahu 'alaihi wasallam berbaring meletakkan kepalanya di atas pahaku dan beliau tertidur. Ia berkata, 'Kamu menahan Rasulullah shallallahu 'alaihi wasallam dan manusia pada tempat yang tidak ada airnya dan mereka juga tidak mempunyai air?\" Aisyah berkata, \"Abu Bakar mencelaku dan beliau mengatakan sebagaimana yang dikehendaki Allah dan ia menekan lambungku dengan tangannya. Tidak ada yang menghalangiku untuk bergerak kecuali keadaan Rasulullah shallallahu 'alaihi wasallam yang berada di atas pahaku! Rasulullah shallallahu 'alaihi wasallam tertidur hingga pagi, tanpa ada air. Kemudian Allah Azza wa Jalla menurunkan ayat tayamum.\" Usaid bin Hudhair berkata; \"Ini bukan keberkahan keluargamu yang pertama wahai keluarga Abu Bakar!\" Aisyah berkata, \"Lalu kami membangunkan unta yang kami tunggangi, dan kalung tersebut ternyata ada di bawahnya.\""},"308":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ اللَّيْثِ عَنْ أَبِيهِ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ هُرْمُزَ عَنْ عُمَيْرٍ مَوْلَى ابْنُ عَبَّاسٍأَنَّهُ سَمِعَهُ يَقُولُ أَقْبَلْتُ أَنَا وَعَبْدُ اللَّهِ بْنُ يَسَارٍ مَوْلَى مَيْمُونَةَ حَتَّى دَخَلْنَا عَلَى أَبِي جُهَيْمِ بْنِ الْحَارِثِ بْنِ الصِّمَّةِ الْأَنْصَارِيِّ فَقَالَ أَبُو جُهَيْمٍ أَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ نَحْوِ بِئْرِ الْجَمَلِ وَلَقِيَهُ رَجُلٌ فَسَلَّمَ عَلَيْهِ فَلَمْ يَرُدَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِ حَتَّى أَقْبَلَ عَلَى الْجِدَارِ فَمَسَحَ بِوَجْهِهِ وَيَدَيْهِ ثُمَّ رَدَّ عَلَيْهِ السَّلَامَ","id":"Telah mengabarkan kepada kami [Ar-Rabi' bin Sulaiman] dia berkata; Telah menceritakan kepada kami [Syu'aib bin Al-Laits] dari [Bapaknya] dari [Ja'far bin Rabi'ah] dari [Abdurrahman bin Hurmuz] dari [Umair] -budak Ibnu Abbas- bahwa dia mendengar Ibnu Abbas berkata; \"Aku dan Abdullah bin Yasar -budak Maimunah- datang menemui Abu Juhaim bin Al Harits bin Ash Shammah Al Anshari.\" [Abu Juhaim] berkata; \"Rasulullah shallallahu 'alaihi wasallam datang dari arah sumur Jamal dan beliau berjumpa dengan seorang laki-laki. Ia memberi salam, namun Rasulullah shallallahu 'alaihi wasallam tidak menjawabnya hingga beliau menghadap dinding lalu mengusap wajah dan keduanya tangannya, baru kemudian beliau membalas salam.\""},"309":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ عَنْ ذَرٍّ عَنْ ابْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِأَنَّ رَجُلًا أَتَى عُمَرَ فَقَالَ إِنِّي أَجْنَبْتُ فَلَمْ أَجِدْ الْمَاءَ قَالَ عُمَرُ لَا تُصَلِّ فَقَالَ عَمَّارُ بْنُ يَاسِرٍ يَا أَمِيرَ الْمُؤْمِنِينَ أَمَا تَذْكُرُ إِذْ أَنَا وَأَنْتَ فِي سَرِيَّةٍ فَأَجْنَبْنَا فَلَمْ نَجِدْ الْمَاءَ فَأَمَّا أَنْتَ فَلَمْ تُصَلِّ وَأَمَّا أَنَا فَتَمَعَّكْتُ فِي التُّرَابِ فَصَلَّيْتُ فَأَتَيْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْنَا ذَلِكَ لَهُ فَقَالَ إِنَّمَا كَانَ يَكْفِيكَ فَضَرَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ إِلَى الْأَرْضِ ثُمَّ نَفَخَ فِيهِمَا ثُمَّ مَسَحَ بِهِمَا وَجْهَهُ وَكَفَّيْهِ وَسَلَمَةُ شَكَّ لَا يَدْرِي فِيهِ إِلَى الْمِرْفَقَيْنِ أَوْ إِلَى الْكَفَّيْنِفَقَالَ عُمَرُ نُوَلِّيكَ مَا تَوَلَّيْتَ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; Telah menceritakan kepada kami [Muhammad] berkata; Telah menceritakan kepada kami [Syubah] dari [Salamah] dari [Dzar] dari [Ibnu Abdurrahman bin Abza] dari [bapaknya], bahwa ada seseorang yang datang kepada Umar dan berkata, \"Aku junub dan aku tidak mendapati air?\" Umar berkata, \"Jangan shalat.\" [Ammar bin Yasir] berkata; \"Wahai Amirul Mukminin, apa kamu tidak ingat saat kita dalam pasukan dan kita sama-sama junub, kemudian engkau tidak shalat sedangkan aku berguling di debu lalu aku shalat. Lantas kita datang kepada Rasulullah shallallahu 'alaihi wasallam dan menceritakan hal tersebut kepala beliau, dan beliau bersabda: \"Cukuplah bagimu (tayamum) \". Lalu beliau menepukkan kedua tangannya ke tanah dan meniup keduanya, lalu mengusap wajah dan kedua telapak tangannya -perawi ragu, sampai siku-siku atau kedua telapak tangan-?\" Umar berkata.\"Aku memasrahkan kepadamu untuk berfatwa dengan ilmu yang kamu ketahui.\""},"310":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُبَيْدِ بْنِ مُحَمَّدٍ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ نَاجِيَةَ بْنِ خُفَافٍ عَنْ عَمَّارِ بْنِ يَاسِرٍ قَالَأَجْنَبْتُ وَأَنَا فِي الْإِبِلِ فَلَمْ أَجِدْ مَاءً فَتَمَعَّكْتُ فِي التُّرَابِ تَمَعُّكَ الدَّابَّةِ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ بِذَلِكَ فَقَالَ إِنَّمَا كَانَ يَجْزِيكَ مِنْ ذَلِكَ التَّيَمُّمُ","id":"Telah mengabarkan kepada kami [Muhammad bin Ubaid bin Muhammad] dia berkata; Telah menceritakan kepada kami [Abu Ahwash] dari [Abu Ishaq] dari [Najiyah bin Khufaf] dari [Ammar bin Yasir] dia berkata; \"Aku pernah junub dan aku di atas unta. Aku tidak mendapatkan air, maka aku lalu berguling-guling di debu seperti hewan yang sedang berguling-guling. Kemudian aku datang kepada Rasulullah shallallahu 'alaihi wasallam dan mengabarkan hal tersebut kepada beliau. Beliau shallallahu 'alaihi wasallam kemudian bersabda,: \"Cukuplah bagimu bertayamum.\" "},"311":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ عَمَّارٍ قَالَعَرَّسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأُولَاتِ الْجَيْشِ وَمَعَهُ عَائِشَةُ زَوْجَتُهُ فَانْقَطَعَ عِقْدُهَا مِنْ جَزْعِ ظِفَارِ فَحُبِسَ النَّاسُ ابْتِغَاءَ عِقْدِهَا ذَلِكَ حَتَّى أَضَاءَ الْفَجْرُ وَلَيْسَ مَعَ النَّاسِ مَاءٌ فَتَغَيَّظَ عَلَيْهَا أَبُو بَكْرٍ فَقَالَ حَبَسْتِ النَّاسَ وَلَيْسَ مَعَهُمْ مَاءٌ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ رُخْصَةَ التَّيَمُّمِ بِالصَّعِيدِ قَالَ فَقَامَ الْمُسْلِمُونَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضَرَبُوا بِأَيْدِيهِمْ الْأَرْضَ ثُمَّ رَفَعُوا أَيْدِيَهُمْ وَلَمْ يَنْفُضُوا مِنْ التُّرَابِ شَيْئًا فَمَسَحُوا بِهَا وُجُوهَهُمْ وَأَيْدِيَهُمْ إِلَى الْمَنَاكِبِ وَمِنْ بُطُونِ أَيْدِيهِمْ إِلَى الْآبَاطِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya bin Abdullah] dia berkata; Telah menceritakan kepada kami [Ya'qub bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Bapaku] dari [Shalih] dari [Ibnu Syihab] berkata; Telah menceritakan kepada kami [Ubaidullah bin Abdullah bin Utbah] dari [Ibnu Abbas] dari [Ammar] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengistirahatkan pasukannya dan beliau bersama Aisyah -istrinya- dan ternyata kalungnya yang dari Akik Zhifar (daerah di Yaman), terputus, maka orang-orang mencari kalung tersebut hingga terbit fajar, sedangkan orang-orang tidak mempunyai air. Abu Bakar marah kepada Aisyah dan berkata, \"Kamu menyebabkan manusia tertahan, padahal mereka tidak mempunyai air!\" Lalu Allah Azza wa Jalla menurunkan keringanan tayamum dengan debu. Ammar berkata, \"Lalu orang-orang berdiri bersama Rasulullah shallallahu 'alaihi wasallam, mereka menepukkan kedua tangan ke tanah, kemudian mengangkat tangan tanpa menghilangkan debu sedikitpun, dan mengusapkannya ke wajah dan tangan sampai siku-siku, dan dari telapak tangan mereka sampai ke ketiak.\" "},"312":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ قَالَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ مَالِكٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّهُ أَخْبَرَهُ عَنْ أَبِيهِ عَنْ عَمَّارِ بْنِ يَاسِرٍ قَالَتَيَمَّمْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالتُّرَابِ فَمَسَحْنَا بِوُجُوهِنَا وَأَيْدِينَا إِلَى الْمَنَاكِبِ","id":"Telah mengabarkan kepada kami [Al Abbas bin Abdul 'Azhim Al Anbari] dia berkata; Telah menceritakan kepada kami [Abdullah bin Muhammad bin Asma'] dia berkata; Telah menceritakan kepada kami [Juwairiyah] dari [Malik] dari [Az-Zuhri] dari [Ubaidillah bin Abdullah bin 'Utbah] bahwa dia telah mengabarkan kepadanya dari [Bapaknya] dari [Ammar bin Yasir] dia berkata; \"Kami tayamum bersama Rasulullah shallallahu 'alaihi wasallam dengan debu. Kami mengusap wajah dan tangan sampai ke bahu.\""},"313":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ عَنْ أَبِي مَالِكٍ وَعَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى قَالَكُنَّا عِنْدَ عُمَرَ فَأَتَاهُ رَجُلٌ فَقَالَ يَا أَمِيرَ الْمُؤْمِنِينَ رُبَّمَا نَمْكُثُ الشَّهْرَ وَالشَّهْرَيْنِ وَلَا نَجِدُ الْمَاءَ فَقَالَ عُمَرُ أَمَّا أَنَا فَإِذَا لَمْ أَجِدْ الْمَاءَ لَمْ أَكُنْ لِأُصَلِّيَ حَتَّى أَجِدَ الْمَاءَ فَقَالَ عَمَّارُ بْنُ يَاسِرٍ أَتَذْكُرُ يَا أَمِيرَ الْمُؤْمِنِينَ حَيْثُ كُنْتَ بِمَكَانِ كَذَا وَكَذَا وَنَحْنُ نَرْعَى الْإِبِلَ فَتَعْلَمُ أَنَّا أَجْنَبْنَا قَالَ نَعَمْ أَمَّا أَنَا فَتَمَرَّغْتُ فِي التُّرَابِ فَأَتَيْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضَحِكَ فَقَالَ إِنْ كَانَ الصَّعِيدُ لَكَافِيكَ وَضَرَبَ بِكَفَّيْهِ إِلَى الْأَرْضِ ثُمَّ نَفَخَ فِيهِمَا ثُمَّ مَسَحَ وَجْهَهُ وَبَعْضَ ذِرَاعَيْهِفَقَالَ اتَّقِ اللَّهَ يَا عَمَّارُ فَقَالَ يَا أَمِيرَ الْمُؤْمِنِينَ إِنْ شِئْتَ لَمْ أَذْكُرْهُ قَالَ وَلَكِنْ نُوَلِّيكَ مِنْ ذَلِكَ مَا تَوَلَّيْتَ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; Telah menceritakan kepada kami [Abdurrahman] berkata; Telah menceritakan kepada kami [Sufyan] dari [Salamah] dari [Abu Malik] dan [Abdullah bin Abdurrahman bin Abza] dari [Abdurrahman bin Abza] berkata; \"Kami sedang di sisi Umar, lalu datang laki-laki dan berkata, 'Wahai Amirul Mukminin, kadang kita melakukan perjalanan selama satu atau dua bulan dan tidak mendapatkan air? ' Umar menjawab, \"Jika aku tidak mendapatkan air maka aku tidak shalat hingga mendapatkannya\" [Ammar] berkata, \"Wahai Amirul Mukminin, apakah kamu ingat tatkala berada di suatu daerah dan kita sedang menggembala unta, engkau mengetahui bahwa kita junub?\" Ia menjawab, \"Ya\" Maka aku berguling-guling di tanah, lalu kita datang kepada Nabi shallallahu 'alaihi wasallam dan beliau tertawa lantas bersabda, 'Bila itu debu, maka itu telah mencukupi kalian'. Kemudian beliau menepukkan kedua telapak tangannya ke tanah lalu meniupkannya, dan mengusapkannya ke wajah dan sebagian lengannya?\" Umar berkata, \"Ya Ammar, bertakwalah kepada Allah!\" Ammar menjawab, \"Wahai Amirul Mukminin, bila engkau mau maka aku tidak akan menyebutkannya.\" Umar berkata, \"Tidak, tetapi kita memasrahkan hal tersebut kepadamu.\" "},"314":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ قَالَ حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا الْحَكَمُ عَنْ ذَرٍّ عَنْ ابْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِأَنَّ رَجُلًا سَأَلَ عُمَرَ بْنَ الْخَطَّابِ عَنْ التَّيَمُّمِ فَلَمْ يَدْرِ مَا يَقُولُ فَقَالَ عَمَّارٌ أَتَذْكُرُ حَيْثُ كُنَّا فِي سَرِيَّةٍ فَأَجْنَبْتُ فَتَمَعَّكْتُ فِي التُّرَابِ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا يَكْفِيكَ هَكَذَا وَضَرَبَ شُعْبَةُ بِيَدَيْهِ عَلَى رُكْبَتَيْهِ وَنَفَخَ فِي يَدَيْهِ وَمَسَحَ بِهِمَا وَجْهَهُ وَكَفَّيْهِ مَرَّةً وَاحِدَةً","id":"Telah mengabarkan kepada kami [Amr bin Yazid] dia berkata; Telah menceritakan kepada kami [Bahaz] berkata; Telah menceritakan kepada kami [Syu'bah] berkata; Telah menceritakan kepada kami [Al Hakam] dari [Dzar] dari [Ibnu Abdurrahman bin Abza] dari [bapaknya], bahwa ada seseorang yang bertanya kepada Umar bin Khattab tentang tayamum, sedangkan Umar tidak tahu apa yang dikatakan Rasulullah shallallahu 'alaihi wasallam. [Ammar] berkata, \"Apakah engkau ingat tatkala kita dalam suatu pasukan, lalu aku junub, sehingga aku berguling-guling di tanah. Aku kemudian menjumpai Rasulullah shallallahu 'alaihi wasallam dan beliau bersabda, 'Begini ini cukup bagimu?\" Dia -Syu'bah (perawi) - mendemontrasikannya dengan menepukkan kedua tangannya ke kedua lututnya, lalu meniup kedua tangan tersebut dan mengusap wajah dan kedua telapak tangannya dengan kedua telapak tangannya sekali. "},"315":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ أَنْبَأَنَا خَالِدٌ أَنْبَأَنَا شُعْبَةُ عَنْ الْحَكَمِ سَمِعْتُ ذَرًّا يُحَدِّثُ عَنْ ابْنِ أَبْزَى عَنْ أَبِيهِ قَالَ وَقَدْ سَمِعَهُ الْحَكَمُ مِنْ ابْنِ عَبْدِ الرَّحْمَنَ قَالَأَجْنَبَ رَجُلٌ فَأَتَى عُمَرَ رَضِيَ اللَّهُ عَنْهُ فَقَالَ إِنِّي أَجْنَبْتُ فَلَمْ أَجِدْ مَاءً قَالَ لَا تُصَلِّ قَالَ لَهُ عَمَّارٌ أَمَا تَذْكُرُ أَنَّا كُنَّا فِي سَرِيَّةٍ فَأَجْنَبْنَا فَأَمَّا أَنْتَ فَلَمْ تُصَلِّ وَأَمَّا أَنَا فَإِنِّي تَمَعَّكْتُ فَصَلَّيْتُ ثُمَّ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ إِنَّمَا كَانَ يَكْفِيكَ وَضَرَبَ شُعْبَةُ بِكَفِّهِ ضَرْبَةً وَنَفَخَ فِيهَا ثُمَّ دَلَكَ إِحْدَاهُمَا بِالْأُخْرَى ثُمَّ مَسَحَ بِهِمَا وَجْهَهُفَقَالَ عُمَرُ شَيْئًا لَا أَدْرِي مَا هُوَ فَقَالَ إِنْ شِئْتَ لَا حَدَّثْتُهُ وَذَكَرَ شَيْئًا فِي هَذَا الْإِسْنَادِ عَنْ أَبِي مَالِكٍ وَزَادَ سَلَمَةَ قَالَ بَلْ نُوَلِّيَكَ مِنْ ذَلِكَ مَا تَوَلَّيْتَ","id":"Telah mengabarkan kepada kami [Ismail bin Mas'ud] Telah memberitakan kepada kami [Khalid] dari [Syu'bah] dari [Al Hakam], Saya mendengar [Dzar] berkata dari [Ibnu Abza] dari [Bapaknya] dia berkata; dan Hakam telah mendengarnya dari Ibnu Abdurrahman dia berkata; \"Seseorang telah junub, lalu datang kepada Umar Radliyallahu'anhu dan berkata, \"Aku junub dan tidak mendapatkan air? ' Umar berkata, 'Jangan shalat! ' Lantas [Ammar] berkata kepada Umar, 'Apakah kamu tidak ingat ketika dalam suatu pasukan dan kita bersama-sama junub? Engkau tidak shalat, sedangkan aku berguling-guling lalu shalat. Kemudian aku datang kepada Nabi shallallahu 'alaihi wasallam dan menceritakan hal tersebut kepada beliau shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam bersabda, \"Begini ini cukup bagimu?\" Dia -Syu'bah (perawi) - mendemontrasikannya dengan menepukkan tangannya sekali tepukkan (ke tanah) lalu meniupnya dan menggosokkan tangan yang satu ke tangan lainnya, kemudian mengusap wajah dengan kedua telapak tangannya. ' Lalu Umar mengatakan sesuatu yang tidak kuketahui. Ia lalu berkata, 'Jika kamu mau, maka tidak akan kuceritakan kepadamu.\" Dalam sanad lain disebutkan, dari Abu Malik, Salamah menambahkan; \"Umar berkata 'Tidak, tetapi kami memasrahkan hal tersebut kepadamu.\""},"316":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ تَمِيمٍ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ وَسَلَمَةُ عَنْ ذَرٍّ عَنْ ابْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِأَنْ رَجُلًا جَاءَ إِلَى عُمَرَ رَضِيَ اللَّهُ عَنْهُ فَقَالَ إِنِّي أَجْنَبْتُ فَلَمْ أَجِد الْمَاءَ فَقَالَ عُمَرُ لَا تُصَلِّ فَقَالَ عَمَّارٌ أَمَا تَذْكُرُ يَا أَمِيرَ الْمُؤْمِنِينَ إِذْ أَنَا وَأَنْتَ فِي سَرِيَّةٍ فَأَجْنَبْنَا فَلَمْ نَجِدْ مَاءً فَأَمَّا أَنْتَ فَلَمْ تُصَلِّ وَأَمَّا أَنَا فَتَمَعَّكْتُ فِي التُّرَابِ ثُمَّ صَلَّيْتُ فَلَمَّا أَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرْتُ ذَلِكَ لَهُ فَقَالَ إِنَّمَا يَكْفِيكَ وَضَرَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدَيْهِ إِلَى الْأَرْضِ ثُمَّ نَفَخَ فِيهِمَا فَمَسَحَ بِهِمَا وَجْهَهُ وَكَفَّيْهِ شَكَّ سَلَمَةُ وَقَالَ لَا أَدْرِي فِيهِ إِلَى الْمِرْفَقَيْنِ أَوْ إِلَى الْكَفَّيْنِقَالَ عُمَرُ نُوَلِّيكَ مِنْ ذَلِكَ مَا تَوَلَّيْتَ قَالَ شُعْبَةُ كَانَ يَقُولُ الْكَفَّيْنِ وَالْوَجْهَ وَالذِّرَاعَيْنِ فَقَالَ لَهُ مَنْصُورٌ مَا تَقُولُ فَإِنَّهُ لَا يَذْكُرُ الذِّرَاعَيْنِ أَحَدٌ غَيْرُكَ فَشَكَّ سَلَمَةُ فَقَالَ لَا أَدْرِي ذَكَرَ الذِّرَاعَيْنِ أَمْ لَا","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin Tamim] dia berkata; telah menceritakan kepada kami [Hajjaj] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dan [Salamah] dari [Dzar] dari [Ibnu Abdurrahman bin Abza] dari [Bapaknya], seorang laki-kaki datang kepada Umar bin Khattab Radliyallahu'anhu dan berkata, \"Bagaimana aku junub dan tidak mendapatkan air?\" Umar berkata kepadanya, \"Jangan shalat!\" [Ammar] lalu berkata, \"Wahai Amirul Mukminin, apakah kamu tidak ingat ketika kita dalam suatu pasukan dan kita sama-sama junub dan tidak mendapatkan air? Engkau tidak shalat, sedangkan aku berguling-guling di tanah lalu shalat. Kemudian kita datang kepada Nabi shallallahu 'alaihi wasallam dan menceritakan hal tersebut kepada beliau shallallahu 'alaihi wasallam. Rasulullah shallallahu 'alaihi wasallam lalu menepukkan kedua tangannya ke tanah dan meniupnya, kemudian mengusapkannya ke muka dan kedua telapak tangannya.\" -perawi ragu, maka ia berkata, 'Aku tidak tahu, apakah sampai siku atau telapak tangan?\" -Umar berkata, \"Kami pasrahkan hal ini kepadamu.\" Syu'bah berkata; -perawi-itu mengatakan kedua telapak tangan, wajah dan kedua siku. Maka kemudian Manshur berkata kepadanya; \"Apa kata mu! Tidak ada yang menyebutkan kedua siku seorangpun kecuali engkau. Maka Salamah pun merasa ragu dan berkata; saya tidak mengetahui apakah dia menyebutkan kedua siku atau tidak. "},"317":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ قَالَكُنْتُ جَالِسًا مَعَ عَبْدِ اللَّهِ وَأَبِي مُوسَى فَقَالَ أَبُو مُوسَى أَوْ لَمْ تَسْمَعْ قَوْلَ عَمَّارٍ لِعُمَرَ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَاجَةٍ فَأَجْنَبْتُ فَلَمْ أَجِدْ الْمَاءَ فَتَمَرَّغْتُ بِالصَّعِيدِ ثُمَّ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ إِنَّمَا كَانَ يَكْفِيكَ أَنْ تَقُولَ هَكَذَا وَضَرَبَ بِيَدَيْهِ عَلَى الْأَرْضِ ضَرْبَةً فَمَسَحَ كَفَّيْهِ ثُمَّ نَفَضَهُمَا ثُمَّ ضَرَبَ بِشِمَالِهِ عَلَى يَمِينِهِ وَبِيَمِينِهِ عَلَى شِمَالِهِ عَلَى كَفَّيْهِ وَوَجْهِهِفَقَالَ عَبْدُ اللَّهِ أَوَ لَمْ تَرَ عُمَرَ لَمْ يَقْنَعْ بِقَوْلِ عَمَّارٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Alla] dia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dia berkata; telah menceritakan kepada kami [Al A'masy] dari [Syaqiq], dia berkata, \"Aku duduk bersama Abdullah dan Abu Musa. [Abu Musa] lalu berkata, 'Apakah kamu belum mendengar perkataan [Ammar] terhadap Umar, \"Rasulullah shallallahu 'alaihi wasallam pernah mengutusku dalam suatu keperluannya, lantas aku junub dan tidak mendapatkan air, maka aku berguling-guling ke tanah. Kemudian aku datang kepada Rasulullah shallallahu 'alaihi wasallam dan menyebutkan hal tersebut kepada beliau. Lalu beliau bersabda, 'Cukuplah bagimu untuk mengatakan begini'. Lalu Nabi shallallahu 'alaihi wasallam menepukkan kedua tangannya ke tanah sekali tepukan, lalu beliau mengusap kedua telapak tangannya, kemudian mengibaskan dan menepukkan telapak tangan kirinya ke telapak tangan kanannya, dan telapak tangan kanan ditepukkan ke telapak kiri, lalu mengusapkan kedua telapak tangannya dan wajahnya?\" Abdullah berkata, 'Apakah kamu tidak melihat Umar yang tidak puas dengan ucapan Ammar?\" "},"318":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ عَوْفٍ عَنْ أَبِي رَجَاءٍ قَالَ سَمِعْتُ عِمْرَانَ بْنَ حُصَيْنٍأَنْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا مُعْتَزِلًا لَمْ يُصَلِّ مَعَ الْقَوْمِ فَقَالَ يَا فُلَانُ مَا مَنَعَكَ أَنْ تُصَلِّيَ مَعَ الْقَوْمِ فَقَالَ يَا رَسُولَ اللَّهِ أَصَابَتْنِي جَنَابَةٌ وَلَا مَاءَ قَالَ عَلَيْكَ بِالصَّعِيدِ فَإِنَّهُ يَكْفِيكَ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah menceritakan kepada kami [Abdullah] dari [Auf] dari [Abu Raja'] dia berkata; Saya mendengar [Imran bin Hushain], bahwa Rasulullah shallallahu 'alaihi wasallam melihat seseorang laki-laki yang menyendiri dan tidak ikut shalat bersama orang-orang, maka beliau bersabda \"Wahai fulan, apa yang menghalangimu untuk tidak ikut shalat dengan orang-orang (berjama'ah)?\" Ia menjawab, \"Wahai Rasulullah shallallahu 'alaihi wasallam! Aku sedang junub dan tidak ada air.\" Beliau shallallahu 'alaihi wasallam menjawab, \"Hendaknya kamu menggunakan debu, karena hal itu cukup bagimu.\" "},"319":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ هِشَامٍ قَالَ حَدَّثَنَا مَخْلَدٌ عَنْ سُفْيَانَ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ عَمْرِو بْنِ بُجْدَانَ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّعِيدُ الطَّيِّبُ وَضُوءُ الْمُسْلِمِ وَإِنْ لَمْ يَجِدْ الْمَاءَ عَشْرَ سِنِينَ","id":"Telah mengabarkan kepada kami [Amr bin Hisyam] dia berkata; telah menceritakan kepada kami [Makhlad] dari [Sufyan] dari [Ayyub] dari [Abu Qilabah] dari [Amr bin Bujdan] dari [Abu Dzar], dia mengatakan bahwa Rasulullah shallallahu 'alaihi wasallam bersabda, \"Debu yang suci adalah alat wudlu bagi kaum muslim, walaupun ia tidak mendapatkan air selama sepuluh tahun.\" "},"320":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُسَيْدَ بْنَ حُضَيْرٍ وَنَاسًا يَطْلُبُونَ قِلَادَةً كَانَتْ لِعَائِشَةَ نَسِيَتْهَا فِي مَنْزِلٍ نَزَلَتْهُ فَحَضَرَتْ الصَّلَاةُ وَلَيْسُوا عَلَى وُضُوءٍ وَلَمْ يَجِدُوا مَاءً فَصَلَّوْا بِغَيْرِ وُضُوءٍ فَذَكَرُوا ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ آيَةَ التَّيَمُّمِقَالَ أُسَيْدُ بْنُ حُضَيْرٍ جَزَاكِ اللَّهُ خَيْرًا فَوَاللَّهِ مَا نَزَلَ بِكِ أَمْرٌ تَكْرَهِينَهُ إِلَّا جَعَلَ اللَّهُ لَكَ وَلِلْمُسْلِمِينَ فِيهِ خَيْرًا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Abu Mu'awiyah] dia berkata; telah menceritakan kepada kami [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah] Radliyallahu'anha, dia berkata; \"Rasulullah shallallahu 'alaihi wasallam mengutus Usaid bin Hudlair dan para sahabat sedang mencari kalung milikku yang ketinggalan ketika singgah di tempat persinggahannya. Lalu datanglah waktu shalat dan mereka dalam keadaan hadats serta mereka tidak punya air. Lalu mereka shalat tanpa wudlu, dan mereka menceritakan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian Allah Azza wa Jalla menurunkan ayat tentang tayamum.\" Usaid bin Hudlair berkata, \"Semoga Allah membalasmu dengan yang lebih baik. Demi Allah, Tidaklah Allah menurunkan kepadamu suatu perkara yang kamu benci kecuali pasti Allah akan menjadikannya kebaikan bagi dirimu dan kaum muslimin.\""},"321":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ أَنْبَأَنَا شُعْبَةُ أَنَّ مُخَارِقًا أَخْبَرَهُمْ عَنْ طَارِقٍأَنْ رَجُلًا أَجْنَبَ فَلَمْ يُصَلِّ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ أَصَبْتَ فَأَجْنَبَ رَجُلٌ آخَرَ فَتَيَمَّمَ وَصَلَّى فَأَتَاهُ فَقَالَ نَحْوَ مَا قَالَ لِلْآخَرِ يَعْنِي أَصَبْتَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; Telah memberitakan kepada kami [Syu'bah] bahwa [Mukhariq] Telah mengabarkan kepada mereka dari [Thariq] bahwa ada seseorang yang junub dan belum shalat datang kepada Rasulullah shallallahu 'alaihi wasallam, kemudian menceritakan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam. Beliau menjawab, \"Kamu benar\". Lalu ada laki-laki yang junub, kemudian dia tayamum dan shalat. Lantas orang ini datang kepada beliau, dan beliau shallallahu 'alaihi wasallam bersabda seperti yang kamu katakan kepada yang lain -yaitu: \"kamu benar\"- "},"322":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ سُفْيَانَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ بَعْضَ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اغْتَسَلَتْ مِنْ الْجَنَابَةِ فَتَوَضَّأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفَضْلِهَا فَذَكَرَتْ ذَلِكَ لَهُ فَقَالَ إِنَّ الْمَاءَ لَا يُنَجِّسُهُ شَيْءٌ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Sufyan] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] bahwa sebagian istri Nabi shallallahu 'alaihi wasallam mandi junub, lalu Rasulullah shallallahu 'alaihi wasallam berwudlu dari air sisanya, maka mereka (para istri Nabi) menceritakan hal tersebut kepada beliau, kemudian beliau bersabda, \"Air itu tidak dapat dinajisi oleh sesuatupun.\" "},"323":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ كَثِيرٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ كَعْبٍ الْقُرَظِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ رَافِعٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقِيلَ يَا رَسُولَ اللَّهِ أَتَتَوَضَّأُ مِنْ بِئْرِ بُضَاعَةَ وَهِيَ بِئْرٌ يُطْرَحُ فِيهَا لُحُومُ الْكِلَابِ وَالْحِيَضُ وَالنَّتَنُ فَقَالَ الْمَاءُ طَهُورٌ لَا يُنَجِّسُهُ شَيْءٌ","id":"Telah mengabarkan kepada kami [Harun bin Abdullah] dia berkata; telah menceritakan kepada kami [Abu Usamah] dia berkata; telah menceritakan kepada kami [Al Walid bin Katsir] dia berkata; telah menceritakan kepada kami [Muhammad bin Ka'ab Al Quradli] dari [Ubaidullah bin Abdurrahman bin Rafi'] dari [Abu Sa'id Al Khudri], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah ditanya, 'Wahai Rasulullah shallallahu 'alaihi wasallam! Apakah kita boleh wudlu dari sumur Budla'ah, yaitu sumur yang dijadikan sebagai pembuangan daging-daging anjing dan kotoran haidl serta barang-barang yang busuk'. Rasulullah shallallahu 'alaihi wasallam bersabda, \"Air itu suci, tidak ada sesuatu pun yang membuatnya najis.\" "},"324":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُسْلِمٍ وَكَانَ مِنْ الْعَابِدِينَ عَنْ مُطَرِّفِ بْنِ طَرِيفٍ عَنْ خَالِدِ بْنِ أَبِي نَوْفٍ عَنْ سَلِيطٍ عَنْ ابْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِيهِ قَالَمَرَرْتُ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَتَوَضَّأُ مِنْ بِئْرِ بُضَاعَةَ فَقُلْتُ أَتَتَوَضَّأُ مِنْهَا وَهِيَ يُطْرَحُ فِيهَا مَا يُكْرَهُ مِنْ النَّتَنِ فَقَالَ الْمَاءُ لَا يُنَجِّسُهُ شَيْءٌ","id":"Telah mengabarkan kepada kami [Al 'Abbas bin Abdul 'Azhim] dia berkata; telah menceritakan kepada kami [Abdul Malik bin Amr] dia berkata; telah menceritakan kepada kami [Abdul Aziz bin Muslim] -salah seorang ahli ibadah- dari [Mutharrif bin Tharif] dari [Khalid bin Abu Nauf] dari [Salith] dari [Ibnu Abu Sa'id Al Khudri] dari [bapaknya], dia berkata; \"Aku pernah melewati Rasulullah shallallahu 'alaihi wasallam dan beliau sedang wudlu dari sumur Budha'ah. Aku bertanya, 'Apakah engkau berwudlu dari sumur Budha'ah, yaitu sumur yang dijadikan pembuangan barang-barang busuk? ' Beliau bersabda; \"Tidak ada sesuatupun yang membuat airnya najis.\""},"325":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ الْمَرْوَزِيُّ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْوَلِيدِ بْنِ كَثِيرٍ عَنْ مُحَمَّدِ بْنِ جَعْفَرِ بْنِ الزُّبَيْرِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمَاءِ وَمَا يَنُوبُهُ مِنْ الدَّوَابِّ وَالسِّبَاعِ فَقَالَ إِذَا كَانَ الْمَاءُ قُلَّتَيْنِ لَمْ يَحْمِلْ الْخَبَثَ","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits Al Marwazi] dia berkata; Telah menceritakan kepada kami [Abu Usamah] dari [Al Walid bin Katsir] dari [Muhammad bin Ja'far bin Jubair] dari [Ubaidullah bin Abdullah bin Umar] dari [Bapaknya] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang air dan sesuatu yang telah menimpanya dari hewan ternak dan binatang buas, beliau shallallahu 'alaihi wasallam berkata, 'Bila air itu lebih dari dua qullah, maka tidak mengandung najis'. "},"326":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ أَعْرَابِيًّا بَالَ فِي الْمَسْجِدِ فَقَامَ إِلَيْهِ بَعْضُ الْقَوْمِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُزْرِمُوهُ فَلَمَّا فَرَغَ دَعَا بِدَلْوٍ مِنْ مَاءٍ فَصَبَّهُ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Anas bin Malik] bahwa ada seorang Arab Badui kencing di masjid, maka sebagian orang bangkit untuk menghentikannya, tetapi Rasulullah shallallahu 'alaihi wasallam menegurnya, \"Jangan hentikan dia (dari hajatnya) \". Setelah ia selesai dari hajatnya, beliau meminta seember air. Kemudian menyiraminya. "},"327":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ عَنْ عُمَرَ بْنِ عَبْدِ الْوَاحِدِ عَنْ الْأَوْزَاعِيِّ عَنْ مُحَمَّدِ بْنِ الْوَلِيدِ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَامَ أَعْرَابِيٌّ فَبَالَ فِي الْمَسْجِدِ فَتَنَاوَلَهُ النَّاسُ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى ا��لَّهُ عَلَيْهِ وَسَلَّمَ دَعُوهُ وَأَهْرِيقُوا عَلَى بَوْلِهِ دَلْوًا مِنْ مَاءٍ فَإِنَّمَا بُعِثْتُمْ مُيَسِّرِينَ وَلَمْ تُبْعَثُوا مُعَسِّرِينَ","id":"Telah mengabarkan kepada kami [Abdurrahman bin Ibrahim] dari [Umar bin Abdul Wahid] dari [Al Auza'i] dari [Muhammad bin Al Walid] dari [Az-Zuhri] dari [Ubaidullah bin Abdullah] dari [Abu Hurairah] dia berkata; bahwa ada Arab Badui kencing di masjid, maka sebagian orang mencelanya, tetapi Rasulullah shallallahu 'alaihi wasallam menegurnya, \"Biarkan dia. Siramkan seember air ke kencingnya. Kalian diutus untuk memberi kemudahan, bukan untuk kesulitan.\""},"328":{"ar":"أَخْبَرَنَا الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ عَنْ عَمْرٍو وَهُوَ ابْنُ الْحَارِثِ عَنْ بُكَيْرٍ أَنَّ أَبَا السَّائِبِ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَغْتَسِلْ أَحَدُكُمْ فِي الْمَاءِ الدَّائِمِ وَهُوَ جُنُبٌ","id":"Telah mengabarkan kepada kami [Al Harits bin Miskin] telah dibacakan kepadanya dan saya mendengarnya dari [Ibnu Wahab] dari [Amr yaitu Ibnu Al Harits] dari [Bukair] bahwa [Abu Sa'ib] berkata kepadanya, dia telah mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian mandi junub pada air yang tergenang (tidak mengalir).\""},"329":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ سَعِيدِ بْنِ أَبِي سَلَمَةَ أَنَّ الْمُغِيرَةَ بْنَ أَبِي بُرْدَةَ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُسَأَلَ رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّا نَرْكَبُ الْبَحْرَ وَنَحْمِلُ مَعَنَا الْقَلِيلَ مِنْ الْمَاءِ فَإِنْ تَوَضَّأْنَا بِهِ عَطِشْنَا أَفَنَتَوَضَّأُ مِنْ مَاءِ الْبَحْرِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ الطَّهُورُ مَاؤُهُ الْحِلُّ مَيْتَتُهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Shafwan bin Sulaim] dari [Said bin Abu Salamah] bahwa [Al Mughirah bin Abu Burdah] Telah mengabarkan kepadanya, sesungguhnya dia mendengar [Abu Hurairah] berkata, \"Seseorang bertanya kepada Rasulullah shallallahu 'alaihi wasallam, 'Wahai Rasulullah shallallahu 'alaihi wasallam, kami mengarungi lautan dengan kapal dan kami hanya membawa air sedikit. Bila kami berwudlu dengannya, maka kami akan kehausan. Jadi apakah kami boleh berwudlu dengan air laut?\" Rasulullah shallallahu 'alaihi wasallam bersabda, \"Laut itu suci airnya dan halal bangkainya.\" "},"330":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ اغْسِلْ خَطَايَايَ بِمَاءِ الثَّلْجِ وَالْبَرَدِ وَنَقِّ قَلْبِي مِنْ الْخَطَايَا كَمَا نَقَّيْتَ الثَّوْبَ الْأَبْيَضَ مِنْ الدَّنَسِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Jarir] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah bersihkanlah kesalahanku dengan air salju dan air embun dan sucikan hatiku dari kesalahan sebagaimana engkau mensucikan kain putih dari kotoran.\" "},"331":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ اغْسِلْنِي مِنْ خَطَايَايَ بِالثَّلْجِ وَالْمَاءِ وَالْبَرَدِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dia berkata; Telah memberitakan kepada kami [Jarir] dari [Umarah bin Al Qa'qa'] dari [Abu Zur'ah bin Amr bin Jarir] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, bersihkanlah kesalahanku dengan salju, air dan embun.\""},"332":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْأَعْمَشِ عَنْ أَبِي رَزِينٍ وَأَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وَلَغَ الْكَلْبُ فِي إِنَاءِ أَحَدِكُمْ فَلْيُرِقْهُ ثُمَّ لِيَغْسِلْهُ سَبْعَ مَرَّاتٍ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dia berkata; Telah memberitakan kepada kami [Ali bin Mushir] dari [Al A'masy] dari [Abu Razin] dan [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Apabila anjing menjilat bejana milik salah satu dari kalian maka tumpahkanlah (apa yang ada di dalamnya), kemudian basuhlah (cucilah sebanyak) tujuh kali.\""},"333":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ الْحَارِثِ عَنْ شُعْبَةَ عَنْ أَبِي التَّيَّاحِ قَالَ سَمِعْتُ مُطَرِّفًا عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِقَتْلِ الْكِلَابِ وَرَخَّصَ فِي كَلْبِ الصَّيْدِ وَالْغَنَمِ وَقَالَ إِذَا وَلَغَ الْكَلْبُ فِي الْإِنَاءِ فَاغْسِلُوهُ سَبْعَ مَرَّاتٍ وَعَفِّرُوهُ الثَّامِنَةَ بِالتُّرَابِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; Telah menceritakan kepada kami [Khalid yaitu Ibnu Al Harits] dari [Syu'bah] dari [Abu Tayyah] dia berkata; saya mendengar [Mutharrif] dari [Abdullah bin Mughaffal] bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk membunuh anjing dan memberi keringanan pada anjing yang digunakan untuk berburu dan menjaga kambing. Beliau lalu bersabda, \" Apabila ada anjing yang menjilat bejana, maka basuhlah (cucilah) tujuh kali dan gosoklah yang ke delapan dengan tanah.\""},"334":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ قَالَ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي التَّيَّاحِ يَزِيدَ بْنِ حُمَيْدٍ قَالَ سَمِعْتُ مُطَرِّفًا يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَ أَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَتْلِ الْكِلَابِ قَالَ مَا بَالُهُمْ وَبَالُ الْكِلَابِ قَالَ وَرَخَّصَ فِي كَلْبِ الصَّيْدِ وَكَلْبِ الْغَنَمِوَقَالَ إِذَا وَلَغَ الْكَلْبُ فِي الْإِنَاءِ فَاغْسِلُوهُ سَبْعَ مَرَّاتٍ وَعَفِّرُوا الثَّامِنَةَ بِالتُّرَابِخَالَفَهُ أَبُو هُرَيْرَةَ فَقَالَ إِحْدَاهُنَّ بِالتُّرَابِ","id":"Telah mengabarkan kepada kami [Amr bin Yazid] dia berkata; Telah menceritakan kepada kami [Bahaz bin Asad] dia berkata; Telah menceritakan kepada kami [Syu'bah] dari [Abu Tayyah Yazid bin Humaid] dia berkata; Saya mendengar [Mutharraf] berkata; dari [Abdullah bin Mughaffal] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk membunuh anjing.\" Abdullah bin Mughaffal berkata, \" Apa urusan mereka dan apa urusan anjing itu? Rasulullah shallallahu 'alaihi wasallam memberi rukhsah (keringanan) untuk anjing yang digunakan untuk berburu dan menjaga kambing. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda, \"Apabila anjing menjilat bejana, maka cucilah tujuh kali dan gosoklah yang ke delapan dengan tanah'. Abu Hurairah menyelisihinya dan berkata, \"salah satunya dengan tanah.\""},"335":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ خِلَاسٍ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا وَلَغَ الْكَلْبُ فِي إِنَاءِ أَحَدِكُمْ فَلْيَغْسِلْهُ سَبْعَ مَرَّاتٍ أُولَاهُنَّ بِالتُّرَابِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Mu'adz bin Hisyam] dia berkata; Telah menceritakan kepadaku [Bapakku] dari [Qatadah] dari [Khilas] dari [Abu Rafi'] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila ada anjing yang menjilat bejana milik salah seorang kalian, basuhlah tujuh kali, dan salah satunya dengan tanah.\""},"336":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ ابْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا وَلَغَ الْكَلْبُ فِي إِنَاءِ أَحَدِكُمْ فَلْيَغْسِلْهُ سَبْعَ مَرَّاتٍ أُولَاهُنَّ بِالتُّرَابِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Ibnu Abu 'Arubah] dari [Qatadah] dari [Ibnu Sirin] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila ada anjing yang menjilat bejana milik salah seorang kalian, maka basuhlah (cucilah) tujuh kali, dan salah satunya dengan tanah.\" "},"337":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ حُمَيْدَةَ بِنْتِ عُبَيْدِ بْنِ رِفَاعَةَ عَنْ كَبْشَةَ بِنْتِ كَعْبِ بْنِ مَالِكٍأَنَّ أَبَا قَتَادَةَ دَخَلَ عَلَيْهَا ثُمَّ ذَكَرَ كَلِمَةً مَعْنَاهَا فَسَكَبْتُ لَهُ وَضُوءًا فَجَاءَتْ هِرَّةٌ فَشَرِبَتْ مِنْهُ فَأَصْغَى لَهَا الْإِنَاءَ حَتَّى شَرِبَتْ قَالَتْ كَبْشَةُ فَرَآنِي أَنْظُرُ إِلَيْهِ فَقَالَ أَتَعْجَبِينَ يَا ابْنَةَ أَخِي قُلْتُ نَعَمْ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّهَا لَيْسَتْ بِنَجَسٍ إِنَّمَا هِيَ مِنْ الطَّوَّافِينَ عَلَيْكُمْ وَالطَّوَّافَاتِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Humaidah binti 'Ubaid bin Rifa'ah] dari [Kabsyah binti Ka'ab bin Malik] bahwa [Abu Qatadah] menemuinya -kemudian menyebutkan suatu kalimat yang maknanya- aku menuangkan air wudlu kepada beliau, lalu datang seekor kucing yang meminum air wudlu tadi. Beliau lalu mendekatkan bejana tadi kepada kucing tersebut hingga ia meminumnya. Kabsyah berkata, \"Dia melihatku sedang memperhatikannya, maka ia berkata, 'Apakah kamu takjub wahai anak perempuan saudaraku? ' Aku menjawab, 'Ya'. Kabsyah berkata; Rasulullah shallallahu 'alaihi wasallam bersabda; Kucing itu tidak najis, ia adalah hewan yang ada di sekeliling kalian. "},"338":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ الْمِقْدَامِ بْنِ شُرَيْحٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكُنْتُ أَتَعَرَّقُ الْعَرْقَ فَيَضَعُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاهُ حَيْثُ وَضَعْتُهُ وَأَنَا حَائِضٌ وَكُنْتُ أَشْرَبُ مِنْ الْإِنَاءِ فَيَضَعُ فَاهُ حَيْثُ وَضَعْتُ وَأَنَا حَائِضٌ","id":"Telah mengabarkan kepada kami [Amr bin Ali] dia berkata; Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Al Miqdam bin Syuraih] dari [Bapaknya] dari [Aisyah] Radliyallahu'anha dia berkata: \"Aku pernah menggigit sepotong daging satu gigitan, lalu Rasulullah shallallahu 'alaihi wasallam meletakkan mulutnya di tempat tadi aku meletakkan mulutku, padahal aku sedang haidl. Aku juga pernah minum dengan suatu bejana, kemudian Rasulullah shallallahu 'alaihi wasallam meletakkan mulutnya ditempat aku meletakkan mulutku sedangkan aku dalam keadaan haidl.\""},"339":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ الرِّجَالُ وَالنِّسَاءُ يَتَوَضَّئُونَ فِي زَمَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمِيعًا","id":"Telah mengabarkan kepada kami [Harun bin Abdullah] dia berkata; Telah menceritakan kepada kami [Ma'an] dia berkata; Telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar] dia berkata; \"Pada zaman Rasulullah shallallahu 'alaihi wasallam, laki-laki dan perempuan wudlu bersama-sama.\""},"340":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ الْأَحْوَلِ قَالَ سَمِعْتُ أَبَا حَاجِبٍ قَالَ أَبُو عَبْدِ الرَّحْمَنِ وَاسْمُهُ سَوَادَةُ بْنُ عَاصِمٍ عَنْ الْحَكَمِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يَتَوَضَّأَ الرَّجُلُ بِفَضْلِ وُضُوءِ الْمَرْأَةِ","id":"Telah mengabarkan kepada kami [Amr bin Ali] dia berkata; Telah menceritakan kepada kami [Abu Daud] dia berkata; Telah menceritakan kepada kami [Syu'bah] dari ['Ashim Al Ahwal] dia berkata; Saya mendengar [Abu Hajib] -menurut Abu Abdurrahman namanya adalah Sawadah bin 'Ashim- dari [Al Hakam bin Amr], bahwa Rasulullah shallallahu 'alaihi wasallam melarang seorang laki-laki berwudlu dengan sisa air wudlu wanita.\""},"341":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّهَا كَانَتْ تَغْتَسِلُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْإِنَاءِ الْوَاحِدِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Al-Laits] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] bahwa ia pernah mandi bersama Rasulullah shallallahu 'alaihi wasallam dalam satu bejana. "},"342":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ جَبْرٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ بِمَكُّوكٍ وَيَغْتَسِلُ بِخَمْسَةِ مَكَاكِيَّ","id":"Telah mengabarkan kepada kami [Amr bin Ali] dia berkata; Telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; Telah menceritakan kepada kami [Syu'bah] dia berkata; Telah menceritakan kepadaku [Abdullah bin Abdullah bin Jabr] dia berkata; \"Saya mendengar [Anas bin Malik] berkata; bahwa Rasulullah shallallahu 'alaihi wasallam bila berwudlu menggunakan satu makkuk (air) sedangkan bila mandi menggunakan lima makkuk. "},"343":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ إِسْحَقَ الْكُوفِيُّ قَالَ حَدَّثَنَا عَبْدَةُ يَعْنِي ابْنَ سُلَيْمَانَ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَوَضَّأُ بِمُدٍّ وَيَغْتَسِلُ بِنَحْوِ الصَّاعِ","id":"Telah mengabarkan kepada kami [Harun bin Ishaq Al Kufii] dia berkata; Telah menceritakan kepada kami ['Abdah yaitu Ibnu Sulaiman] dari [Sa'id] dari [Qatadah] dari [Shafiyyah binti Syaibah] dari [Aisyah] Radliyallahu'anha bahwa Rasulullah shallallahu 'alaihi wasallam pernah berwudlu dengan satu mud dan mandi dengan kurang lebih satu sha'. "},"344":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ إِسْحَقَ قَالَ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى قَالَ حَدَّثَنَا شَيْبَانُ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ أُمِّهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ بِالْمُدِّ وَيَغْتَسِلُ بِالصَّاعِ","id":"Telah mengabarkan kepada kami [Abu Bakar bin Ishaq] dia berkata; Telah menceritakan kepada kami [Al Hasan bin Musa] dia berkata; Telah menceritakan kepada kami [Syaiban] dari [Qatadah] dari [Al Hasan] dari [Ibunya] dari [Aisyah] Radliyallahu'anha dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah berwudlu dengan satu mud dan mandi dengan satu sha'.\""},"345":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ بْنِ مُحَمَّدِ بْنِ أَبِي بَكْرٍ الصِّدِّيقِ رَضِيَ اللَّهُ عَنْهُ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نُرَى إِلَّا الْحَجَّ فَلَمَّا كُنَّا بِسَرِفَ حِضْتُ فَدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أَبْكِي فَقَالَ مَا لَكِ أَنَفِسْتِ قُلْتُ نَعَمْ قَالَ هَذَا أَمْرٌ كَتَبَهُ اللَّهُ عَزَّ وَجَلَّ عَلَى بَنَاتِ آدَمَ فَاقْضِي مَا يَقْضِي الْحَاجُّ غَيْرَ أَنْ لَا تَطُوفِي بِالْبَيْتِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Sufyan] dari [Abdurrahman bin Al Qasim bin Muhammad bin Abu Bakar As-Shiddiq Radliyallahu'anhu] dari [Bapaknya] dari [Aisyah] Radliyallahu'anha dia berkata; \"Kami pergi bersama Rasulullah shallallahu 'alaihi wasallam dan kami tidak menaksir selain untuk haji. Setelah sampai di Sarif, aku haidl. Ketika Rasulullah shallallahu 'alaihi wasallam datang kepadaku, aku sedang menangis. Beliau lalu bersabda, 'Ada apa denganmu? Apakah kamu sedang haidl? ' Aku menjawab; Ya. Beliau bersabda: Ini adalah perkara yang telah Allah Azza wa Jalla tetapkan bagi kaum wanita, maka kerjakan apa yang dikerjakan oleh orang yang haji, kecuali thawaf di Ka'bah'.\""},"346":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَبْدِ اللَّهِ وَهُوَ ابْنُ سَمَاعَةَ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ أَخْبَرَنِي هِشَامُ بْنُ عُرْوَةَ عَنْ عُرْوَةَأَنَّ فَاطِمَةَ بِنْتَ قَيْسٍ مِنْ بَنِي أَسَدِ قُرَيْشٍ أَنَّهَا أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ أَنَّهَا تُسْتَحَاضُ فَزَعَمَتْ أَنَّهُ قَالَ لَهَا إِنَّمَا ذَلِكَ عِرْقٌ فَإِذَا أَقْبَلَتْ الْحَيْضَةُ فَدَعِي الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَاغْتَسِلِي وَاغْسِلِي عَنْكِ الدَّمَ ثُمَّ صَلِّي","id":"Telah mengabarkan kepada kami ['Imran bin Yazid] dia berkata; Telah menceritakan kepada kami [Ismail bin Abdullah yaitu Ibnu Sama'ah] dia berkata; Telah menceritakan kepada kami [Al Auza'i] dia berkata; Telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; Telah mengabarkan kepadaku [Hisyam bin Urwah] dari [Urwah] bahwa [Fatimah binti Qais] -dari Bani Asad Quraisy- pernah datang kepada Rasulullah shallallahu 'alaihi wasallam untuk menceritakan bahwa dirinya sedang mengalami istihadah. Seingatnya Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya, \"Itu darah penyakit. Bila datang haidl maka tinggalkan shalat, dan bila telah selesai mandilah dan cucilah darah yang masih ada kemudian kerjakanlah shalat.\" "},"347":{"ar":"أَخْبَرَنَا هِشَامُ بْنُ عَمَّارٍ قَالَ حَدَّثَنَا سَهْلُ بْنُ هَاشِمٍ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَقْبَلَتْ الْحَيْضَةُ فَدَعِي الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَاغْتَسِلِي","id":"Telah mengabarkan kepada kami [Hisyam bin 'Ammar] dia berkata; Telah menceritakan kepada kami [Sahal bin Hasyim] dia berkata; Telah menceritakan kepada kami [Al Auza'i] dari [Az-Zuhri] dari [Urwah] dari [Aisyah] Radliyallahu'anha, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bila datang haidl, tinggalkan shalat, dan bila selesai, mandilah.\""},"348":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْاسْتَفْتَتْ أُمُّ حَبِيبَةَ بِنْتُ جَحْشٍ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي أُسْتَحَاضُ فَقَالَ إِنَّ ذَلِكَ عِرْقٌ فَاغْتَسِلِي ثُمَّ صَلِّي فَكَانَتْ تَغْتَسِلُ عِنْدَ كُلِّ صَلَاةٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Al-Laits] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] Radliyallahu'anha, bahwa Ummu Habibah binti Jahsy meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam, \"Wahai Rasulullah shallallahu 'alaihi wasallam! Aku mengalami istihadhah? ' Beliau shallallahu 'alaihi wasallam bersabda: \"Itu darah penyakit, maka mandilah kemudian kerjakanlah shalat.\" Lalu dia pun mandi di setiap akan shalat. "},"349":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْإِنَّ أُمَّ حَبِيبَةَ سَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدَّمِ فَقَالَتْ عَائِشَةُ رَأَيْتُ مِرْكَنَهَا مَلْآنَ دَمًا فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْكُثِي قَدْرَ مَا كَانَتْ تَحْبِسُكِ حَيْضَتُكِ ثُمَّ اغْتَسِلِيأَخْبَرَنَا بِهِ قُتَيْبَةُ مَرَّةً أُخْرَى وَلَمْ يَذْكُرْ فِيهِ جَعْفَرَ بْنَ رَبِيعَةَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Al-Laits] dari [Yazid bin Abu Habib] dari [Ja'far bin Rabi'ah] dari ['Irak bin Malik] dari ['Urwah] dari [Aisyah] bahwa Ummu Habibah bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang darah? Aisyah Radliyallahu'anha lalu berkata, \"Aku melihat tempatnya mencuci pakaian penuh darah. Lantas Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Tetapkanlah olehmu sesuai ukuran kebiasaan haidlmu, kemudian mandilah.\" Juga telah mengabarkan kepada kami Qutaibah dengan hadits yang serupa, tetapi tidak menyebutkan Ja'far bin Rabi'ah. "},"350":{"ar":"أَنْبَأَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ قَالَ أَخْبَرَنِي عَنْ نَافِعٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ أُمِّ سَلَمَةَ قَالَتْسَأَلَتْ امْرَأَةٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ إِنِّي أُسْتَحَاضُ فَلَا أَطْهُرُ أَفَأَدَعُ الصَّلَاةَ قَالَ لَا وَلَكِنْ دَعِي قَدْرَ تِلْكَ الْأَيَّامِ وَاللَّيَالِي الَّتِي كُنْتِ تَحِيضِينَ فِيهَا ثُمَّ اغْتَسِلِي وَاسْتَثْفِرِي وَصَلِّي","id":"Telah memberitakan kepada kami [Muhammad bin Abdullah bin Al Mubarak] dia berkata; Telah menceritakan kepada kami [Abu Usamah] berkata; Telah menceritakan kepada kami ['Ubaidullah bin Umar] berkata; Telah mengabarkan kepadaku dari [Nafi'] dari [Sulaiman bin Yasar] dari [Ummu Salamah] berkata; \"Ada seorang perempuan yang bertanya kepada Nabi shallallahu 'alaihi wasallam, 'Aku sedang istihadhah, maka aku tidak suci. Apakah aku harus meninggalkan shalat? ' beliau shallallahu 'alaihi wasallam bersabda: 'Tidak, tetapi tinggalkan shalat pada ukuran hari dan malam sesuai jadwal haidlmu, kemudian mandi dan balutlah dengan kain pada tempat keluarnya darah, lalu shalatlah'.\""},"351":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ أُمِّ سَلَمَةَأَنَّ امْرَأَةً كَانَتْ تُهَرَاقُ الدَّمَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَفْتَتْ لَهَا أُمُّ سَلَمَةَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِتَنْظُرْ عَدَدَ اللَّيَالِي وَالْأَيَّامِ الَّتِي كَانَتْ تَحِيضُ مِنْ الشَّهْرِ قَبْلَ أَنْ يُصِيبَهَا الَّذِي أَصَابَهَا فَلْتَتْرُكْ الصَّلَاةَ قَدْرَ ذَلِكَ مِنْ الشَّهْرِ فَإِذَا خَلَّفَتْ ذَلِكَ فَلْتَغْتَسِلْ ثُمَّ لِتَسْتَثْفِرْ بِالثَّوْبِ ثُمَّ لِتُصَلِّ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Nafi'] dari [Sulaiman bin Yasar] dari [Ummu Salamah] bahwa ada seorang perempuan yang selalu mengeluarkan darah pada zaman Rasulullah shallallahu 'alaihi wasallam, dia meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam? beliau bersabda, \"Hendaklah kamu menghitung malam dan hari sesuai jadwal haidlmu setiap bulan, sebelum mengalami hal (seringnya darah keluar) tersebut dalam setiap bulannya. Bila waktu kebiasaan haidl telah selesai, maka mandi dan letakkan kain pada tempat haidl, lalu shalatlah. '"},"352":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ بْنِ دَاوُدَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا إِسْحَقُ وَهُوَ ابْنُ بَكْرِ بْنِ مُضَرَ قَالَ حَدَّثَنِي أَبِي عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ وَهُوَ ابْنُ أُسَامَةَ بْنِ الْهَادِ عَنْ أَبِي بَكْرٍ وَهُوَ ابْنُ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْإِنَّ أُمَّ حَبِيبَةَ بِنْتَ جَحْشٍ الَّتِي كَانَتْ تَحْتَ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَأَنَّهَا اسْتُحِيضَتْ لَا تَطْهُرُ فَذُكِرَ شَأْنُهَا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَتْ بِالْحَيْضَةِ وَلَكِنَّهَا رَكْضَةٌ مِنْ الرَّحِمِ لِتَنْظُرْ قَدْرَ قَرْئِهَا الَّتِي كَانَتْ تَحِيضُ لَهَا فَلْتَتْرُكْ الصَّلَاةَ ثُمَّ تَنْظُرْ مَا بَعْدَ ذَلِكَ فَلْتَغْتَسِلْ عِنْدَ كُلِّ صَلَاةٍ","id":"Telah mengabarkan kepada kami [Ar-Rabi' bin Sulaiman bin Daud bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Ishaq yaitu Ibnu Bakr bin Mudlar] dia berkata; Telah menceritakan kepadaku [Bapakku] dari [Yazid bin Abdullah yaitu Ibnu Usamah bin Al Had] dari [Abu Bakr yaitu Ibnu Muhammad bin 'Amr bin Hazm] dari ['Amrah] dari [Aisyah] dia berkata; Bahwa Ummu Habibah binti Jahsy -istri Abdurrahman bin Auf- mengalami istihadhah dan tidak suci, sehingga hal itu diadukan kepada Rasulullah shallallahu 'alaihi wasallam. Lalu beliau shallallahu 'alaihi wasallam bersabda kepadanya: \"Ini bukan haidl, tetapi hentakan rahim. Jadi hendaklah dia mandi dan mengerjakan shalat. Lalu hendaklah dia memperhatikan kebiasaan masa haidlnya, kemudian meninggalkan shalat dan melihat apa yang terjadi setelah itu, lalu hendaknya mandi setiap akan shalat.\""},"353":{"ar":"أَخْبَرَنَا أَبُو مُوسَى قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عَمْرَةَ عَنْ عَائِشَةَأَنَّ ابْنَةَ جَحْشٍ كَانَتْ تُسْتَحَاضُ سَبْعَ سِنِينَ فَسَأَلَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَيْسَتْ بِالْحَيْضَةِ إِنَّمَا هُوَ عِرْقٌ فَأَمَرَهَا أَنْ تَتْرُكَ الصَّلَاةَ قَدْرَ أَقْرَائِهَا وَحَيْضَتِهَا وَتَغْتَسِلَ وَتُصَلِّيَ فَكَانَتْ تَغْتَسِلُ عِنْدَ كُلِّ صَلَاةٍ","id":"Telah mengabarkan kepada kami [Abu Musa] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Az-Zuhri] dari ['Amrah] dari [Aisyah] bahwa Ummu Habibah binti Jahsy pernah mengalami haidl selama tujuh tahun. Lalu ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang hal tersebut, dan beliau menjawab, \"Itu bukan haidl, tetapi darah penyakit. ' Kemudian beliau memerintahkannya meninggalkan shalat menurut jadwal haidlnya, lalu mandi serta tetap shalat, dan dia mandi setiap akan shalat. "},"354":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ قَالَ أَنْبَأَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ عَنْ الْمُنْذِرِ بْنِ الْمُغِيرَةِ عَنْ عُرْوَةَ أَنَّ فَاطِمَةَ بِنْتَ أَبِي حُبَيْشٍ حَدَّثَتْهُأَنَّهَا أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَكَتْ إِلَيْهِ الدَّمَ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا ذَلِكَ عِرْقٌ فَانْظُرِي إِذَا أَتَاكِ قَرْؤُكِ فَلَا تُصَلِّي وَإِذَا مَرَّ قَرْؤُكِ فَلْتَطَهَّرِي ثُمَّ صَلِّي مَا بَيْنَ الْقَرْءِ إِلَى الْقَرْءِقَالَ أَبُو عَبْد الرَّحْمَنِ قَدْ رَوَى هَذَا الْحَدِيثَ هِشَامُ بْنُ عُرْوَةَ عَنْ عُرْوَةَ وَلَمْ يَذْكُرْ فِيهِ مَا ذَكَرَ الْمُنْذِرُ","id":"Telah mengabarkan kepada kami ['Isa bin Hammad] dia berkata; Telah memberitakan kepada kami [Al-Laits] dari [Yazid bin Abu Habib] dari [Bukair bin Abdullah] dari [Al Mundzir bin Al Mughirah] dari [Urwah] bahwa [Fatimah binti Abu Hubaisy] berkata kepadanya, dirinya pernah datang kepada Rasulullah shallallahu 'alaihi wasallam untuk mengadukan darahnya. Rasulullah shallallahu 'alaihi wasallam lalu bersabda kepadanya: \"Itu darah penyakit. Perhatikanlah jadwal haidlmu. Jika datang maka jangan shalat dan jika telah berlalu jadwal haidlnya maka bersucilah, kemudian shalatlah antara waktu haidl yang satu ke waktu haidl yang lain.\" "},"355":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدَةُ وَوَكِيعٌ وَأَبُو مُعَاوِيَةَ قَالُوا حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْجَاءَتْ فَاطِمَةُ بِنْتُ أَبِي حُبَيْشٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنِّي امْرَأَةٌ أُسْتَحَاضُ فَلَا أَطْهُرُ أَفَأَدَعُ الصَّلَاةَ قَالَ لَا إِنَّمَا ذَلِكَ عِرْقٌ وَلَيْسَتْ بِالْحَيْضَةِ فَإِذَا أَقْبَلَتْ الْحَيْضَةُ فَدَعِي الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَاغْسِلِي عَنْكِ الدَّمَ وَصَلِّي","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah menceritakan kepada kami ['Abdah], [Waki'] dan [Abu Mu'awiyah] mereka berkata; Telah menceritakan kepada kami [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah] dia berkata, \" Fatimah binti Hubaisy datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, 'Aku sedang mengalami istihadhah dan aku tidak suci, jadi apakah aku harus meninggalkan shalat? ' Beliau bersabda: 'Tidak, itu darah penyakit, bukan haidl. Bila datang haidl maka tinggalkanlah shalat, dan jika sudah selesai haidl maka cucilah darah itu dan shalatlah.\""},"356":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ امْرَأَةً مُسْتَحَاضَةً عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِيلَ لَهَا إِنَّهُ عِرْقٌ عَانِدٌ وَأُمِرَتْ أَنْ تُؤَخِّرَ الظُّهْرَ وَتُعَجِّلَ الْعَصْرَ وَتَغْتَسِلَ لَهُمَا غُسْلًا وَاحِدًا وَتُؤَخِّرَ الْمَغْرِبَ وَتُعَجِّلَ الْعِشَاءَ وَتَغْتَسِلَ لَهُمَا غُسْلًا وَاحِدًا وَتَغْتَسِلَ لِصَلَاةِ الصُّبْحِ غُسْلًا وَاحِدًا","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; Telah menceritakan kepada kami [Muhammad] dia berkata; Telah menceritakan kepada kami [Syu'bah] dari [Abdurrahman bin Al Qasim] dari [Bapaknya] dari [Aisyah] bahwa ada seorang perempuan yang sedang istihadhah pada jaman Rasulullah shallallahu 'alaihi wasallam, lalu dikatakan kepadanya bahwa itu adalah darah penyakit di luar kebiasaan. Lalu diperintahkan untuk mengakhirkan shalat Zhuhur dan memajukan shalat Ashar, dengan satu kali mandi untuk keduanya. Mengakhirkan maghrib dan memajukan Isya' dengan satu kali mandi untuk keduanya. Dan satu kali mandi untuk shalat subuh. "},"357":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ سُفْيَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ الْقَاسِمِ عَنْ زَيْنَبَ بِنْتِ جَحْشٍ قَالَتْقُلْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا مُسْتَحَاضَةٌ فَقَالَ تَجْلِسُ أَيَّامَ أَقْرَائِهَا ثُمَّ تَغْتَسِلُ وَتُؤَخِّرُ الظُّهْرَ وَتُعَجِّلُ الْعَصْرَ وَتَغْتَسِلُ وَتُصَلِّي وَتُؤَخِّرُ الْمَغْرِبَ وَتُعَجِّلُ الْعِشَاءَ وَتَغْتَسِلُ وَتُصَلِّيهِمَا جَمِيعًا وَتَغْتَسِلُ لِلْفَجْرِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah menceritakan kepada kami [Abdullah] dari [Sufyan] dari [Abdurrahman bin Al Qasim] dari [Al Qasim] dari [Zainab binti Jahsy], dia berkata; \"Aku berkata kepada Rasulullah Shallallahu'alihi wasallam bahwa aku sedang istihadhah, lalu beliau bersabda: \"Hendaknya kamu duduk (menunggu) pada hari-hari biasa haidl, kemudian mandi dan akhirkanlah shalat Zhuhur dan memajukan shalat Ashar. Mandi dan shalat, juga untuk mengakhirkan Maghrib dan memajukan shalat Isya, serta mandi satu kali untuk dua shalat, kemudian mandi sekali untuk shalat Subuh.\" "},"358":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ مُحَمَّدِ بْنِ عَمْرٍو وَهُوَ ابْنُ عَلْقَمَةَ بْنِ وَقَّاصٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ فَاطِمَةَ بِنْتِ أَبِي حُبَيْشٍأَنَّهَا كَانَتْ تُسْتَحَاضُ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ دَمُ الْحَيْضِ فَإِنَّهُ دَمٌ أَسْوَدُ يُعْرَفُ فَأَمْسِكِي عَنْ الصَّلَاةِ وَإِذَا كَانَ الْآخَرُ فَتَوَضَّئِي فَإِنَّمَا هُوَ عِرْقٌقَالَ مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ هَذَا مِنْ كِتَابِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; Telah menceritakan kepada kami [Ibnu Abu 'Adi] dari telah menceritakan kepada kami [Muhammad bin Amr yaitu Ibnu 'Alqamah bin Waqqash] dari [Ibnu Syihab] dari [Urwah bin Jubair] dari [Fathimah binti Abu Hubaisy], bahwa ia mengalami istihadhah, maka Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Bila darah itu adalah darah haidl, maka darahnya hitam yang sudah dikenal, sehingga tinggalkanlah shalat. Jika selain itu maka berwudlulah, karena itu adalah darah penyakit.\" Muhammad bin Al Mutsanna berkata; Telah menceritakan kepada kami -tentang ini- Ibnu Abu Adi dari kitabnya. "},"359":{"ar":"و أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ مِنْ حِفْظِهِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ فَاطِمَةَ بِنْتَ أَبِي حُبَيْشٍ كَانَتْ تُسْتَحَاضُ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ دَمَ الْحَيْضِ دَمٌ أَسْوَدُ يُعْرَفُ فَإِذَا كَانَ ذَلِكَ فَأَمْسِكِي عَنْ الصَّلَاةِ فَإِذَا كَانَ الْآخَرُ فَتَوَضَّئِي وَصَلِّيقَالَ أَبُو عَبْد الرَّحْمَنِ قَدْ رَوَى هَذَا الْحَدِيثَ غَيْرُ وَاحِدٍ وَلَمْ يَذْكُرْ أَحَدٌ مِنْهُمْ مَا ذَكَرَ ابْنُ أَبِي عَدِيٍّ وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; Telah menceritakan kepada kami [Ibnu Abu Adi] -dari hafalannya- dia berkata; Telah menceritakan kepada kami [Muhammad bin Amr] dari [Ibnu syihab] dari [Urwah] dari [Aisyah] bahwa Fatimah binti Hubaisy mengalami istihadhah, lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya, \"Bila darah itu adalah darah haidl, maka darahnya hitam yang sudah dikenal, sehingga tinggalkanlah shalat. Jika selain itu maka berwudlulah, dan kerjakanlah shalat.\" Abu Abdurrahman berkata; Tidak hanya satu orang yang meriwayatkan hadits ini, dan tidak seorangpun dari mereka yang menyebutkan sebagaimana yang disebutkan oleh Ibnu Adi Wallahu Ta'ala A'lam. "},"360":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ عَنْ حَمَّادٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْاسْتُحِيضَتْ فَاطِمَةُ بِنْتُ أَبِي حُبَيْشٍ فَسَأَلَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي أُسْتَحَاضُ فَلَا أَطْهُرُ أَفَأَدَعُ الصَّلَاةَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا ذَلِكَ عِرْقٌ وَلَيْسَتْ بِالْحَيْضَةِ فَإِذَا أَقْبَلَتْ الْحَيْضَةُ فَدَعِي الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَاغْسِلِي عَنْكِ الدَّمَ وَتَوَضَّئِي وَصَلِّي فَإِنَّمَا ذَلِكَ عِرْقٌ وَلَيْسَتْ بِالْحَيْضَةِ قِيلَ لَهُ فَالْغُسْلُ قَالَ وَذَلِكَ لَا يَشُكُّ فِيهِ أَحَدٌقَالَ أَبُو عَبْد الرَّحْمَنِ قَدْ رَوَى هَذَا الْحَدِيثَ غَيْرُ وَاحِدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ وَلَمْ يَذْكُرْ فِيهِ وَتَوَضَّئِي غَيْرُ حَمَّادٍ وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin 'Arabi] dari [Hammad] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah] Radliyallahu'anha bahwa Fatimah binti Hubaisy mengalami istihadhah, lalu bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \"Wahai Rasulullah shallallahu 'alaihi wasallam! Aku sedang istihadhah, maka aku tidak suci. Jadi apakah aku harus meninggalkan shalat?\" Rasulullah shallallahu 'alaihi wasallam menjawab; \"Itu darah penyakit, bukan haidl. Bila datang haidl, maka cucilah bekas darah darimu dan berwudlulah, karena itu hanya darah penyakit, bukan haidl.\" Beliau ditanya, \"Bagaimana dengan mandi?\" Beliau menjawab: \"Tidak seorang pun yang meragukannya.\" Abu Abdurrahman berkata; Yang meriwayatkan hadits ini tidak hanya satu orang, dari Hisyam bin Urwah dan dia tidak menyebutkan didalamnya -wa tawadla'i- (.. dan berwudlulah..) selain Hammad saja. Wallahu Ta'ala A'lam. "},"361":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ فَاطِمَةَ بِنْتَ أَبِي حُبَيْشٍ أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي أُسْتَحَاضُ فَلَا أَطْهُرُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا ذَلِكَ عِرْقٌ وَلَيْسَتْ بِالْحَيْضَةِ فَإِذَا أَقْبَلَتْ الْحَيْضَةُ فَأَمْسِكِي عَنْ الصَّلَاةِ وَإِذَا أَدْبَرَتْ فَاغْسِلِي عَنْكِ الدَّمَ وَصَلِّي","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah menceritakan kepada kami [Abdullah] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah] Radliyallahu'anha dia berkata: Fatimah binti Abu Hubaisy berkata, \"Wahai Rasulullah Shallallahu'alihi wasallam, aku sedang mengalami istihadhah, dan aku tidak suci.\" Beliau Shallallahu'alihi wasallam bersabda: \"Itu hanya darah penyakit, bukan darah haidl. Bila datang waktu haidl, maka tinggalkanlah shalat, dan jika telah selesai haidl, maka cucilah tempat darah itu dan shalatlah.\" "},"362":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَقَالَتْ قَالَتْ فَاطِمَةُ بِنْتُ أَبِي حُبَيْشٍ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أَطْهُرُ أَفَأَدَعُ الصَّلَاةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا ذَلِكَ عِرْقٌ وَلَيْسَتْ بِالْحَيْضَةِ فَإِذَا أَقْبَلَتْ الْحَيْضَةُ فَدَعِي الصَّلَاةَ وَإِذَا ذَهَبَ قَدْرُهَا فَاغْسِلِي عَنْكِ الدَّمَ وَصَلِّي","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah] Radliyallahu'anha dia berkata; \" Fatimah binti Abu Hubaisy berkata, 'Wahai Rasulullah shallallahu 'alaihi wasallam, aku tidak suci, jadi apakah aku harus meninggalkan shalat? ' Beliau shallallahu 'alaihi wasallam menjawab: 'Itu hanya darah penyakit, bukan darah haidl. Bila datang haidl, maka tinggalkanlah shalat, dan jika telah selesai waktu jadwal haidlnya, maka cucilah tempat darah itu dan shalatlah.\" "},"363":{"ar":"أَخْبَرَنَا أَبُو الْأَشْعَثِ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ سَمِعْتُ هِشَامًا يُحَدِّثُ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ بِنْتَ أَبِي حُبَيْشٍ قَالَتْ يَا رَسُولَ اللَّهِ إِنِّي لَا أَطْهُرُ أَفَأَتْرُكُ الصَّلَاةَ قَالَ لَا إِنَّمَا هُوَ عِرْقٌ قَالَ خَالِدٌ وَفِيمَا قَرَأْتُ عَلَيْهِ وَلَيْسَتْ بِالْحَيْضَةِ فَإِذَا أَقْبَلَتْ الْحَيْضَةُ فَدَعِي الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَاغْسِلِي عَنْكِ الدَّمَ ثُمَّ صَلِّي","id":"Telah mengabarkan kepada kami [Abu Asy'ats] dia berkata; Telah menceritakan kepada kami [Khalid bin Harits] dia berkata; Saya mendengar [Hisyam] berkata; dari [Bapaknya] dari [Aisyah] Radliyallahu'anha dia berkata: ' Fatimah binti Abu Hubaisy berkata, 'Wahai Rasulullah shallallahu 'alaihi wasallam, aku tidak suci, jadi apakah aku harus meninggalkan shalat? ' Beliau shallallahu 'alaihi wasallam menjawab: \"Itu hanya darah penyakit\". Khalid berkata; Dan dari apa yang saya baca ada tambahan lain: \"Dan bukan darah haidl. Jadi bila datang waktu haidl maka tinggalkanlah shalat, dan jika telah selesai haidl maka cucilah tempat itu dan shalatlah.\""},"364":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ زُرَارَةَ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ قَالَ قَالَتْ أُمُّ عَطِيَّةَكُنَّا لَا نَعُدُّ الصُّفْرَةَ وَالْكُدْرَةَ شَيْئًا","id":"Telah mengabarkan kepada kami [Amr bin Zurarah] dia berkata; Telah memberitakan kepada kami [Ismail] dari [Ayyub] dari [Muhammad] dia berkata; \" [Ummu Athiyyah] berkata; 'Kita tidak menganggap (darah) yang kekuning-kuningan dan (darah) yang kehitam-hitaman (sebagai darah haidl).\""},"365":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَكَانَتْ الْيَهُودُ إِذَا حَاضَتْ الْمَرْأَةُ مِنْهُمْ لَمْ يُؤَاكِلُوهُنَّ وَلَا يُشَارِبُوهُنَّ وَلَا يُجَامِعُوهُنَّ فِي الْبُيُوتِ فَسَأَلُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ قُلْ هُوَ أَذًى }الْآيَةَ فَأَمَرَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُؤَاكِلُوهُنَّ وَيُشَارِبُوهُنَّ وَيُجَامِعُوهُنَّ فِي الْبُيُوتِ وَأَنْ يَصْنَعُوا بِهِنَّ كُلَّ شَيْءٍ مَا خَلَا الْجِمَاعَ فَقَالَتْ الْيَهُودُ مَا يَدَعُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا مِنْ أَمْرِنَا إِلَّا خَالَفَنَا فَقَامَ أُسَيْدُ بْنُ حُضَيْرٍ وَعَبَّادُ بْنُ بِشْرٍ فَأَخْبَرَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَا أَنُجَامِعُهُنَّ فِي الْمَحِيضِ فَتَمَعَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَمَعُّرًا شَدِيدًا حَتَّى ظَنَنَّا أَنَّهُ قَدْ غَضِبَ فَقَامَا فَاسْتَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَدِيَّةَ لَبَنٍ فَبَعَثَ فِي آثَارِهِمَا فَرَدَّهُمَا فَسَقَاهُمَا فَعُرِفَ أَنَّهُ لَمْ يَغْضَبْ عَلَيْهِمَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Sulaiman bin Harb] dia berkata; Telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] dia berkata; orang Yahudi bila istri mereka haidl, mereka tidak mengajak makan dan minum bersama, dan tidak berkumpul bersamanya di rumah. Mereka menanyakan hal itu kepada Nabi shallallahu 'alaihi wasallam, Lalu Allah Azza wa Jalla menurunkan ayat \"Mereka bertanya kepadamu tentang haidl. Katakanlah, 'Itu adalah penyakit…\" Lalu Rasulullah shallallahu 'alaihi wasallam memerintahkan mereka untuk ikut makan dan minum dengannya, berkumpul dengan mereka di rumah, serta berbuat apa saja selain bersetubuh. Perempuan Yahudi tersebut berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak membiarkan satu perkara pun yang ada pada kami kecuali dia menyelisihinya!\" Lalu bangkitlah Usaid bin Hudlair dan Abbad bin Bisyr untuk memberitahukannya kepada Rasulullah shallallahu 'alaihi wasallam, mereka berkata: \"Apakah kita boleh menggauli mereka (para istri) yang sedang haidl?\" Wajah Rasulullah shallallahu 'alaihi wasallam lalu berubah dengan perubahan yang mencolok, sehingga kami menyangka bahwa beliau sangat marah, lalu keduanya pergi. Kemudian Rasulullah shallallahu 'alaihi wasallam menerima hadiah susu, maka beliau mencari jejak kedua orang ini lalu keduanya dibawa kepada Nabi shallallahu 'alaihi wasallam dan beliau memberi minum susu kepada keduanya. Jadi diketahuilah bahwa beliau shallallahu 'alaihi wasallam tidak marah pada kedua orang ini. "},"366":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ قَالَ حَدَّثَنِي الْحَكَمُ عَنْ عَبْدِ الْحَمِيدِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الرَّجُلِ يَأْتِي امْرَأَتَهُ وَهِيَ حَائِضٌ يَتَصَدَّقُ بِدِينَارٍ أَوْ بِنِصْفِ دِينَارٍ","id":"Telah mengabarkan kepada kami [Amr bin Ali] dia berkata; Telah menceritakan kepada kami [Yahya] dari [Syu'bah] dia berkata; Telah menceritakan kepadaku [Al Hakam] dari [Abdul Hamid] dari [Miqsam] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda tentang seseorang laki-laki yang menggauli istrinya dalam keadaan haidl, \"Bersedekahlah dengan satu Dinar atau setengah Dinar.\""},"367":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ ح وَأَنْبَأَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي ح وَأَنْبَأَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ وَهُوَ ابْنُ الْحَارِثِ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ أَنَّ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ حَدَّثَتْهُ أَنَّ أُمَّ سَلَمَةَ حَدَّثَتْهَا قَالَتْبَيْنَمَا أَنَا مُضْطَجِعَةٌ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ حِضْتُ فَانْسَلَلْتُ فَأَخَذْتُ ثِيَابَ حَيْضَتِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَفِسْتِ قُلْتُ نَعَمْ فَدَعَانِي فَاضْطَجَعْتُ مَعَهُ فِي الْخَمِيلَةِوَاللَّفْظُ لِعُبَيْدِ اللَّهِ بْنِ سَعِيدٍ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] dia berkata; Telah menceritakan kepada kami [Mu'adz bin Hisyam] dan Telah memberitakan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Mu'adz bin Hisyam] dia berkata; Telah menceritakan kepadaku [Bapakku] dan Telah memberitakan kepada kami [Ismail bin Mas'ud] dia berkata; Telah menceritakan kepada kami [Khalid yaitu Ibnu Al Harits] dia berkata; Telah menceritakan kepada kami [Hisyam] dari [Yahya bin Abu Katsir] berkata; Telah menceritakan kepadaku [Abu Salamah] bahwa [Zainab binti Abu Salamah] berkata kepadanya; [Ummu Salamah] berkata kepadanya; \"Ketika aku sedang berbaring bersama Rasulullah shallallahu 'alaihi wasallam di dalam selimut, tiba-tiba aku mendapat haidl, maka akupun segera keluar perlahan-lahan kemudian mengambil pakaian (yang biasa dipakai saat) haidl. Rasulullah shallallahu 'alaihi wasallam bertanya, 'Apakah kamu sedang haidl? ' Aku menjawab, 'Ya'. Beliau lalu memanggilku dan tidur bersama dalam satu selimut.\" Lafazh ini dari Abdullah bin Sa'id. "},"368":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى عَنْ جَابِرِ بْنِ صُبْحٍ قَالَ سَمِعْتُ خِلَاسًا يُحَدِّثُ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبِيتُ فِي الشِّعَارِ الْوَاحِدِ وَأَنَا طَامِثٌ حَائِضٌ فَإِنْ أَصَابَهُ مِنِّي شَيْءٌ غَسَلَ مَكَانَهُ لَمْ يَعْدُهُ ثُمَّ صَلَّى فِيهِ ثُمَّ يَعُودُ فَإِنْ أَصَابَهُ مِنِّي شَيْءٌ فَعَلَ مِثْلَ ذَلِكَ غَسَلَ مَكَانَهُ لَمْ يَعْدُهُ وَصَلَّى فِيهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Mutsanna] dia berkata; Telah menceritakan kepada kami [Yahya] dari [Jabir bin Shubhi] dia berkata; Saya mendengar [Khilas] berkata; dari [Aisyah] Radliyallahu'anha berkata; \"Aku pernah tidur bersama Rasulullah shallallahu 'alaihi wasallam dalam satu selimut, sedang aku sedang haidl. Jika beliau terkena sesuatu dariku, maka beliau membasuh tempat yang terkena tadi dan tidak melebihinya, kemudian beliau shalat dengan selimut tadi, dan beliau kembali lagi. Jika beliau terkena sesuatu dariku, maka dia melakukan seperti tadi dan tidak melebihinya, lalu shalat dengan selimut tersebut.\" "},"369":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُ إِحْدَانَا إِذَا كَانَتْ حَائِضًا أَنْ تَشُدَّ إِزَارَهَا ثُمَّ يُبَاشِرُهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Abu Ahwash] dari [Abu Ishaq] dari [Amr bin Surahbil] dari [Aisyah] Radliyallahu'anha dia berkata; bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan salah satu dari kami yang sedang haidl mengikat kainnya, kemudian beliau mempergaulinya (selain hubungan intim). "},"370":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكَانَتْ إِحْدَانَا إِذَا حَاضَتْ أَمَرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَتَّزِرَ ثُمَّ يُبَاشِرُهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] Radliyallahu'anha dia berkata; \"Salah satu dari kami sedang haidl, maka Rasulullah shallallahu 'alaihi wasallam memerintahkannya untuk memakai kain, kemudian beliau mempergaulinya (selain hubungan intim).\" "},"371":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ ابْنِ عَيَّاشٍ وَهُوَ أَبُو بَكْرٍ عَنْ صَدَقَةَ بْنِ سَعِيدٍ ثُمَّ ذَكَرَ كَلِمَةً مَعْنَاهَا حَدَّثَنَا جُمَيْعُ بْنُ عُمَيْرٍ قَالَدَخَلْتُ عَلَى عَائِشَةَ مَعَ أُمِّي وَخَالَتِي فَسَأَلَتَاهَا كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ إِذَا حَاضَتْ إِحْدَاكُنَّ قَالَتْ كَانَ يَأْمُرُنَا إِذَا حَاضَتْ إِحْدَانَا أَنْ تَتَّزِرَ بِإِزَارٍ وَاسِعٍ ثُمَّ يَلْتَزِمُ صَدْرَهَا وَثَدْيَيْهَا","id":"Telah mengabarkan kepada kami [Hannad bin As-Sariy] dari [Ibnu Ayyas yaitu Abu Bakr] dari [Shadaqah bin Sa'id] kemudian dia menyebutkan satu kalimat yang maksudnya adalah Telah menceritakan kepada kami [Jumai' bin 'Umair] dia berkata; Saya, Ibuku dan bibiku menemui Aisyah maka Ibuku dan bibiku bertanya kepada Aisyah; \"Apa yang diperbuat oleh Rasulullah shallallahu 'alaihi wasallam kepada salah seorang diantara kalian -istri-istrinya- ketika sedang haidl? [Aisyah] menjawab; \"Jika di antara kami sedang haidl, maka beliau menyuruh salah seorang di antara kami -yang haidl- agar memakai kain yang longgar kemudian beliau menggauli dada dan kedua susunya."},"372":{"ar":"أَخْبَرَنَا الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ عَنْ يُونُسَ وَاللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ حَبِيبٍ مَوْلَى عُرْوَةَ عَنْ بُدَيَّةَ وَكَانَ اللَّيْثُ يَقُولُ نَدَبَةَ مَوْلَاةِ مَيْمُونَةَ عَنْ مَيْمُونَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُبَاشِرُ الْمَرْأَةَ مِنْ نِسَائِهِ وَهِيَ حَائِضٌ إِذَا كَانَ عَلَيْهَا إِزَارٌ يَبْلُغُ أَنْصَافَ الْفَخِذَيْنِ وَالرُّكْبَتَيْنِ فِي حَدِيثِ اللَّيْثِ تَحْتَجِزُ بِهِ","id":"Telah mengabarkan kepada kami [Al Harits bin Miskin] telah dibacakan kepadanya dan saya mendengarnya dari [Ibnu Wahab] dari [Yunus] dan [Al-Laits] dari [Ibnu Syihab] dari [Habib] -budak Urwah- dari [Budayyah] dan Al-Laits menyebutnya budak Maimunah yang fasih, dari [Maimunah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam mencumbui salah satu istrinya yang sedang haidl bila di atasnya ada kain yang sampai ke tengah-tengah kedua pahanya dan kedua lututnya, sebagai penghalang.\""},"373":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدِ بْنِ جَمِيلِ بْنِ طَرِيفٍ قَالَ أَنْبَأَنَا يَزِيدُ ابْنُ الْمِقْدَامِ بْنِ شُرَيْحِ بْنِ هَانِئٍ عَنْ أَبِيهِ شُرَيْحٍ أَنَّهُ سَأَلَ عَائِشَةَهَلْ تَأْكُلُ الْمَرْأَةُ مَعَ زَوْجِهَا وَهِيَ طَامِثٌ قَالَتْ نَعَمْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُونِي فَآكُلُ مَعَهُ وَأَنَا عَارِكٌ كَانَ يَأْخُذُ الْعَرْقَ فَيُقْسِمُ عَلَيَّ فِيهِ فَأَعْتَرِقُ مِنْهُ ثُمَّ أَضَعُهُ فَيَأْخُذُهُ فَيَعْتَرِقُ مِنْهُ وَيَضَعُ فَمَهُ حَيْثُ وَضَعْتُ فَمِي مِنْ الْعَرْقِ وَيَدْعُو بِالشَّرَابِ فَيُقْسِمُ عَلَيَّ فِيهِ مِنْ قَبْلِ أَنْ يَشْرَبَ مِنْهُ فَآخُذُهُ فَأَشْرَبُ مِنْهُ ثُمَّ أَضَعُهُ فَيَأْخُذُهُ فَيَشْرَبُ مِنْهُ وَيَضَعُ فَمَهُ حَيْثُ وَضَعْتُ فَمِي مِنْ الْقَدَحِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id bin Jamil bin Tharif] dia berkata; Telah memberitakan kepada kami; [Yazid bin Miqdam bin Syuraih bin Hani] dari Bapaknya - [Syuraih] - bahwa dia pernah bertanya kepada [Aisyah] Radliyallahu'anha 'Apakah perempuan boleh makan bersama suaminya jika dia sedang haidl? ' Dia (Aisyah) berkata, 'Ya, boleh. Rasulullah shallallahu 'alaihi wasallam pernah memanggilku, lalu aku makan bersama beliau, padahal aku sedang haidl. Beliau shallallahu 'alaihi wasallam mengambil daging, kemudian membaginya kepadaku, dan aku segera memakannya. Kemudian aku menaruhnya, lalu Rasulullah shallallahu 'alaihi wasallam mengambil dan memakannya. Beliau meletakkan mulutnya pada daging di tempat aku meletakkan mulutku tadi. Lalu beliau meminta air minum dan membaginya kepadaku, sebelum beliau meminumnya, maka aku mengambil dan meminumnya, lalu meletakkannya. Kemudian beliau mengambilnya dan meminumnya, dan beliau meletakkan mulutnya ditempat aku meletakkan mulutku di gelas tadi.\" "},"374":{"ar":"أَخْبَرَنِي أَيُّوبُ بْنُ مُحَمَّدٍ الْوَزَّانُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ الْأَعْمَشِ عَنْ الْمِقْدَامِ بْنِ شُرَيْحٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضَعُ فَاهُ عَلَى الْمَوْضِعِ الَّذِي أَشْرَبُ مِنْهُ وَيَشْرَبُ مِنْ فَضْلِ شَرَابِي وَأَنَا حَائِضٌ","id":"Telah mengabarkan kepada kami [Ayyub bin Muhammad Al Wazzan] dia berkata; Telah menceritakan kepada kami [Abdullah bin Ja'far] dia berkata; [Ubaidullah bin Amr] dari [Al A'masy] dari [Miqdam bin Syuraih] dari [Bapaknya] dari [Aisyah] Radliyallahu'anha dia berkata; \"Rasulullah shallallahu 'alaihi wasallam meletakkan mulutnya di tempat aku meminumnya, dan beliau meminum sisa minumku, padahal aku sedang haidl.\""},"375":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مِسْعَرٍ عَنْ الْمِقْدَامِ بْنِ شُرَيْحٍ عَنْ أَبِيهِ قَالَ سَمِعْتُ عَائِشَةَ تَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنَاوِلُنِي الْإِنَاءَ فَأَشْرَبُ مِنْهُ وَأَنَا حَائِضٌ ثُمَّ أُعْطِيهِ فَيَتَحَرَّى مَوْضِعَ فَمِي فَيَضَعُهُ عَلَى فِيهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Mis'ar] dari [Miqdam bin Suraih] dari [Bapaknya] dia berkata; Saya mendengar [Aisyah] Radliyallahu'anha berkata; \"Rasulullah shallallahu 'alaihi wasallam memberi gelas kepadaku, lalu aku minum darinya, sementara aku sedang haidl. Kemudian aku berikan kepadanya -gelas itu- maka beliau mencari bekas tempat mulutku, lalu meletakkan mulutnya di situ.\""},"376":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا مِسْعَرٌ وَسُفْيَانُ عَنْ الْمِقْدَامِ بْنِ شُرَيْحٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَشْرَبُ مِنْ الْقَدَحِ وَأَنَا حَائِضٌ فَأُنَاوِلُهُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَضَعُ فَاهُ عَلَى مَوْضِعِ فِيَّ فَيَشْرَبُ مِنْهُ وَأَتَعَرَّقُ مِنْ الْعَرْقِ وَأَنَا حَائِضٌ فَأُنَاوِلَهُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَضَعُ فَاهُ عَلَى مَوْضِعِ فِيَّ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] dia berkata; telah menceritakan kepada kami [Waki'] dia berkata; telah menceritakan kepada kami [Mis'ar] dan [Syufyan] dari [Al-Miqdam bin syuraih] dari [bapaknya] dari [Aisyah] Radliyallahu'anha dia berkata, \"Aku pernah minum dari sebuah gelas, sementara aku sedang haidl. Lalu aku berikan gelas itu kepada Nabi shallallahu 'alaihi wasallam, maka beliau meletakkan mulutnya di tempat bekas mulutku, lalu meminumnya. Aku juga pernah menggigit sepotong daging saat sedang haidl, lalu daging itu aku berikan kepada Nabi shallallahu 'alaihi wasallam, maka beliau meletakkan mulutnya di tempat bekas mulutku tadi.\" "},"377":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَلِيُّ بْنُ حُجْرٍ وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ أُمِّهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَأْسُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حِجْرِ إِحْدَانَا وَهِيَ حَائِضٌ وَهُوَ يَقْرَأُ الْقُرْآنَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dan [Ali bin Hujr] lafazhnya dari dia, keduanya berkata; telah menceritakan kepada kami [Syufyan] dari [Manshur] dari [ibunya] dari [Aisyah] Radliyallahu'anha dia berkata; \"Kepala Rasulullah shallallahu 'alaihi wasallam di pangkuan salah satu dari kami (istri-istri Nabi) yang sedang haidl, sementara beliau membaca Al Qur'an.\""},"378":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ زُرَارَةَ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَ��ْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ مُعَاذَةَ الْعَدَوِيَّةِ قَالَتْسَأَلَتْ امْرَأَةٌ عَائِشَةَ أَتَقْضِي الْحَائِضُ الصَّلَاةَ فَقَالَتْ أَحَرُورِيَّةٌ أَنْتِ قَدْ كُنَّا نَحِيضُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا نَقْضِي وَلَا نُؤْمَرُ بِقَضَاءٍ","id":"Telah mengabarkan kepada kami [Amr bin Zurarah] dia berkata; telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari [Abu Qilabah] dari [Mu'adzah Al 'Adawiyah] dari dia berkata; \"Seorang perempuan bertanya kepada [Aisyah], 'Apakah orang haidl harus mengqadla shalat? ' dia menjawab, 'Apakah kamu orang Haruriyah? Kita dahulu mengalami haidl pada zaman Rasulullah shallallahu 'alaihi wasallam, dan kita tidak mengqadlanya, dan juga tidak disuruh mengqadlanya.\" "},"379":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ يَزِيدَ ابْنِ كَيْسَانَ قَالَ حَدَّثَنِي أَبُو حَازِمٍ قَالَ قَالَ أَبُو هُرَيْرَةَبَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ إِذْ قَالَ يَا عَائِشَةُ نَاوِلِينِي الثَّوْبَ فَقَالَتْ إِنِّي لَا أُصَلِّي فَقَالَ إِنَّهُ لَيْسَ فِي يَدِكِ فَنَاوَلَتْهُ","id":"Telah mengabarkan kepada kami [Muhammad Al-Mutsana] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Yazid bin Kaisan] dia berkata; telah menceritakan kepadaku [Abu Hazim] dia berkata; [Abu Hurairah] berkata; \"Tatkala Rasulullah shallallahu 'alaihi wasallam berada di masjid, tiba-tiba beliau bersabda; 'Wahai Aisyah, ambilkan baju'. Aisyah menjawab, 'Aku sedang tidak suci'. Beliau bersabda, 'Haidl itu tidak di tanganmu'. Lalu dia pun mengambilkannya.\""},"380":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ عَبِيدَةَ عَنْ الْأَعْمَشِ ح و أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ ثَابِتِ بْنِ عُبَيْدٍ عَنْ الْقَاسِمِ ابْنِ مُحَمَّدٍ قَالَ قَالَتْ عَائِشَةُقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاوِلِينِي الْخُمْرَةَ مِنْ الْمَسْجِدِ فَقُلْتُ إِنِّي حَائِضٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَتْ حَيْضَتُكِ فِي يَدِكِقَالَ إِسْحَقُ أَنْبَأَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari ['Abidah] dari [Al-A'masy] dan dalam jalur periwayatan yang lain disebutkan; telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] dari [Al A'masy] dari [Tsabit bin Ubaid] dari [Al Qasim bin Muhammad] dia berkata; [Aisyah] Radliyallahu'anha berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ambilkan tikar kecil dari masjid'. Aisyah berkata, 'Aku sedang haidl'. Rasulullah shallallahu 'alaihi wasallam bersabda: 'Haidlmu itu bukan di tanganmu.\" Ishaq mengatakan; [Abu Mu'awiyah] telah memberitakan kepada kami dari A'masy dengan isnad ini semisalnya. "},"381":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ عَنْ سُفْيَانَ عَنْ مَنْبُوذٍ عَنْ أُمِّهِ أَنَّ مَيْمُونَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضَعُ رَأْسَهُ فِي حِجْرِ إِحْدَانَا فَيَتْلُو الْقُرْآنَ وَهِيَ حَائِضٌ وَتَقُومُ إِحْدَانَا بِخُمْرَتِهِ إِلَى الْمَسْجِدِ فَتَبْسُطُهَا وَهِيَ حَائِضٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dari [Syufyan] dari [Manbudz] dari [Ibunya] bahwasanya [Maimunah] berkata; \"Rasulullah shallallahu 'alaihi wasallam meletakkan kepalanya di pangkuan salah seorang dari kami (istri-istri Nabi shallallahu 'alaihi wasallam), dan beliau membaca Al Qur'an, sedangkan ia sedang haidl. Salah seorang dari kami (istri-istri Nabi shallallahu 'alaihi wasallam) bangkit menggelar untuk tikar di masjid, padahal ia sedang haidl.\" "},"382":{"ar":"أَخْبَرَنَا نَصْرُ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّهَا كَانَتْ تُرَجِّلُ رَأْسَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ حَائِضٌ وَهُوَ مُعْتَكِفٌ فَيُنَاوِلُهَا رَأْسَهُ وَهِيَ فِي حُجْرَتِهَا","id":"Telah mengabarkan kepada kami [Nashr bin Ali] dia berkata; Telah menceritakan kepada kami [Abdul A'la] dia berkata; Telah menceritakan kepada kami [Ma'mar] dari [Az-Zuhri] dari [Urwah] dari [Aisyah] Radliyallahu'anha bahwa ia pernah menyisir rambut Rasulullah shallallahu 'alaihi wasallam, padahal ia sedang haidl, sementara Rasulullah shallallahu 'alaihi wasallam sedang i'tikaf, maka Rasulullah shallallahu 'alaihi wasallam memberikan (menyodorkan) kepalanya sementara ia berada di kamarnya. "},"383":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنِي سُفْيَانُ قَالَ حَدَّثَنِي مَنْصُورٌ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُدْنِي إِلَيَّ رَأْسَهُ وَهُوَ مُعْتَكِفٌ فَأَغْسِلُهُ وَأَنَا حَائِضٌ","id":"Telah mengabarkan kepada kami [Amru bin Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepadaku [Syufyan] dia berkata; telah menceritakan kepadaku [Manshur] dari [Ibrahim] dari [Al-Aswad] dari [Aisyah] Radliyallahu'anha dia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mendekatkan kepalanya kepadaku, padahal ia sedang i'tikaf di masjid, maka aku membasuhnya sedangkan aku dalam keadaan haidl.\" "},"384":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا الْفُضَيْلُ وَهُوَ ابْنُ عِيَاضٍ عَنْ الْأَعْمَشِ عَنْ تَمِيمِ بْنِ سَلَمَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُخْرِجُ رَأْسَهُ مِنْ الْمَسْجِدِ وَهُوَ مُعْتَكِفٌ فَأَغْسِلُهُ وَأَنَا حَائِضٌ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Al-fudhail yaitu Ibnu Iyadl] dari dia berkata; [Al-A'masy] dari [Tamim bin Salamah] dari [Urwah] dari [Aisyah] Radliyallahu'anha dia berkata: \"Rasulullah shallallahu 'alaihi wasallam pernah mengeluarkan kepalanya kepadaku, dan beliau sedang I'tikaf di masjid, maka aku membasuhnya, sedangkan aku sedang haidl.\""},"385":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكُنْتُ أُرَجِّلُ رَأْسَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا حَائِضٌ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah], dia berkata: \"Aku pernah menyisir rambut Rasulullah shallallahu 'alaihi wasallam, padahal aku sedang haidl.\""},"386":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ زُرَارَةَ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ حَفْصَةَ قَالَتْكَانَتْ أُمُّ عَطِيَّةَ لَا تَذْكُرُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا قَالَتْ بِأَبَا فَقُلْتُ أَسَمِعْتِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كَذَا وَكَذَا قَالَتْ نَعَمْ بِأَبَا قَالَ لِتَخْرُجْ الْعَوَاتِقُ وَذَوَاتُ الْخُدُورِ وَالْحُيَّضُ فَيَشْهَدْنَ الْخَيْرَ وَدَعْوَةَ الْمُسْلِمِينَ وَتَعْتَزِلْ الْحُيَّضُ الْمُصَلَّى","id":"Telah mengabarkan kepada kami [Amr bin Zurarah] dia berkata; telah memberitakan kepada kami [Ismail] dari [Ayub] dari [Hafshah] dia berkata; \" [Ummu Athiyyah] berkata kepada Rasulullah shallallahu 'alaihi wasallam, 'Ayahku menjadi jaminanku'. Aku berkata, 'Apakah kamu mendengar Rasulullah shallallahu 'alaihi wasallam bersabda begini dan begitu? ' Ia menjawab, 'Ya, ayahku menjadi jaminanku. Beliau shallallahu 'alaihi wasallam bersabda, \"Hendaklah para budak dan gadis-gadis pingitan, serta perempuan-perempuan yang sedang haidl keluar untuk menyaksikan kebaikan dan dakwah kaum muslimin. Perempuan-perempuan yang sedang haidl hendaknya menjauh dari tempat shalat.\" "},"387":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْقَاسِمِ قَالَ أَخْبَرَنِي مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ عَنْ عَمْرَةَ عَنْ عَائِشَةَأَنَّهَا قَالَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ صَفِيَّةَ بِنْتَ حُيَيٍّ قَدْ حَاضَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلَّهَا تَحْبِسُنَا أَلَمْ تَكُنْ طَافَتْ مَعَكُنَّ بِالْبَيْتِ قَالَتْ بَلَى قَالَ فَاخْرُجْنَ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; Telah menceritakan kepada kami [Abdurrahman bin Al Qasim] dia berkata; Telah mengabarkan kepadaku [Malik] dari [Abdullah bin Abu Bakar] dari [Bapaknya] dari ['Amrah] dari [Aisyah] Radliyallahu'anha, dia berkata kepada Rasulullah shallallahu 'alaihi wasallam bahwa Shafiyyah binti Huyay telah haidl. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangkalikah dia membuat kita tertahan? Bukankah dia sudah thawaf di Ka'bah bersama kalian?\" Aisyah berkata, \"Ya\" Rasulullah shallallahu 'alaihi wasallam bersabda, \"Keluarlah kalian.\""},"388":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِفِي حَدِيثِ أَسْمَاءَ بِنْتِ عُمَيْسٍ حِينَ نُفِسَتْ بِذِي الْحُلَيْفَةِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَبِي بَكْرٍ مُرْهَا أَنْ تَغْتَسِلَ وَتُهِلَّ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dia berkata; telah menceritakan kepada kami [Jarir] dari [Yahya bin Sa'id] dari [Ja'far bin Muhammad] dari [Bapaknya] dari [Jabir bin Abdullah] dalam hadis Asma' binti Umais ketika dia nifas (haidl) di Dzul Hulaifah, bahwa Rasulullah shallallahu 'alaihi wasallam pernah berkata kepada Abu Bakar, \"Suruh dia mandi lalu berihram.\""},"389":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ عَبْدِ الْوَارِثِ عَنْ حُسَيْنٍ يَعْنِي الْمُعَلِّمَ عَنْ ابْنِ بُرَيْدَةَ عَنْ سَمُرَةَ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أُمِّ كَعْبٍ مَاتَتْ فِي نِفَاسِهَا فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّلَاةِ فِي وَسَطِهَا","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dari [Abdul Warits] dari [Husain yaitu Al-Mu'allim] dari [Ibnu Buraidah] dari [Samurah] dia berkata; \"Aku shalat (jenazah) bersama Rasulullah shallallahu 'alaihi wasallam atas mayit Ummu Ka'ab -yang meninggal dunia dalam keadaan nifas (haidl) - maka Rasulullah shallallahu 'alaihi wasallam berdiri shalat (menghadap) di tengah-tengahnya.\" "},"390":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ فَاطِمَةَ بِنْتِ الْمُنْذِرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ وَكَانَتْ تَكُونُ فِي حَجْرِهَاأَنَّ امْرَأَةً اسْتَفْتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ دَمِ الْحَيْضِ يُصِيبُ الثَّوْبَ فَقَالَ حُتِّيهِ وَاقْرُصِيهِ وَانْضَحِيهِ وَصَلِّي فِيهِ","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin 'Arabi] dia berkata; telah menceritakan kepada kami [Hamad] dari [Hisyam bin Urwah] dari [Fathimah binti Mundzir] dari [Asma' binti Abu Bakar] -dan dia berada di kamarnya- bahwa ada seorang perempuan meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam tentang darah haidl yang mengenai pakaian, Beliau bersabda: \"Gosoklah dengan ujung jari, kemudian cucilah dengan air. Lalu shalatlah dengan kain tersebut.\" "},"391":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي أَبُو الْمِقْدَامِ ثَابِتٌ الْحَدَّادُ عَنْ عَدِيِّ بْنِ دِينَارٍ قَالَ سَمِعْتُ أُمَّ قَيْسٍ بِنْتَ مِحْصَنٍأَنَّهَا سَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ دَمِ الْحَيْضَةِ يُصِيبُ الثَّوْبَ قَالَ حُكِّيهِ بِضِلَعٍ وَاغْسِلِيهِ بِمَاءٍ وَسِدْرٍ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya] dari [Syufyan] dia berkata; telah menceritakan kepadaku [Abu Miqdam Tsabit Al-Haddad] dari [Adi bin Dinar] dia berkata; saya mendengar [Ummu Qais bin Mihshan], bahwa dia pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang darah haidl yang mengenai pakaian, Maka beliau menjawab.\"Gosoklah dengan kayu, lalu cuci dengan air dan sidr (daun Bidara).\""},"392":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ أَنَّ أَبَا السَّائِبِ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَغْتَسِلْ أَحَدُكُمْ فِي الْمَاءِ الدَّائِمِ وَهُوَ جُنُبٌ","id":"Telah mengabarkan kepada kami [Sulaiman bin daud] dan [Harits bin Miskin] telah dibacakan kepadanya dan saya mendengar dari [Ibnu Wahab] dari [Amr bin Harits] dari [Bukair bin Al-Asyaj] bahwasanya [Abu Sa'ib] berkata kepadanya, dia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda; \"Janganlah salah seorang dari kalian mandi junub pada air yang diam (menggenang).\" "},"393":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ حَدَّثَنَا حِبَّانُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ مَعْمَرٍ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَبُولَنَّ الرَّجُلُ فِي الْمَاءِ الدَّائِمِ ثُمَّ يَغْتَسِلُ مِنْهُ أَوْ يَتَوَضَّأُ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] dia berkata; telah menceritakan kepada kami [Hibban] dia berkata; telah menceritakan kepada kami [Abdullah] dari [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Janganlah kalian sekali-kali buang air kecil pada air yang menggenang, kemudian mandi atau wudlu dari air itu.\" "},"394":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ صَالِحٍ الْبَغْدَادِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ مُحَمَّدٍ قَالَ حَدَّثَنِي ابْنُ عَجْلَانَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُبَالَ فِي الْمَاءِ الدَّائِمِ ثُمَّ يُغْتَسَلَ فِيهِ مِنْ الْجَنَابَةِ","id":"Telah mengabarkan kepada kami [Ahmad bin Shalih Al-bagdadi] dia berkata; telah menceritakan kepada kami [Yahya bin Muhammad] dia berkata; telah menceritakan kepada kami [Ibnu Ajlan] dari [Abu Zinad] dari [Al-A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam melarang kencing di air yang menggenang kemudian mandi junub di sana. "},"395":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ سُفْيَانَ عَنْ أَبِي الزِّنَادِ عَنْ مُوسَى بْنِ أَبِي عُثْمَانَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُبَالَ فِي الْمَاءِ الرَّاكِدِ ثُمَّ يُغْتَسَلَ مِنْهُ","id":"Telah mengabarkan kepada kami [Muhamad bin Abdullah bin Yazid] dari [Syufyan] dari [Abu Zinad] dari [Musa bin Abu Utsman] dari [Bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam melarang kencing di air yang menggenang kemudian mandi junub di air itu. "},"396":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَلَا يَبُولَنَّ أَحَدُكُمْ فِي الْمَاءِ الدَّائِمِ الَّذِي لَا يَجْرِي ثُمَّ يَغْتَسِلُ مِنْهُقَالَ سُفْيَانُ قَالُوا لِهِشَامٍ يَعْنِي ابْنَ حَسَّانَ إِنَّ أَيُّوبَ إِنَّمَا يَنْتَهِي بِهَذَا الْحَدِيثِ إِلَى أَبِي هُرَيْرَةَ فَقَالَ إِنَّ أَيُّوبَ لَوْ اسْتَطَاعَ أَنْ لَا يَرْفَعَ حَدِيثًا لَمْ يَرْفَعْهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Ayyub] dari [Ibnu Sirin] dari [Abu Hurairah] mengatakan; \"Janganlah salah seorang kalian kencing di air menggenang, tidak mengalir, kemudian mandi di sana.\" Sufyan mengatakan; mereka mengatakan kepada Hasyim yakni Ibnu Hasan, bahwa Ayyub membawakan hadits ini hingga Abu Hurairah. Lalu ia mengatakan; Ayyub sekiranya bisa untuk tidak memarfu'kan hadits, maka ia tidak memarfu'kannya. "},"397":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ عَطَاءٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلَا يَدْخُلْ الْحَمَّامَ إِلَّا بِمِئْزَرٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Mu'adz bin Hisyam] dia berkata; Telah menceritakan kepadaku [Bapakku] dari ['Atha'] dari [Abu Zubair] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa beriman kepada Allah dan hari akhir, janganlah masuk kamar mandi kecuali memakai kain (menutup auratnya).\" "},"398":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَجْزَأَةَ بْنِ زَاهِرٍ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَدْعُو اللَّهُمَّ طَهِّرْنِي مِنْ الذُّنُوبِ وَالْخَطَايَا اللَّهُمَّ نَقِّنِي مِنْهَا كَمَا يُنَقَّى الثَّوْبُ الْأَبْيَضُ مِنْ الدَّنَسِ اللَّهُمَّ طَهِّرْنِي بِالثَّلْجِ وَالْبَرَدِ وَالْمَاءِ الْبَارِدِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ibrahim] dia berkata; telah menceritakan kepada kami [Bisyir bin Mufadlal] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Majza'ah bin Zahir] bahwasanya dia mendengar [Abdullah bin Abu Aufa] berkata; dari Nabi shallallahu 'alaihi wasallam bahwa beliau pernah berdoa, \"Ya Allah, sucikan aku dari segala dosa dan kesalahan. Ya Allah, bersihkanlah aku dari segala dosa dan kesalahan sebagaimana engkau membersihkan baju putih dari kotoran. Ya Allah, sucikan aku dengan salju, air embun, dan air dingin.\""},"399":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ مُحَمَّدٍ حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ يَزِيدَ عَنْ رُقْبَةَ عَنْ مَجْزَأَةَ الْأَسْلَمِيِّ عَنْ ابْنِ أَبِي أَوْفَى قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ طَهِّرْنِي بِالثَّلْجِ وَالْبَرَدِ وَالْمَاءِ الْبَارِدِ اللَّهُمَّ طَهِّرْنِي مِنْ الذُّنُوبِ كَمَا يُطَهَّرُ الثَّوْبُ الْأَبْيَضُ مِنْ الدَّنَسِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya bin Muhammad] telah menceritakan kepada kami [Muhammad bin Musa] dia berkata; telah menceritakan kepada kami [Ibrahim bin Yazid] dari [Ruqbah] dari [Majza'ah Al-Aslamy] dari [Ibnu Abu Aufa] dia berkata; bahwa Nabi shallallahu 'alaihi wasallam berdoa, \"Ya Allah, sucikan aku dengan air salju, air embun dan air dingin. Ya Allah, sucikan aku dari segala dosa dan kesalahan sebagaimana engkau mensucikan (membersihkan) baju putih dari kotoran.\""},"400":{"ar":"أَخْبَرَنَا شُعَيْبُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَيْسٍ قَالَسَأَلْتُ عَائِشَةَ كَيْفَ كَانَ نَوْمُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْجَنَابَةِ أَيَغْتَسِلُ قَبْلَ أَنْ يَنَامَ أَوْ يَنَامُ قَبْلَ أَنْ يَغْتَسِلَ قَالَتْ كُلُّ ذَلِكَ قَدْ كَانَ يَفْعَلُ رُبَّمَا اغْتَسَلَ فَنَامَ وَرُبَّمَا تَوَضَّأَ فَنَامَ","id":"Telah mengabarkan kepada kami [Syu'aib bin Yusuf] dia berkata; Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Mu'awiyah bin Shalih] dari [Abdullah bin Abu Qais] dia berkata; \"Aku bertanya kepada [Aisyah] bagaimana Rasulullah shallallahu 'alaihi wasallam. tidur dalam keadaan junub? Apakah beliau mandi sebelum tidur? Atau tidur sebelum mandi? ' Aisyah menjawab, 'Semua pernah dilakukan oleh Rasulullah shallallahu 'alaihi wasallam.. Kadang beliau mandi dahulu lantas tidur, dan kadang (hanya) wudlu lalu tidur.\""},"401":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ بُرْدٍ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ غُضَيْفِ بْنِ الْحَارِثِ قَالَدَخَلْتُ عَلَى عَائِشَةَ فَسَأَلْتُهَا فَقُلْتُ أَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْتَسِلُ مِنْ أَوَّلِ اللَّيْلِ أَوْ مِنْ آخِرِهِ قَالَتْ كُلُّ ذَلِكَ كَانَ رُبَّمَا اغْتَسَلَ مِنْ أَوَّلِهِ وَرُبَّمَا اغْتَسَلَ مِنْ آخِرِهِ قُلْتُ الْحَمْدُ لِلَّهِ الَّذِي جَعَلَ فِي الْأَمْرِ سَعَةً","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin Arabi] dia berkata; Telah menceritakan kepada kami [Hammad] dari [Burd] dari ['Ubadah bin Nusay] dari [Ghudlaif bin Al Harits] dia berkata, \"Aku datang kepada Aisyah Radliyallahu'anha dan bertanya kepadanya, 'Apakah Rasulullah shallallahu 'alaihi wasallam. mandi pada permulaan malam atau akhirnya? ' [Aisyah] menjawab, 'Semua waktu pernah dilakukan. Kadang beliau mandi pada permulaan malam, dan kadang mandi pada akhir malam'. Aku berkata, 'Segala puji bagi Allah yang telah menjadikan kelonggaran pada masalah ini.\""},"402":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا النُّفَيْلِيُّ قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ عَنْ يَعْلَىأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يَغْتَسِلُ بِالْبَرَازِ فَصَعِدَ الْمِنْبَرَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَقَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ حَلِيمٌ حَيِيٌّ سِتِّيرٌ يُحِبُّ الْحَيَاءَ وَالسَّتْرَ فَإِذَا اغْتَسَلَ أَحَدُكُمْ فَلْيَسْتَتِرْ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub] dia berkata; Telah menceritakan kepada kami [An-Nufaily] dia berkata; Telah menceritakan kepada kami [Zuhair] dia berkata; Telah menceritakan kepada kami [Abdul Malik] berkata; dari ['Atha'] dari [Ya'la] bahwa Rasulullah shallallahu 'alaihi wasallam. melihat seorang laki-laki sedang mandi di tanah lapang, maka beliau naik ke atas mimbar lalu memuji Allah, kemudian bersabda: \"Allah Azza wa Jalla Maha Murah Hati, Maha Malu, dan Maha Tertutup. Dan cinta terhadap rasa malu dan tertutup. Apabila salah seorang dari kalian mandi, hendaklah memasang penutup.\""},"403":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ إِسْحَقَ قَالَ حَدَّثَنَا الْأَسْوَدُ بْنُ عَامِرٍ قَالَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ عَنْ عَطَاءٍ عَنْ صَفْوَانَ بْنِ يَعْلَى عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ عَزَّ وَجَلَّ سِتِّيرٌ فَإِذَا أَرَادَ أَحَدُكُمْ أَنْ يَغْتَسِلَ فَلْيَتَوَارَ بِشَيْءٍ","id":"Telah mengabarkan kepada kami [Abu Bakr bin Ishaq] dia berkata; Telah menceritakan kepada kami [Al Aswad bin Amir] dia berkata; Telah menceritakan kepada kami [Abu Bakar bin Ayyas] dari [Abdul Malik bin Sulaiman] dari [Atha'] dari [Shafwan bin Ya'la] dari [Bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam. bersabda: \"Allah Azza wa Jalla Maha Tertutup. Jika salah seorang dari kalian mandi, maka buatlah penutup dengan suatu penghalang.\""},"404":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبِيدَةُ عَنْ الْأَعْمَشِ عَنْ سَالِمٍ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ قَالَتْوَضَعْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاءً قَالَتْ فَسَتَرْتُهُ فَذَكَرَتْ الْغُسْلَ قَالَتْ ثُمَّ أَتَيْتُهُ بِخِرْقَةٍ فَلَمْ يُرِدْهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami ['Abidah] dari [Al A'masy] dari [Salim] dari [Kuraib] dari [Ibnu Abbas] dari [Maimunah] dia berkata; \"Aku menaruh air untuk Rasulullah shallallahu 'alaihi wasallam, kemudian aku menutupinya.\" Kemudian Maimunah berkata; \" Rasulullah shallallahu 'alaihi wasallam mandi\". Ia melanjutkan ceritanya, \"Kemudian aku membawakan handuk, namun beliau tidak menginginkannya.\" "},"405":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَفْصِ بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ عَطَاءِ ابْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَمَا أَيُّوبُ عَلَيْهِ السَّلَام يَغْتَسِلُ عُرْيَانًا خَرَّ عَلَيْهِ جَرَادٌ مِنْ ذَهَبٍ فَجَعَلَ يَحْثِي فِي ثَوْبِهِ قَالَ فَنَادَاهُ رَبُّهُ عَزَّ وَجَلَّ يَا أَيُّوبُ أَلَمْ أَكُنْ أَغْنَيْتُكَ قَالَ بَلَى يَا رَبِّ وَلَكِنْ لَا غِنَى بِي عَنْ بَرَكَاتِكَ","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh bin Abdullah] dia berkata; Telah menceritakan kepadaku [Bapakku] Telah menceritakan kepadaku [Ibrahim] dari [Musa bin 'Uqbah] dari [Shafwan bin Sulaim] dari ['Atha bin Yasar] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam. bersabda: \"Tatkala Nabi Ayyub 'alaihi salam mandi dengan telanjang, tiba-tiba ada seekor belalang emas hinggap. Lalu beliau menangkap belalang yang ada di bajunya dengan tangan. Kemudian Rabbnya -Azza wa Jalla- menyerunya, 'Wahai Ayyub, bukankah Aku sudah membuatmu kaya? ' Ayyub menjawab, 'Ya, wahai Tuhanku tetapi aku masih butuh keberkahan-Mu.\""},"406":{"ar":"أَخْبَرَنَا الْقَاسِمُ بْنُ زَكَرِيَّا بْنِ دِينَارٍ قَالَ حَدَّثَنِي إِسْحَقُ بْنُ مَنْصُورٍ عَنْ إِبْرَاهِيمَ بْنِ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْتَسِلُ فِي الْإِنَاءِ وَهُوَ الْفَرَقُ وَكُنْتُ أَغْتَسِلُ أَنَا وَهُوَ مِنْ إِنَاءٍ وَاحِدٍ","id":"Telah mengabarkan kepada kami [Al Qasim bin Jakaria bin Dinar] dia berkata; Telah menceritakan kepadaku [Ishaq bin Manshur] dari [Ibrahim bin Sa'ad] dari [Az-Zuhri] dari [Al Qasim bin Muhammad] dari [Aisyah] dia berkata; \" Rasulullah shallallahu 'alaihi wasallam. pernah mandi dalam sebuah bejana, yaitu Al Faraq, aku dan beliau mandi dari satu bejana. '"},"407":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ هِشَامٍ ح و أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَغْتَسِلُ وَأَنَا مِنْ إِنَاءٍ وَاحِدٍ نَغْتَرِفُ مِنْهُ جَمِيعًا وَقَالَ سُوَيْدٌ قَالَتْ كُنْتُ أَنَا","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah menceritakan kepada kami [Abdullah] dari [Hisyam] dan Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah] dia berkata; \" Rasulullah shallallahu 'alaihi wasallam. mandi bersamaku dari satu bejana. Kami menyiduk air dari bejana tersebut bersama-sama.\" Suwaid berkata dengan redaksi; Aisyah berkata; \"Dahulu saya pernah -dan selanjutnya-\""},"408":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ الْقَاسِمِ قَالَ سَمِعْتُ الْقَاسِمَ يُحَدِّثُ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَغْتَسِلُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ مِنْ الْجَنَابَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; Telah menceritakan kepada kami [Khalid] dia berkata; Telah menceritakan kepada kami [Syu'bah] dia berkata; telah mengabarkan kepada kami [Abdurrahman bin Al Qashim] ia berkata; Aku mendengar [Al Qashim] bercerita dari [Aisyah] dia berkata; \"Aku dan Rasulullah shallallahu 'alaihi wasallam. mandi junub bersama-sama dari satu bejana.\""},"409":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبِيدَةُ بْنُ حُمَيْدٍ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْلَقَدْ رَأَيْتُنِي أُنَازِعُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْإِنَاءَ أَغْتَسِلُ أَنَا وَهُوَ مِنْهُ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; Telah menceritakan kepada kami ['Abidah bin Humaid] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] dia berkata; \"Aku mendapati diriku berebut bejana air bersama Rasulullah shallallahu 'alaihi wasallam. Aku dan beliau shallallahu 'alaihi wasallam. mandi dari bejana tersebut.\""},"410":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ عَنْ مُحَمَّدٍ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ ح و أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ عَاصِمٍ عَنْ مُعَاذَةَ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَغْتَسِلُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ أُبَادِرُهُ وَيُبَادِرُنِي حَتَّى يَقُولَ دَعِي لِي وَأَقُولَ أَنَا دَعْ لِيقَالَ سُوَيْدٌ يُبَادِرُنِي وَأُبَادِرُهُ فَأَقُولُ دَعْ لِي دَعْ لِي","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dari [Muhammad] Telah menceritakan kepada kami [Syu'bah] dari ['Ashim] dan Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah memberitakan kepada kami [Abdullah] dari ['Ashim] dari [Mu'adzah] dari [Aisyah] dia berkata; \"Aku dulu mandi bersama Rasulullah shallallahu 'alaihi wasallam dari satu bejana. Ia mendahuluiku dan akupun mendahului beliau, hingga beliau berkata, \"Tinggalkan aku\". Aku juga berkata, \"Tinggalkan untukku.\" Suwaid berkata; \"Ia mendahuluiku dan akupun mendahului beliau, hingga Aku berkata, \"Tinggalkan untukku, tinggalkan untukku.\""},"411":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ مُحَمَّدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى بْنِ أَعْيَنَ قَالَ حَدَّثَنَا أَبِي عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ عَنْ عَطَاءٍ قَالَ حَدَّثَتْنِي أُمُّ هَانِئٍأَنَّهَا دَخَلَتْ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ وَهُوَ يَغْتَسِلُ قَدْ سَتَرَتْهُ بِثَوْبٍ دُونَهُ فِي قَصْعَةٍ فِيهَا أَثَرُ الْعَجِينِ قَالَتْ فَصَلَّى الضُّحَى فَمَا أَدْرِي كَمْ صَلَّى حِينَ قَضَى غُسْلَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya bin Muhammad] dia berkata; Telah menceritakan kepada kami [Muhammad bin Musa bin A'yan] dia berkata; Telah menceritakan kepada kami [Bapakku] dari [Abdul Malik bin Sulaiman] dari ['Atha] dia berkata; Telah menceritakan kepadaku [Ummu Hani'] bahwa dia menemui Nabi shallallahu 'alaihi wasallam saat Fathu (penaklukan) Makkah, dan beliau sedang mandi di baskom bekas adonan, sedangkan dia menutupinya dengan baju. Ia (Ummu Hani) berkata, \"Kemudian beliau shalat Dluha, dan aku tidak tahu berapa kali beliau shalat ketika selesai dari mandinya.\""},"412":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ إِبْرَاهِيمَ بْنِ طَهْمَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ أَنَّ عَائِشَةَ قَالَتْلَقَدْ رَأَيْتُنِي أَغْتَسِلُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ هَذَا فَإِذَا تَوْرٌ مَوْضُوعٌ مِثْلُ الصَّاعِ أَوْ دُونَهُ فَنَشْرَعُ فِيهِ جَمِيعًا فَأُفِيضُ عَلَى رَأْسِي بِيَدَيَّ ثَلَاثَ مَرَّاتٍ وَمَا أَنْقُضُ لِي شَعْرًا","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah memberitakan kepada kami [Abdullah] dari [Ibrahim bin Thamhan] dari [Abu Zubair] dari ['Ubaid bin Umair] bahwa [Aisyah] Radliyallahu'anha berkata, \"Aku pernah mandi bersama Rasulullah shallallahu 'alaihi wasallam. dari benda ini, yakni bejana kecil yang memuat satu sha' -atau kurang- lalu kami mulai mandi bersama-sama. Aku menyiram air ke kepala sebanyak tiga kali, dan aku tidak menguraikan rambutku.\" "},"413":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ وَكِيعٍ عَنْ مِسْعَرٍ وَسُفْيَانَ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ أَبِيهِ قَالَ سَمِعْتُ ابْنَ عُمَرَ يَقُولُلَأَنْ أُصْبِحَ مُطَّلِيًا بِقَطِرَانٍ أَحَبُّ إِلَيَّ مِنْ أَنْ أُصْبِحَ مُحْرِمًا أَنَضَخُ طِيبًا فَدَخَلْتُ عَلَى عَائِشَةَ فَأَخْبَرْتُهَا بِقَوْلِهِ فَقَالَتْ طَيَّبْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطَافَ عَلَى نِسَائِهِ ثُمَّ أَصْبَحَ مُحْرِمًا","id":"Telah mengabarkan kepada kami [Hannad bin As-Sari] dari [Waki'] dari [Mis'ar] dan [Sufyan] dari [Ibrahim bin Muhammad bin Al Muntasyir] dari [Bapaknya] dia berkata; Saya mendengar Ibnu Umar berkata; \"Aku disepuh dengan ter masih lebih aku sukai daripada harus melakukan ihram dalam keadaan memakai wewangian.\" Lalu Ibnu Umar menemui Aisyah dan mengabarkan padanya tentang perkataannya ini, maka [Aisyah] lalu berkata, \"Aku pernah memberikan wewangian kepada Rasulullah shallallahu 'alaihi wasallam. lalu beliau keliling (menggilir) diantara para istrinya, kemudian paginya beliau ihram.\""},"414":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ سَالِمٍ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ قَالَتْتَوَضَّأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وُضُوءَهُ لِلصَّلَاةِ غَيْرَ رِجْلَيْهِ وَغَسَلَ فَرْجَهُ وَمَا أَصَابَهُ ثُمَّ أَفَاضَ عَلَيْهِ الْمَاءَ ثُمَّ نَحَّى رِجْلَيْهِ فَغَسَلَهُمَاقَالَتْ هَذِهِ غِسْلَةٌ لِلْجَنَابَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin bin Ali] dia berkata; Telah menceritakan kepada kami [Muhammad bin Yusuf] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Salim] dari [Kuraib] dari [Ibnu Abbas] dari [Maimunah] dia berkata, \" Rasulullah shallallahu 'alaihi wasallam. berwudlu sebagaimana wudlu untuk shalat, kecuali kedua kakinya. Beliau mencuci kemaluannya dan apa-apa yang mengenainya, kemudian menuangkan air ke kemaluannya, lalu ke kedua kakinya, dan membasuhnya. Setelah itu beliau bersabda, 'Inilah mandi junub.\" "},"415":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ بِنْتِ الْحَارِثِ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اغْتَسَلَ مِنْ الْجَنَابَةِ يَبْدَأُ فَيَغْسِلُ يَدَيْهِ ثُمَّ يُفْرِغُ بِيَمِينِهِ عَلَى شِمَالِهِ فَيَغْسِلُ فَرْجَهُ ثُمَّ يَضْرِبُ بِيَدِهِ عَلَى الْأَرْضِ ثُمَّ يَمْسَحُهَا ثُمَّ يَغْسِلُهَا ثُمَّ يَتَوَضَّأُ وُضُوءَهُ لِلصَّلَاةِ ثُمَّ يُفْرِغُ عَلَى رَأْسِهِ وَعَلَى سَائِرِ جَسَدِهِ ثُمَّ يَتَنَحَّى فَيَغْسِلُ رِجْلَيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Alla] dia berkata; Telah menceritakan kepada kami [Abu Mu'awiyyah] dari [Al A'masy] dari [Salim bin Abu Ja'ad] dari [Kuraib] dari [Ibnu Abbas] dari [Maimunah binti Al Harits] -istri Nabi shallallahu 'alaihi wasallam- dia berkata; \" Rasulullah shallallahu 'alaihi wasallam bila mandi junub, beliau memulainya dengan mencuci kedua tangannya, kemudian menuangkan dengan tangan kanannya ke bagian tubuhnya sebelah kiri, lalu membasuh kemaluannya, menepukkan tangannya ke tanah, kemudian mengusapnya, lalu beliau mencucinya dan berwudlu sebagaimana untuk shalat. Selanjutnya beliau menyiramkan air ke kepalanya dan membasuh seluruh badannya, kemudian membasuh kakinya.\" "},"416":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اغْتَسَلَ مِنْ الْجَنَابَةِ غَسَلَ يَدَيْهِ ثُمَّ تَوَضَّأَ وُضُوءَهُ لِلصَّلَاةِ ثُمَّ اغْتَسَلَ ثُمَّ يُخَلِّلُ بِيَدِهِ شَعْرَهُ حَتَّى إِذَا ظَنَّ أَنَّهُ قَدْ أَرْوَى بَشَرَتَهُ أَفَاضَ عَلَيْهِ الْمَاءَ ثَلَاثَ مَرَّاتٍ ثُمَّ غَسَلَ سَائِرَ جَسَدِهِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah memberitakan kepada kami [Abdullah] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah] Radliyallahu'anha dia berkata, \"Bila Rasulullah shallallahu 'alaihi wasallam. hendak mandi junub, maka beliau mencuci tangannya, kemudian berwudlu, sebagaimana wudlu untuk shalat, kemudian mandi dan meratakan air ke celah-celah rambutnya dengan tangannya, hingga seolah-olah beliau mengira bahwa dirinya telah membasahi kulit kepalanya. Selanjutnya beliau menyiram kepalanya tiga kali, kemudian seluruh anggota badannya.\" "},"417":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ شُعْبَةَ عَنْ الْأَشْعَثِ بْنِ أَبِي الشَّعْثَاءِ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ التَّيَمُّنَ مَا اسْتَطَاعَ فِي طُهُورِهِ وَتَنَعُّلِهِ وَتَرَجُّلِهِ وَقَالَ بِوَاسِطٍ فِي شَأْنِهِ كُلِّهِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nasr] dia berkata; Telah memberitakan kepada kami [Abdullah] dari [Syu'bah] dari [Al Asy'ats bin Abu Sya'tsa] dari [Bapaknya] dari [Masruq] dari [Aisyah] Radliyallahu'anha dia berkata, \" Rasulullah shallallahu 'alaihi wasallam menyukai tayaamun (mendahului yang kanan) semaksimal mungkin dalam masalah bersuci, memakai sandal, serta menyisir rambutnya.\" Dan dia -perawi- berkata di kota Wasith, \"Di semua urusannya.\""},"418":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ يَزِيدَ بْنِ خَالِدٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَبْدِ اللَّهِ هُوَ ابْنُ سَمَاعَةَ قَالَ أَنْبَأَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ وَعَنْ عَمْرِو بْنِ سَعْدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ عُمَرَ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْغُسْلِ مِنْ الْجَنَابَةِ وَاتَّسَقَتْ الْأَحَادِيثُ عَلَى هَذَا يَبْدَأُ فَيُفْرِغُ عَلَى يَدِهِ الْيُمْنَى مَرَّتَيْنِ أَوْ ثَلَاثًا ثُمَّ يُدْخِلُ يَدَهُ الْيُمْنَى فِي الْإِنَاءِ فَيَصُبُّ بِهَا عَلَى فَرْجِهِ وَيَدُهُ الْيُسْرَى عَلَى فَرْجِهِ فَيَغْسِلُ مَا هُنَالِكَ حَتَّى يُنْقِيَهُ ثُمَّ يَضَعُ يَدَهُ الْيُسْرَى عَلَى التُّرَابِ إِنْ شَاءَ ثُمَّ يَصُبُّ عَلَى يَدِهِ الْيُسْرَى حَتَّى يُنْقِيَهَا ثُمَّ يَغْسِلُ يَدَيْهِ ثَلَاثًا وَيَسْتَنْشِقُ وَيُمَضْمِضُ وَيَغْسِلُ وَجْهَهُ وَذِرَاعَيْهِ ثَلَاثًا ثَلَاثًا حَتَّى إِذَا بَلَغَ رَأْسَهُ لَمْ يَمْسَحْ وَأَفْرَغَ عَلَيْهِ الْمَاءَ فَهَكَذَا كَانَ غُسْلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا ذُكِرَ","id":"Telah mengabarkan kepada kami ['Imran bin Yazid bin Khalid] dia berkata; Telah menceritakan kepada kami [Ismail bin Abdullah yaitu Ibnu Sama'ah] dia berkata; Telah memberitakan kepada kami [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Aisyah] Radliyallahu'anha juga dari [Amr bin Sa'ad] dari [Nafi'] dari [Ibnu Umar] bahwa Umar bin Khatthab pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam. tentang mandi junub. Beliau memulainya dengan menyiram tangan kanannya dua kali -atau tiga kali- kemudian memasukkan tangan kanannya ke dalam bejana, lalu menyiramkan air dengan tangan kanan tersebut ke kemaluannya dan tangan kirinya pada kemaluannya, lalu membersihkannya sampai bersih. Kemudian beliau menepukkan tangan kirinya ke tanah bila beliau berkehendak. Kemudian menyiram tangan kirinya sampai bersih, lalu mencuci kedua tangannya sampai bersih dan memasukkan air ke hidung kemudian mengeluarkannya. Lalu beliau membasuh mukanya serta kedua lengannya tiga kali-tiga kali. Ketika sampai pada giliran mengusap kepala, beliau tidak melakukannya, lalu menyiramkan air pada kepalanya. Begitulah cara mandi Rasulullah shallallahu 'alaihi wasallam. sebagaimana yang disebutkan.\""},"419":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اغْتَسَلَ مِنْ الْجَنَابَةِ غَسَلَ يَدَيْهِ ثُمَّ تَوَضَّأَ وُضُوءَهُ لِلصَّلَاةِ ثُمَّ يُخَلِّلُ رَأْسَهُ بِأَصَابِعِهِ حَتَّى إِذَا خُيِّلَ إِلَيْهِ أَنَّهُ قَدْ اسْتَبْرَأَ الْبَشَرَةَ غَرَفَ عَلَى رَأْسِهِ ثَلَاثًا ثُمَّ غَسَلَ سَائِرَ جَسَدِهِ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; Telah menceritakan kepada kami [Ali bin Mushir] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah] Radliyallahu'anha bahwa Rasulullah shallallahu 'alaihi wasallam. bila mandi junub, beliau membasuh kedua tangannya, kemudian berwudlu sebagaimana wudlu untuk shalat. Lalu membersihkan celah-celah rambutnya dengan jari-jari tangan beliau hingga terbayangkan bahwa beliau menyiram kepalanya tiga kali, kemudian membasuh seluruh anggota badannya. "},"420":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا الضَّحَّاكُ بْنُ مَخْلَدٍ عَنْ حَنْظَلَةَ بْنِ أَبِي سُفْيَانَ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اغْتَسَلَ مِنْ الْجَنَابَةِ دَعَا بِشَيْءٍ نَحْوِ الْحِلَابِ فَأَخَذَ بِكَفِّهِ بَدَأَ بِشِقِّ رَأْسِهِ الْأَيْمَنِ ثُمَّ الْأَيْسَرِ ثُمَّ أَخَذَ بِكَفَّيْهِ فَقَالَ بِهِمَا عَلَى رَأْسِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; Telah menceritakan kepada kami [Ad-Dlahak bin Makhlad] dari [Hanzhalah bin Abu Sufyan] dari [Al Qasim] dari [Aisyah] Radliyallahu'anha dia berkata; \"Bila Rasulullah shallallahu 'alaihi wasallam mandi junub, maka beliau meminta sesuatu yang seukuran bejana (yang biasa untuk memerah susu), lalu beliau mengambil dengan telapak tangannya. Beliau memulai dengan kepala bagian kanan, kemudian bagian kiri. Lantas mengambil dengan telapak tangannya (perawi berkata); dan menyiramkan air ke kepalanya dengan kedua telapak tangan tadi.\""},"421":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ عَنْ يَحْيَى عَنْ شُعْبَةَ قَالَ حَدَّثَنَا أَبُو إِسْحَقَ ح وَأَنْبَأَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ شُعْبَةَ عَنْ أَبِي إِسْحَقَ قَالَ سَمِعْتُ سُلَيْمَانَ بْنَ صُرَدٍ يُحَدِّثُ عَنْ جُبَيْرِ بْنِ مُطْعِمٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذُكِرَ عِنْدَهُ الْغُسْلُ فَقَالَ أَمَّا أَنَا فَأُفْرِغُ عَلَى رَأْسِي ثَلَاثًا لَفْظُ سُوَيْدٍ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'di] dari [Yahya] dari [Syu'bah] dia berkata; Telah menceritakan kepada kami [Abu Ishaq] dan Telah memberitakan kepada kami [Suwaid bin Nashr] dia berkata; Telah menceritakan kepada kami [Abdullah] dari [Syu'bah] dari [Abu Ishaq] dia berkata; Saya mendengar [Sulaiman bin Shurad] berkata; dari [Jubair bin Muth'im] bahwa pernah diceritakan kepada Nabi shallallahu 'alaihi wasallam tentang mandi junub, maka beliau shallallahu 'alaihi wasallam bersabda: \"Sedangkan aku, maka aku menuangkan air ke kepalaku tiga kali.\" Sebagaimana lafazh Suwaid. "},"422":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ مُخَوَّلٍ عَنْ أَبِي جَعْفَرٍ عَنْ جَابِرٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اغْتَسَلَ أَفْرَغَ عَلَى رَأْسِهِ ثَلَاثًا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; Telah menceritakan kepada kami [Khalid] dari [Syu'bah] dari [Mukhawal] dari [Abu Ja'far] dari [Jabir] dia berkata; \" Rasulullah shallallahu 'alaihi wasallam apabila mandi junub, beliau menuangkan air ke kepala tiga kali.\""},"423":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا مَنْصُورُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أُمِّهِ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ عَائِشَةَأَنَّ امْرَأَةً سَأَلَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ يَا رَسُولَ اللَّهِ كَيْفَ أَغْتَسِلُ عِنْدَ الطُّهُورِ قَالَ خُذِي فِرْصَةً مُمَسَّكَةً فَتَوَضَّئِي بِهَا قَالَتْ كَيْفَ أَتَوَضَّأُ بِهَا قَالَ تَوَضَّئِي بِهَا قَالَتْ كَيْفَ أَتَوَضَّأُ بِهَا قَالَتْ ثُمَّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبَّحَ وَأَعْرَضَ عَنْهَا فَفَطِنَتْ عَائِشَةُ لِمَا يُرِيدُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ فَأَخَذْتُهَا وَجَبَذْتُهَا إِلَيَّ فَأَخْبَرْتُهَا بِمَا يُرِيدُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Al Hasan bin Muhammad] dia berkata; Telah menceritakan kepada kami ['Affan] dia berkata; Telah menceritakan kepada kami [Wuhaib] berkata; Telah menceritakan kepada kami [Manshur bin Abdurrahman] dari Ibunya - [Shafiyyah binti Syaibah] - dari [Aisyah] Radliyallahu'anha Bahwa ada seorang wanita bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \"Bagaimana aku mandi untuk bersuci (dari haid)?\" Rasulullah berkata; \"Ambillah sepotong kapas yang sudah diberi minyak wangi misik, dan bersucilah dengannya.\"Dia bertanya, \"Bagaimana aku bersuci dengannya?\" Rasulullah bersabda, \"Bersucilah dari hal itu.\"Lalu dia bertanya, \"Bagaimana aku bersuci dengannya?\" Beliau lalu bertasbih dan berpaling dari wanita itu.\"Maka Aisyah memahami apa yang diinginkan Rasulullah, lalu dia berkata; Aku tarik wanita tersebut agar mendekat kepadaku dan kuberitahu maksud perkataan Rasulullah shallallahu 'alaihi wasallam tadi.\""},"424":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْاغْتَسَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْجَنَابَةِ فَغَسَلَ فَرْجَهُ وَدَلَكَ يَدَهُ بِالْأَرْضِ أَوْ الْحَائِطِ ثُمَّ تَوَضَّأَ وُضُوءَهُ لِلصَّلَاةِ ثُمَّ أَفَاضَ عَلَى رَأْسِهِ وَسَائِرِ جَسَدِهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Jarir] dari [Al A'masy] dari [Salim bin Abu Ja'ad] dari [Kuraib] dari [Ibnu Abbas] dari [Maimunah] -Istri Nabi shallallahu 'alaihi wasallam- dia berkata; \"Nabi shallallahu 'alaihi wasallam pernah mandi junub. Beliau membasuh kemaluannya, kemudian menggosokkan tangannya ke tanah atau tembok, kemudian berwudlu untuk shalat. Selanjutnya beliau menyiramkan air ke kepala dan seluruh badannya.\""},"425":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَيَعْقُوبُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لَهُ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا جَعْفَرُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنِي أَبِي قَالَأَتَيْنَا جَابِرَ بْنَ عَبْدِ اللَّهِ فَسَأَلْنَاهُ عَنْ حَجَّةِ الْوَدَاعِ فَحَدَّثَنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ لِخَمْسٍ بَقِينَ مِنْ ذِي الْقَعْدَةِ وَخَرَجْنَا مَعَهُ حَتَّى إِذَا أَتَى ذَا الْحُلَيْفَةِ وَلَدَتْ أَسْمَاءُ بِنْتُ عُمَيْسٍ مُحَمَّدَ بْنَ أَبِي بَكْرٍ فَأَرْسَلَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ أَصْنَعُ فَقَالَ اغْتَسِلِي ثُمَّ اسْتَثْفِرِي ثُمَّ أَهِلِّي","id":"Telah mengabarkan kepada kami [Amr bin Ali] dan [Muhammad bin Al Mutsanna] serta [Ya'qub bin Ibrahim] lafazh ini dari dia, dia berkata; Telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; Telah menceritakan kepada kami [Ja'far bin Muhammad] dia berkata; Telah menceritakan kepadaku [Bapakku] dia berkata; \" Kami datang kepada [Jabir bin Abdullah] untuk bertanya tentang haji Wada. Dia lalu bercerita kepada kami bahwa Rasulullah shallallahu 'alaihi wasallam keluar pada tanggal dua puluh lima Dzul Qa'dah dan beberapa sahabat ikut bersama beliau shallallahu 'alaihi wasallam. Tatkala kami sampai ke Dzul Hulaifah, Asma' binti 'Umais melahirkan Muhammad bin Abu Bakar maka dia mengirim orang kepada Rasulullah shallallahu 'alaihi wasallam untuk menanyakan apa yang harus diperbuat. Rasulullah shallallahu 'alaihi wasallam menjawab: \"Suruh ia mandi dan meletakkan kain pada tempat keluarnya darah, lalu berihramlah.\""},"426":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا حَسَنٌ عَنْ أَبِي إِسْحَقَ ح وَأَنْبَأَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَتَوَضَّأُ بَعْدَ الْغُسْلِ","id":"Telah mengabarkan kepada kami [Ahmad bin Utsman bin Hakim] dia berkata; Telah menceritakan kepada kami [Bapakku] dia berkata; Telah menceritakan kepada kami [Hasan] dari [Abu Ishaq] dan Telah memberitakan kepada kami [Amr bin Ali] dia berkata; Telah menceritakan kepada kami [Abdurrahman] dia berkata; Telah menceritakan kepada kami [Syarik] dari [Abu Ishaq] dari [Al Aswad] dari [Aisyah] Radliyallahu'anha dia berkata; Rasulullah shallallahu 'alaihi wasallam tidak berwudlu lagi setelah mandi (Junub).\""},"427":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ بِشْرٍ وَهُوَ ابْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ قَالَ قَالَتْ عَائِشَةُكُنْتُ أُطَيِّبُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَطُوفُ عَلَى نِسَائِهِ ثُمَّ يُصْبِحُ مُحْرِمًا يَنْضَخُ طِيبًا","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] Telah mengabarkan kepada kami [Bisyir yaitu Ibnu Mufadlal] dia berkata; Telah menceritakan kepada kami [Syu'bah] dari [Ibrahim bin Muhammad] dari [Bapaknya] dia berkata; [Aisyah] Radliyallahu'anha berkata; Aku pernah memberi wewangian kepada Rasulullah shallallahu 'alaihi wasallam. lalu beliau keliling di antara para istrinya, kemudian paginya beliau ihram dalam keadaan masih wangi.\""},"428":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ إِسْمَعِيلَ بْنِ سُلَيْمَانَ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ أَنْبَأَنَا سَيَّارٌ عَنْ يَزِيدَ الْفَقِيرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُعْطِيتُ خَمْسًا لَمْ يُعْطَهُنَّ أَحَدٌ قَبْلِي نُصِرْتُ بِالرُّعْبِ مَسِيرَةَ شَهْرٍ وَجُعِلَتْ لِي الْأَرْضُ مَسْجِدًا وَطَهُورًا فَأَيْنَمَا أَدْرَكَ الرَّجُلَ مِنْ أُمَّتِي الصَّلَاةُ يُصَلِّي وَأُعْطِيتُ الشَّفَاعَةَ وَلَمْ يُعْطَ نَبِيٌّ قَبْلِي وَبُعِثْتُ إِلَى النَّاسِ كَافَّةً وَكَانَ النَّبِيُّ يُبْعَثُ إِلَى قَوْمِهِ خَاصَّةً","id":"Telah mengabarkan kepada kami [Al Hasan bin Ismail bin Sulaiman] dia berkata; Telah menceritakan kepada kami [Husyaim] berkata; Telah memberitakan kepada kami [Sayyar] dari [Yazid Al Faqir] dari [Jabir bin Abdullah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku diberi lima perkara yang tidak pernah diberikan kepada nabi-nabi sebelumku, yaitu, aku ditolong (oleh Allah) dengan rasa takut yang dicampakkan pada musuh-musuhku selama satu bulan, dijadikannya bumi sebagai tempat bersujud dan bersuci, maka di manapun seseorang dari kalangan umatku mendapati (waktu) shalat, shalatlah di situ, dan aku beri syafa'at yang tidak diberikan kepada nabi sebelumku, dan aku juga diutus kepada seluruh manusia, sedangkan nabi-nabi sebelumku khusus diutus hanya kepada kaumnya.\""},"429":{"ar":"أَخْبَرَنَا مُسْلِمُ بْنُ عَمْرِو بْنِ مُسْلِمٍ قَالَ حَدَّثَنِي ابْنُ نَافِعٍ عَنْ اللَّيْثِ بْنِ سَعْدٍ عَنْ بَكْرِ بْنِ سَوَادَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍأَنَّ رَجُلَيْنِ تَيَمَّمَا وَصَلَّيَا ثُمَّ وَجَدَا مَاءً فِي الْوَقْتِ فَتَوَضَّأَ أَحَدُهُمَا وَعَادَ لِصَلَاتِهِ مَا كَانَ فِي الْوَقْتِ وَلَمْ يُعِدْ الْآخَرُ فَسَأَلَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِلَّذِي لَمْ يُعِدْ أَصَبْتَ السُّنَّةَ وَأَجْزَأَتْكَ صَلَاتُكَ وَقَالَ لِلْآخَرِ أَمَّا أَنْتَ فَلَكَ مِثْلُ سَهْمِ جَمْعٍأَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ لَيْثِ بْنِ سَعْدٍ قَالَ حَدَّثَنِي عَمِيرَةُ وَغَيْرُهُ عَنْ بَكْرِ بْنِ سَوَادَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ أَنَّ رَجُلَيْنِ وَسَاقَ الْحَدِيثَ","id":"Telah mengabarkan kepada kami [Muslim bin Amr bin Muslim] dia berkata; Telah menceritakan kepadaku [Ibnu Nafi'] dari [Al-Laits bin Sa'ad] dari [Bakr bin Sawadah] dari ['Atha bin Yasar] dari [Abu Sa'id] bahwa ada dua orang yang tayamum, lalu keduanya shalat. Kemudian keduanya mendapatkan air pada waktu shalat tersebut belum selesai, maka salah seorang dari keduanya berwudlu dan mengulangi shalatnya, sedangkan yang kedua tidak mengulanginya. Setelah itu keduanya bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang hal tersebut. Maka Rasulullah shallallahu 'alaihi wasallam bersabda kepada yang tidak mengulangi shalatnya, \"Kamu sesuai dengan Sunnah dan shalatmu sudah cukup.\" Lalu beliau bersabda kepada yang mengulangi shalatnya, \"Kamu seperti mendapatkan bagian ganda.\" Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah menceritakan kepada kami [Abdullah] dari [Laits bin Sa'ad] dia berkata; Telah menceritakan kepadaku ['Amirah] dan yang lainnya dari Bakr bin Sawadah dari 'Atha bin Yasar bahwa dua orang laki-laki……. dan seterusnya kemudian ia membawakan hadits. "},"430":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ مَيْمُونٍ قَالَ حَدَّثَنَا مَخْلَدُ بْنُ يَزِيدَ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَ تَذَاكَرَ عَلِيٌّ وَالْمِقْدَادُ وَعَمَّارٌفَقَالَ عَلِيٌّ إِنِّي امْرُؤٌ مَذَّاءٌ وَإِنِّي أَسْتَحِي أَنْ أَسْأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمَكَانِ ابْنَتِهِ مِنِّي فَيَسْأَلُهُ أَحَدُكُمَا فَذَكَرَ لِي أَنَّ أَحَدَهُمَا وَنَسِيتُهُ سَأَلَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاكَ الْمَذْيُ إِذَا وَجَدَهُ أَحَدُكُمْ فَلْيَغْسِلْ ذَلِكَ مِنْهُ وَلْيَتَوَضَّأْ وُضُوءَهُ لِلصَّلَاةِ أَوْ كَوُضُوءِ الصَّلَاةِالِاخْتِلَافُ عَلَى سُلَيْمَانَ","id":"Telah mengabarkan kepada kami [Ali bin Maimun] dia berkata; Telah menceritakan kepada kami [Makhlad bin Yazid] dari [Ibnu Juraij] dari [Atha] dari [Ibnu Abbas] dia berkata; Ali, Miqdad, dan 'Ammar saling mengingatkan, maka kemudian [Ali] berkata; \"Saya adalah orang yang sering keluar air madzinya, dan saya merasa malu untuk menanyakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam karena putrinya adalah istriku, kemudian salah seorang diantara kalian -saya lupa diantara keduanya- menanyakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam. Maka kemudian beliau menjawab: \"Itu adalah madzi, apabila salah seorang diantara kalian mendapatkannya, hendaklah dia mencuci kemaluannya, dan berwudlulah sebagaimana wudlu untuk shalat -dalam lafazh lain dengan redaksi-, \"Ka wudlu lis shalah\", (seperti wudlu shalat) perbedaan ini terjadi pada Sulaiman. "},"431":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ حَدَّثَنَا عَبِيدَةُ قَالَ حَدَّثَنَا سُلَيْمَانُ الْأَعْمَشُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ رَجُلًا مَذَّاءً فَأَمَرْتُ رَجُلًا فَسَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ فِيهِ الْوُضُوءُ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] dia berkata; Telah menceritakan kepada kami ['Abidah] dia berkata; Telah menceritakan kepada kami [Sulaiman Al A'masy] dari [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Ali] Radliyallahu'anhu dia berkata; \"Aku adalah orang yang mudah keluar madzi, maka kemudian aku menyuruh seseorang untuk menanyakan kepada Nabi shallallahu 'alaihi wasallam lalu beliau bersabda: \"Baginya berwudlu\""},"432":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي سُلَيْمَانُ الْأَعْمَشُ قَالَ سَمِعْتُ مُنْذِرًا عَنْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَاسْتَحْيَيْتُ أَنْ أَسْأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمَذْيِ مِنْ أَجْلِ فَاطِمَةَ فَأَمَرْتُ الْمِقْدَادَ فَسَأَلَهُ فَقَالَ فِيهِ الْوُضُوءُالِاخْتِلَافُ عَلَى بُكَيْرٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid bin Al Harits] dari [Syu'bah] dia berkata; Telah mengabarkan kepadaku [Sulaiman] dia berkata; Saya mendengar [Mundzir] dari [Muhammad bin Ali] dari [Ali] dia berkata; \"Aku malu bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang madzi karena Fatimah adalah puteri beliau, jadi aku menyuruh Miqdad bin Al Aswad untuk bertanya. Lalu dia bertanya, dan Rasulullah shallallahu 'alaihi wasallam menjawab: Mengenai hal itu, ia harus wudlu.\" Ada perbedaan pada Bukair. "},"433":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عِيسَى عَنْ ابْنِ وَهْبٍ وَذَكَرَ كَلِمَةً مَعْنَاهَا أَخْبَرَنِي مَخْرَمَةُ بْنُ بُكَيْرٍ عَنْ أَبِيهِ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُأَرْسَلْتُ الْمِقْدَادَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْأَلُهُ عَنْ الْمَذْيِ فَقَالَ تَوَضَّأْ وَانْضَحْ فَرْجَكَقَالَ أَبُو عَبْد الرَّحْمَنِ مَخْرَمَةُ لَمْ يَسْمَعْ مِنْ أَبِيهِ شَيْئًا","id":"Telah mengabarkan kepada kami [Ahmad bin Isa] dari [Ibnu Wahab] dan dia menyebutkan satu kalimat yang maksudnya adalah telah mengabarkan kepadaku [Makhramah bin Bukair] dari [Bapaknya] dari [Sulaiman bin Yasar] dari [Ibnu Abbas] dia berkata; [Ali] Radliyallahu'anhu berkata; \"Aku mengutus Miqdad kepada Rasulullah shallallahu 'alaihi wasallam untuk bertanya tentang madzi? lalu beliau bersabda: Berwudlulah dan basahi atau perciki kemaluanmu.\" Abu Abdurrahman berkata; Makhramah tidak pernah mendengar dari Bapaknya sedikitpun. "},"434":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ لَيْثِ بْنِ سَعْدٍ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ قَالَأَرْسَلَ عَلِيُّ بْنُ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ الْمِقْدَادَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْأَلُهُ عَنْ الرَّجُلِ يَجِدُ الْمَذْيَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْسِلُ ذَكَرَهُ ثُمَّ لِيَتَوَضَّأْ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah memberitakan kepada kami [Abdullah] dari [Laits bin Sa'ad] dari [Bukair bin Al-Asyaj] dari [Sulaiman bin Yasar] dia berkata; \"Ali bin Abu Thalib Radliyallahu'anhu mengutus Miqdad kepada Rasulullah shallallahu 'alaihi wasallam untuk menyatakan seorang laki-laki yang mengeluarkan madzi. Beliau shallallahu 'alaihi wasallam menjawab: \"Hendaklah ia mencuci kemaluannya kemudian berwudlu.\""},"435":{"ar":"أَخْبَرَنَا عُتْبَةُ بْنُ عَبْدِ اللَّهِ قَالَ قُرِئَ عَلَى مَالِكٍ وَأَنَا أَسْمَعُ عَنْ أَبِي النَّضْرِ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ الْمِقْدَادِ بْنِ الْأَسْوَدِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُأَمَرَهُ أَنْ يَسْأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرَّجُلِ إِذَا دَنَا مِنْ الْمَرْأَةِ فَخَرَجَ مِنْهُ الْمَذْيُ فَإِنَّ عِنْدِي ابْنَتَهُ وَأَنَا أَسْتَحْيِي أَنْ أَسْأَلَهُ فَسَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَقَالَ إِذَا وَجَدَ أَحَدُكُمْ ذَلِكَ فَلْيَنْضَحْ فَرْجَهُ وَلْيَتَوَضَّأْ وَضُوءَهُ لِلصَّلَاةِ","id":"Telah mengabarkan kepada kami ['Utbah bin Abdullah] dia berkata; telah dibacakan kepada [Malik] dan saya mendengarnya dari [Abu Nadlar] dari [Sulaiman bin Yasar] dari [Miqdad bin Al Aswad] dari Ali Radliyallahu'anhu bahwa dia memerintahkannya untuk bertanya Rasulullah shallallahu 'alaihi wasallam tentang seorang yang ingin mendekati istrinya, lalu keluar madzi, maka apa yang harus dia perbuat? Karena anak perempuan beliau adalah istriku - jadi aku malu untuk bertanya hal itu! Lalu dia pun (Miqdad) bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang hal tersebut, dan beliau menjawab: \"Bila salah seorang dari kalian mendapati hal tersebut, maka basahi dan percikilah kemaluannya dengan air, lalu berwudlu sebagaimana wudlu untuk shalat.\""},"436":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ مُسْلِمٍ الزُّهْرِيُّ قَالَ حَدَّثَنِي سَعِيدُ بْنُ الْمُسَيَّبِ قَالَ حَدَّثَنِي أَبُو هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ أَحَدُكُمْ مِنْ اللَّيْلِ فَلَا يُدْخِلْ يَدَهُ فِي الْإِنَاءِ حَتَّى يُفْرِغَ عَلَيْهَا مَرَّتَيْنِ أَوْ ثَلَاثًا فَإِنَّ أَحَدَكُمْ لَا يَدْرِي أَيْنَ بَاتَتْ يَدُهُ","id":"Telah mengabarkan kepada kami ['Imran bin Yazid] dia berkata; Telah menceritakan kepada kami [Ismail bin Abdullah] dia berkata; Telah menceritakan kepada kami [Al Auza'i] dia berkata; Telah menceritakan kepada kami [Muhammad bin Muslim Az-Zuhri] dia berkata; Telah menceritakan kepadaku [Sa'id Al Musayyab] dia berkata; Telah menceritakan kepadaku [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian bangun dari tidurnya, janganlah memasukkan tangannya ke dalam bejana air hingga menuangkan ke tangannya sebanyak dua kali atau tiga kali, karena dia tidak tahu dimana tangannya menginap (berada waktu dia tidur).\""},"437":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا دَاوُدُ عَنْ عَمْرٍو عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَقُمْتُ عَنْ يَسَارِهِ فَجَعَلَنِي عَنْ يَمِينِهِ فَصَلَّى ثُمَّ اضْطَجَعَ وَرَقَدَ فَجَاءَهُ الْمُؤَذِّنُ فَصَلَّى وَلَمْ يَتَوَضَّأْ مُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Daud] dari ['Amr] dari [Kuraib] dari [Ibnu Abbas] dia berkata; Aku pernah shalat pada suatu malam bersama Rasulullah shallallahu 'alaihi wasallam. Aku berdiri di samping kirinya, lalu beliau memindahkanku ke samping kanannya. Setelah shalat beliau berbaring dan tidur. Kemudian datanglah mu'adzin, lalu beliau shalat tanpa wudlu lagi.\""},"438":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ الطُّفَاوِيُّ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا نَعَسَ أَحَدُكُمْ فِي صَلَاتِهِ فَلْيَنْصَرِفْ وَلْيَرْقُدْ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Muhammad bin Abdurrahaman At Thufawi] dia berkata; Telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam. bersabda: \"Apabila salah seorang dari kalian mengantuk dalam (Shalatnya), hendaklah ia menghentikan shalat dan tidur.\""},"439":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ يَعْنِي ابْنَ أَبِي بَكْرٍ قَالَ عَلَى أَثَرِهِ قَالَ أَبُو عَبْدِ الرَّحْمَنِ وَلَمْ أُتْقِنْهُ عَنْ عُرْوَةَ عَنْ بُسْرَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ مَسَّ فَرْجَهُ فَلْيَتَوَضَّأْ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Sufyan] dari [Abdullah yaitu Ibnu Abu Bakar] dia berkata; dengan atsarnya, Abu Abdurrahman berkata; -dan aku belum memastikannya- dari [Urwah] dari [Busrah] dia berkata; Rasulullah shallallahu 'alaihi wasallam. bersabda: \"Barang siapa menyentuh kemaluannya, hendaklah ia berwudlu.\""},"440":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ مُوسَى قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَوَاءٍ عَنْ شُعْبَةَ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ بُسْرَةَ بِنْتِ صَفْوَانَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَفْضَى أَحَدُكُمْ بِيَدِهِ إِلَى فَرْجِهِ فَلْيَتَوَضَّأْ","id":"Telah mengabarkan kepada kami ['Imran bin Musa] dia berkata; Telah menceritakan kepada kami [Muhammad bin Sawa] dari [Syu'bah] dari [Ma'mar] dari [Az-Zuhri] dari [Urwah bin Jubair] dari [Busrah binti Shafwan] bahwa Rasulullah shallallahu 'alaihi wasallam. bersabda: \"Apabila salah seorang dari kalian menyentuh kemaluannya dengan tangannya, hendaklah berwudlu. "},"441":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ مَرْوَانَ بْنِ الْحَكَمِ أَنَّهُ قَالَ الْوُضُوءُ مِنْ مَسِّ الذَّكَرِفَقَالَ مَرْوَانُ أَخْبَرَتْنِيهِ بُسْرَةُ بِنْتُ صَفْوَانَ فَأَرْسَلَ عُرْوَةُ قَالَتْ ذَكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يُتَوَضَّأُ مِنْهُ فَقَالَ مِنْ مَسِّ الذَّكَرِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Al-Laits] dari [Ibnu Syihab] dari [Urwah bin Jubair] dari [Marwan bin Al Hakam] dia berkata; berwudlu karena menyentuh kemaluan. Marwan berkata; \" [Busrah binti Shafwan] mengabarkan kepadaku berita ini, bahwa Urwah mengutusnya, ia mengatakan bahwa Rasulullah shallallahu 'alaihi wasallam menyebutkan hal yang membuat seseorang harus berwudlu, beliau bersabda: \"Diantaranya karena menyentuh kemaluan.\""},"442":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ قَالَ أَخْبَرَنِي أَبِي عَنْ بُسْرَةَ بِنْتِ صَفْوَانَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ مَسَّ ذَكَرَهُ فَلَا يُصَلِّي حَتَّى يَتَوَضَّأَقَالَ أَبُو عَبْد الرَّحْمَنِ هِشَامُ بْنُ عُرْوَةَ لَمْ يَسْمَعْ مِنْ أَبِيهِ هَذَا الْحَدِيثَ وَاللَّهُ سُبْحَانَهُ وَتَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam bin Urwah] dia berkata; Telah mengabarkan kepadaku [Bapakku] dari [Busrah binti Shafwan] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa menyentuh kemaluannya, janganlah shalat hingga ia berwudlu.\" Abu Abdurrahman berkata; Hisyam bin Urwah tidak pernah mendengar dari Bapaknya mengenai hadits ini. Wallahu Subhanahu wa Ta'la A'lam. "},"443":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا هِشَامٌ الدَّسْتَوَائِيُّ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ مَالِكِ بْنِ صَعْصَعَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَا أَنَا عِنْدَ الْبَيْتِ بَيْنَ النَّائِمِ وَالْيَقْظَانِ إِذْ أَقْبَلَ أَحَدُ الثَّلَاثَةِ بَيْنَ الرَّجُلَيْنِ فَأُتِيتُ بِطَسْتٍ مِنْ ذَهَبٍ مَلْآنَ حِكْمَةً وَإِيمَانًا فَشَقَّ مِنْ النَّحْرِ إِلَى مَرَاقِّ الْبَطْنِ فَغَسَلَ الْقَلْبَ بِمَاءِ زَمْزَمَ ثُمَّ مُلِئَ حِكْمَةً وَإِيمَانًا ثُمَّ أُتِيتُ بِدَابَّةٍ دُونَ الْبَغْلِ وَفَوْقَ الْحِمَارِ ثُمَّ انْطَلَقْتُ مَعَ جِبْرِيلَ عَلَيْهِ السَّلَام فَأَتَيْنَا السَّمَاءَ الدُّنْيَا فَقِيلَ مَنْ هَذَا قَالَ جِبْرِيلُ قِيلَ وَمَنْ مَعَكَ قَالَ مُحَمَّدٌ قِيلَ وَقَدْ أُرْسِلَ إِلَيْهِ مَرْحَبًا بِهِ وَنِعْمَ الْمَجِيءُ جَاءَ فَأَتَيْتُ عَلَى آدَمَ عَلَيْهِ السَّلَام فَسَلَّمْتُ عَلَيْهِ قَالَ مَرْحَبًا بِكَ مِنْ ابْنٍ وَنَبِيٍّ ثُمَّ أَتَيْنَا السَّمَاءَ الثَّانِيَةَ قِيلَ مَنْ هَذَا قَالَ جِبْرِيلُ قِيلَ وَمَنْ مَعَكَ قَالَ مُحَمَّدٌ فَمِثْلُ ذَلِكَ فَأَتَيْتُ عَلَى يَحْيَى وَعِيسَى فَسَلَّمْتُ عَلَيْهِمَا فَقَالَا مَرْحَبًا بِكَ مِنْ أَخٍ وَنَبِيٍّ ثُمَّ أَتَيْنَا السَّمَاءَ الثَّالِثَةَ قِيلَ مَنْ هَذَا قَالَ جِبْرِيلُ قِيلَ وَمَنْ مَعَكَ قَالَ مُحَمَّدٌ فَمِثْلُ ذَلِكَ فَأَتَيْتُ عَلَى يُوسُفَ عَلَيْهِ السَّلَام فَسَلَّمْتُ عَلَيْهِ قَالَ مَرْحَبًا بِكَ مِنْ أَخٍ وَنَبِيٍّ ثُمَّ أَتَيْنَا السَّمَاءَ الرَّابِعَةَ فَمِثْلُ ذَلِكَ فَأَتَيْتُ عَلَى إِدْرِيسَ عَلَيْهِ السَّلَام فَسَلَّمْتُ عَلَيْهِ فَقَالَ مَرْحَبًا بِكَ مِنْ أَخٍ وَنَبِيٍّ ثُمَّ أَتَيْنَا السَّمَاءَ الْخَامِسَةَ فَمِثْلُ ذَلِكَ فَأَتَيْتُ عَلَى هَارُونَ عَلَيْهِ السَّلَام فَسَلَّمْتُ عَلَيْهِ قَالَ مَرْحَبًا بِكَ مِنْ أَخٍ وَنَبِيٍّ ثُمَّ أَتَيْنَا السَّمَاءَ السَّادِسَةَ فَمِثْلُ ذَلِكَ ثُمَّ أَتَيْتُ عَلَى مُوسَى عَلَيْهِ السَّلَام فَسَلَّمْتُ عَلَيْهِ فَقَالَ مَرْحَبًا بِكَ مِنْ أَخٍ وَنَبِيٍّ فَلَمَّا جَاوَزْتُهُ بَكَى قِيلَ مَا يُبْكِيكَ قَالَ يَا رَبِّ هَذَا الْغُلَامُ الَّذِي بَعَثْتَهُ بَعْدِي يَدْخُلُ مِنْ أُمَّتِهِ الْجَنَّةَ أَكْثَرُ وَأَفْضَلُ مِمَّا يَدْخُلُ مِنْ أُمَّتِي ثُمَّ أَتَيْنَا السَّمَاءَ السَّابِعَةَ فَمِثْلُ ذَلِكَ فَأَتَيْتُ عَلَى إِبْرَاهِيمَ عَلَيْهِ السَّلَام فَسَلَّمْتُ عَلَيْهِ فَقَالَ مَرْحَبًا بِكَ مِنْ ابْنٍ وَنَبِيٍّ ثُمَّ رُفِعَ لِي الْبَيْتُ الْمَعْمُورُ فَسَأَلْتُ جِبْرِيلَ فَقَالَ هَذَا الْبَيْتُ الْمَعْمُورُ يُصَلِّي فِيهِ كُلَّ يَوْمٍ سَبْعُونَ أَلْفَ مَلَكٍ فَإِذَا خَرَجُوا مِنْهُ لَمْ يَعُودُوا فِيهِ آخِرَ مَا عَلَيْهِمْ ثُمَّ رُفِعَتْ لِي سِدْرَةُ الْمُنْتَهَى فَإِذَا نَبْقُهَا مِثْلُ قِلَالِ هَجَرٍ وَإِذَا وَرَقُهَا مِثْلُ آذَانِ الْفِيَلَةِ وَإِذَا فِي أَصْلِهَا أَرْبَعَةُ أَنْهَارٍ نَهْرَانِ بَاطِنَانِ وَنَهْرَانِ ظَاهِرَانِ فَسَأَلْتُ جِبْرِيلَ فَقَالَ أَمَّا الْبَاطِنَانِ فَفِي الْجَنَّةِ وَأَمَّا الظَّاهِرَانِ فَالْبُطَاءُ وَالنَّيْل ثُمَّ فُرِضَتْ عَلَيَّ خَمْسُونَ صَلَاةً فَأَتَيْتُ عَلَى مُوسَى فَقَالَ مَا صَنَعْتَ قُلْتُ فُرِضَتْ عَلَيَّ خَمْسُونَ صَلَاةً قَالَ إِنِّي أَعْلَمُ بِالنَّاسِ مِنْكَ إِنِّي عَالَجْتُ بَنِي إِسْرَائِيلَ أَشَدَّ الْمُعَالَجَةِ وَإِنَّ أُمَّتَكَ لَنْ يُطِيقُوا ذَلِكَ فَارْجِعْ إِلَى رَبِّكَ فَاسْأَلْهُ أَنْ يُخَفِّفَ عَنْكَ فَرَجَعْتُ إِلَى رَبِّي فَسَأَلْتُهُ أَنْ يُخَفِّفَ عَنِّي فَجَعَلَهَا أَرْبَعِينَ ثُمَّ رَجَعْتُ إِلَى مُوسَى عَلَيْهِ السَّلَام فَقَالَ مَا صَنَعْتَ قُلْتُ جَعَلَهَا أَرْبَعِينَ فَقَالَ لِي مِثْلَ مَقَالَتِهِ الْأُولَى فَرَجَعْتُ إِلَى رَبِّي عَزَّ وَجَلَّ فَجَعَلَهَا ثَلَاثِينَ فَأَتَيْتُ عَلَى مُوسَى عَلَيْهِ السَّلَام فَأَخْبَرْتُهُ فَقَالَ لِي مِثْلَ مَقَالَتِهِ الْأُولَى فَرَجَعْتُ إِلَى رَبِّي فَجَعَلَهَا عِشْرِينَ ثُمَّ عَشْرَةً ثُمَّ خَمْسَةً فَأَتَيْتُ عَلَى مُوسَى عَلَيْهِ السَّلَام فَقَالَ لِي مِثْلَ مَقَالَتِهِ الْأُولَى فَقُلْتُ إِنِّي أَسْتَحِي مِنْ رَبِّي عَزَّ وَجَلَّ أَنْ أَرْجِعَ إِلَيْهِ فَنُودِيَ أَنْ قَدْ أَمْضَيْتُ فَرِيضَتِي وَخَفَّفْتُ عَنْ عِبَادِي وَأَجْزِي بِالْحَسَنَةِ عَشْرَ أَمْثَالِهَا","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; Telah menceritakan kepada kami [Hisyam Ad-Dastawaa'i] dia berkata; Telah menceritakan kepada kami [Qatadah] dari [Anas bin Malik] dari [Malik bin Sha'sha'ah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Ketika saya di depan Ka'bah antara tidur dan terjaga, tiba-tiba datang salah satu dari tiga orang yang ada di tengah-tengah dengan membawa ember emas yang isinya penuh hikmah dan iman, maka ia membelahku dari kerongkongan sampai perut, kemudian mencuci hati dengan air zamzam, lalu diisi hikmah dan iman. Lantas aku didatangkan seekor hewan tunggangan yang lebih kecil dari baghal (hewan hasil perkawinan silang antara kuda dan keledai-penerj) dan lebih besar dari keledai. Selanjutnya aku diajak pergi oleh Jibril Alaihis Salam. Kami sampai ke langit dunia, lalu kami ditanya, Siapa ini? 'dia menjawab, Jibril. Lalu ditanya lagi, \"siapa yang bersamamu?\" Jibril menjawab, 'Muhammad'. Dia ditanya lagi, dia sudah diutus kepada-Nya? Selamat datang, tamu mulia telah datang! Lalu aku mendatangi Adam? laihis Salam dan mengucapkan salam kepadanya, dia berkata, Selamat datang putra dan nabiku! Kemudian kami datang ke langit kedua dan ditanya, Siapa ini? Jibril menjawab, 'Jibril'. Ditanya lagi, 'Siapa yang bersamamu? Ia menjawab, 'Muhammad'. Lalu terjadilah apa yang terjadi saat bersama Adam. Aku datang kepada Yahya dan Isa dan mengucapkan salam kepada keduanya, lalu keduanya menjawab, Selamat datang wahai saudara dan nabi yang mulia! Selanjutnya kami datang ke langit yang ketiga, dan dia (Jibril) ditanya, 'Siapa ini? Ia menjawab, 'Jibril'. Lalu ditanya lagi, 'Siapa yang bersamamu? Ia menjawab 'Muhammad'. Lalu terjadilah hal yang sama dengan yang sebelumnya. Lalu aku bertemu dengan Yusuf Alaihis Salam, dan kuucapkan salam kepadanya, lalu ia menjawab; 'Selamat datang wahai saudaraku dan Nabi yang mulia! Kemudian kami sampai ke langit yang keempat dan terjadi seperti yang terjadi pada sebelumnya, aku datang kepada Idris Alaihis Salam, dan kuucapkan salam kepadanya, lalu ia menjawab, 'Selamat datang wahai saudaraku dan nabi yang mulia. Kemudian kami datang ke langit yang kelima dan terjadi seperti yang sebelumnya, aku datang kepada Harun Alaihis Salam dan kuucapkan salam kepadanya, lalu dia menjawab. Selamat datang saudara dan nabiku! Lalu kami datang ke langit yang ke enam, dan terjadi seperti itu juga, dan aku datang kepada Musa? laihis Salam dan aku ucapkan salam kepadanya, lalu ia menjawab, 'Selamat datang wahai saudaraku dan nabi yang mulia!. Setelah aku melewatinya, ia menangis, maka ia ditanya, 'Kenapa kamu menangis? 'Ia menjawab, 'Wahai Tuhanku, pemuda ini diutus setelah masaku, namun umatnya yang masuk surga lebih banyak dan lebih utama dari pada umatku. Kemudian kami datang ke langit ke tujuh dan juga terjadi seperti yang sebelumnya, aku datang kepada Ibrahim? laihis Salam dan kuucapkan salam kepadanya, lalu ia menjawab, 'Selamat datang wahai puteraku dan nabi yang mulia! Kemudian aku diangkat ke Baitul Makmur. Aku bertanya kepada Jibril tentang hal itu, dan ia menjawab, 'Inilah Baitul Makmur. Pada tiap hari ada tujuh puluh ribu malaikat yang shalat di dalamnya. Bila mereka keluar daripadanya, mereka tak kembali lagi. Kemudian aku diangkat ke Sidratul Muntaha, dan aku mendapati pohon yang buahnya besar seperti tempayan, daunnya seperti telinga gajah, dan di dasarnya ada empat sungai. Dua sungai yang tersembunyi dan dua sungai yang nampak jelas. Maka aku bertanya kepada Jibril, diapun menjawab; Adapun dua sungai yang tersembunyi dia adalah sungai dalam surga, sedangkan dua sungai yang nampak jelas adalah sungai Eufrat dan sungai Nil. Kemudian diwajibkan shalat lima puluh kali kepadaku. Aku kemudian datang kepada Musa, dan dia berkata, 'Apa yang engkau perbuat? Aku menjawab, 'Telah diwajibkan kepadaku shalat lima puluh kali. 'Dia berkata, 'Aku lebih mengetahui keadaan manusia dari pada kamu. Aku telah mencoba sekuat tenaga pada Bani Israil. Umatmu tidak akan mampu mengembannya, maka kembalilah ke Rabbmu dan mintalah keringanan kepada-Nya'. Maka Aku kembali lagi ke Rabbku dan aku meminta keringanan kepada-Nya, dan Allah menguranginya menjadi empat puluh kali. Kemudian aku kembali ke Musa? laihis Salam dan ia berkata, 'Apa yang kamu perbuat? 'Aku menjawab, 'Dia menguranginya menjadi empat puluh kali. Lalu dia berkata seperti perkataannya yang pertama kali, maka aku kembali lagi ke Rabbku Azza wa Jalla. Dan Dia menguranginya menjadi tiga puluh. Lantas aku datang kepada Musa Alaihis salam untuk memberitahukannya, dan dia berkata seperti perkataan yang semula. Aku lalu kembali lagi ke Rabbku dan Dia menguranginya menjadi dua puluh kali. Kemudian sepuluh kali, dan terakhir menjadi lima kali. Lalu aku datang kepada Musa Alaihis salam, dan beliau berkata seperti perkataannya yang pertama, namun aku malu untuk kembali kepada Allah Azza wa Jalla.\" Lalu dia (Nabi Muhammad shallallahu 'alaihi wasallam) diseru \"Telah kutetapkan kewajiban-Ku, telah kuringankan hamba-Ku, dan akan dibalas tiap kebaikan dengan sepuluh pahala. "},"444":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَنَسُ بْنُ مَالِكٍ وَابْنُ حَزْمٍقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَضَ اللَّهُ عَزَّ وَجَلَّ عَلَى أُمَّتِي خَمْسِينَ صَلَاةً فَرَجَعْتُ بِذَلِكَ حَتَّى أَمُرَّ بِمُوسَى عَلَيْهِ السَّلَام فَقَالَ مَا فَرَضَ رَبُّكَ عَلَى أُمَّتِكَ قُلْتُ فَرَضَ عَلَيْهِمْ خَمْسِينَ صَلَاةً قَالَ لِي مُوسَى فَرَاجِعْ رَبَّكَ عَزَّ وَجَلَّ فَإِنَّ أُمَّتَكَ لَا تُطِيقُ ذَلِكَ فَرَاجَعْتُ رَبِّي عَزَّ وَجَلَّ فَوَضَعَ شَطْرَهَا فَرَجَعْتُ إِلَى مُوسَى فَأَخْبَرْتُهُ فَقَالَ رَاجِعْ رَبَّكَ فَإِنَّ أُمَّتَكَ لَا تُطِيقُ ذَلِكَ فَرَاجَعْتُ رَبِّي عَزَّ وَجَلَّ فَقَالَ هِيَ خَمْسٌ وَهِيَ خَمْسُونَ لَا يُبَدَّلُ الْقَوْلُ لَدَيَّ فَرَجَعْتُ إِلَى مُوسَى فَقَالَ رَاجِعْ رَبَّكَ فَقُلْتُ قَدْ اسْتَحْيَيْتُ مِنْ رَبِّي عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la] dia berkata; Telah menceritakan kepada kami [Ibnu Wahab] dia berkata; Telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab], [Anas bin Malik] dan [Ibnu Hazm] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Azza wa Jalla mewajibkan umatku shalat lima puluh kali, lalu aku kembali melewati nabi Musa? laihis Salam dan berkata apa yang Allah wajibkan kepada umatmu? ` aku menjawab `Allah mewajibkan mereka shalat lima puluh kali`. Musa berkata kepadaku kembalilah ke Rabbmu Azza wa Jalla, karena umatmu tidak akan mampu mengembannya`. Lalu aku kembali kepada Rabbku, dan dia memotong separuhnya. Kemudian aku kembali kepada Musa? laihis Salam dan kuberitahu hasilnya. Ia berkata, `kembali ke Rabb-mu, karena umatmu tidak akan mampu mengembannya`. Lalu aku kembali lagi ke Rabbku Azza wa Jalla dan Allah berfirman: ` (shalat) itu lima kali dan itu (sama dengan) lima puluh kali. Ini ketetapan-Ku yang tidak akan Ku-ganti lagi kemudian aku kembali lagi ke Musa? laihis Salam dan dia berkata; kembali lagi ke Rabbmu dan aku berkata, `Aku malu terhadap Rabbku Azza Wa Jalla. "},"445":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ هِشَامٍ قَالَ حَدَّثَنَا مَخْلَدٌ عَنْ سَعِيدِ بْنِ عَبْدِ الْعَزِيزِ قَالَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي مَالِكٍ قَالَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُتِيتُ بِدَابَّةٍ فَوْقَ الْحِمَارِ وَدُونَ الْبَغْلِ خَطْوُهَا عِنْدَ مُنْتَهَى طَرْفِهَا فَرَكِبْتُ وَمَعِي جِبْرِيلُ عَلَيْهِ السَّلَام فَسِرْتُ فَقَالَ انْزِلْ فَصَلِّ فَفَعَلْتُ فَقَالَ أَتَدْرِي أَيْنَ صَلَّيْتَ صَلَّيْتَ بِطَيْبَةَ وَإِلَيْهَا الْمُهَاجَرُ ثُمَّ قَالَ انْزِلْ فَصَلِّ فَصَلَّيْتُ فَقَالَ أَتَدْرِي أَيْنَ صَلَّيْتَ صَلَّيْتَ بِطُورِ سَيْنَاءَ حَيْثُ كَلَّمَ اللَّهُ عَزَّ وَجَلَّ مُوسَى عَلَيْهِ السَّلَام ثُمَّ قَالَ انْزِلْ فَصَلِّ فَنَزَلْتُ فَصَلَّيْتُ فَقَالَ أَتَدْرِي أَيْنَ صَلَّيْتَ صَلَّيْتَ بِبَيْتِ لَحْمٍ حَيْثُ وُلِدَ عِيسَى عَلَيْهِ السَّلَام ثُمَّ دَخَلْتُ بَيْتَ الْمَقْدِسِ فَجُمِعَ لِي الْأَنْبِيَاءُ عَلَيْهِمْ السَّلَام فَقَدَّمَنِي جِبْرِيلُ حَتَّى أَمَمْتُهُمْ ثُمَّ صُعِدَ بِي إِلَى السَّمَاءِ الدُّنْيَا فَإِذَا فِيهَا آدَمُ عَلَيْهِ السَّلَام ثُمَّ صُعِدَ بِي إِلَى السَّمَاءِ الثَّانِيَةِ فَإِذَا فِيهَا ابْنَا الْخَالَةِ عِيسَى وَيَحْيَى عَلَيْهِمَا السَّلَام ثُمَّ صُعِدَ بِي إِلَى السَّمَاءِ الثَّالِثَةِ فَإِذَا فِيهَا يُوسُفُ عَلَيْهِ السَّلَام ثُمَّ صُعِدَ بِي إِلَى السَّمَاءِ الرَّابِعَةِ فَإِذَا فِيهَا هَارُونُ عَلَيْهِ السَّلَام ثُمَّ صُعِدَ بِي إِلَى السَّمَاءِ الْخَامِسَةِ فَإِذَا فِيهَا إِدْرِيسُ عَلَيْهِ السَّلَام ثُمَّ صُعِدَ بِي إِلَى السَّمَاءِ السَّادِسَةِ فَإِذَا فِيهَا مُوسَى عَلَيْهِ السَّلَام ثُمَّ صُعِدَ بِي إِلَى السَّمَاءِ السَّابِعَةِ فَإِذَا فِيهَا إِبْرَاهِيمُ عَلَيْهِ السَّلَام ثُمَّ صُعِدَ بِي فَوْقَ سَبْعِ سَمَوَاتٍ فَأَتَيْنَا سِدْرَةَ الْمُنْتَهَى فَغَشِيَتْنِي ضَبَابَةٌ فَخَرَرْتُ سَاجِدًا فَقِيلَ لِي إِنِّي يَوْمَ خَلَقْتُ السَّمَوَاتِ وَالْأَرْضَ فَرَضْتُ عَلَيْكَ وَعَلَى أُمَّتِكَ خَمْسِينَ صَلَاةً فَقُمْ بِهَا أَنْتَ وَأُمَّتُكَ فَرَجَعْتُ إِلَى إِبْرَاهِيمَ فَلَمْ يَسْأَلْنِي عَنْ شَيْءٍ ثُمَّ أَتَيْتُ عَلَى مُوسَى فَقَالَ كَمْ فَرَضَ اللَّهُ عَلَيْكَ وَعَلَى أُمَّتِكَ قُلْتُ خَمْسِينَ صَلَاةً قَالَ فَإِنَّكَ لَا تَسْتَطِيعُ أَنْ تَقُومَ بِهَا أَنْتَ وَلَا أُمَّتُكَ فَارْجِعْ إِلَى رَبِّكَ فَاسْأَلْهُ التَّخْفِيفَ فَرَجَعْتُ إِلَى رَبِّي فَخَفَّفَ عَنِّي عَشْرًا ثُمَّ أَتَيْتُ مُوسَى فَأَمَرَنِي بِالرُّجُوعِ فَرَجَعْتُ فَخَفَّفَ عَنِّي عَشْرًا ثُمَّ رُدَّتْ إِلَى خَمْسِ صَلَوَاتٍ قَالَ فَارْجِعْ إِلَى رَبِّكَ فَاسْأَلْهُ التَّخْفِيفَ فَإِنَّهُ فَرَضَ عَلَى بَنِي إِسْرَائِيلَ صَلَاتَيْنِ فَمَا قَامُوا بِهِمَا فَرَجَعْتُ إِلَى رَبِّي عَزَّ وَجَلَّ فَسَأَلْتُهُ التَّخْفِيفَ فَقَالَ إِنِّي يَوْمَ خَلَقْتُ السَّمَوَاتِ وَالْأَرْضَ فَرَضْتُ عَلَيْكَ وَعَلَى أُمَّتِكَ خَمْسِينَ صَلَاةً فَخَمْسٌ بِخَمْسِينَ فَقُمْ بِهَا أَنْتَ وَأُمَّتُكَ فَعَرَفْتُ أَنَّهَا مِنْ اللَّهِ تَبَارَكَ وَتَعَالَى صِرَّى فَرَجَعْتُ إِلَى مُوسَى عَلَيْهِ السَّلَام فَقَالَ ارْجِعْ فَعَرَفْتُ أَنَّهَا مِنْ اللَّهِ صِرَّى أَيْ حَتْمٌ فَلَمْ أَرْجِعْ","id":"Telah mengabarkan kepada kami [Amr bin Hisyam] dia berkata; Telah menceritakan kepada kami [Makhlad] dari [Sa'id bin Abdul Aziz] dia berkata; Telah menceritakan kepada kami [Yazid bin Abu Malik] dia berkata; Telah menceritakan kepada kami [Anas bin Malik] bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Aku diberi seekor hewan tunggangan yang lebih kecil dari baghal (hewan hasil perkawinan silang antara kuda dan keledai - penerj) dan lebih besar dari keledai yang langkahnya secepat mata memandang. Aku dan Jibril? laihis Salam naik ke atasnya, dan kamipun berjalan. Kemudian Jibril? laihis Salam berkata; 'Turun dan shalatlah!. Lalu akupun shalat. Dia (Jibril? laihis Salam) bertanya; Tahukah kamu di mana kamu shalat?. kamu shalat di Thaibah, yang ke sanalah orang-orang hendaknya pergi berhijrah. Kemudian Jibril? laihis Salam berkata lagi; \"Turun dan shalatlah!\". Lalu akupun shalat. Jibril? laihis Salam bertanya, Tahukah kamu dimana kamu shalat?, sesungguhnya kamu shalat di Tursina', yang di situlah Allah berbicara kepada Musa? laihis Salam. Kemudian Jibril? laihis Salam berkata; \"Turun dan Shalatlah!. Maka aku turun dan shalat. Dia bertanya lagi tahukah kamu dimana kamu shalat?, kamu shalat di Baitul Lahm, yang di situlah Isa? laihis Salam dilahirkan. Kemudian aku masuk ke Baitul Maqdis, dan dikumpulkanlah para Nabi 'Alaihimus Salam bagiku. Lalu aku disuruh Jibril? laihis Salam untuk maju mengimami mereka. Selanjutnya aku diajak naik ke langit dunia dan di sana ada Adam? laihis Salam. Lalu aku diajak naik ke langit yang kedua, dan ternyata di sana ada Isa dan Yahya Alaihimus Salam. Lalu aku diajak ke langit yang ketiga, dan ternyata di sana ada Yusuf? laihis Salam. Kemudian aku diajak ke langit yang ke empat, dan ternyata di sana ada Harun? laihis Salam. Lalu aku diajak ke langit yang ke lima, dan ternyata di sana ada Idris? laihis Salam. Selanjutnya aku diajak ke langit yang ke enam, dan ternyata di sana ada Musa? laihis Salam. Lalu aku diajak ke langit yang ke tujuh, dan ternyata di sana ada Ibrahim? laihis Salam. Kemudian aku diangkat ke atas tujuh langit hingga kami sampai di Sidratul Muntaha, dan tiba-tiba awan menutupiku akupun tersungkur sujud, lalu dikatakan kepadaku: Sesungguhnya pada hari Aku menciptakan langit dan bumi, Aku mewajibkan shalat lima puluh kali kepadamu dan kepada umatmu, maka kerjakanlah olehmu dan oleh umatmu, lalu aku kembali menemui Ibrahim, namun dia tidak memintaku sesuatupun, kemudian aku menemui Musa, dan dia bertanya kepadaku; 'Berapa jumlah kewajiban yang Allah tetapkan kepadamu dan umatmu, aku menjawab: Shalat lima puluh kali. Musa berkata; engkau dan umatmu tidak akan mampu melaksanakannya, kembalilah kepada Rabbmu dan mintalah kepada-Nya keringanan. Aku pun kembali kepada Rabbku, lalu Dia menguranginya sepuluh, lalu aku menemui Musa, namun ia menyuruhku kembali, aku pun kembali dan Allah mengurangi lagi sepuluh, hal itu terjadi berulang-ulang hingga akhirnya menjadi lima kali. Tapi Musa tetap menyuruhku kembali meminta keringanan, sebagaimana Allah wajibkan kepada bani Israil dua kali shalat, itupun mereka tidak mampu melaksanakannya, lalu aku kembali kepada Rabbku agar menguranginya lagi, Allah menjawab: Sesungguhnya ketika aku menciptakan langit dan bumi, Aku mewajibkan shalat lima puluh kali kepadamu dan umatmu, maka yang lima kali ini sama nilainya dengan lima puluh kali, kerjakanlah olehmu dan umatmu. Akupun menyadari bahwa perintah itu dari Allah Tabaraka wa Ta'ala. Lalu Aku kembali kepada Musa? laihis Salam, Ia pun berkata; Kembalilah. Tapi aku tidak kembali lagi karena itu adalah ketetapan Allah yang sudah pasti.\""},"446":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ عَنْ مُرَّةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا أُسْرِيَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْتُهِيَ بِهِ إِلَى سِدْرَةِ الْمُنْتَهَى وَهِيَ فِي السَّمَاءِ السَّادِسَةِ وَإِلَيْهَا يَنْتَهِي مَا عُرِجَ بِهِ مِنْ تَحْتِهَا وَإِلَيْهَا يَنْتَهِي مَا أُهْبِطَ بِهِ مِنْ فَوْقِهَا حَتَّى يُقْبَضَ مِنْهَا قَالَ{ إِذْ يَغْشَى السِّدْرَةَ مَا يَغْشَى }قَالَ فَرَاشٌ مِنْ ذَهَبٍ فَأُعْطِيَ ثَلَاثًا الصَّلَوَاتُ الْخَمْسُ وَخَوَاتِيمُ سُورَةِ الْبَقَرَةِ وَيُغْفَرُ لِمَنْ مَاتَ مِنْ أُمَّتِهِ لَا يُشْرِكُ بِاللَّهِ شَيْئًا الْمُقْحِمَاتُ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; Telah menceritakan kepada kami [Yahya bin Adam] dia berkata; Telah menceritakan kepada kami [Malik bin Mighwal] dari [Zubair bin 'Adi] dari [Thalhah bin Musharrif] dari [Murrah] dari [Abdulah] dia berkata; \" Ketika Rasulullah shallallahu 'alaihi wasallam diisra'kan beliau sampai ke Sidratul Muntaha, yaitu satu tempat di langit yang ke enam dan sampai di situlah berakhirnya semua yang naik dari bawah dan sampai di situ pula semua yang turun dari atas hingga dapat terpegang. Nabi shallallahu 'alaihi wasallam kemudian membacakan ayat: \"Ketika Sidratul Muntaha diliputi oleh sesuatu yang meliputinya\" (Qs. An-Najm (53): 16) Rasulullah shallallahu 'alaihi wasallam bersabda: \" (Yang meliputi Sidratul Muntaha) adalah kupu-kupu dari emas, lalu aku diberi tiga hal, yaitu shalat lima waktu, akhir-akhir surat Al Baqarah, dan orang yang mati dari umatku diampuni, asalkan tidak menyekutukan Allah Azza Wa Jalla dengan sesuatupun.\" "},"447":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ عَبْدَ رَبِّهِ بْنَ سَعِيدٍ حَدَّثَهُ أَنَّ الْبُنَانِيَّ حَدَّثَهُ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ الصَّلَوَاتِ فُرِضَتْ بِمَكَّةَ وَأَنَّ مَلَكَيْنِ أَتَيَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَهَبَا بِهِ إِلَى زَمْزَمَ فَشَقَّا بَطْنَهُ وَأَخْرَجَا حَشْوَهُ فِي طَسْتٍ مِنْ ذَهَبٍ فَغَسَلَاهُ بِمَاءِ زَمْزَمَ ثُمَّ كَبَسَا جَوْفَهُ حِكْمَةً وَعِلْمًا","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud] dari [Ibnu Wahab] dia berkata; Telah mengabarkan kepadaku [Amr bin Al Haritst] bahwa seorang budak tuannya - [Ibnu Sa'id] - berkata kepadanya; Sesungguhnya [Al Bunani] berkata kepadanya, dari [Anas bin Malik] bahwa shalat diwajibkan di Makkah, dan ada dua Malaikat datang kepada Rasulullah shallallahu 'alaihi wasallam. Keduanya pergi membawa Rasulullah shallallahu 'alaihi wasallam ke sumur zamzam, lalu membelah perutnya dan mencuci dengan air zamzam. Setelah itu memasukkan ke dalam hatinya hikmah dan ilmu. "},"448":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْأَوَّلَ مَا فُرِضَتْ الصَّلَاةُ رَكْعَتَيْنِ فَأُقِرَّتْ صَلَاةُ السَّفَرِ وَأُتِمَّتْ صَلَاةُ الْحَضَرِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Sufyan] dari [Az-Zuhri] dari [Urwah] dari [Aisyah] Radliyallahu'anha dia berkata; \" Shalat yang pertama kali diwajibkan adalah dua raka'at. Lalu ditetapkan untuk shalat dalam perjalanan, dan disempurnakan (menjadi empat raka'at) shalat bagi yang menetap (tidak bepergian). "},"449":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ هَاشِمٍ الْبَعْلَبَكِّيُّ قَالَ أَنْبَأَنَا الْوَلِيدُ قَالَ أَخْبَرَنِي أَبُو عَمْرٍو يَعْنِي الْأَوْزَاعِيَّأَنَّهُ سَأَلَ الزُّهْرِيَّ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ قَبْلَ الْهِجْرَةِ إِلَى الْمَدِينَةِ قَالَ أَخْبَرَنِي عُرْوَةُ عَنْ عَائِشَةَ قَالَتْ فَرَضَ اللَّهُ عَزَّ وَجَلَّ الصَّلَاةَ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَّلَ مَا فَرَضَهَا رَكْعَتَيْنِ رَكْعَتَيْنِ ثُمَّ أُتِمَّتْ فِي الْحَضَرِ أَرْبَعًا وَأُقِرَّتْ صَلَاةُ السَّفَرِ عَلَى الْفَرِيضَةِ الْأُولَى","id":"Telah mengabarkan kepada kami [Muhammad bin Hasyim AlBa'labaki] dia berkata; Telah memberitakan kepada kami [Al Walid] dia berkata; Telah mengabarkan kepadaku [Abu Amr yaitu Al Auza`i] bahwa ia pernah bertanya kepada Az-Zuhri cara shalat Rasulullah shallallahu 'alaihi wasallam saat di Makkah (sebelum hijrah ke Madinah). [Az-Zuhri] menjawab; Telah mengabarkanku [Urwah] dari [Aisyah] Radliyallahu'anha dia berkata; \" Allah Azza Wa Jalla mewajibkan shalat kepada Rasulullah shallallahu 'alaihi wasallam yang pertama kalinya sebanyak dua raka'at, kemudian disempurnakan menjadi empat raka'at bagi yang menetap, dan ditetapkan shalat safar dua raka'at seperti awal mulanya. "},"450":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْفُرِضَتْ الصَّلَاةُ رَكْعَتَيْنِ رَكْعَتَيْنِ فَأُقِرَّتْ صَلَاةُ السَّفَرِ وَزِيدَ فِي صَلَاةِ الْحَضَرِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Shalih bin Kaisan] dari [Urwah] dari [Aisyah] Radliyallahu'anha dia berkata; \" Telah diwajibkan shalat, dua raka'at-dua raka'at, maka ditetapkan untuk shalat safar, dan ditambah (dua raka'at) shalat bagi yang tidak bepergian. "},"451":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى وَعَبْدُ الرَّحْمَنِ قَالَا حَدَّثَنَا أَبُو عَوَانَةَ عَنْ بُكَيْرِ بْنِ الْأَخْنَسِ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَفُرِضَتْ الصَّلَاةُ عَلَى لِسَانِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْحَضَرِ أَرْبَعًا وَفِي السَّفَرِ رَكْعَتَيْنِ وَفِي الْخَوْفِ رَكْعَةً","id":"Telah mengabarkan kepada kami [Amr bin Ali] dia berkata; Telah menceritakan kepada kami [yahya] dan [Abdurrahman] keduanya berkata; Telah menceritakan kepada kami [Abu 'Awanah] dari [Bukair bin Al Akhnas] dari [Mujahid] dari [Ibnu Abbas] dia berkata; \" Shalat diwajibkan lewat lisan Rasulullah shallallahu 'alaihi wasallam bagi yang tidak berpergian empat raka'at, dalam keadaan safar dua raka'at, dalam keadaan takut satu raka'at. "},"452":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الشُّعَيْثِيُّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أُمَيَّةَ بْنِ عَبْدِ اللَّهِ بْنِ خَالِدِ بْنِ أَسِيدٍأَنَّهُ قَالَ لِابْنِ عُمَرَ كَيْفَ تَقْصُرُ الصَّلَاةَ وَإِنَّمَا قَالَ اللَّهُ عَزَّ وَجَلَّ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَقْصُرُوا مِنْ الصَّلَاةِ إِنْ خِفْتُمْ }فَقَالَ ابْنُ عُمَرَ يَا ابْنَ أَخِي إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَانَا وَنَحْنُ ضُلَّالٌ فَعَلَّمَنَا فَكَانَ فِيمَا عَلَّمَنَا أَنَّ اللَّهَ عَزَّ وَجَلَّ أَمَرَنَا أَنْ نُصَلِّيَ رَكْعَتَيْنِ فِي السَّفَرِقَالَ الشُّعَيْثِيُّ وَكَانَ الزُّهْرِيُّ يُحَدِّثُ بِهَذَا الْحَدِيثِ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ","id":"Telah mengabarkan kepada kami [Yusuf bin Sa'id] dia berkata; Telah menceritakan kepada kami [Hajaj bin Muhammad] dia berkata; Telah menceritakan kepada kami [Muhammad bin Abdullah As-Syu'atsi] dari [Abdullah bin Abu Bakr bin Al Harits bin Hisyam] dari [Umayah bin Abdullah bin khalid bin Usaid] bahwa dia pernah bertanya kepada Ibnu Umar, bagaimana engkau menqashar (meringkas) shalat, sedang Allah Azza Wa Jalla berfirman: Tidak ada dosa bagi kalian untuk menqashar (meringkas) shalat jika kalian dalam keadaan takut? [Ibnu Umar] berkata; wahai anak saudaraku, Rasulullah shallallahu 'alaihi wasallam datang kepada kami dan kami dalam keadaan tersesat, maka Rasulullah shallallahu 'alaihi wasallam mengajari kami, dan yang diajarkan antara lain adalah Allah Azza Wa Jalla memerintah shalat dua raka'at bila kita dalam perjalanan. Asyu'atsi berkata; [Az-Zuhri] pernah mengatakan hadits ini dari [Abdullah bin Abu Bakr]. "},"453":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ أَبِي سُهَيْلٍ عَنْ أَبِيهِ أَنَّهُ سَمِعَ طَلْحَةَ بْنَ عُبَيْدِ اللَّهِ يَقُولُجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَهْلِ نَجْدٍ ثَائِرَ الرَّأْسِ نَسْمَعُ دَوِيَّ صَوْتِهِ وَلَا نَفْهَمُ مَا يَقُولُ حَتَّى دَنَا فَإِذَا هُوَ يَسْأَلُ عَنْ الْإِسْلَامِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمْسُ صَلَوَاتٍ فِي الْيَوْمِ وَاللَّيْلَةِ قَالَ هَلْ عَلَيَّ غَيْرُهُنَّ قَالَ لَا إِلَّا أَنْ تَطَّوَّعَ قَالَ وَصِيَامُ شَهْرِ رَمَضَانَ قَالَ هَلْ عَلَيَّ غَيْرُهُ قَالَ لَا إِلَّا أَنْ تَطَّوَّعَ وَذَكَرَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الزَّكَاةَ قَالَ هَلْ عَلَيَّ غَيْرُهَا قَالَ لَا إِلَّا أَنْ تَطَّوَّعَ فَأَدْبَرَ الرَّجُلُ وَهُوَ يَقُولُ وَاللَّهِ لَا أَزِيدُ عَلَى هَذَا وَلَا أَنْقُصُ مِنْهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْلَحَ إِنْ صَدَقَ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abu Suhail] dari [Bapaknya] bahwa dia mendengar [Thalhah bin Ubaidillah] berkata; Seseorang yang rambutnya acak-acakan -dari penduduk Najed- datang kepada Rasulullah shallallahu 'alaihi wasallam. Kami mendengar logat suaranya, tetapi kami tidak paham dengan perkataannya hingga dia mendekat dan ternyata dia bertanya tentang Islam. Maka Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: Shalat lima kali sehari semalam. Dia bertanya lagi; Apakah ada kewajiban bagiku selainnya? Rasulullah menjawab: Tidak ada kecuali kamu mau melakukan sunnah-sunnahnya. Rasulullah menambahkan puasa bulan Ramadhan, dia berkata apakah ada kewajiban lain bagiku? Rasulullah menjawab; Tidak ada kecuali kamu mau melakukannya secara sukarela (puasa sunnah). Selanjutnya Rasulullah shallallahu 'alaihi wasallam menyebutkan tentang zakat dan dia berkata; Apakah ada kewajiban yang lain bagiku? Rasul shallallahu 'alaihi wasallam menjawab: Tidak, kecuali kamu mau melakukannya secara sukarela. Kemudian dia mundur ke belakang sambil berkata; Demi Allah aku tidak akan menambah atau mengurangi hal tersebut. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dia selamat jika jujur.\" "},"454":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا نُوحُ بْنُ قَيْسٍ عَنْ خَالِدِ بْنِ قَيْسٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَسَأَلَ رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ كَمْ افْتَرَضَ اللَّهُ عَزَّ وَجَلَّ عَلَى عِبَادِهِ مِنْ الصَّلَوَاتِ قَالَ افْتَرَضَ اللَّهُ عَلَى عِبَادِهِ صَلَوَاتٍ خَمْسًا قَالَ يَا رَسُولَ اللَّهِ هَلْ قَبْلَهُنَّ أَوْ بَعْدَهُنَّ شَيْئًا قَالَ افْتَرَضَ اللَّهُ عَلَى عِبَادِهِ صَلَوَاتٍ خَمْسًا فَحَلَفَ الرَّجُلُ لَا يَزِيدُ عَلَيْهِ شَيْئًا وَلَا يَنْقُصُ مِنْهُ شَيْئًا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ صَدَقَ لَيَدْخُلَنَّ الْجَنَّةَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Nuh bin Qais] dari [Khalid bin Qais] dari [Qatadah] dari [Anas] dia berkata; \"Ada seorang laki-laki yang bertanya pada Rasulullah shallallahu 'alaihi wasallam.\"Wahai Rasulullah shallallahu 'alaihi wasallam, berapa kali Allah Azza Wa Jalla mewajibkan shalat kepada hamba-Nya?\". Beliau shallallahu 'alaihi wasallam menjawab; \"Allah Azza Wa Jalla mewajibkan shalat lima kali (waktu) kepada hamba-Nya\". Dia bertanya lagi, wahai Rasulullah shallallahu 'alaihi wasallam, apakah ada sesuatu (yang harus dikerjakan) sebelum dan sesudah lima waktu ini?\" Rasulullah shallallahu 'alaihi wasallam menjawab, \"Allah Azza WA Jalla mewajibkan shalat kepada hamba-Nya lima kali.\" Laki-laki tersebut bersumpah untuk tidak menambah atau menguranginya sedikitpun. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika dia benar, maka pasti masuk surga.\" "},"455":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا أَبُو مُسْهِرٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الْعَزِيزِ عَنْ رَبِيعَةَ بْنِ يَزِيدَ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي مُسْلِمٍ الْخَوْلَانِيِّ قَالَ أَخْبَرَنِي الْحَبِيبُ الْأَمِينُ عَوْفُ بْنُ مَالِكٍ الْأَشْجَعِيُّ قَالَكُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَا تُبَايِعُونَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَدَّدَهَا ثَلَاثَ مَرَّاتٍ فَقَدَّمْنَا أَيْدِيَنَا فَبَايَعْنَاهُ فَقُلْنَا يَا رَسُولَ اللَّهِ قَدْ بَايَعْنَاكَ فَعَلَامَ قَالَ عَلَى أَنْ تَعْبُدُوا اللَّهَ وَلَا تُشْرِكُوا بِهِ شَيْئًا وَالصَّلَوَاتِ الْخَمْسِ وَأَسَرَّ كَلِمَةً خَفِيَّةً أَنْ لَا تَسْأَلُوا النَّاسَ شَيْئًا","id":"Telah mengabarkan kepada kami [Amr bin Manshur] dia berkata; Telah menceritakan kepada kami [Abu Mushir] dia berkata; Telah menceritakan kepada kami [Sa'id bin Abdul Aziz] dari [Rabi'ah bin Yazid] dari [Abu Idris Al Khaulani] dari [Abu Muslim Al Khaulani] dia berkata; Telah mengabarkan kepadaku [Al Habib Al Amin Auf bin Malik Al Asyja`i] dia berkata; \"Kami dahulu di sisi Rasulullah shallallahu 'alaihi wasallam lalu beliau shallallahu 'alaihi wasallam bersabda: \"Maukah kalian berbaiat kepada Rasulullah shallallahu 'alaihi wasallam? Beliau shallallahu 'alaihi wasallam mengulangi sampai tiga kali, kemudian kami menyodorkan tangan-tangan kami dan selanjutnya kami berbaiat kepadanya. Kami bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \" wahai Rasulullah shallallahu 'alaihi wasallam kami telah berbaiat kepadamu, lantas untuk apa kami berbaiat kepadamu?\" Beliau shallallahu 'alaihi wasallam menjawab: Untuk beribadah hanya kepada Allah dan tidak menyekutukan-Nya dengan sesuatupun, shalat lima waktu - dan seraya melirihkan suara beliau bersabda - serta untuk tidak meminta-minta kepada manusia sesuatupun.\" "},"456":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ ابْنِ مُحَيْرِيزٍ أَنَّ رَجُلًا مِنْ بَنِي كِنَانَةَ يُدْعَى الْمُخْدَجِيَّ سَمِعَ رَجُلًا بِالشَّامِ يُكْنَى أَبَا مُحَمَّدٍ يَقُولُ الْوِتْرُ وَاجِبٌ قَالَ الْمُخْدَجِيُّفَرُحْتُ إِلَى عُبَادَةَ بْنِ الصَّامِتِ فَاعْتَرَضْتُ لَهُ وَهُوَ رَائِحٌ إِلَى الْمَسْجِدِ فَأَخْبَرْتُهُ بِالَّذِي قَالَ أَبُو مُحَمَّدٍ فَقَالَ عُبَادَةُ كَذَبَ أَبُو مُحَمَّدٍ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ خَمْسُ صَلَوَاتٍ كَتَبَهُنَّ اللَّهُ عَلَى الْعِبَادِ مَنْ جَاءَ بِهِنَّ لَمْ يُضَيِّعْ مِنْهُنَّ شَيْئًا اسْتِخْفَافًا بِحَقِّهِنَّ كَانَ لَهُ عِنْدَ اللَّهِ عَهْدٌ أَنْ يُدْخِلَهُ الْجَنَّةَ وَمَنْ لَمْ يَأْتِ بِهِنَّ فَلَيْسَ لَهُ عِنْدَ اللَّهِ عَهْدٌ إِنْ شَاءَ عَذَّبَهُ وَإِنْ شَاءَ أَدْخَلَهُ الْجَنَّةَ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [Ibnu Muhairiz] bahwa seorang dari Bani Kinanah -biasa dipanggil [Al-Mukhdaji] - telah mendengar seseorang di Syam -yang dijuluki Abu Muhammad- dia berkata; \"Shalat witir adalah wajib.\"Al Mukhdaji berkata: \"Kontan aku segera datang ke Ubadah bin Shamit, kupaparkan kepadanya, juga kuberitahukan apa yang dikatakan oleh Abu Muhammad, sementara dia sedang istirahat di Masjid. ['Ubadah] lalu berkata, \"Abu Muhammad berdusta! Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \" Lima waktu shalat yang telah diwajibkan kepada para hamba-Nya, barangsiapa mengerjakannya tanpa meremehkan hak shalat ini sedikitpun, maka baginya di sisi Allah suatu perjanjian untuk dimasukkan ke surga, dan barangsiapa tidak mengerjakan, dia tidak mempunyai perjanjian dengan Allah sedikitpun. Jika Allah berkehendak, Dia menyiksanya, dan jika berkehendak maka Dia akan memasukkannya ke surga.\" "},"457":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرَأَيْتُمْ لَوْ أَنَّ نَهَرًا بِبَابِ أَحَدِكُمْ يَغْتَسِلُ مِنْهُ كُلَّ يَوْمٍ خَمْسَ مَرَّاتٍ هَلْ يَبْقَى مِنْ دَرَنِهِ شَيْءٌ قَالُوا لَا يَبْقَى مِنْ دَرَنِهِ شَيْءٌ قَالَ فَكَذَلِكَ مَثَلُ الصَّلَوَاتِ الْخَمْسِ يَمْحُو اللَّهُ بِهِنَّ الْخَطَايَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Al-Laits] dari [Ibnu Al Haad] dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Bagaimana pendapatmu jika di depan pintu -rumah- salah seorang dari kalian ada sungai, dia mandi di sungai itu setiap hari lima kali, apakah ada sisa kotoran padanya?\" Mereka menjawab, \"Tidak ada kotoran yang tersisa sedikitpun.\" Beliau shallallahu 'alaihi wasallam berkata: \"Begitulah perumpamaan shalat lima waktu. Allah menghapus dosa-dosa dengan shalat tersebut.\""},"458":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ أَنْبَأَنَا الْفَضْلُ بْنُ مُوسَى عَنْ الْحُسَيْنِ بْنِ وَاقِدٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْعَهْدَ الَّذِي بَيْنَنَا وَبَيْنَهُمْ الصَّلَاةُ فَمَنْ تَرَكَهَا فَقَدْ كَفَرَ","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits] dia berkata; Telah memberitakan kepada kami [Al Fadl bin Musa] dari [Husain bin Waqid] dari [Abdullah bin Buraidah] dari [Bapaknya] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Perjanjian yang ada di antara kita dan mereka (orang-orang kafir) adalah shalat. Barangsiapa meninggalkannya berarti kafir.\""},"459":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ حَدَّثَنَا مُحَمَّدُ بْنُ رَبِيعَةَ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ بَيْنَ الْعَبْدِ وَبَيْنَ الْكُفْرِ إِلَّا تَرْكُ الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Ahmad bin Harb] Telah menceritakan kepada kami [Muhammad bin Rabi'ah] dari [Ibnu Juraij] dari [Abu Jubair] dari [Jabir] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda; \" Tidak ada perbedaan antara hamba dengan kekufuran, kecuali meninggalkan shalat.\""},"460":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا هَارُونُ هُوَ ابْنُ إِسْمَعِيلَ الْخَزَّازُ قَالَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ حُرَيْثِ بْنِ قَبِيصَةَ قَالَقَدِمْتُ الْمَدِينَةَ قَالَ قُلْتُ اللَّهُمَّ يَسِّرْ لِي جَلِيسًا صَالِحًا فَجَلَسْتُ إِلَى أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَ فَقُلْتُ إِنِّي دَعَوْتُ اللَّهَ عَزَّ وَجَلَّ أَنْ يُيَسِّرَ لِي جَلِيسًا صَالِحًا فَحَدِّثْنِي بِحَدِيثٍ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلَّ اللَّهَ أَنْ يَنْفَعَنِي بِهِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ أَوَّلَ مَا يُحَاسَبُ بِهِ الْعَبْدُ بِصَلَاتِهِ فَإِنْ صَلَحَتْ فَقَدْ أَفْلَحَ وَأَنْجَحَ وَإِنْ فَسَدَتْ فَقَدْ خَابَ وَخَسِرَقَالَ هَمَّامٌ لَا أَدْرِي هَذَا مِنْ كَلَامِ قَتَادَةَ أَوْ مِنْ الرِّوَايَةِ فَإِنْ انْتَقَصَ مِنْ فَرِيضَتِهِ شَيْءٌ قَالَ انْظُرُوا هَلْ لِعَبْدِي مِنْ تَطَوُّعٍ فَيُكَمَّلُ بِهِ مَا نَقَصَ مِنْ الْفَرِيضَةِ ثُمَّ يَكُونُ سَائِرُ عَمَلِهِ عَلَى نَحْوِ ذَلِكَ خَالَفَهُ أَبُو الْعَوَّامِ","id":"Telah mengabarkan kepada kami [Abu Daud] dia berkata; Telah menceritakan kepada kami [Harun yaitu Ibnu Ismail Al Khazaz] dia berkata; Telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Al Hasan] dari [Huraits bin Qabishah] dia berkata; \"Aku datang ke Madinah dan berdoa, 'Ya Allah, mudahkanlah bagiku -untuk mendapatkan- teman yang shalih. 'Lalu aku duduk dengan [Abu Hurairah Radliyallahu'anhu], maka aku berkata kepadanya, 'Aku pernah berdoa kepada Allah Azza wa Jalla agar Dia memudahkanku untuk mendapat teman duduk yang shalih, maka ceritakanlah kepadaku hadits yang engkau dengar dari Rasulullah shallallahu 'alaihi wasallam. Semoga Allah memberikan manfaat kepadaku dengan ilmu tersebut. 'Abu Hurairah berkata, 'Aku mendengar dari Rasulullah shallallahu 'alaihi wasallam. bersabda: \" Yang pertama kali dihisab (dihitung) dari perbuatan seorang hamba pada hari kiamat adalah shalat; jika shalatnya baik maka dia beruntung dan selamat, dan jika shalatnya rusak maka dia merugi.\" Hammam (salah satu perawi hadits tersebut) berkata; \"Aku tidak tahu, apakah ini ucapan Qatadah (salah satu perawinya) atau termasuk matan, dia berkata, \"Apabila ada sesuatu yang kurang dari shalat wajibnya, Allah berfirman; maka lihatlah apakah hamba-Ku mempunyai shalat sunnah?\" Lalu kekurangannya dalam shalat fardlu disempurnakan dengannya. Kemudian semua amalan ibadahnya juga seperti itu.\" Abul 'Awwam menyelisihi redaksi ini. "},"461":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعَيْبٌ يَعْنِي ابْنَ بَيَانِ بْنِ زِيَادِ بْنِ مَيْمُونٍ قَالَ كَتَبَ عَلِيُّ بْنُ الْمَدِينِيِّ عَنْهُ أَخْبَرَنَا أَبُو الْعَوَّامِ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَوَّلَ مَا يُحَاسَبُ بِهِ الْعَبْدُ يَوْمَ الْقِيَامَةِ صَلَاتُهُ فَإِنْ وُجِدَتْ تَامَّةً كُتِبَتْ تَامَّةً وَإِنْ كَانَ انْتُقِصَ مِنْهَا شَيْءٌ قَالَ انْظُرُوا هَلْ تَجِدُونَ لَهُ مِنْ تَطَوُّعٍ يُكَمِّلُ لَهُ مَا ضَيَّعَ مِنْ فَرِيضَةٍ مِنْ تَطَوُّعِهِ ثُمَّ سَائِرُ الْأَعْمَالِ تَجْرِي عَلَى حَسَبِ ذَلِكَ","id":"Telah mengabarkan kepada kami [Abu Daud] dia berkata; Telah menceritakan kepada kami [Syu'aib yaitu Ibnu Bayan bin Ziyad bin Maimun] dia berkata; Ali bin Al Madini telah menulis darinya, Telah mengabarkan kepada kami [Abul 'Awwam] dari [Qatadah] dari [Al Hasan] dari [Abu Rafi'] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Yang pertama kali dihisab (dihitung) dari perbuatan seorang hamba pada hari kiamat adalah shalatnya; jika shalatnya sempurna maka ditulis secara sempurna, dan jika shalatnya ada kekurangan (Allah) berkata, 'Lihatlah, apakah kalian dapati ia melakukan shalat sunnah yang dapat melengkapi kekurangan shalat wajibnya? ' Kemudian semua amalan ibadah yang lain juga dihitung seperti itu.\""},"462":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ قَالَ أَنْبَأَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ الْأَزْرَقِ بْنِ قَيْسٍ عَنْ يَحْيَى بْنِ يَعْمَرَ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَوَّلُ مَا يُحَاسَبُ بِهِ الْعَبْدُ صَلَاتُهُ فَإِنْ كَانَ أَكْمَلَهَا وَإِلَّا قَالَ اللَّهُ عَزَّ وَجَلَّ انْظُرُوا لِعَبْدِي مِنْ تَطَوُّعٍ فَإِنْ وُجِدَ لَهُ تَطَوُّعٌ قَالَ أَكْمِلُوا بِهِ الْفَرِيضَةَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah menceritakan kepada kami [An-Nadlr bin Syumail] dia berkata; Telah memberitakan kepada kami [Hammad bin Salamah] dari [Al Azraq bin Qais] dari [Yahya bin Ya'mar] dari [Abu hurairah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Yang pertama kali yang dihisab (dihitung) dari perbuatan seorang hamba pada hari Kiamat adalah shalatnya, jika sempurna (ia beruntung) dan jika tidak (sempurna) maka Allah Azza wa Jalla berkata, ' Lihatlah apakah hamba-Ku mempunyai amalan shalat sunnah? '. Bila didapati ia memiliki amalan shalat sunnah maka Dia berkata 'Lengkapilah shalat wajibnya (yang kurang) dengan shalat sunnahnya'.\""},"463":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُثْمَانَ بْنِ أَبِي صَفْوَانَ الثَّقَفِيُّ قَالَ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عُثْمَانَ بْنِ عَبْدِ اللَّهِ وَأَبُوهُ عُثْمَانُ بْنُ عَبْدِ اللَّهِ أَنَّهُمَا سَمِعَا مُوسَى بْنَ طَلْحَةَ يُحَدِّثُ عَنْ أَبِي أَيُّوبَأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ أَخْبِرْنِي بِعَمَلٍ يُدْخِلُنِي الْجَنَّةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعْبُدَ اللَّهَ وَلَا تُشْرِكَ بِهِ شَيْئًا وَتُقِيمَ الصَّلَاةَ وَتُؤْتِيَ الزَّكَاةَ وَتَصِلَ الرَّحِمَ ذَرْهَا كَأَنَّهُ كَانَ عَلَى رَاحِلَتِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Utsman bin Abu Shafwan Ats-Tsaqafi] dia berkata; Telah menceritakan kepada kami [Bahaz bin Asad] dia berkata; Telah menceritakan kepada kami [Syu'bah] dia berkata; Telah menceritakan kepada kami [Muhammad bin Utsman bin Abdullah] dan Bapaknya [Utsman bin Abdullah] keduanya mendengar [Musa bin Thalhah] berkata; dari [Abu Ayub] bahwa ada seorang laki-laki berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam kabarkan kepadaku tentang amal yang dapat membuatku masuk surga?\" Rasulullah shallallahu 'alaihi wasallam menjawab, ' Beribadah kepada Allah dan jangan menyekutukan-Nya dengan sesuatupun, menegakkan shalat, menunaikan zakat, dan menyambung hubungan silaturrahim -sekarang lepaskanlah unta itu-' sepertinya saat itu beliau shallallahu 'alaihi wasallam di atas kendaraannya (waktu sang penanya bertanya dan menahan untanya).\""},"464":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ الْمُنْكَدِرِ وَإِبْرَاهِيمَ بْنِ مَيْسَرَةَ سَمِعَا أَنَسًا قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ بِالْمَدِينَةِ أَرْبَعًا وَبِذِي الْحُلَيْفَةِ الْعَصْرَ رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Ibnu Al Munkadir] dan [Ibrahim bin Maisarah] keduanya mendengar [Anas] berkata; \" Aku shalat zhuhur empat raka'at bersama Rasulullah shallallahu 'alaihi wasallam di Madinah, dan shalat Ashar dua raka'at di Dzul Hulaifah.\""},"465":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ بْنِ عُتَيْبَةَ قَالَ سَمِعْتُ أَبَا جُحَيْفَةَ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْهَاجِرَةِ قَالَ ابْنُ الْمُثَنَّى إِلَى الْبَطْحَاءِ فَتَوَضَّأَ وَصَلَّى الظُّهْرَ رَكْعَتَيْنِ وَالْعَصْرَ رَكْعَتَيْنِ وَبَيْنَ يَدَيْهِ عَنَزَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basyar] keduanya berkata; Telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; Telah menceritakan kepada kami [Syu'bah] dari [Al Hakam bin 'Utaibah] dia berkata; Saya mendengar [Abu Juhaifah] berkata; \" Rasulullah shallallahu 'alaihi wasallam pernah keluar -pada tengah hari (setelah matahari condong) - Ibnu Mutsanna berkata; ke Bathha, lalu beliau berwudlu dan mengerjakan shalat Zhuhur dua raka'at, juga shalat Ashar dua raka'at, dan dihadapannya ada tombak.\""},"466":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا مِسْعَرٌ وَابْنُ أَبِي خَالِدٍ وَالْبَخْتَرِيُّ بْنُ أَبِي الْبَخْتَرِيِّ كُلُّهُمْ سَمِعُوهُ مِنْ أَبِي بَكْرِ بْنِ عُمَارَةَ بْنِ رُوَيْبَةَ الثَّقَفِيِّ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَنْ يَلِجَ النَّارَ مَنْ صَلَّى قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ غُرُوبِهَا","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] dia berkata; Telah menceritakan kepada kami [Waki'] dia berkata; Telah menceritakan kepada kami [Mis'ar] dan [Ibnu Abu Khalid] dan [Al Bakhtari bin Abu Al Bakhtari] mereka semua mendengarnya dari [Abu Bakr bin 'Umarah bin Ruwaibah Ats-Tsaqafi] dari [Bapaknya] dia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \" Tidak akan masuk neraka orang yang mengerjakan shalat sebelum matahari terbit (subuh) dan shalat sebelum matahari terbenam (Ashar).\""},"467":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي يُونُسَ مَوْلَى عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَأَمَرَتْنِي عَائِشَةُ أَنْ أَكْتُبَ لَهَا مُصْحَفًا فَقَالَتْ إِذَا بَلَغْتَ هَذِهِ الْآيَةَ فَآذِنِّي{ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى }فَلَمَّا بَلَغْتُهَا آذَنْتُهَا فَأَمْلَتْ عَلَيَّ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى وَصَلَاةِ الْعَصْرِ وَقُومُوا لِلَّهِ قَانِتِينَ ثُمَّ قَالَتْ سَمِعْتُهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Zaid bin Aslam] dari [Al Qa'qa' bin Hakim] dari [Abu Yunus] -mantan budak Aisyah istri Rasulullah shallallahu 'alaihi wasallam- dia berkata, \" Aisyah menyuruhku menulis mushhaf untuknya. [Aisyah] berkata, 'Bila kamu sampai pada ayat ini, maka beritahu aku, \"Peliharalah shalat-shalat dan shalat Wushtha\"! Setelah aku sampai pada ayat tersebut, aku memberitahu beliau, maka beliau pun mendektekan kepadaku, 'Peliharalah semua shalat dan shalat Wushtha serta shalat Ashar. Berdirilah karena Allah (dalam shalatmu) dengan khusyu'. Kemudian beliau berkata, 'Aku mendengarnya dari Rasulullah shallallahu 'alaihi wasallam.\" "},"468":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي قَتَادَةُ عَنْ أَبِي حَسَّانَ عَنْ عَبِيدَةَ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ شَغَلُونَا عَنْ الصَّلَاةِ الْوُسْطَى حَتَّى غَرَبَتْ الشَّمْسُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; Telah menceritakan kepada kami [Khalid] dia berkata; Telah menceritakan kepada kami [Syu'bah] dia berkata; Telah mengabarkan kepadaku [Qatadah] dari [Abu Hasan] dari [Ubaidah] dari [Ali] Radliyallahu'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \" Mereka telah menyibukkan kami dari shalat Wushtha (Ashar) hingga terbenam matahari.\""},"469":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنِي يَحْيَى عَنْ هِشَامٍ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي قِلَابَةَ قَالَ حَدَّثَنِي أَبُو الْمَلِيحِ قَالَكُنَّا مَعَ بُرَيْدَةَ فِي يَوْمٍ ذِي غَيْمٍ فَقَالَ بَكِّرُوا بِالصَّلَاةِ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَرَكَ صَلَاةَ الْعَصْرِ فَقَدْ حَبِطَ عَمَلُهُ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] dia berkata; Telah menceritakan kepadaku [Yahya] dari [Hisyam] dia berkata; Telah menceritakan kepadaku [Yahya bin Abu Katsir] dari [Abu Qilabah] berkata; Telah menceritakan kepadaku [Abul Malih] dia berkata; \"Kami pernah bersama [Buraidah] pada hari yang mendung, lalu dia berkata, 'Bersegeralah untuk shalat, karena Rasulullah shallallahu 'alaihi wasallam pernah bersabda, \" Barangsiapa meninggalkan shalat Ashar, maka gugurlah (pahala) amalannya.\""},"470":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ أَنْبَأَنَا مَنْصُورُ بْنُ زَاذَانَ عَنْ الْوَلِيدِ بْنِ مُسْلِمٍ عَنْ أَبِي الصِّدِّيقِ النَّاجِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكُنَّا نَحْزُرُ قِيَامَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الظُّهْرِ وَالْعَصْرِ فَحَزَرْنَا قِيَامَهُ فِي الظُّهْرِ قَدْرَ ثَلَاثِينَ آيَةً قَدْرَ سُورَةِ السَّجْدَةِ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ وَفِي الْأُخْرَيَيْنِ عَلَى النِّصْفِ مِنْ ذَلِكَ وَحَزَرْنَا قِيَامَهُ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ مِنْ الْعَصْرِ عَلَى قَدْرِ الْأُخْرَيَيْنِ مِنْ الظُّهْرِ وَحَزَرْنَا قِيَامَهُ فِي الرَّكْعَتَيْنِ الْأُخْرَيَيْنِ مِنْ الْعَصْرِ عَلَى النِّصْفِ مِنْ ذَلِكَ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Husyaim] berkata; Telah memberitakan kepada kami [Manshur bin Zadzan] dari [Al Walid bin Muslim] dari [Abu Shiddiq An-Naji] dari [Abu Sa'id Al Khudri] dia berkata; \"Pernah kami menaksir waktu berdirinya Rasulullah shallallahu 'alaihi wasallam. Saat shalat Zhuhur dan Ashar, maka kami menaksir berdirinya beliau saat shalat Zhuhur sekitar tiga puluh ayat, seukuran surat As-Sajdah pada dua raka'at pertama. Sedangkan pada dua raka'at terakhir beliau membaca (seukuran) separuh dari pertama. Kami perkirakan berdirinya pada dua raka'at yang pertama dari shalat Ashar seukuran dua raka'at yang terakhir dari shalat Zhuhur, dan berdirinya pada dua raka'at terakhir dari shalat Ashar separuh dari raka'at pertama.\" "},"471":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ أَبِي عَوَانَةَ عَنْ مَنْصُورِ بْنِ زَاذَانَ عَنْ الْوَلِيدِ أَبِي بِشْرٍ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُومُ فِي الظُّهْرِ فَيَقْرَأُ قَدْرَ ثَلَاثِينَ آيَةً فِي كُلِّ رَكْعَةٍ ثُمَّ يَقُومُ فِي الْعَصْرِ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ قَدْرَ خَمْسَ عَشْرَةَ آيَةً","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah memberitakan kepada kami [Abdullah bin Al Mubarak] dari [Abu 'Awanah] dari [Manshur bin Zadzan] dari [Al Walid Abu Bisyir] dari [Abu Al Mutawakkil] dari [Abu Sa'id Al Khudri] dia berkata; \"Dulu Rasulullah shallallahu 'alaihi wasallam shalat Zhuhur dan membaca sekitar tiga puluh ayat setiap raka'at. Kemudian beliau shalat ashar dengan membaca seukuran lima belas ayat pada dua raka'at pertama.\""},"472":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الظُّهْرَ بِالْمَدِينَةِ أَرْبَعًا وَصَلَّى الْعَصْرَ بِذِي الْحُلَيْفَةِ رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami [Qutaibah] Telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Abu Qilabah] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam shalat Zhuhur empat raka'at di Madinah, dan shalat Ashar dua raka'at di Dzul Hulaifah. "},"473":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ قَالَ أَنْبَأَنَا جَعْفَرُ بْنُ رَبِيعَةَ أَنَّ عِرَاكَ بْنَ مَالِكٍ حَدَّثَهُ أَنَّ نَوْفَلَ بْنَ مُعَاوِيَةَ حَدَّثَهُأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ فَاتَتْهُ صَلَاةُ الْعَصْرِ فَكَأَنَّمَا وُتِرَ أَهْلَهُ وَمَالَهُقَالَ عِرَاكٌ وَأَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عُمَرَ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ فَاتَتْهُ صَلَاةُ الْعَصْرِ فَكَأَنَّمَا وُتِرَ أَهْلَهُ وَمَالَهُ خَالَفَهُ يَزِيدُ بْنُ أَبِي حَبِيبٍ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah memberitakan kepada kami [Abdullah bin Al Mubarak] dari [Haiwah bin Syuraih] dia berkata; Telah memberitakan kepada kami [Ja'far bin Rabi'ah] bahwa ['Irak bin Malik] berkata kepadanya; sesungguhnya [Naufal bin Mu'awiyah] berkata kepadanya bahwa dia telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda; \" Barangsiapa kehilangan shalat Ashar, seolah-olah dia kehilangan (dirampas) keluarga dan hartanya. ['Irak] berkata; Telah mengabarkan kepadaku [Abdullah bin Umar] bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda; \"Barang siapa kehilangan Shalat ashar, seolah-olah dia telah kehilangan keluarga dan hartanya. Hal ini diselisihi oleh Habib bin Yazid. "},"474":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ زُغْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عِرَاكِ بْنِ مَالِكٍ أَنَّهُ بَلَغَهُ أَنَّ نَوْفَلَ بْنَ مُعَاوِيَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مِنْ الصَّلَاةِ صَلَاةٌ مَنْ فَاتَتْهُ فَكَأَنَّمَا وُتِرَ أَهْلَهُ وَمَالَهُقَالَ ابْنُ عُمَرَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ هِيَ صَلَاةُ الْعَصْرِ خَالَفَهُ مُحَمَّدُ بْنُ إِسْحَقَ","id":"Telah mengabarkan kepada kami [Isa bin Hammad Zughbah] dia berkata; Telah menceritakan kepada kami [Al-Laits] dari [Yazid bin Abu Habib] dari ['Irak bin Malik] bahwa telah sampai kepadanya, sesungguhnya [Naufal bin Mu'awiyah] berkata; \"Saya Pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda setelah menunaikan shalat: \"Itulah shalat yang barang siapa kehilangan waktunya, maka seolah-olah dia telah kehilangan keluarga dan hartanya\". [Ibnu Umar] berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa kehilangan shalat Ashar, maka seolah-olah dia kehilangan (dirampas) keluarga dan hartanya\". Ibnu Umar berkata; yaitu shalat Ashar. Ibnu Ishaq menyelisihinya. "},"475":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ بْنِ سَعْدٍ قَالَ حَدَّثَنِي عَمِّي قَالَ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَقَ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ عِرَاكِ بْنِ مَالِكٍ قَالَ سَمِعْتُ نَوْفَلَ بْنَ مُعَاوِيَةَ يَقُولُصَلَاةٌ مَنْ فَاتَتْهُ فَكَأَنَّمَا وُتِرَ أَهْلَهُ وَمَالَهُقَالَ ابْنُ عُمَرَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هِيَ صَلَاةُ الْعَصْرِ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'ad bin Ibrahim bin Sa'ad] dia berkata; Telah menceritakan kepadaku [Pamanku] dia berkata; Telah menceritakan kepadaku [Bapakku] dari [Muhammad bin Ishaq] berkata; Telah menceritakan kepadaku [Yazid bin Abu Habib] dari ['Irak bin Malik] dia berkata; Saya mendengar [Naufal bin Mu'awiyah] berkata, \"Diantara shalat, ada shalat yang jika ditinggalkan oleh seseorang, maka seolah-olah dia kehilangan (dirampas) keluarga dan hartanya'. [Ibnu Umar] berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Itu adalah shalat Ashar'.\" "},"476":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ قَالَ رَأَيْتُ سَعِيدَ بْنَ جُبَيْرٍ بِجَمْعٍأَقَامَ فَصَلَّى الْمَغْرِبَ ثَلَاثَ رَكَعَاتٍ ثُمَّ أَقَامَ فَصَلَّى يَعْنِي الْعِشَاءَ رَكْعَتَيْنِ ثُمَّ ذَكَرَ أَنَّ ابْنَ عُمَرَ صَنَعَ بِهِمْ مِثْلَ ذَلِكَ فِي ذَلِكَ الْمَكَانِ وَذَكَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَنَعَ مِثْلَ ذَلِكَ فِي ذَلِكَ الْمَكَانِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; Telah menceritakan kepada kami [Khalid] dia berkata; Telah menceritakan kepada kami [Syu'bah] dari [Salamah bin Kuhail] berkata; \"Aku melihat [Sa'id bin Jubair] di Muzdalifah melakukan iqamah lalu shalat Maghrib tiga raka'at kemudian melakukan iqamah dan shalat -yakni Isya'- dua raka'at.\" Kemudian dia menyebutkan bahwa [Ibnu Umar] berbuat serupa di tempat yang sama, dan beliau juga menyebutkan bahwa Rasulullah shallallahu 'alaihi wasallam. melakukan hal tersebut di tempat itu.\""},"477":{"ar":"أَخْبَرَنَا نَصْرُ بْنُ عَلِيِّ بْنِ نَصْرٍ عَنْ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْأَعْتَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْعِشَاءِ حَتَّى نَادَاهُ عُمَرُ رَضِيَ اللَّهُ عَنْهُ نَامَ النِّسَاءُ وَالصِّبْيَانُ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهُ لَيْسَ أَحَدٌ يُصَلِّي هَذِهِ الصَّلَاةَ غَيْرَكُمْ وَلَمْ يَكُنْ يَوْمَئِذٍ أَحَدٌ يُصَلِّي غَيْرَ أَهْلِ الْمَدِينَةِ","id":"Telah mengabarkan kepada kami [Nashr bin Ali bin Nashr] dari [Abdul A'la] dia berkata; Telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Urwah] dari [Aisyah] Radliyallahu'anha dia berkata, \" Rasulullah shallallahu 'alaihi wasallam. mengakhirkan shalat Isya' hingga Ibnu Umar Radliyallahu'anhu memanggil-manggil, 'Para wanita dan anak-anak telah tidur! ' Lalu Rasulullah shallallahu 'alaihi wasallam keluar dan bersabda: \" Tidak ada yang melakukan shalat ini selain kalian\". Pada hari itu yang melakukan shalat hanya penduduk Madinah.\""},"478":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ قَالَ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي الْحَكَمُقَالَ صَلَّى بِنَا سَعِيدُ بْنُ جُبَيْرٍ بِجَمْعٍ الْمَغْرِبَ ثَلَاثًا بِإِقَامَةٍ ثُمَّ سَلَّمَ ثُمَّ صَلَّى الْعِشَاءَ رَكْعَتَيْنِ ثُمَّ ذَكَرَ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ فَعَلَ ذَلِكَ وَذَكَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Amr bin Yazid] dia berkata; Telah menceritakan kepada kami [Bahaz bin Asad] dia berkata; Telah menceritakan kepada kami [Syu'bah] dia berkata; Telah mengabarkan kepadaku [Al Hakam] dia berkata; \" [Sa'id bin Jubair] shalat Maghrib bersama kami di Muzdalifah tiga raka'at dengan satu iqamah, lalu salam. Kemudian shalat Isya' dua raka'at.\" Lalu beliau menyebutkan bahwa [Abdullah bin Umar] melakukan hal tersebut, dan beliau (Abdullah bin Umar) menyebutkan bahwa Rasulullah shallallahu 'alaihi wasallam juga melakukan tersebut. "},"479":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ قَالَ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا سَلَمَةُ بْنُ كُهَيْلٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ قَالَرَأَيْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ صَلَّى بِجَمْعٍ فَأَقَامَ فَصَلَّى الْمَغْرِبَ ثَلَاثًا ثُمَّ صَلَّى الْعِشَاءَ رَكْعَتَيْنِ ثُمَّ قَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ فِي هَذَا الْمَكَانِ","id":"Telah mengabarkan kepada kami [Amr bin Yazid] dia berkata; Telah menceritakan kepada kami [Bahaz bin Asad] dia berkata; Telah menceritakan kepada kami [Syu'bah] dia berkata; Telah menceritakan kepada kami [Salamah bin Kuhail] dia berkata; \"Saya mendengar [Sa'id bin Jubair] berkata; \"Aku melihat [Abdullah bin Umar] shalat di Jam' (Muzdalifah). Beliau qamat lalu shalat Maghrib tiga raka'at, kemudian shalat Isya dua raka'at. Setelah itu beliau berkata; 'Aku melihat Rasulullah shallallahu 'alaihi wasallam melakukan seperti ini di tempat ini'.\" "},"480":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَتَعَاقَبُونَ فِيكُمْ مَلَائِكَةٌ بِاللَّيْلِ وَمَلَائِكَةٌ بِالنَّهَارِ وَيَجْتَمِعُونَ فِي صَلَاةِ الْفَجْرِ وَصَلَاةِ الْعَصْرِ ثُمَّ يَعْرُجُ الَّذِينَ بَاتُوا فِيكُمْ فَيَسْأَلُهُمْ وَهُوَ أَعْلَمُ بِهِمْ كَيْفَ تَرَكْتُمْ عِبَادِي فَيَقُولُونَ تَرَكْنَاهُمْ وَهُمْ يُصَلُّونَ وَأَتَيْنَاهُمْ وَهُمْ يُصَلُّونَ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Para malaikat malam dan para malaikat siang saling bergantian mendatangi kalian. Mereka berkumpul saat shalat Subuh dan Ashar. Kemudian naiklah para malaikat malam -yang mendatangi kalian- Lalu Allah bertanya kepada mereka -dan Dia lebih mengetahui semua urusan mereka-: Bagaimana keadaan hamba-hambaKu ketika kalian meninggalkannya? ' Mereka menjawab, 'Kami meninggalkan mereka sedang shalat dan ketika kami mendatangi mereka, mereka juga sedang shalat'.\""},"481":{"ar":"أَخْبَرَنَا كَثِيرُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَفْضُلُ صَلَاةُ الْجَمْعِ عَلَى صَلَاةِ أَحَدِكُمْ وَحْدَهُ بِخَمْسَةٍ وَعِشْرِينَ جُزْءًا وَيَجْتَمِعُ مَلَائِكَةُ اللَّيْلِ وَالنَّهَارِ فِي صَلَاةِ الْفَجْرِ وَاقْرَءُوا إِنْ شِئْتُمْ{ وَقُرْآنَ الْفَجْرِ إِنَّ قُرْآنَ الْفَجْرِ كَانَ مَشْهُودًا }","id":"Telah mengabarkan kepada kami [Katsir bin Ubaid] dia berkata; Telah menceritakan kepada kami [Muhammad bin Harb] dari [Az-Zubaidi] dari [Az-Zuhri] dari [Sa'id bin Musayyab] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Shalat jama'ah salah seorang dari kalian lebih utama dua puluh lima (pahala) daripada shalat salah seorang dari kalian sendirian. Malaikat malam dan malaikat siang berkumpul saat shalat Fajar, dan bacalah jika engkau menghendaki, 'Dan (dirikanlah pula shalat) Subuh'. Sesungguhnya shalat subuh disaksikan (oleh malaikat). "},"482":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَيَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ إِسْمَعِيلَ قَالَ حَدَّثَنِي أَبُو بَكْرِ بْنُ عُمَارَةَ بْنِ رُوَيْبَةَ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَلِجُ النَّارَ أَحَدٌ صَلَّى قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ أَنْ تَغْرُبَ","id":"Telah mengabarkan kepada kami [Amr bin Ali] dan [Ya'qub bin Ibrahim] keduanya berkata; Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ismail] dia berkata; Telah menceritakan kepadaku [Abu Bakr bin Umarah bin Ruwaibah] dari [Bapaknya] dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: ' Tidak akan masuk neraka orang yang melakukan shalat sebelum matahari terbit dan sebelum matahari terbenam'.\""},"483":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ الْبَرَاءِ قَالَصَلَّيْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ بَيْتِ الْمَقْدِسِ سِتَّةَ عَشَرَ شَهْرًا أَوْ سَبْعَةَ عَشَرَ شَهْرًا شَكَّ سُفْيَانُ وَصُرِفَ إِلَى الْقِبْلَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; Telah menceritakan kepada kami [Yahya bin Sa'id] Telah menceritakan kepada kami [Sufyan] dia berkata; Telah menceritakan kepada kami [Abu Ishaq] dari [Al Bara'] dia berkata; \" Kami shalat bersama Rasulullah shallallahu 'alaihi wasallam (menghadap) ke arah Baitul Maqdis selama enam belas bulan atau tujuh belas bulan -Sufyan merasa ragu-, lalu dialihkan ke kiblat (Ka'bah). "},"484":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ الْأَزْرَقُ عَنْ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَقَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ فَصَلَّى نَحْوَ بَيْتِ الْمَقْدِسِ سِتَّةَ عَشَرَ شَهْرًا ثُمَّ إِنَّهُ وُجِّهَ إِلَى الْكَعْبَةِ فَمَرَّ رَجُلٌ قَدْ كَانَ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى قَوْمٍ مِنْ الْأَنْصَارِ فَقَالَ أَشْهَدُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ وُجِّهَ إِلَى الْكَعْبَةِ فَانْحَرَفُوا إِلَى الْكَعْبَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ismail bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Ishaq bi yusuf Al Azraq] dari [Zakariyya bin Abu Zaidah] dari [Abu Ishaq] dari [Al Bara' bin 'Azib] dia berkata; \" Rasulullah shallallahu 'alaihi wasallam datang ke Madinah lalu shalat (menghadap) ke arah Baitul Maqdis selama enam belas bulan, kemudian dialihkan ke Ka'bah. Ada seorang -yang pernah shalat bersama Nabi shallallahu 'alaihi wasallam- melewati golongan kaum Anshar, lalu berkata, 'Aku bersaksi bahwa Rasulullah shallallahu 'alaihi wasallam telah dihadapkan ke Ka'bah. Lalu mereka beralih (menghadap) ke Ka'bah.\""},"485":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ زُغْبَةُ وَأَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسَبِّحُ عَلَى الرَّاحِلَةِ قِبَلَ أَيِّ وَجْهٍ تَتَوَجَّهُ وَيُوتِرُ عَلَيْهَا غَيْرَ أَنَّهُ لَا يُصَلِّي عَلَيْهَا الْمَكْتُوبَةَ","id":"Telah mengabarkan kepada kami [Isa bin Hammad Zughbah] dan [Ahmad bin Amr bin As-Sarh] dan [Al Harits bin Miskin] telah dibacakan kepadanya dan saya mendengarnya, lafazhnya dari dia, dari [Ibnu wahab] dari [Yunus] dari [Ibnu Syihab] dari [Salim] dari [Bapaknya] dia berkata; \"Dahulu Rasulullah shallallahu 'alaihi wasallam shalat sunnah di atas kendaraannya ke arah mana saja kendaraannya menghadap. Beliau juga shalat witir di atasnya, tetapi beliau tidak pernah shalat wajib di atas kendaraan.\""},"486":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ الْمُثَنَّى عَنْ يَحْيَى عَنْ عَبْدِ الْمَلِكِ قَالَ حَدَّثَنَا سَعِيدُ بْنُ جُبَيْرٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى دَابَّتِهِ وَهُوَ مُقْبِلٌ مِنْ مَكَّةَ إِلَى الْمَدِينَةِ وَفِيهِ أُنْزِلَتْ{ فَأَيْنَمَا تُوَلُّوا فَثَمَّ وَجْهُ اللَّهِ }","id":"Telah mengabarkan kepada kami [Amr bin Ali] dan [Muhammad bin Al Mutsanna] dari [Yahya] dari [Abdul Malik] dia berkata; Telah menceritakan kepada kami [Sa'id bin Jubair] dari [Ibnu Umar] dia berkata; \"Dahulu Rasulullah shallallahu 'alaihi wasallam shalat di atas hewan kendaraannya dan beliau dari arah Makkah ke arah Madinah, dan di situlah turun ayat, 'Maka kemana pun kamu menghadap di situlah wajah Allah. Sesungguhnya Allah Maha Luas (rahmat-Nya) lagi Maha Mengetahui.\""},"487":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى رَاحِلَتِهِ فِي السَّفَرِ حَيْثُمَا تَوَجَّهَتْ بِهِقَالَ مَالِكٌ قَالَ عَبْدُ اللَّهِ بْنُ دِينَارٍ وَكَانَ ابْنُ عُمَرَ يَفْعَلُ ذَلِكَ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Abdullah bin Dinar] dari [Ibnu Umar] dia berkata; \"Dahulu Rasulullah shallallahu 'alaihi wasallam shalat di atas hewan kendaraannya saat safar dan menghadap ke arah mana saja hewan itu melaju.\" Malik berkata; Abdullah bin Dinar berkata; \"Ibnu Umar juga melakukan hal yang sama.\" "},"488":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَبَيْنَمَا النَّاسُ بِقُبَاءَ فِي صَلَاةِ الصُّبْحِ جَاءَهُمْ آتٍ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أُنْزِلَ عَلَيْهِ اللَّيْلَةَ وَقَدْ أُمِرَ أَنْ يَسْتَقْبِلَ الْكَعْبَةَ فَاسْتَقْبِلُوهَاوَكَانَتْ وُجُوهُهُمْ إِلَى الشَّامِ فَاسْتَدَارُوا إِلَى الْكَعْبَةِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abdullah bin Dinar] dari [Ibnu Umar] dia berkata; \"Tatkala orang-orang berada di Quba saat shalat Subuh, datanglah seseorang, lalu berkata, \" Rasulullah shallallahu 'alaihi wasallam pada malam ini mendapat wahyu, dan beliau diperintahkan menghadap ke Ka'bah', maka beralihlah kalian menghadap ke Ka'bah. Sebelumnya wajah-wajah mereka menghadap ke Syam (Baitul Maqdis), lalu mereka berputar (menghadap) ke Ka'bah.\""},"489":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ أَنَّ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ أَخَّرَ الْعَصْرَ شَيْئًا فَقَالَ لَهُ عُرْوَةُ أَمَا إِنَّ جِبْرِيلَ عَلَيْهِ السَّلَام قَدْ نَزَلَ فَصَلَّى إِمَامَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عُمَرُ اعْلَمْ مَا تَقُولُ يَا عُرْوَةُ فَقَالَ سَمِعْتُ بَشِيرَ بْنَ أَبِي مَسْعُودٍ يَقُولُ سَمِعْتُ أَبَا مَسْعُودٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ نَزَلَ جِبْرِيلُ فَأَمَّنِي فَصَلَّيْتُ مَعَهُ ثُمَّ صَلَّيْتُ مَعَهُ ثُمَّ صَلَّيْتُ مَعَهُ ثُمَّ صَلَّيْتُ مَعَهُ ثُمَّ صَلَّيْتُ مَعَهُ يَحْسُبُ بِأَصَابِعِهِ خَمْسَ صَلَوَاتٍ","id":"Telah mengabarkan kepada kami [Qutaibah] Telah menceritakan kepada kami [Al-Laits bin Sa'ad] dari [Ibnu Syihab] bahwa Umar bin Abdul Aziz mengakhirkan shalat Ashar beberapa waktu. Urwah berkata kepadanya, \"Jibril As telah turun dan shalat mengimami Rasulullah shallallahu 'alaihi wasallam.\" Lalu Umar berkata, \"Wahai Urwah, ketahuilah apa yang engkau katakan!\" Lantas [Urwah] berkata, \"Aku mendengar [Basyir bin Abu Mas'ud] berkata; 'Aku mendengar [Abu Mas'ud] berkata; \"Aku mendengar ' Rasulullah shallallahu 'alaihi wasallam bersabda: ' Jibril telah turun shalat dengan mengimami aku. Lalu aku shalat bersamanya. Kemudian aku shalat bersamanya. Kemudian aku shalat bersamanya. Kemudian aku shalat bersamanya. Kemudian aku shalat bersamanya. Beliau shallallahu 'alaihi wasallam menghitung dengan jari beliau semuanya sebanyak lima shalat. "},"490":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا سَيَّارُ بْنُ سَلَامَةَ قَالَسَمِعْتُ أَبِي يَسْأَلُ أَبَا بَرْزَةَ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ أَنْتَ سَمِعْتَهُ قَالَ كَمَا أَسْمَعُكَ السَّاعَةَ فَقَالَ أَبِي يَسْأَلُ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ لَا يُبَالِي بَعْضَ تَأْخِيرِهَا يَعْنِي الْعِشَاءَ إِلَى نِصْفِ اللَّيْلِ وَلَا يُحِبُّ النَّوْمَ قَبْلَهَا وَلَا الْحَدِيثَ بَعْدَهَاقَالَ شُعْبَةُ ثُمَّ لَقِيتُهُ بَعْدُ فَسَأَلْتُهُ قَالَ كَانَ يُصَلِّي الظُّهْرَ حِينَ تَزُولُ الشَّمْسُ وَالْعَصْرَ يَذْهَبُ الرَّجُلُ إِلَى أَقْصَى الْمَدِينَةِ وَالشَّمْسُ حَيَّةٌ وَالْمَغْرِبَ لَا أَدْرِي أَيَّ حِينٍ ذَكَرَ ثُمَّ لَقِيتُهُ بَعْدُ فَسَأَلْتُهُ فَقَالَ وَكَانَ يُصَلِّي الصُّبْحَ فَيَنْصَرِفُ الرَّجُلُ فَيَنْظُرُ إِلَى وَجْهِ جَلِيسِهِ الَّذِي يَعْرِفُهُ فَيَعْرِفُهُ قَالَ وَكَانَ يَقْرَأُ فِيهَا بِالسِّتِّينَ إِلَى الْمِائَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; Telah menceritakan kepada kami [Khalid] dia berkata; Telah menceritakan kepada kami [Syu'bah] dia berkata; Telah menceritakan kepada kami [Sayyar bin Salamah] dia berkata; Saya mendengar Bapakku bertanya kepada [Abu Barzah] tentang shalat Rasulullah shallallahu 'alaihi wasallam. Aku berkata, \"Apakah kamu mendengarnya?\" dia (Sayar) menjawab, \"Sebagaimana aku mengabarkan tentang waktu (shalat) kepadamu, aku mendengar ayahku bertanya tentang shalat Rasulullah shallallahu 'alaihi wasallam -Ayahku menjawab, \" Rasulullah shallallahu 'alaihi wasallam tidak menghiraukan sebagian tindakannya mengakhirkan shalat- (yakni shalat Isya' sampai tengah malam). Beliau shallallahu 'alaihi wasallam tidak suka tidur sebelum melakukan shalat Isya' dan beliau shallallahu 'alaihi wasallam tidak suka bercakap-cakap sesudahnya. Syu'bah berkata; \"Kemudian aku menemui Abu Barzah dan bertanya kepadanya. Ia menjawab, \"Beliau shallallahu 'alaihi wasallam melaksanakan shalat Zhuhur ketika matahari telah tergelincir, sedangkan beliau shalat Ashar ketika seseorang memulai perjalanannya ke ujung Madinah dan matahari masih bersinar terang'. Adapun shalat Maghrib, aku tidak mengetahui secara pasti pada waktu mana yang telah disebutkan oleh Abu Barzah. Setelah itu aku menemuinya kembali dan bertanya kepadanya. Dia (Abu Barzah) menjawab, \"Beliau shallallahu 'alaihi wasallam shalat Subuh ketika lelaki dari kalangan mereka dapat mengenali teman yang berada di sampingnya. Beliau biasanya membaca enam puluh ayat hingga seratus ayat ketika shalat Subuh.\""},"491":{"ar":"أَخْبَرَنَا كَثِيرُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَنَسٌأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ حِينَ زَاغَتْ الشَّمْسُ فَصَلَّى بِهِمْ صَلَاةَ الظُّهْرِ","id":"Telah mengabarkan kepada kami [Katsir bin Ubaid] dia berkata; Telah menceritakan kepada kami [Muhammad bin Harb] dari [Az-Zubaidi] dari [Az-Zuhri] dia berkata; Telah mengabarkan kepadaku [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam keluar ketika matahari telah tergelincir, lalu shalat Zhuhur mengimami mereka (para sahabat). "},"492":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ عَنْ سَعِيدِ بْنِ وَهْبٍ عَنْ خَبَّابٍ قَالَشَكَوْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّ الرَّمْضَاءِ فَلَمْ يُشْكِنَاقِيلَ لِأَبِي إِسْحَقَ فِي تَعْجِيلِهَا قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Humaid bin Abdurrahman] dia berkata; Telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] dari [Sa'id bin Wahab] dari [Khabab] dia berkata; \"Kami mengadu kepada Rasulullah shallallahu 'alaihi wasallam dari teriknya panas, tetapi beliau shallallahu 'alaihi wasallam tidak menanggapi aduan kami.\" Abu Ishaq pernah ditanya tentang menyegerakannya (shalat Zhuhur) lalu ia menjawab, \"Ya\". "},"493":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ قَالَ حَدَّثَنِي حَمْزَةُ الْعَائِذِيُّ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا نَزَلَ مَنْزِلًا لَمْ يَرْتَحِلْ مِنْهُ حَتَّى يُصَلِّيَ الظُّهْرَ فَقَالَ رَجُلٌ وَإِنْ كَانَتْ بِنِصْفِ النَّهَارِ قَالَ وَإِنْ كَانَتْ بِنِصْفِ النَّهَارِ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] dia berkata; Telah menceritakan kepadaku [Hamzah Al 'Aa`idzi] dia berkata; Saya mendengar [Anas bin Malik] dia berkata; \" Rasulullah shallallahu 'alaihi wasallam bila singgah di suatu tempat, beliau shallallahu 'alaihi wasallam. tidak meninggalkan tempat tersebut sebelum mengerjakan shalat Zhuhur. Lalu ada seorang laki-laki yang berkata, 'Kendati baru setengah hari? ' Aku menjawab, \"Ya, kendati baru setengah hari'.\""},"494":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ دِينَارٍ أَبُو خَلْدَةَ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ الْحَرُّ أَبْرَدَ بِالصَّلَاةِ وَإِذَا كَانَ الْبَرْدُ عَجَّلَ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] dia berkata; Telah menceritakan kepada kami [Abu Sa'id] -mantan budak Bani Hasyim- dia berkata; Telah menceritakan kepada kami [Khalid bin Dinar Abu Khaldah] dia berkata; Saya mendengar [Anas bin Malik] berkata; \" Apabila cuaca sangat panas, maka 'Rasulullah shallallahu 'alaihi wasallam menunggu hingga suhu agak dingin untuk melaksanakan shalat (Zhuhur), dan jika cuaca dingin maka beliau menyegerakan.\""},"495":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا اشْتَدَّ الْحَرُّ فَأَبْرِدُوا عَنْ الصَّلَاةِ فَإِنَّ شِدَّةَ الْحَرِّ مِنْ فَيْحِ جَهَنَّمَ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; Telah menceritakan kepada kami [Al-Laits] dari [Ibnu Syihab] dari [Ibnu Al Musayyab] dan [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] berkata; bahwa Rasulullah shallallahu 'alaihi wasallam. bersabda: \" Apabila cuaca sangat panas, maka tundalah shalat hingga cuaca dingin, karena panas yang menyengat berasal dari uap neraka Jahannam.\""},"496":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ قَالَ حَدَّثَنَا أَبِي ح وَأَنْبَأَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ قَالَ حَدَّثَنَا حَفْصٌ ح وَأَنْبَأَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ قَالَ حَدَّثَنَا أَبِي عَنْ الْحَسَنِ بْنِ عُبَيْدِ اللَّهِ عَنْ إِبْرَاهِيمَ عَنْ يَزِيدَ بْنِ أَوْسٍ عَنْ ثَابِتِ بْنِ قَيْسٍ عَنْ أَبِي مُوسَى يَرْفَعُهُ قَالَأَبْرِدُوا بِالظُّهْرِ فَإِنَّ الَّذِي تَجِدُونَ مِنْ الْحَرِّ مِنْ فَيْحِ جَهَنَّمَ","id":"Telah mengabarkan kepada kami [Ibrahim bih Ya'qub] dia berkata; Telah menceritakan kepada kami [Umar bin Hafsh] dia berkata; Telah menceritakan kepada kami [Bapakku] dan Telah memberitakan kepada kami [Ibrahim bin Ya'qub] dia berkata; Telah menceritakan kepada kami [Yahya bin Ma'in] dia berkata; Telah menceritakan kepada kami [Hafsh]. Dari jalur lain, Telah memberitakan kepada kami [Amr bin Manshur] dia berkata; Telah menceritakan kepada kami [Umar bin Hafsh bin Ghiyats] dia berkata; Telah menceritakan kepada kami [Bapakku] dari [Al Hasan bin Ubaidullah] dari [Ibrahim] dari [Yazid bin Aus] dari [Tsabit bin Qais] dari [Abu Musa] -dia menyandarkannya kepada Nabi shallallahu 'alaihi wasallam- dia berkata; \" Tangguhkanlah shalat Zhuhur sampai cuaca dingin -jika cuaca saat itu panas- karena panas yang kamu rasakan adalah bagian dari uap neraka Jahannam.\""},"497":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ أَنْبَأَنَا الْفَضْلُ بْنُ مُوسَى عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا جِبْرِيلُ عَلَيْهِ السَّلَام جَاءَكُمْ يُعَلِّمُكُمْ دِينَكُمْ فَصَلَّى الصُّبْحَ حِينَ طَلَعَ الْفَجْرُ وَصَلَّى الظُّهْرَ حِينَ زَاغَتْ الشَّمْسُ ثُمَّ صَلَّى الْعَصْرَ حِينَ رَأَى الظِّلَّ مِثْلَهُ ثُمَّ صَلَّى الْمَغْرِبَ حِينَ غَرَبَتْ الشَّمْسُ وَحَلَّ فِطْرُ الصَّائِمِ ثُمَّ صَلَّى الْعِشَاءَ حِينَ ذَهَبَ شَفَقُ اللَّيْلِ ثُمَّ جَاءَهُ الْغَدَ فَصَلَّى بِهِ الصُّبْحَ حِينَ أَسْفَرَ قَلِيلًا ثُمَّ صَلَّى بِهِ الظُّهْرَ حِينَ كَانَ الظِّلُّ مِثْلَهُ ثُمَّ صَلَّى الْعَصْرَ حِينَ كَانَ الظِّلُّ مِثْلَيْهِ ثُمَّ صَلَّى الْمَغْرِبَ بِوَقْتٍ وَاحِدٍ حِينَ غَرَبَتْ الشَّمْسُ وَحَلَّ فِطْرُ الصَّائِمِ ثُمَّ صَلَّى الْعِشَاءَ حِينَ ذَهَبَ سَاعَةٌ مِنْ اللَّيْلِ ثُمَّ قَالَ الصَّلَاةُ مَا بَيْنَ صَلَاتِكَ أَمْسِ وَصَلَاتِكَ الْيَوْمَ","id":"Telah mengabarkan kepada kami [Al Hasan bin Huraits] dia berkata; Telah memberitakan kepada kami [Al Fadhlu bin Musa] dari [Muhammad bin Amr] dari [Abu Salamah] dari [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam. bersabda: \"Inilah Jibril, datang kepada kalian untuk mengajarkan agama kalian. Lalu dia shalat Subuh ketika telah terbit fajar, shalat Zhuhur ketika matahari telah tergelincir, shalat Ashar ketika dia melihat (ukuran) bayangan seperti bendanya, shalat Maghrib tatkala matahari terbenam dan saat orang yang berpuasa boleh berbuka, dan shalat Isya' ketika telah hilang mega merah. Kemudian datang lagi besoknya dan shalat Subuh ketika sedikit terang, kemudian shalat zhuhur bersamanya saat bayangan seperti aslinya, lantas shalat Ashar ketika bayangan benda dua kali dari aslinya, kemudian shalat Maghrib dengan satu waktu, yaitu saat terbenamnya matahari dan halalnya orang berpuasa untuk berbuka, selanjutnya shalat Isya' ketika berlalu sebagian malam. Kemudian dia (Jibril) berkata, ' (Waktu) shalat adalah diantara shalatmu yang kemarin dan shalatmu sekarang. "},"498":{"ar":"أَخْبَرَنَا أَبُو عَبْدِ الرَّحْمَنِ عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الْأَذْرَمِيُّ قَالَ حَدَّثَنَا عَبِيدَةُ بْنُ حُمَيْدٍ عَنْ أَبِي مَالِكٍ الْأَشْجَعِيِّ سَعْدِ بْنِ طَارِقٍ عَنْ كَثِيرِ بْنِ مُدْرِكٍ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَكَانَ قَدْرُ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ فِي الصَّيْفِ ثَلَاثَةَ أَقْدَامٍ إِلَى خَمْسَةِ أَقْدَامٍ وَفِي الشِّتَاءِ خَمْسَةَ أَقْدَامٍ إِلَى سَبْعَةِ أَقْدَامٍ","id":"Telah mengabarkan kepada kami [Abu Abdurrahman Abdullah bin Muhammad Al Adzrami] dia berkata; Telah menceritakan kepada kami [Abidah bin Humaid] dari [Abu Malik Al Asyja'i Sa'ad bin Thariq] dari [Katsir bin Mudrik] dari [Al Aswad bin Yazid] dari [Abdullah bin Mas'ud] dia berkata; \" Ukuran shalat Rasulullah shallallahu 'alaihi wasallam pada waktu Zhuhur ketika musim panas tiga sampai lima (bayangan) telapak kaki, dan musim dingin lima sampai tujuh (bayangan) telapak kaki.\""},"499":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا ثَوْرٌ حَدَّثَنِي سُلَيْمَانُ بْنُ مُوسَى عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ جَابِرٍ قَالَسَأَلَ رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ مَوَاقِيتِ الصَّلَاةِ فَقَال�� صَلِّ مَعِي فَصَلَّى الظُّهْرَ حِينَ زَاغَتْ الشَّمْسُ وَالْعَصْرَ حِينَ كَانَ فَيْءُ كُلِّ شَيْءٍ مِثْلَهُ وَالْمَغْرِبَ حِينَ غَابَتْ الشَّمْسُ وَالْعِشَاءَ حِينَ غَابَ الشَّفَقُ قَالَ ثُمَّ صَلَّى الظُّهْرَ حِينَ كَانَ فَيْءُ الْإِنْسَانِ مِثْلَهُ وَالْعَصْرَ حِينَ كَانَ فَيْءُ الْإِنْسَانِ مِثْلَيْهِ وَالْمَغْرِبَ حِينَ كَانَ قُبَيْلَ غَيْبُوبَةِ الشَّفَقِ قَالَ عَبْدُ اللَّهِ بْنُ الْحَارِثِ ثُمَّ قَالَ فِي الْعِشَاءِ أُرَى إِلَى ثُلُثِ اللَّيْلِ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] dia berkata; Telah menceritakan kepada kami [Abdullah bin Al Harits] dia berkata; Telah menceritakan kepada kami [Tsaur] Telah menceritakan kepadaku [Sulaiman bin Musa] dari [Atha bin Abu Rabah] dari [Jabir] dia berkata; \"Seorang laki-laki bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang waktu shalat. Lalu beliau shallallahu 'alaihi wasallam menjawab \" Shalatlah bersamaku\". Kemudian Rasulullah shallallahu 'alaihi wasallam shalat Zhuhur saat matahari tergelincir, Shalat Ashar ketika bayangan setiap benda seperti aslinya, shalat Maghrib tatkala matahari telah terbenam, dan shalat Isya' ketika mega merah di langit telah lenyap. Laki-laki tersebut berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam. shalat Zhuhur ketika bayangan manusia seperti aslinya, shalat Ashar ketika bayangan orang menjadi dua kali lipat, dan shalat Maghrib ketika menjelang hilangnya mega merah.\" Abdullah bin Al Harits berkata; kemudian laki-laki tersebut berkata tentang shalat Isya 'kutaksir hingga sepertiga malam. '"},"500":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى صَلَاةَ الْعَصْرِ وَالشَّمْسُ فِي حُجْرَتِهَا لَمْ يَظْهَرْ الْفَيْءُ مِنْ حُجْرَتِهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Urwah] dari [Aisyah] Radliyallahu'anha Bahwa Rasulullah Shallallahu'alaihi wasallam mengerjakan shalat Ashar ketika sinar matahari masih ada di dalam kamarnya dan bayangan belum nampak dari kamarnya."}};
